-- Combined seed for SSIAP 1/2/3 (600 cc_questions)
-- Apply via Supabase Dashboard SQL Editor

-- Wipe old hand-crafted ssiap1-box-* cc_modules
delete from public.cc_modules where id like 'ssiap1-box-%';

-- ===== ssiap1-partie1-sub01.sql =====
begin;
-- SSIAP 1 — Le feu et ses conséquences (partie 1, sub 1/3, 20 cc_questions)
values ('ssiap1-partie1', 1, 'Le feu et ses conséquences', '60 cc_questions', '🔥', 'from-red-500 to-orange-600', 0, true)
on conflict (id) do update set title=excluded.title, subtitle=excluded.subtitle, icon=excluded.icon, color=excluded.color, display_order=excluded.display_order;
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap1-q0', 'ssiap1-partie1', 'quiz', 'Quels sont les trois éléments indispensables à la combustion selon le triangle du feu ?', 'Le triangle du feu représente les trois éléments nécessaires à la combustion : le combustible (matière qui brûle), le comburant (généralement l''oxygène de l''air) et l''énergie d''activation (chaleur ou étincelle nécessaire pour amorcer la réaction). L''absence de l''un de ces trois éléments empêche ou éteint le feu.', 0, null::integer[], array['theme1','seq1','Le feu - triangle et tétraèdre','La combustion']::text[], 0),
('ssiap1-q1', 'ssiap1-partie1', 'quiz', 'Le tétraèdre du feu ajoute un quatrième élément au triangle du feu. Lequel ?', 'Le tétraèdre du feu est une évolution du triangle du feu. Il ajoute un quatrième élément : la réaction en chaîne (ou chaîne de combustion). Cette réaction en chaîne correspond à la propagation des radicaux libres qui entretiennent la combustion. Les agents extincteurs halogénés agissent spécifiquement sur cet élément.', 0, null::integer[], array['theme1','seq1','Le feu - triangle et tétraèdre','La combustion']::text[], 1),
('ssiap1-q2', 'ssiap1-partie1', 'quiz', 'Quelle est la teneur minimale en oxygène dans l''air nécessaire pour qu''une combustion soit possible ?', 'L''air contient normalement 21 % d''oxygène. La combustion est possible jusqu''à une teneur de 15 % environ. En dessous de 15 %, la combustion s''arrête faute de comburant suffisant. C''est le principe des systèmes d''extinction par réduction d''oxygène (hypoxie) utilisés dans certaines salles techniques.', 1, null::integer[], array['theme1','seq1','Le feu - triangle et tétraèdre','La combustion']::text[], 2),
('ssiap1-q3', 'ssiap1-partie1', 'quiz', 'Comment appelle-t-on le phénomène de décomposition thermique d''un combustible solide ou liquide avant inflammation ?', 'La pyrolyse est la décomposition thermique d''un matériau sous l''effet de la chaleur, sans présence d''oxygène. Elle produit des gaz combustibles qui, mélangés à l''air, pourront s''enflammer. La pyrolyse du bois, par exemple, produit des gaz inflammables à partir de 250–300 °C. Comprendre la pyrolyse est essentiel pour anticiper le comportement des matériaux en feu.', 1, null::integer[], array['theme1','seq1','Le feu - triangle et tétraèdre','La combustion']::text[], 3),
('ssiap1-q4', 'ssiap1-partie1', 'quiz', 'Qu''est-ce que le point éclair d''un liquide inflammable ?', 'Le point éclair (ou point d''éclair) est la température minimale à laquelle un liquide inflammable émet suffisamment de vapeurs pour former, avec l''air ambiant, un mélange qui s''enflamme momentanément au contact d''une source d''allumage. Il ne faut pas confondre avec le point d''auto-inflammation, où le liquide s''enflamme sans apport extérieur. Le point éclair est crucial pour le classement des liquides inflammables (ex : essence ≈ -40 °C, gazole ≈ 55 °C).', 1, null::integer[], array['theme1','seq1','Le feu - triangle et tétraèdre','La combustion']::text[], 4),
('ssiap1-q5', 'ssiap1-partie1', 'quiz', 'Parmi les propositions suivantes, laquelle décrit correctement la combustion vive ?', 'La combustion vive est une combustion rapide caractérisée par la présence de flammes et un fort dégagement de chaleur et de lumière. Elle s''oppose à la combustion lente (ou couvante) qui se déroule sans flamme visible, avec des braises et des fumées. L''incendie classique est une combustion vive. La combustion lente peut précéder l''embrasement général dans certaines situations.', 1, null::integer[], array['theme1','seq1','Le feu - triangle et tétraèdre','La combustion']::text[], 5),
('ssiap1-q6', 'ssiap1-partie1', 'quiz', 'La conduction est un mode de propagation de la chaleur. Comment se propage-t-elle ?', 'La conduction thermique est le transfert de chaleur qui se produit par contact direct entre les molécules d''un matériau ou entre deux matériaux en contact. Elle est particulièrement efficace dans les métaux (bons conducteurs). Un exemple classique : une barre métallique chauffée à une extrémité transmet la chaleur à l''autre extrémité par conduction. Dans un incendie, les structures métalliques peuvent conduire la chaleur à travers les cloisons.', 1, null::integer[], array['theme2','seq1','Modes de propagation de la chaleur','La combustion']::text[], 6),
('ssiap1-q7', 'ssiap1-partie1', 'quiz', 'La convection est responsable de la majorité des décès lors d''un incendie. Par quoi se caractérise-t-elle ?', 'La convection est le mode de propagation de la chaleur par déplacement de masses fluides (gaz chauds, fumées). Les fumées et gaz chauds montent naturellement et se propagent horizontalement sous les plafonds. La convection est le principal vecteur de propagation d''un incendie d''un local à un autre (par les couloirs, cages d''escalier, gaines techniques). Elle est responsable d''une grande partie des victimes car les fumées toxiques progressent rapidement et silencieusement.', 1, null::integer[], array['theme2','seq1','Modes de propagation de la chaleur','La combustion']::text[], 7),
('ssiap1-q8', 'ssiap1-partie1', 'quiz', 'Le rayonnement thermique peut provoquer un incendie à distance. Quelle est sa caractéristique principale ?', 'Le rayonnement thermique est un transfert de chaleur par ondes électromagnétiques (infrarouges). Sa particularité est de ne nécessiter aucun support matériel : il peut se propager dans le vide. Lors d''un incendie, le rayonnement peut enflammer des matériaux situés à plusieurs mètres du foyer initial, même sans contact ou convection. C''est pourquoi il faut maintenir des distances de sécurité entre les bâtiments (principes de compartimentage).', 2, null::integer[], array['theme2','seq1','Modes de propagation de la chaleur','La combustion']::text[], 8),
('ssiap1-q9', 'ssiap1-partie1', 'quiz', 'Des escarbilles portées par le vent allument un feu à 200 mètres du foyer principal. De quel mode de propagation s''agit-il ?', 'La projection (ou transport de brandons) est un mode de propagation particulier aux incendies de grande ampleur (feux de forêt, incendies industriels). Des particules enflammées ou des brandons sont transportés par le vent ou les courants thermiques et peuvent allumer de nouveaux foyers à grande distance. C''est l''un des modes de propagation les plus redoutés car il peut créer des foyers simultanés dans plusieurs zones.', 3, null::integer[], array['theme2','seq1','Modes de propagation de la chaleur','La combustion']::text[], 9),
('ssiap1-q10', 'ssiap1-partie1', 'quiz', 'Lors d''un incendie dans un immeuble, les fumées se propagent principalement vers :', 'Les fumées chaudes, plus légères que l''air ambiant, montent naturellement (phénomène de convection). Elles se propagent vers les niveaux supérieurs via les cages d''escalier, les gaines techniques et les vides de construction. Horizontalement, elles s''accumulent en couche sous les plafonds. C''est pourquoi les plans d''évacuation prévoient de se maintenir le plus bas possible (l''air plus frais reste près du sol) et de ne pas utiliser les ascenseurs.', 1, null::integer[], array['theme2','seq1','Modes de propagation de la chaleur','La combustion']::text[], 10),
('ssiap1-q11', 'ssiap1-partie1', 'quiz', 'Quelle est la principale cause de décès lors des incendies ?', 'L''intoxication par les fumées et gaz toxiques est la principale cause de décès lors des incendies (environ 80 % des victimes). La fumée contient du monoxyde de carbone (CO), du dioxyde de carbone (CO2), et de nombreux gaz toxiques issus de la combustion des matériaux synthétiques (acide cyanhydrique HCN, chlorure d''hydrogène HCl, etc.). Ces gaz peuvent provoquer la mort en quelques minutes même loin du foyer.', 1, null::integer[], array['theme3','seq1','Produits de la combustion et effets','La combustion']::text[], 11),
('ssiap1-q12', 'ssiap1-partie1', 'quiz', 'Le monoxyde de carbone (CO) est particulièrement dangereux lors d''un incendie. Pourquoi ?', 'Le monoxyde de carbone (CO) est un gaz incolore et inodore, produit par la combustion incomplète. Il est extrêmement toxique car il se fixe sur l''hémoglobine du sang avec une affinité 200 fois supérieure à l''oxygène (O2). Il empêche ainsi le transport de l''oxygène vers les organes, provoquant une asphyxie chimique. Son caractère imperceptible le rend d''autant plus dangereux : les victimes peuvent perdre connaissance sans s''en rendre compte.', 1, null::integer[], array['theme3','seq1','Produits de la combustion et effets','La combustion']::text[], 12),
('ssiap1-q13', 'ssiap1-partie1', 'quiz', 'Quels sont les principaux produits d''une combustion complète d''un hydrocarbure ?', 'La combustion complète d''un hydrocarbure (composé de carbone et d''hydrogène) produit du dioxyde de carbone (CO2) et de la vapeur d''eau (H2O). Cette combustion nécessite un apport suffisant en oxygène. En cas de manque d''oxygène, la combustion devient incomplète et produit du monoxyde de carbone (CO), de la suie et d''autres substances toxiques. Les pompiers mesurent la teneur en CO2 et CO dans l''atmosphère pour évaluer la dangerosité.', 1, null::integer[], array['theme3','seq1','Produits de la combustion et effets','La combustion']::text[], 13),
('ssiap1-q14', 'ssiap1-partie1', 'quiz', 'La combustion de matières plastiques (PVC, polyuréthane) est particulièrement dangereuse car :', 'Les matières synthétiques contiennent des éléments chimiques complexes qui, en brûlant, produisent des gaz hautement toxiques. Le PVC (chlorure de polyvinyle) dégage du chlorure d''hydrogène (HCl). Les polyuréthanes et matières azotées libèrent de l''acide cyanhydrique (HCN), extrêmement mortel même en faible concentration. Les plastiques ignifugés bromés produisent des dibromures très toxiques. La généralisation des matériaux synthétiques dans les bâtiments a considérablement augmenté la toxicité des fumées d''incendie.', 2, null::integer[], array['theme3','seq1','Produits de la combustion et effets','La combustion']::text[], 14),
('ssiap1-q15', 'ssiap1-partie1', 'quiz', 'A quelle classe de feu correspond la combustion de bois, papier, carton et textiles ?', 'La classe A regroupe les feux de matières solides, généralement d''origine organique, dont la combustion produit des braises. Exemples : bois, papier, carton, textiles, paille, certains plastiques. L''extincteur à eau (pulvérisée ou additif) est le plus efficace sur les feux de classe A. L''eau agit par refroidissement et étouffement.', 0, null::integer[], array['theme4','seq1','Classes de feu','La combustion']::text[], 15),
('ssiap1-q16', 'ssiap1-partie1', 'quiz', 'Un feu d''essence, de fuel ou de solvants organiques correspond à quelle classe ?', 'La classe B regroupe les feux de liquides ou de solides liquéfiables inflammables : hydrocarbures (essence, fioul, gazole), solvants, alcools, peintures, huiles minérales. Les extincteurs à mousse ou à CO2 sont adaptés aux feux de classe B. L''eau seule est contre-indiquée car elle peut projeter le liquide enflammé et aggraver l''incendie.', 1, null::integer[], array['theme4','seq1','Classes de feu','La combustion']::text[], 16),
('ssiap1-q17', 'ssiap1-partie1', 'quiz', 'Les feux de gaz (propane, butane, méthane) appartiennent à quelle classe ?', 'La classe C regroupe les feux de gaz inflammables : propane, butane, gaz naturel (méthane), hydrogène, acétylène. La priorité absolue sur un feu de gaz est de couper l''alimentation en gaz. Il ne faut pas éteindre les flammes sans couper le gaz car cela crée un risque d''explosion (accumulation de gaz puis inflammation). Les extincteurs à poudre polyvalente conviennent pour les feux de classe C.', 2, null::integer[], array['theme4','seq1','Classes de feu','La combustion']::text[], 17),
('ssiap1-q18', 'ssiap1-partie1', 'quiz', 'Les feux de métaux (magnésium, aluminium, titane) appartiennent à la classe D. Quel agent extincteur est adapté ?', 'Les feux de métaux (classe D) nécessitent des agents extincteurs spéciaux : sable sec, poudre graphite ou poudre spéciale D. L''eau est extrêmement dangereuse sur ces feux car certains métaux (magnésium, sodium) réagissent violemment avec l''eau en produisant de l''hydrogène (gaz explosif) et en aggravant l''incendie. Le CO2 et la mousse sont également contre-indiqués. La poudre D agit par smothering (étouffement) sans réaction chimique.', 2, null::integer[], array['theme4','seq1','Classes de feu','La combustion']::text[], 18),
('ssiap1-q19', 'ssiap1-partie1', 'quiz', 'Un feu dans une friteuse professionnelle (huile de cuisson surchauffée) correspond à quelle classe ?', 'La classe F a été créée pour les feux impliquant des huiles et graisses de cuisson (végétales ou animales) à haute température. Ces feux nécessitent des extincteurs spécifiques classe F (à base d''acétate de potassium). L''eau ou la mousse classique est dangereuse sur ce type de feu car l''eau se vaporise instantanément au contact de l''huile surchauffée et projette des gouttelettes d''huile enflammée (phénomène de ''crépitement''). La classe F est distincte de la classe B car les huiles de cuisson ont un comportement spécifique.', 3, null::integer[], array['theme4','seq1','Classes de feu','La combustion']::text[], 19)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap1-q0','ssiap1-q1','ssiap1-q2','ssiap1-q3','ssiap1-q4','ssiap1-q5','ssiap1-q6','ssiap1-q7','ssiap1-q8','ssiap1-q9','ssiap1-q10','ssiap1-q11','ssiap1-q12','ssiap1-q13','ssiap1-q14','ssiap1-q15','ssiap1-q16','ssiap1-q17','ssiap1-q18','ssiap1-q19');
commit;

-- ===== ssiap1-partie1-sub02.sql =====
begin;
-- SSIAP 1 — Le feu et ses conséquences (partie 1, sub 2/3, 20 cc_questions)
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap1-q20', 'ssiap1-partie1', 'quiz', 'Qu''est-ce que la Limite Inférieure d''Explosivité (LIE) d''un gaz inflammable ?', 'La LIE (Limite Inférieure d''Explosivité) est la concentration minimale d''un gaz ou vapeur dans l''air en dessous de laquelle le mélange est trop pauvre pour s''enflammer (mélange pauvre). La LSE (Limite Supérieure d''Explosivité) est la concentration au-delà de laquelle le mélange est trop riche pour s''enflammer. Entre la LIE et la LSE se trouve la zone explosive ou inflammable. Exemple pour le méthane : LIE = 5 %, LSE = 15 %.', 1, null::integer[], array['theme5','seq1','Limites d''inflammabilité LIE/LSE','La combustion']::text[], 20),
('ssiap1-q21', 'ssiap1-partie1', 'quiz', 'Un local présente une concentration en propane de 12 %. Sachant que la LIE du propane est de 2,1 % et la LSE de 9,5 %, quelle est la situation ?', 'Avec 12 % de propane dans l''air, la concentration dépasse la LSE de 9,5 %. Le mélange est trop riche pour s''enflammer directement. Cependant, la situation reste extrêmement dangereuse : si de l''air frais entre (ventilation, ouverture d''une porte), la concentration peut redescendre dans la zone explosive (entre LIE 2,1 % et LSE 9,5 %) et créer un risque d''explosion. Il faut évacuer, ne pas créer d''étincelle et alerter les secours.', 2, null::integer[], array['theme5','seq1','Limites d''inflammabilité LIE/LSE','La combustion']::text[], 21),
('ssiap1-q22', 'ssiap1-partie1', 'quiz', 'Qu''est-ce qu''un backdraft ?', 'Le backdraft est une explosion ou déflagration soudaine provoquée par l''apport d''oxygène (air frais) dans un local confiné où les fumées et gaz combustibles se sont accumulés lors d''un incendie sous-ventilé. Les signes précurseurs sont : portes et fenêtres chaudes, fumée noire et dense sortant par les interstices, verre des fenêtres noirci, absence apparente de flammes. L''ouverture d''une porte ou d''une fenêtre peut déclencher une explosion violente projetant des flammes. C''est un danger mortel pour les sapeurs-pompiers.', 1, null::integer[], array['theme6','seq2','Backdraft, flashover, phénomènes dangereux','Phénomènes particuliers']::text[], 22),
('ssiap1-q23', 'ssiap1-partie1', 'quiz', 'Le flashover (embrasement généralisé éclair) se produit lorsque :', 'Le flashover est l''embrasement généralisé et quasi-simultané de tous les matériaux combustibles présents dans un local. Il se produit quand les gaz chauds sous le plafond atteignent environ 500-600 °C ou quand le rayonnement thermique au niveau du sol atteint 20 kW/m². Le flashover marque le passage d''un incendie localisé à un incendie généralisé. En quelques secondes, la température du local peut dépasser 1000 °C. Il est mortel et constitue un risque majeur pour les sapeurs-pompiers.', 1, null::integer[], array['theme6','seq2','Backdraft, flashover, phénomènes dangereux','Phénomènes particuliers']::text[], 23),
('ssiap1-q24', 'ssiap1-partie1', 'quiz', 'BLEVE est l''acronyme de « Boiling Liquid Expanding Vapour Explosion ». Ce phénomène concerne :', 'Le BLEVE (Boiling Liquid Expanding Vapour Explosion) est l''explosion d''un récipient (citerne, bouteille de GPL) contenant un liquide sous pression (comme le propane liquide) soumis à un apport de chaleur. La chaleur surchauffe le liquide au-delà de son point d''ébullition normal, provoquant une vaporisation instantanée et explosive lors de la rupture du récipient. Si le gaz libéré est inflammable, une boule de feu géante (fireball) se forme. C''est l''un des accidents les plus violents dans l''industrie pétro-chimique.', 1, null::integer[], array['theme6','seq2','Backdraft, flashover, phénomènes dangereux','Phénomènes particuliers']::text[], 24),
('ssiap1-q25', 'ssiap1-partie1', 'quiz', 'Quels sont les signes précurseurs d''un backdraft que l''agent SSIAP doit reconnaître ?', 'Les signes précurseurs d''un backdraft sont caractéristiques : 1) La porte est chaude (ne jamais ouvrir une porte chaude sans précaution) ; 2) Fumée noire et dense sortant par les interstices ; 3) Absence apparente de flammes (le feu couve sous les fumées) ; 4) Vitres noircies ; 5) Parfois, ''respiration'' de la fumée (rentrée/sortie rythmée). Face à ces signes, l''agent SSIAP doit immédiatement évacuer la zone, ne pas ouvrir la porte et alerter les pompiers.', 1, null::integer[], array['theme6','seq2','Backdraft, flashover, phénomènes dangereux','Phénomènes particuliers']::text[], 25),
('ssiap1-q26', 'ssiap1-partie1', 'quiz', 'À quelle température les structures en acier commencent-elles à perdre significativement leur résistance mécanique ?', 'Les structures en acier commencent à perdre significativement leur résistance mécanique à partir de 550 °C environ. À 700 °C, l''acier a perdu environ 70 % de sa résistance initiale. À 1000 °C, la perte est quasi totale. C''est pourquoi les structures métalliques doivent être protégées (peintures intumescentes, encoffrement, faux-plafonds coupe-feu) pour résister au feu pendant la durée réglementaire. Cette caractéristique explique l''effondrement de certains bâtiments à ossature métallique lors d''incendies importants.', 2, null::integer[], array['theme7','seq3','Effets du feu sur les structures','Conséquences sur les personnes et les biens']::text[], 26),
('ssiap1-q27', 'ssiap1-partie1', 'quiz', 'Pourquoi le béton peut-il éclater lors d''un incendie ?', 'Le béton peut éclater lors d''un incendie par un phénomène appelé ''écaillage thermique'' ou spalling. Ce phénomène est dû à la vaporisation brutale de l''eau contenue dans le béton sous l''effet de la chaleur rapide, créant une pression interne qui fait éclater le matériau. Les différences de dilatation thermique entre la pâte de ciment et les granulats contribuent également à cet éclatement. Les bétons modernes à haute performance, plus denses, sont particulièrement vulnérables à ce phénomène.', 1, null::integer[], array['theme7','seq3','Effets du feu sur les structures','Conséquences sur les personnes et les biens']::text[], 27),
('ssiap1-q28', 'ssiap1-partie1', 'quiz', 'Un feu se déclare dans un local. Quelles sont les conséquences possibles pour les occupants ?', 'Les conséquences d''un incendie pour les personnes sont multiples : 1) Intoxication aux fumées et gaz toxiques (CO, HCN, HCl...) - principale cause de décès ; 2) Brûlures par contact direct avec les flammes ou matériaux chauds ; 3) Effets thermiques des gaz chauds sur les voies respiratoires ; 4) Panique entraînant des blessures lors de l''évacuation (bousculades, chutes) ; 5) Effets psychologiques (traumatismes). La prévention et l''évacuation organisée sont essentielles pour limiter ces conséquences.', 1, null::integer[], array['theme7','seq3','Effets du feu sur les structures','Conséquences sur les personnes et les biens']::text[], 28),
('ssiap1-q29', 'ssiap1-partie1', 'quiz', 'L''auto-inflammation est la capacité d''un matériau à s''enflammer spontanément. Quelle en est la cause ?', 'L''auto-inflammation (ou ignition spontanée) se produit lorsqu''un matériau combustible est porté à sa température d''auto-inflammation sans apport d''une flamme ou d''une étincelle externe. Elle peut se produire par accumulation de chaleur (oxydation lente d''un tas de chiffons imprégnés d''huile siccative, foin humide), par échauffement prolongé d''une surface (tuyau de chauffage contre une poutre en bois), ou par rayonnement thermique intense. Le stockage de matières organiques doit tenir compte de ce risque.', 2, null::integer[], array['theme7','seq3','Effets du feu sur les structures','Conséquences sur les personnes et les biens']::text[], 29),
('ssiap1-q77', 'ssiap1-partie1', 'multiple-select', 'Parmi les propositions suivantes, lesquelles sont des modes de propagation de la chaleur lors d''un incendie ? (plusieurs réponses possibles)', 'Les quatre modes de propagation de la chaleur lors d''un incendie sont : la conduction (transfert par contact matériel), la convection (déplacement de masses gazeuses chaudes), le rayonnement (ondes électromagnétiques infrarouges) et la projection (transport de brandons enflammés). La précipitation n''est pas un mode de propagation thermique. L''oxydation est la réaction chimique de la combustion, non un mode de propagation.', null, array[0,1,3,5]::integer[], array['theme2','seq1','Modes de propagation de la chaleur','La combustion']::text[], 30),
('ssiap1-q78', 'ssiap1-partie1', 'multiple-select', 'Quelles affirmations concernant le triangle du feu sont CORRECTES ? (plusieurs réponses possibles)', 'Les affirmations correctes : supprimer le combustible (débroussaillage, coupure de gaz) éteint bien le feu. Supprimer l''énergie d''activation (refroidissement par eau) éteint aussi le feu. La mousse agit principalement par étouffement en séparant le combustible du comburant (oxygène). En revanche, le feu ne peut pas brûler sans comburant quelle que soit la température. L''eau agit principalement par refroidissement (suppression de l''énergie) et non par suppression du comburant.', null, array[0,2,4]::integer[], array['theme1','seq1','Le feu - triangle et tétraèdre','La combustion']::text[], 31),
('ssiap1-q79', 'ssiap1-partie1', 'quiz', 'Quel est le quatrième élément du tétraèdre du feu selon la proposition suivante qui identifie un élément INEXISTANT dans cette théorie ?', 'Le tétraèdre du feu comporte exactement quatre éléments : combustible, comburant, énergie d''activation et réaction en chaîne. La pression atmosphérique, la teneur en azote, la densité de l''air et l''humidité ambiante influencent les conditions de combustion mais ne font pas partie de la définition du tétraèdre du feu. Aucune des propositions ne correspond au quatrième élément réel (la réaction en chaîne), donc ''Aucune de ces réponses n''est correcte'' est la bonne réponse.', 4, null::integer[], array['theme1','seq1','Le feu - triangle et tétraèdre','La combustion']::text[], 32),
('ssiap1-q80', 'ssiap1-partie1', 'multiple-select', 'La combustion lente (couvante) se caractérise par : (plusieurs réponses possibles)', 'La combustion lente (ou couvante) se caractérise par l''absence de flammes visibles, la présence de braises incandescentes et un dégagement de fumée dense (souvent blanche ou grise). Elle peut durer très longtemps et reprendre en combustion vive en cas d''apport d''air. Elle ne produit pas de flammes bleues (caractéristiques des flammes de gaz). Une explosion n''est pas inévitable mais possible si les gaz de combustion s''accumulent (risque de backdraft).', null, array[0,1,3]::integer[], array['theme1','seq1','Le feu - triangle et tétraèdre','La combustion']::text[], 33),
('ssiap1-q81', 'ssiap1-partie1', 'multiple-select', 'Quels gaz toxiques peut-on trouver dans les fumées d''un incendie impliquant des matières plastiques ? (plusieurs réponses possibles)', 'Les fumées d''incendie de matières plastiques contiennent de nombreux gaz toxiques : le CO (monoxyde de carbone, produit par toute combustion incomplète), l''HCN (acide cyanhydrique, produit par la combustion des polyuréthanes et matières azotées), l''HCl (chlorure d''hydrogène, produit par la combustion du PVC), et le NO2 (dioxyde d''azote, très irritant). L''oxygène pur n''est pas un produit de combustion, au contraire, la combustion consomme l''oxygène. D''autres gaz toxiques peuvent aussi être présents selon les matériaux (phosgène, styrène, etc.).', null, array[0,1,3,4]::integer[], array['theme3','seq1','Produits de la combustion et effets','La combustion']::text[], 34),
('ssiap1-q82', 'ssiap1-partie1', 'quiz', 'Quelle classe de feu correspond à un feu de magnésium en poudre ?', 'Le magnésium est un métal combustible (classe D). Les feux de métaux (classe D) comprennent le magnésium, l''aluminium en poudre, le titane, le sodium, le potassium, le lithium. Ils nécessitent des agents extincteurs spéciaux (poudre D, sable sec). L''eau, le CO2 et la mousse sont contre-indiqués et peuvent aggraver ces feux. La classe A concerne les solides ordinaires, B les liquides, C les gaz, F les huiles de cuisson.', 3, null::integer[], array['theme4','seq1','Classes de feu','La combustion']::text[], 35),
('ssiap1-q83', 'ssiap1-partie1', 'multiple-select', 'Pour éteindre un feu de classe C (gaz), quelles sont les actions prioritaires à mener ? (plusieurs réponses possibles)', 'Pour un feu de gaz : la priorité absolue est de couper l''alimentation en gaz (fermer le robinet, le détendeur ou la vanne principale). Il ne faut jamais éteindre les flammes sans avoir coupé le gaz car cela accumulerait le gaz qui pourrait exploser au contact de la moindre source d''ignition. Une fois le gaz coupé, ventiler le local pour évacuer les gaz résiduels. L''arrosage à l''eau sans couper le gaz est inefficace. L''utilisation immédiate d''un extincteur CO2 sur les flammes sans couper le gaz est contre-indiqué.', null, array[0,2,3]::integer[], array['theme4','seq1','Classes de feu','La combustion']::text[], 36),
('ssiap1-q84', 'ssiap1-partie1', 'quiz', 'Un feu se déclare dans une bibliothèque (livres, revues, rayonnages bois). De quelle(s) classe(s) s''agit-il ?', 'Les livres, revues et rayonnages en bois sont des solides d''origine organique produisant des braises lors de leur combustion : c''est typiquement un feu de classe A. Il n''y a pas de liquide inflammable ni de gaz impliqué dans ce scénario. L''extincteur à eau pulvérisée est le plus adapté pour les feux de classe A car il refroidit en profondeur et évite la reprise. La poudre ABC peut être utilisée mais laisse des résidus qui endommagent les collections.', 0, null::integer[], array['theme4','seq1','Classes de feu','La combustion']::text[], 37),
('ssiap1-q111', 'ssiap1-partie1', 'quiz', 'Quel est le rôle de l''agent extincteur dans un extincteur à poudre ABC ?', 'La poudre ABC (bicarbonate de sodium ou phosphate d''ammonium) agit par deux mécanismes : l''inhibition de la réaction en chaîne (action sur le tétraèdre du feu, côté réaction en chaîne) en détruisant les radicaux libres, et l''étouffement partiel en formant un écran entre les flammes et le combustible. Son efficacité polyvalente (A, B, C) la rend idéale pour les extincteurs portatifs d''usage général. Inconvénients : résidus importants, corrosive pour certains matériaux, dégrade les équipements électroniques.', 1, null::integer[], array['theme1','seq1','Le feu - triangle et tétraèdre','La combustion']::text[], 38),
('ssiap1-q112', 'ssiap1-partie1', 'multiple-select', 'Quels sont les signes précurseurs d''un flashover que l''agent SSIAP peut observer depuis l''extérieur d''un local ? (plusieurs réponses possibles)', 'Avant le flashover, on peut observer : des flammes apparaissant en partie haute des ouvertures (les gaz chauds sous plafond commencent à brûler), des fumées noires très denses s''échappant sous pression (signe de combustion intense), des bruits de crépitement et craquement intenses. Le local ne paraît jamais calme avant un flashover. L''éclair lumineux caractéristique se produit AU MOMENT du flashover, non avant. Face à ces signes, l''agent SSIAP doit immédiatement s''éloigner, ne jamais ouvrir la porte, et alerter les pompiers.', null, array[0,1,2]::integer[], array['theme6','seq2','Backdraft, flashover, phénomènes dangereux','Phénomènes particuliers']::text[], 39)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap1-q20','ssiap1-q21','ssiap1-q22','ssiap1-q23','ssiap1-q24','ssiap1-q25','ssiap1-q26','ssiap1-q27','ssiap1-q28','ssiap1-q29','ssiap1-q77','ssiap1-q78','ssiap1-q79','ssiap1-q80','ssiap1-q81','ssiap1-q82','ssiap1-q83','ssiap1-q84','ssiap1-q111','ssiap1-q112');
commit;

-- ===== ssiap1-partie1-sub03.sql =====
begin;
-- SSIAP 1 — Le feu et ses conséquences (partie 1, sub 3/3, 20 cc_questions)
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap1-q113', 'ssiap1-partie1', 'quiz', 'La teneur normale en oxygène dans l''air atmosphérique est de :', 'La teneur normale en oxygène dans l''air atmosphérique est de 21 % (plus précisément 20,9 %). Aucune des propositions (16 %, 18 %, 25 %, 30 %) n''est correcte. En dessous de 15 %, la combustion ne peut plus être entretenue. En dessous de 16 %, les premiers effets physiologiques apparaissent chez l''homme (essoufflement). Les systèmes d''extinction par réduction d''oxygène maintiennent l''atmosphère entre 15 % et 16 % pour empêcher la combustion tout en permettant au personnel d''intervenir brièvement.', 3, null::integer[], array['theme1','seq1','Le feu - triangle et tétraèdre','La combustion']::text[], 40),
('ssiap1-q114', 'ssiap1-partie1', 'multiple-select', 'Un feu de voiture en parking souterrain implique quelles classes de feu ? (plusieurs réponses possibles)', 'Un incendie de véhicule peut impliquer plusieurs classes de feu simultanément : Classe A (matières solides : plastiques de l''habitacle, tissus, mousse des sièges, caoutchoucs) ; Classe B (liquides inflammables : essence ou diesel, huile moteur, liquide de frein, liquide de refroidissement si inflammable) ; Classe C (gaz) si le véhicule fonctionne au GPL ou GNV (fuite possible). La carrosserie en acier et aluminium ne brûle pas dans des conditions normales d''incendie de véhicule (classe D non applicable ici). Les huiles de cuisson (classe F) n''ont rien à voir avec un véhicule.', null, array[0,1,2]::integer[], array['theme4','seq1','Classes de feu','La combustion']::text[], 41),
('ssiap1-q115', 'ssiap1-partie1', 'quiz', 'La teneur en CO (monoxyde de carbone) devient immédiatement mortelle à partir de quelle concentration dans l''air ?', 'Les seuils de danger du CO : 100 ppm : maux de tête après 2-3 heures ; 400 ppm : maux de tête violents après 3 heures ; 1 500 ppm : dangereux après 1 heure d''exposition ; 6 400 ppm : mort en moins de 30 minutes ; 12 800 ppm (1,28 %) : mort immédiate. Pour référence, une atmosphère d''incendie contient souvent entre 1 000 et 10 000 ppm de CO. Les détecteurs de CO domestiques sonnent l''alarme à 50-70 ppm (seuil sur 8 heures). Le CO est indétectable par l''homme sans appareil de mesure.', 3, null::integer[], array['theme3','seq1','Produits de la combustion et effets','La combustion']::text[], 42),
('ssiap1-q116', 'ssiap1-partie1', 'multiple-select', 'La mousse extinctrice agit principalement sur le feu par : (plusieurs réponses possibles)', 'La mousse extinctrice agit par deux mécanismes principaux : l''étouffement, en formant un tapis de mousse imperméable qui sépare la surface du liquide inflammable de l''oxygène de l''air ; et le refroidissement, car la mousse contient une forte proportion d''eau qui absorbe la chaleur en s''évaporant. Elle n''agit pas directement sur la réaction en chaîne (contrairement à la poudre) ni ne dilue les gaz. Elle est particulièrement efficace sur les feux de classe B (liquides inflammables) et certains feux de classe A. Elle est déconseillée sur les feux de métaux et équipements électriques sous tension.', null, array[0,1]::integer[], array['theme1','seq1','Le feu - triangle et tétraèdre','La combustion']::text[], 43),
('ssiap1-q117', 'ssiap1-partie1', 'quiz', 'Lors d''un feu de forêt (végétation, broussailles, arbres), quelle classe de feu s''applique principalement ?', 'Les feux de forêt (feux de végétation, broussailles, herbe sèche, bois) sont des feux de classe A : combustion de matières solides d''origine organique produisant des braises. L''eau reste le meilleur agent extincteur (refroidissement et pénétration des braises). La propagation par projection (brandons portés par le vent) est un risque majeur dans les feux de forêt. La lutte contre les feux de forêt est assurée par les SDIS (Services Départementaux d''Incendie et de Secours) avec des moyens spécialisés (canadairs, bombardiers d''eau, VLHR).', 0, null::integer[], array['theme4','seq1','Classes de feu','La combustion']::text[], 44),
('ssiap1-q118', 'ssiap1-partie1', 'quiz', 'Un feu se propage de l''appartement du 3ème étage vers les niveaux supérieurs par les gaines de vide-ordures. Ce mode de propagation est principalement :', 'Les gaines verticales (vide-ordures, gaines techniques, gaines de ventilation) constituent des voies de propagation privilégiées par convection : les gaz chauds et les flammes remontent naturellement dans ces espaces confinés et verticaux, pouvant enflammer chaque niveau qu''ils traversent. Ce phénomène explique pourquoi les gaines doivent être équipées de clapets coupe-feu à chaque niveau. Les vides d''ordures ont été progressivement supprimés des immeubles modernes en partie pour cette raison. La conduction est possible mais plus lente, le rayonnement est limité dans un espace confiné.', 1, null::integer[], array['theme2','seq1','Modes de propagation de la chaleur','La combustion']::text[], 45),
('ssiap1-q119', 'ssiap1-partie1', 'quiz', 'Quels matériaux sont considérés comme bons conducteurs thermiques et favorisent la propagation du feu par conduction ? (plusieurs réponses possibles)', 'Les métaux (acier, aluminium, cuivre) sont d''excellents conducteurs thermiques et peuvent transmettre la chaleur à travers les parois ou structures qu''ils traversent. C''est pourquoi les poutres et colonnes métalliques traversant les planchers coupe-feu doivent être protégées (manchons coupe-feu, encoffrement). Le béton, le verre, le bois et les matériaux isolants sont de mauvais conducteurs thermiques. Paradoxalement, le bois est un meilleur isolant thermique que l''acier, même s''il est combustible. Les matériaux isolants ont été justement conçus pour limiter les transferts de chaleur.', 0, null::integer[], array['theme2','seq1','Modes de propagation de la chaleur','La combustion']::text[], 46),
('ssiap1-q120', 'ssiap1-partie1', 'multiple-select', 'L''acide cyanhydrique (HCN) se distingue du monoxyde de carbone (CO) car : (plusieurs réponses possibles)', 'L''HCN (acide cyanhydrique ou prussique) est produit par la combustion de matières azotées (polyuréthanes, nylons, laine, soie, certains plastiques). Sa toxicité est 25 fois supérieure à celle du CO. Contrairement au CO qui bloque le transport de l''oxygène, l''HCN bloque la respiration cellulaire en inhibant la cytochrome oxydase (chaîne respiratoire mitochondriale) : les cellules ne peuvent plus utiliser l''oxygène même si celui-ci est présent. L''odeur d''amandes amères est caractéristique mais beaucoup de personnes ne peuvent pas la détecter génétiquement (anosmie à l''HCN). L''HCN reste dangereux quelle que soit la température.', null, array[0,1,3]::integer[], array['theme3','seq1','Produits de la combustion et effets','La combustion']::text[], 47),
('ssiap1-q152', 'ssiap1-partie1', 'quiz', 'Qu''est-ce que l''auto-inflammation par accumulation de chaleur ? Donnez un exemple concret.', 'L''auto-inflammation par accumulation de chaleur (ou combustion spontanée) est le phénomène par lequel un matériau s''enflamme sans source d''ignition externe, par élévation progressive de sa température due à une réaction exothermique interne. Exemple classique : les chiffons imprégnés d''huile siccative (lin, teck, tung) qui s''oxydent en dégageant de la chaleur. Si entassés, la chaleur s''accumule et peut atteindre la température d''auto-inflammation. D''autres exemples : tas de foin humide (fermentation), charbon de bois stocké en masse, certains engrais. C''est pourquoi ces matériaux doivent être stockés à plat, séchés, dans des contenants ouverts.', 0, null::integer[], array['theme1','seq1','Le feu - triangle et tétraèdre','La combustion']::text[], 48),
('ssiap1-q153', 'ssiap1-partie1', 'multiple-select', 'La densité de fumée affecte directement l''évacuation des occupants. Quelles en sont les conséquences ? (plusieurs réponses possibles)', 'Les fumées denses ont plusieurs effets néfastes sur l''évacuation : réduction de la visibilité (parfois à quelques centimètres), rendant les pictogrammes et cheminements invisibles ; irritation intense des voies respiratoires (toux, suffocation) et des yeux (larmoiement, brûlures), ralentissant les déplacements ; création de panique chez les occupants, augmentant le risque de bousculades et de chutes. Des études montrent que la vitesse de déplacement peut chuter de 1,2 m/s en conditions normales à 0,3 m/s dans les fumées. C''est pourquoi il est recommandé de se baisser pour trouver l''air plus frais et de ramper si nécessaire.', null, array[0,1,2]::integer[], array['theme3','seq1','Produits de la combustion et effets','La combustion']::text[], 49),
('ssiap1-q154', 'ssiap1-partie1', 'quiz', 'La température d''auto-inflammation du bois sec est d''environ :', 'La température d''auto-inflammation du bois sec est d''environ 250 à 300 °C selon l''essence et le degré de séchage. La pyrolyse (décomposition thermique sans oxygène) commence vers 200-250 °C, et les gaz produits s''enflamment spontanément autour de 250-300 °C. Aucune des propositions (100°C, 150°C, 600°C) n''est correcte. Pour information : l''essence s''enflamme spontanément vers 280 °C, le papier vers 233 °C (d''où le titre du roman ''Fahrenheit 451'' de Ray Bradbury), le polyéthylène vers 350 °C.', 0, null::integer[], array['theme1','seq1','Le feu - triangle et tétraèdre','La combustion']::text[], 50),
('ssiap1-q155', 'ssiap1-partie1', 'quiz', 'Le phénomène de stratification des fumées lors d''un incendie signifie que :', 'La stratification des fumées est un phénomène physique résultant de la différence de densité entre les gaz chauds (légers) et l''air froid (lourd). Les fumées chaudes montent et s''accumulent en couche sous le plafond, tandis que l''air plus frais reste en partie basse. Ce phénomène explique pourquoi il faut se baisser voire ramper lors d''une évacuation dans un couloir enfumé : l''air respirant se trouve près du sol. La stratification disparaît progressivement quand la fumée se refroidit ou quand l''apport de fumées est très important.', 1, null::integer[], array['theme3','seq1','Produits de la combustion et effets','La combustion']::text[], 51),
('ssiap1-q156', 'ssiap1-partie1', 'multiple-select', 'Un feu de cuisine dans une friteuse professionnelle s''enflamme. Quelles actions sont correctes ? (plusieurs réponses possibles)', 'Pour un feu de friteuse : utiliser un extincteur classe F (à acétate de potassium) conçu spécifiquement pour les huiles de cuisson ; couvrir avec un couvercle ou une plaque métallique (étouffement, suppression du comburant) ; couper l''alimentation (électricité ou gaz) pour stopper le chauffage. Si le feu ne peut être maîtrisé immédiatement, appeler les pompiers. Jeter de l''eau dans une friteuse en feu est EXTRÊMEMENT DANGEREUX : l''eau se vaporise instantanément au contact de l''huile surchauffée (300-400 °C), créant une explosion de gouttelettes d''huile enflammées projetées à plusieurs mètres (boule de feu). C''est l''une des causes les plus fréquentes de brûlures graves en restauration.', null, array[0,1,3,4]::integer[], array['theme4','seq1','Classes de feu','La combustion']::text[], 52),
('ssiap1-q157', 'ssiap1-partie1', 'quiz', 'La résistance au feu d''un élément de construction REI 120 signifie :', 'La classification de résistance au feu européenne (EN 13501-2) utilise trois critères : R (Résistance mécanique - capacité portante), E (Étanchéité aux flammes et gaz chauds), I (Isolation thermique - face non exposée < 140°C en moyenne). Le nombre indique la durée en minutes. REI 120 = les 3 critères sont satisfaits pendant 120 minutes (2 heures). Les éléments porteurs de planchers sont REI, les cloisons non porteuses peuvent être EI. Les durées réglementaires courantes sont 30, 60, 90, 120, 180 et 240 minutes.', 1, null::integer[], array['theme7','seq3','Effets du feu sur les structures','Conséquences sur les personnes et les biens']::text[], 53),
('ssiap1-q158', 'ssiap1-partie1', 'multiple-select', 'Quelles sont les principales causes d''incendie dans les ERP ? (plusieurs réponses possibles)', 'Les principales causes d''incendie dans les ERP et bâtiments sont : les défauts électriques (première cause en France : court-circuit, surcharge de câble, arc électrique, vieillissement des installations) ; les imprudences liées au tabac (mégots mal éteints dans les corbeilles, sur les balcons) ; les travaux par points chauds (brûlures de matériaux isolants, projections de métal fondu) ; la malveillance (incendies volontaires, 2ème ou 3ème cause selon les secteurs). Les systèmes de protection comme les sprinklers sont des moyens de lutte, non des causes d''incendie.', null, array[0,1,2,3]::integer[], array['theme7','seq3','Effets du feu sur les structures','Conséquences sur les personnes et les biens']::text[], 54),
('ssiap1-q159', 'ssiap1-partie1', 'quiz', 'Le ''feu de nappe'' est caractéristique des feux de :', 'Le feu de nappe est un type de feu de classe B caractéristique des liquides inflammables répandus en nappe sur le sol (ou sur l''eau). La nappe de liquide inflammable (essence, solvants, huiles) brûle en surface avec des flammes plates et s''étend facilement. Les extincteurs à mousse sont particulièrement efficaces car ils forment un tapis imperméable sur toute la surface de la nappe. Le feu de nappe est très difficile à circonscrire car le liquide peut s''écouler et propager l''incendie. Les bacs de rétention sont obligatoires pour les stockages de liquides inflammables afin d''éviter la formation de nappe.', 1, null::integer[], array['theme4','seq1','Classes de feu','La combustion']::text[], 55),
('ssiap1-q160', 'ssiap1-partie1', 'quiz', 'Quel est l''effet de l''humidité sur la combustibilité d''un matériau solide ?', 'L''humidité d''un matériau retarde ou empêche sa combustion pour deux raisons : l''eau contenue doit d''abord être vaporisée avant que la pyrolyse puisse commencer (ce qui absorbe de l''énergie : 2 257 kJ/kg pour la vaporisation de l''eau) ; la vapeur d''eau diluele les gaz combustibles et le comburant. C''est pourquoi le bois vert brûle mal, le foin humide couve plutôt qu''il ne flambe, et qu''un incendie se propage moins vite par temps humide. En revanche, l''humidité peut favoriser la combustion lente (couvante) dans certains matériaux organiques.', 2, null::integer[], array['theme1','seq1','Le feu - triangle et tétraèdre','La combustion']::text[], 56),
('ssiap1-q161', 'ssiap1-partie1', 'multiple-select', 'Quels sont les effets physiologiques du dioxyde de carbone (CO2) à haute concentration lors d''un incendie ? (plusieurs réponses possibles)', 'Le CO2 n''est pas directement toxique mais ses effets à haute concentration sont dangereux : à 3-5 %, il accélère le rythme respiratoire (hyperventilation), augmentant ainsi l''absorption de tous les autres gaz toxiques présents ; à 7-10 %, maux de tête intenses, perte de conscience possible ; à >10 %, asphyxie par manque d''oxygène et sensation de brûlure dans les voies respiratoires (réaction acide de l''acide carbonique). De plus, chaque inspiration dans une atmosphère enrichie en CO2 entraîne davantage d''inhalation de CO, HCN et autres gaz toxiques. Le CO2 n''est donc pas inoffensif à haute concentration.', null, array[0,1,2,3]::integer[], array['theme3','seq1','Produits de la combustion et effets','La combustion']::text[], 57),
('ssiap1-q194', 'ssiap1-partie1', 'multiple-select', 'Quels sont les effets des hautes températures des fumées sur les voies respiratoires ? (plusieurs réponses possibles)', 'Les gaz et fumées à haute température causent des lésions graves des voies respiratoires : brûlures thermiques des muqueuses nasales, pharyngées, trachéales et bronchiques ; œdème glottique (gonflement de la glotte et des cordes vocales) pouvant survenir plusieurs heures après l''exposition et obstruer complètement les voies aériennes ; bronchospasme réflexe (contraction des muscles bronchiques) réduisant le calibre des bronches et provoquant une détresse respiratoire. Ces lésions peuvent apparaître avec un délai de quelques heures et être mortelles même après évacuation. Les victimes exposées à des fumées chaudes doivent être systématiquement examinées par les secours médicaux même si elles semblent bien.', null, array[0,1,3]::integer[], array['theme7','seq3','Effets du feu sur les structures','Conséquences sur les personnes et les biens']::text[], 58),
('ssiap1-q197', 'ssiap1-partie1', 'multiple-select', 'Quels sont les 3 principes d''extinction d''un feu correspondant aux 3 côtés du triangle du feu ? (plusieurs réponses possibles)', 'Les trois principes d''extinction correspondent exactement aux trois côtés du triangle du feu : 1) Refroidissement = suppression de l''énergie d''activation (l''eau refroidit le combustible en dessous de son point d''ignition) ; 2) Étouffement = suppression du comburant (la mousse ou le CO2 réduisent l''oxygène disponible) ; 3) Isolation/Séparation = suppression du combustible (couper l''alimentation en gaz, débroussailler, éloigner les matières combustibles). Le 4ème principe, inhibition de la réaction en chaîne (poudre), correspond au 4ème côté du tétraèdre du feu. La pressurisation et la dilution sont des effets secondaires, non des principes d''extinction primaires.', null, array[0,1,2]::integer[], array['theme1','seq1','Le feu - triangle et tétraèdre','La combustion']::text[], 59)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap1-q113','ssiap1-q114','ssiap1-q115','ssiap1-q116','ssiap1-q117','ssiap1-q118','ssiap1-q119','ssiap1-q120','ssiap1-q152','ssiap1-q153','ssiap1-q154','ssiap1-q155','ssiap1-q156','ssiap1-q157','ssiap1-q158','ssiap1-q159','ssiap1-q160','ssiap1-q161','ssiap1-q194','ssiap1-q197');
commit;

-- ===== ssiap1-partie2-sub01.sql =====
begin;
-- SSIAP 1 — La sécurité incendie (partie 2, sub 1/3, 20 cc_questions)
values ('ssiap1-partie2', 1, 'La sécurité incendie', '55 cc_questions', '🏛️', 'from-blue-600 to-indigo-700', 1, true)
on conflict (id) do update set title=excluded.title, subtitle=excluded.subtitle, icon=excluded.icon, color=excluded.color, display_order=excluded.display_order;
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap1-q30', 'ssiap1-partie2', 'quiz', 'Qu''est-ce qu''un ERP (Établissement Recevant du Public) ?', 'Selon l''article R.123-2 du Code de la Construction et de l''Habitation, un ERP est tout bâtiment, local ou enceinte dans lequel des personnes extérieures à l''entreprise ou à la famille sont admises, que l''accès soit payant ou gratuit, libre ou restreint. Les hôtels, restaurants, supermarchés, cinémas, hôpitaux, musées, administrations sont des ERP. La réglementation ERP impose des règles strictes de sécurité incendie proportionnelles à l''effectif et à la nature de l''activité.', 1, null::integer[], array['theme1','seq1','Catégories et types d''ERP','Réglementation - ERP/IGH']::text[], 0),
('ssiap1-q31', 'ssiap1-partie2', 'quiz', 'Les ERP sont classés en 5 catégories selon leur effectif. À quelle catégorie appartient un ERP de 2ème catégorie ?', 'Le classement des ERP par catégorie selon l''effectif : 1ère catégorie : > 1500 personnes ; 2ème catégorie : de 701 à 1500 personnes ; 3ème catégorie : de 301 à 700 personnes ; 4ème catégorie : ≤ 300 personnes (sauf la 5ème cat.) ; 5ème catégorie : effectifs inférieurs aux seuils réglementaires définis par type. Les 4 premières catégories sont soumises aux prescriptions du règlement de sécurité ERP. La 5ème catégorie a des obligations allégées.', 1, null::integer[], array['theme1','seq1','Catégories et types d''ERP','Réglementation - ERP/IGH']::text[], 1),
('ssiap1-q32', 'ssiap1-partie2', 'quiz', 'Un cinéma est classé dans quel type d''ERP ?', 'Les ERP sont classés par types selon leur activité. Type L : Salles d''auditions, de conférences, de réunions, de spectacles ou à usage multiple (cinémas, théâtres, salles polyvalentes). Type M : Magasins de vente et centres commerciaux. Type N : Restaurants et débits de boissons. Type O : Hôtels et pensions de famille. Type P : Salles de danse et de jeux. Type R : Établissements d''enseignement. Type S : Bibliothèques, centres de documentation. Type U : Établissements sanitaires. Type W : Administrations, banques, bureaux.', 0, null::integer[], array['theme1','seq1','Catégories et types d''ERP','Réglementation - ERP/IGH']::text[], 2),
('ssiap1-q33', 'ssiap1-partie2', 'quiz', 'Qu''est-ce qu''un Immeuble de Grande Hauteur (IGH) ?', 'Selon la loi du 7 janvier 1983, un IGH est un bâtiment dont le plancher bas du dernier niveau accessible est situé à plus de 50 m du sol pour les immeubles d''habitation, ou à plus de 28 m pour les autres usages (bureaux, hôtels, commerces, etc.). Les IGH sont soumis à une réglementation spécifique très stricte (article R.122 du CCH) en raison des difficultés d''évacuation et d''intervention des secours. Les IGH sont classés en plusieurs classes (GHA, GHB, GHC, GHD, GHE, GHF, GHZ).', 1, null::integer[], array['theme1','seq1','Catégories et types d''ERP','Réglementation - ERP/IGH']::text[], 3),
('ssiap1-q34', 'ssiap1-partie2', 'quiz', 'La commission de sécurité dans un ERP a pour rôle principal de :', 'La commission de sécurité est une instance administrative présidée par le représentant de l''État (préfet ou sous-préfet) qui visite les ERP pour vérifier la conformité avec la réglementation sécurité incendie. Elle délivre un avis favorable ou défavorable sur l''ouverture ou la poursuite de l''exploitation d''un ERP. En cas d''avis défavorable, le maire peut prononcer la fermeture. Les commissions se réunissent périodiquement et lors de travaux importants ou d''accidents.', 1, null::integer[], array['theme1','seq1','Catégories et types d''ERP','Réglementation - ERP/IGH']::text[], 4),
('ssiap1-q35', 'ssiap1-partie2', 'quiz', 'Quelle est la distance maximale à parcourir pour atteindre un extincteur dans un ERP ?', 'La réglementation ERP impose que tout point d''un bâtiment doit se trouver à moins de 15 mètres d''un extincteur (distance à parcourir de 15 m). En pratique, pour garantir cela, les extincteurs sont positionnés de façon à ce que la distance maximale de parcours soit de 15 m pour les feux de classe B et 20 m pour les feux de classe A. Les extincteurs doivent être visibles, accessibles et signalés. En règle générale, on prévoit au minimum 1 extincteur pour 200 m² et par niveau.', 2, null::integer[], array['theme2','seq2','Extincteurs - types et utilisation','Moyens d''extinction']::text[], 5),
('ssiap1-q36', 'ssiap1-partie2', 'quiz', 'Quel type d''extincteur est contre-indiqué sur un feu d''origine électrique sous tension ?', 'L''eau est conductrice d''électricité. Un extincteur à eau (jet plein ou pulvérisé sans additif) ne doit pas être utilisé sur un équipement électrique sous tension en raison du risque d''électrocution. Les extincteurs adaptés aux risques électriques sont : le CO2 (gaz non conducteur, idéal pour le matériel électronique), et la poudre (mais qui dégrade irrémédiablement l''équipement). Avant d''intervenir sur un équipement électrique, il faut idéalement couper le courant. Certains extincteurs à eau additionnée sont homologués pour risques électriques.', 1, null::integer[], array['theme2','seq2','Extincteurs - types et utilisation','Moyens d''extinction']::text[], 6),
('ssiap1-q37', 'ssiap1-partie2', 'quiz', 'Un extincteur CO2 de 5 kg permet d''éteindre un feu de classe B. Quelle est sa durée de décharge approximative ?', 'La durée de décharge d''un extincteur CO2 de 5 kg est d''environ 10 à 15 secondes. Cette durée courte impose d''être précis et rapide lors de l''utilisation. Le CO2 agit par étouffement (réduction de l''oxygène) et par refroidissement. Ses avantages : gaz propre (pas de résidu), non conducteur d''électricité, adapté aux archives, matériels électroniques. Ses inconvénients : refroidissement rapide (risque de re-ignition), efficacité réduite en extérieur (le gaz se dissipe), risque d''asphyxie dans les espaces confinés.', 1, null::integer[], array['theme2','seq2','Extincteurs - types et utilisation','Moyens d''extinction']::text[], 7),
('ssiap1-q38', 'ssiap1-partie2', 'quiz', 'Quelle est la fréquence de vérification réglementaire des extincteurs ?', 'La réglementation impose une vérification annuelle des extincteurs par un technicien qualifié. Cette vérification comprend : contrôle visuel de l''état général, vérification de la pression (pour les extincteurs à pression permanente), contrôle du scellement du dispositif de sécurité et de l''étiquette. La révision (déchargement, nettoyage, recharge) est effectuée selon les préconisations du fabricant et au minimum tous les 5 à 10 ans. L''agent SSIAP doit effectuer des contrôles visuels réguliers entre les vérifications officielles.', 1, null::integer[], array['theme2','seq2','Extincteurs - types et utilisation','Moyens d''extinction']::text[], 8),
('ssiap1-q39', 'ssiap1-partie2', 'quiz', 'Quelle est la technique correcte d''utilisation d''un extincteur à poudre ?', 'La technique d''utilisation d''un extincteur se résume par l''acronyme DIPA : Dégoupiller (retirer la goupille de sécurité), Inspecter (vérifier visuellement), Pointer (diriger le jet à la base des flammes), Appuyer (sur la manette). Il faut diriger le jet à la BASE des flammes (et non vers le haut) et balayer en mouvement de va-et-vient. Se positionner vent dans le dos, à 2-3 mètres du feu minimum. Ne jamais se mettre seul en danger : si le feu est trop important, évacuer et alerter les secours.', 1, null::integer[], array['theme2','seq2','Extincteurs - types et utilisation','Moyens d''extinction']::text[], 9),
('ssiap1-q40', 'ssiap1-partie2', 'quiz', 'Qu''est-ce qu''un Robinet d''Incendie Armé (RIA) ?', 'Le RIA (Robinet d''Incendie Armé) est un équipement fixe de lutte contre l''incendie constitué d''un dévidoir (enrouleur), d''un tuyau semi-rigide de 25 ou 33 mm de diamètre et d''une lance d''incendie. Il est alimenté par un réseau d''eau permanent sous pression. Le RIA est utilisable par tout occupant (formation minimale requise). Il est efficace sur les feux de classe A et permet une intervention rapide sans manipulation complexe. Les RIA sont vérifiés annuellement et une pression minimale de 2,5 bars doit être maintenue.', 1, null::integer[], array['theme3','seq2','RIA et colonnes sèches/humides','Moyens d''extinction']::text[], 10),
('ssiap1-q41', 'ssiap1-partie2', 'quiz', 'Quelle est la différence entre une colonne sèche et une colonne humide ?', 'La colonne sèche est une canalisation verticale noyée dans les parois du bâtiment, vide en temps normal, avec une prise de raccordement en façade (alimentée par les pompiers avec leur autopompe) et des prises d''incendie à chaque niveau. Elle est obligatoire dans les bâtiments de plus de 28 m. La colonne humide est une canalisation sous pression permanente (eau) avec des robinets de décharge à chaque niveau. Obligatoire au-delà de 50 m (IGH) ou dans certains ERP. Les deux systèmes sont réservés aux sapeurs-pompiers.', 1, null::integer[], array['theme3','seq2','RIA et colonnes sèches/humides','Moyens d''extinction']::text[], 11),
('ssiap1-q42', 'ssiap1-partie2', 'quiz', 'Quel est l''objectif principal du désenfumage dans un bâtiment en feu ?', 'Le désenfumage a pour objectif de maintenir praticables les cheminements d''évacuation (couloirs, escaliers) et de faciliter l''intervention des secours en évacuant ou en limitant la propagation des fumées. Il existe deux types : le désenfumage naturel (exutoires de fumées, ouvrants en façade) qui exploite la poussée thermique, et le désenfumage mécanique (ventilateurs d''extraction) utilisé dans les parkings souterrains, tunnels et grands bâtiments. Le désenfumage est déclenché automatiquement par le SSI ou manuellement.', 1, null::integer[], array['theme4','seq3','Désenfumage naturel et mécanique','Désenfumage']::text[], 12),
('ssiap1-q43', 'ssiap1-partie2', 'quiz', 'Un exutoire de désenfumage (EFC) est déclenché. Quelle est la procédure pour l''agent SSIAP ?', 'Face au déclenchement d''un exutoire de désenfumage, l''agent SSIAP doit : 1) Identifier la zone de déclenchement sur le tableau de signalisation ; 2) Se rendre sur les lieux pour lever le doute (vérifier s''il y a réellement un feu) ; 3) Ne pas refermer l''exutoire si un feu est confirmé (il remplit sa fonction) ; 4) Alerter les secours si nécessaire ; 5) Mettre en œuvre le POI (Plan Opérationnel d''Intervention). Les exutoires peuvent se déclencher sur déclenchement automatique (détecteur de fumée) ou manuel (commande depuis le PC sécurité).', 1, null::integer[], array['theme4','seq3','Désenfumage naturel et mécanique','Désenfumage']::text[], 13),
('ssiap1-q44', 'ssiap1-partie2', 'quiz', 'Quel type de détecteur est le plus adapté à une cuisine professionnelle où de la fumée de cuisson est fréquente ?', 'Dans une cuisine professionnelle, la présence fréquente de fumées de cuisson rendrait un détecteur de fumée inutilisable (déclenchements intempestifs). Le détecteur thermovélocimétrique (ou détecteur de chaleur) réagit à la variation rapide de température (plus de 3 à 5 °C/min) plutôt qu''aux fumées, ce qui le rend adapté aux environnements poussiéreux ou avec fumées non liées à un incendie. Il existe aussi le détecteur thermostatique qui se déclenche quand la température dépasse un seuil fixe (57, 68 ou 90 °C).', 2, null::integer[], array['theme5','seq4','Types de détecteurs automatiques','Détection incendie']::text[], 14),
('ssiap1-q45', 'ssiap1-partie2', 'quiz', 'Un détecteur optique de fumée fonctionne selon quel principe ?', 'Le détecteur optique de fumée (ou photoélectrique) utilise une source lumineuse (LED infrarouge) et un récepteur. En absence de fumée, le faisceau lumineux n''atteint pas le récepteur (chambres à diffusion - Tyndall). Quand des particules de fumée entrent dans la chambre, elles dévient le faisceau vers le récepteur et déclenchent l''alarme. Ce type est efficace pour les fumées visibles (combustion lente, plastiques, bois). Le détecteur ionique utilise une source radioactive pour ioniser l''air et est plus sensible aux combustions vives avec peu de fumée visible.', 1, null::integer[], array['theme5','seq4','Types de détecteurs automatiques','Détection incendie']::text[], 15),
('ssiap1-q46', 'ssiap1-partie2', 'quiz', 'Quelle doit être la largeur minimale d''une issue de secours dans un ERP de 1ère catégorie ?', 'Les sorties et dégagements dans les ERP sont calculés en unités de passage (UP). Une UP = 0,60 m. La largeur minimale d''un dégagement est de 2 UP (1,20 m à 1,40 m selon le type d''ERP). Dans les ERP importants (1ère et 2ème catégorie), les calculs sont plus exigeants. La largeur totale des sorties est proportionnelle à l''effectif. Règle générale : 1 UP pour 100 personnes maximum. Les portes d''issues de secours doivent toujours s''ouvrir dans le sens de l''évacuation (poussée vers l''extérieur).', 3, null::integer[], array['theme6','seq5','Issues de secours et dégagements','Issues de secours et balisage']::text[], 16),
('ssiap1-q47', 'ssiap1-partie2', 'quiz', 'Qu''est-ce qu''un BAES (Bloc Autonome d''Éclairage de Sécurité) ?', 'Le BAES (Bloc Autonome d''Éclairage de Sécurité) est un appareil d''éclairage intégrant sa propre source d''énergie (batterie) qui s''allume automatiquement lors d''une coupure de l''alimentation électrique normale. Il assure l''évacuation des personnes (éclairage d''évacuation) et la surveillance des locaux (éclairage d''ambiance/anti-panique). La durée minimale de fonctionnement est d''1 heure. Les BAES font l''objet de tests périodiques (automatiques pour les modèles SATI, ou manuels). L''agent SSIAP doit vérifier leur état lors de ses rondes.', 1, null::integer[], array['theme6','seq5','Issues de secours et dégagements','Issues de secours et balisage']::text[], 17),
('ssiap1-q48', 'ssiap1-partie2', 'quiz', 'Quelle est la durée minimale d''autonomie des BAES (Blocs Autonomes d''Éclairage de Sécurité) ?', 'La durée minimale d''autonomie d''un BAES est de 1 heure (60 minutes), conformément à la norme NF EN 60598-2-22. Cette durée est calculée pour permettre l''évacuation de tous les occupants et l''intervention initiale des secours. Les BAES d''ambiance (anti-panique) ont la même durée. Après un fonctionnement sur batterie, les BAES doivent se recharger dans un délai maximum de 12 heures. L''agent SSIAP signale immédiatement tout BAES défaillant et consigne l''anomalie dans la main courante.', 1, null::integer[], array['theme6','seq5','Issues de secours et dégagements','Issues de secours et balisage']::text[], 18),
('ssiap1-q49', 'ssiap1-partie2', 'quiz', 'La signalisation de sécurité incendie (flèches d''évacuation, sorties de secours) est de quelle couleur réglementaire ?', 'La signalisation de sécurité incendie (voies d''évacuation, sorties de secours) est réglementairement de couleur blanche sur fond vert (ISO 7010). Le vert signifie sécurité, sauvetage, premiers secours. Les pictogrammes sur fond vert indiquent les issues de secours, les voies d''évacuation, les équipements de secours (douches de sécurité, etc.). La signalisation de prohibition (interdiction de fumer, etc.) est rouge. Les avertissements sont jaunes. Les équipements de lutte contre l''incendie (extincteurs) sont signalés en rouge.', 1, null::integer[], array['theme6','seq5','Issues de secours et dégagements','Issues de secours et balisage']::text[], 19)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap1-q30','ssiap1-q31','ssiap1-q32','ssiap1-q33','ssiap1-q34','ssiap1-q35','ssiap1-q36','ssiap1-q37','ssiap1-q38','ssiap1-q39','ssiap1-q40','ssiap1-q41','ssiap1-q42','ssiap1-q43','ssiap1-q44','ssiap1-q45','ssiap1-q46','ssiap1-q47','ssiap1-q48','ssiap1-q49');
commit;

-- ===== ssiap1-partie2-sub02.sql =====
begin;
-- SSIAP 1 — La sécurité incendie (partie 2, sub 2/3, 20 cc_questions)
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap1-q50', 'ssiap1-partie2', 'quiz', 'Qu''est-ce qu''une porte coupe-feu EI 60 ?', 'La résistance au feu des éléments de construction est caractérisée par des critères : E = Étanchéité aux flammes et gaz chauds ; I = Isolation thermique (le côté non exposé ne doit pas dépasser 140°C en moyenne ou 180°C localement) ; R = Résistance mécanique (pour les éléments porteurs). Le chiffre indique la durée en minutes : EI 30 = 30 min, EI 60 = 60 min, EI 120 = 2 heures. Une porte REI 60 satisfait les 3 critères pendant 60 min. Les portes coupe-feu doivent se fermer automatiquement (dispositif de fermeture automatique) et ne jamais être bloquées ouvertes.', 1, null::integer[], array['theme7','seq6','Portes coupe-feu et compartimentage','Compartimentage et cloisonnement']::text[], 20),
('ssiap1-q51', 'ssiap1-partie2', 'quiz', 'Le compartimentage coupe-feu a pour objectif de :', 'Le compartimentage coupe-feu consiste à diviser un bâtiment en compartiments (ou secteurs) indépendants, séparés par des éléments constructifs résistants au feu (murs, planchers, portes coupe-feu). L''objectif est de confiner l''incendie dans le compartiment d''origine, empêchant sa propagation aux autres zones pendant un temps suffisant pour l''évacuation et l''intervention des secours. Les portes coupe-feu doivent toujours être maintenues fermées (jamais calées ouvertes). Les passages de câbles, gaines techniques constituent des points faibles du compartimentage qui nécessitent des protections spécifiques.', 1, null::integer[], array['theme7','seq6','Portes coupe-feu et compartimentage','Compartimentage et cloisonnement']::text[], 21),
('ssiap1-q52', 'ssiap1-partie2', 'quiz', 'Lors d''une ronde, un agent SSIAP constate qu''une porte coupe-feu est maintenue ouverte par un extincteur. Quelle est la bonne réaction ?', 'Une porte coupe-feu calée ouverte compromet totalement le compartimentage coupe-feu. L''agent SSIAP doit immédiatement retirer l''obstacle (extincteur ou tout autre cale), refermer la porte et s''assurer qu''elle se ferme correctement. Il consigne l''anomalie dans la main courante (date, heure, localisation, action prise) et en informe sa hiérarchie. Si la porte est défectueuse (ne se ferme plus correctement), il doit le signaler en urgence et suivre la procédure de signalement d''anomalie du POI.', 1, null::integer[], array['theme7','seq6','Portes coupe-feu et compartimentage','Compartimentage et cloisonnement']::text[], 22),
('ssiap1-q53', 'ssiap1-partie2', 'quiz', 'Un sprinkler (tête d''aspersion automatique) se déclenche :', 'Un sprinkler contient un élément thermosensible : soit un alliage fusible (soudure), soit une ampoule de verre remplie d''un liquide thermolatent. Quand la température au niveau de la tête sprinkler atteint une température calibrée (57°C, 68°C, 79°C, 93°C, 141°C, 182°C selon les applications), l''élément fond ou se brise, libérant le jet d''eau. Seules les têtes situées au-dessus du foyer se déclenchent. Contrairement aux idées reçues, les sprinklers ne se déclenchent PAS tous simultanément lors d''une alarme incendie.', 1, null::integer[], array['theme8','seq7','Système sprinkler','Sprinklers']::text[], 23),
('ssiap1-q85', 'ssiap1-partie2', 'multiple-select', 'Quels établissements relèvent de la réglementation ERP ? (plusieurs réponses possibles)', 'Relèvent de la réglementation ERP tous les bâtiments où des personnes extérieures sont admises : un supermarché (type M), un hôtel (type O), un cinéma (type L) sont des ERP. Un atelier industriel sans accueil du public relève de la réglementation des ICPE (Installations Classées pour la Protection de l''Environnement) et de la réglementation du travail (code du travail). Un entrepôt logistique fermé au public est également soumis à la réglementation du travail et des ICPE selon sa taille et son activité, mais pas à la réglementation ERP.', null, array[0,2,3]::integer[], array['theme1','seq1','Catégories et types d''ERP','Réglementation - ERP/IGH']::text[], 24),
('ssiap1-q86', 'ssiap1-partie2', 'quiz', 'Un ERP de type J correspond à :', 'Le type J correspond aux structures d''accueil pour personnes âgées ou personnes handicapées (maisons de retraite, EHPAD, foyers d''accueil médicalisé). Ces établissements ont des règles renforcées car les occupants ont des capacités d''évacuation réduites. Type J est considéré comme un établissement ''à sommeil'' avec des contraintes particulières (évacuation horizontale, compartimentage renforcé). Les types non listés ici incluent : G (gares), H (garages), I (salles de danses et jeux - non, c''est P), etc.', 1, null::integer[], array['theme1','seq1','Catégories et types d''ERP','Réglementation - ERP/IGH']::text[], 25),
('ssiap1-q87', 'ssiap1-partie2', 'multiple-select', 'Parmi les extincteurs suivants, lesquels sont adaptés aux feux d''équipements électriques sous tension ? (plusieurs réponses possibles)', 'Pour les feux sur équipements électriques sous tension : le CO2 est le plus adapté (gaz non conducteur, propre, pas de résidu) ; certains extincteurs à eau additionnée sont homologués pour les risques électriques (vérifier l''homologation sur l''étiquette). La poudre ABC est techniquement non conductrice à faible pression mais dégrade irrémédiablement les équipements électroniques. L''eau sans additif et la mousse sont conductrices et présentent un risque d''électrocution grave. Avant toute intervention sur matériel électrique, couper l''alimentation si possible.', null, array[0,3]::integer[], array['theme2','seq2','Extincteurs - types et utilisation','Moyens d''extinction']::text[], 26),
('ssiap1-q88', 'ssiap1-partie2', 'multiple-select', 'Lors de la vérification visuelle d''un extincteur en ronde, quels points l''agent SSIAP doit-il contrôler ? (plusieurs réponses possibles)', 'Lors d''un contrôle visuel en ronde, l''agent SSIAP vérifie : la présence de l''extincteur à son emplacement (non déplacé), l''intégrité du sceau/goupille (si déclenché, à signaler immédiatement), la date de vérification annuelle (étiquette à jour), l''absence de détérioration (corrosion, bosses, fissures). Il ne doit PAS ouvrir la valve ni déclencher partiellement l''extincteur pour vérifier la charge : cela vide l''appareil et le rend inutilisable. La vérification de charge est effectuée par le technicien lors de la visite annuelle (pesée ou indicateur de pression).', null, array[0,1,2,4]::integer[], array['theme2','seq2','Extincteurs - types et utilisation','Moyens d''extinction']::text[], 27),
('ssiap1-q89', 'ssiap1-partie2', 'multiple-select', 'Un extincteur à CO2 a les avantages suivants : (plusieurs réponses possibles)', 'Les avantages du CO2 : pas de résidu (agent propre, idéal pour archives, matériel électronique, musées), non conducteur d''électricité (utilisable sur risques électriques), adapté aux espaces sensibles. Ses limites : il se dissipe très rapidement en extérieur ou par vent (inefficace), il ne refroidit pas suffisamment pour prévenir la reprise sur les feux de classe A (pas d''effet refroidissant durable), sa courte durée de décharge (10-15 s) impose d''être précis. En espace confiné, il présente un risque d''asphyxie.', null, array[0,1,4]::integer[], array['theme2','seq2','Extincteurs - types et utilisation','Moyens d''extinction']::text[], 28),
('ssiap1-q90', 'ssiap1-partie2', 'multiple-select', 'Le déclenchement d''un seul sprinkler lors d''un incendie prouve que : (plusieurs réponses possibles)', 'Contrairement aux idées reçues, un seul sprinkler se déclenche à la fois lors d''un incendie : uniquement celui dont la température de déclenchement est atteinte (au-dessus du foyer). Les autres têtes ne se déclenchent pas. Cela prouve que le système fonctionne correctement et que le déclenchement est localisé. L''avantage est de limiter les dégâts des eaux à la zone du foyer. Les sprinklers ne détectent pas la fumée mais la chaleur. Le déclenchement simultané de tous les sprinklers (déluge) n''existe que dans des systèmes spéciaux (déluge ou préaction) utilisés dans des applications particulières.', null, array[0,2]::integer[], array['theme8','seq7','Système sprinkler','Sprinklers']::text[], 29),
('ssiap1-q91', 'ssiap1-partie2', 'multiple-select', 'Quels éléments doivent impérativement rester dégagés dans un ERP ? (plusieurs réponses possibles)', 'Doivent impérativement rester dégagés : les issues de secours et couloirs d''évacuation (jamais encombrés, bloqués ou cadenassés), les voies d''accès pour les engins des pompiers (zones de stationnement des véhicules de secours, voies ''pompiers''), les emplacements des extincteurs et RIA (accessibles immédiatement). Les locaux techniques doivent être fermés à clé (pour éviter les intrusions) mais les clés doivent être accessibles au PC sécurité. Les bureaux de direction ne sont pas soumis à des exigences de dégagement spécifiques liées à la sécurité incendie.', null, array[0,2,3]::integer[], array['theme6','seq5','Issues de secours et dégagements','Issues de secours et balisage']::text[], 30),
('ssiap1-q92', 'ssiap1-partie2', 'multiple-select', 'Concernant les portes coupe-feu, quelles affirmations sont vraies ? (plusieurs réponses possibles)', 'Les vérités sur les portes coupe-feu : elles doivent être fermées en permanence ou équipées d''un ferme-porte automatique ; elles peuvent être maintenues ouvertes légalement via des électroaimants reliés au SSI (qui les relâchent automatiquement en cas d''alarme) ; un rideau coupe-feu peut en remplacement dans certains cas réglementaires. En revanche, les bloquer avec une cale physique (bois, extincteur) est formellement interdit et supprime toute protection. Les portes CF n''ont pas d''obligation d''ouvrir dans le sens de l''évacuation (c''est une règle pour les issues de secours, pas spécifique aux CF).', null, array[0,1,4]::integer[], array['theme7','seq6','Portes coupe-feu et compartimentage','Compartimentage et cloisonnement']::text[], 31),
('ssiap1-q93', 'ssiap1-partie2', 'quiz', 'Le désenfumage naturel fonctionne grâce à quel phénomène physique ?', 'Le désenfumage naturel exploite la poussée thermique (ou tirage thermique) : les fumées chaudes sont moins denses que l''air froid et montent naturellement. Des exutoires de désenfumage (EFC - Évacuateurs de Fumées et de Chaleur) placés en partie haute du local s''ouvrent pour laisser sortir les fumées. Des entrées d''air frais en partie basse compensent la sortie des fumées. Ce principe simple et fiable (pas de partie mécanique) est utilisé en toiture des halls, entrepôts et ERP. Le désenfumage mécanique (ventilateurs) est utilisé quand la géométrie des locaux ne permet pas le naturel (parkings souterrains, tunnels).', 1, null::integer[], array['theme4','seq3','Désenfumage naturel et mécanique','Désenfumage']::text[], 32),
('ssiap1-q121', 'ssiap1-partie2', 'quiz', 'Parmi les propositions suivantes, laquelle correspond à la définition d''un IGH classe GHA ?', 'GHA correspond aux immeubles à usage d''habitation dépassant 50 m. Les IGH sont classés par lettres : GHA (habitation), GHB (bureaux), GHC (commerces), GHD (hôtels), GHE (enseignement), GHF (établissements sanitaires), GHO (hôtels de grande hauteur), GHR (résidences), GHS (dépôts d''archives), GHU (usage mixte), GHZ (à usage principal d''habitation mais avec autres activités). Aucune des trois propositions ne correspond correctement à GHA (qui est HABITATION, non bureaux, commerces ou enseignement).', 3, null::integer[], array['theme1','seq1','Catégories et types d''ERP','Réglementation - ERP/IGH']::text[], 33),
('ssiap1-q122', 'ssiap1-partie2', 'quiz', 'Quelle est la largeur d''une Unité de Passage (UP) utilisée pour calculer les dégagements dans les ERP ?', 'Une Unité de Passage (UP) est la largeur minimale pour le passage d''une personne, soit 0,60 m. Les dégagements (portes, couloirs, escaliers) sont calculés en UP selon l''effectif à évacuer. Règle générale : 1 UP pour 100 personnes (avec des règles spécifiques selon le type d''ERP). La largeur minimale d''un dégagement principal est de 2 UP (1,20 m à 1,40 m selon la tolérance de construction). Les UP permettent de standardiser les calculs et de s''assurer que les flux d''évacuation sont suffisants.', 1, null::integer[], array['theme6','seq5','Issues de secours et dégagements','Issues de secours et balisage']::text[], 34),
('ssiap1-q123', 'ssiap1-partie2', 'quiz', 'Lors de la mise en place du désenfumage mécanique dans un parking souterrain, les ventilateurs de soufflage et d''extraction doivent fonctionner selon quel principe ?', 'Dans le désenfumage mécanique d''un parking souterrain, le principe est : soufflage d''air frais en partie basse (pour pousser les fumées vers le haut et maintenir une couche d''air respirable au niveau des personnes) et extraction des fumées en partie haute (les fumées chaudes et légères se concentrent en hauteur). Ce principe respecte la stratification naturelle des fumées. Les ventilateurs utilisés dans ce contexte doivent être certifiés F400 (fonctionnement à 400 °C pendant 120 minutes) pour garantir leur efficacité pendant l''intervention des secours.', 1, null::integer[], array['theme4','seq3','Désenfumage naturel et mécanique','Désenfumage']::text[], 35),
('ssiap1-q124', 'ssiap1-partie2', 'multiple-select', 'Quels types de détecteurs sont les mieux adaptés aux risques d''incendie dans une salle informatique (serveurs, baies de brassage) ? (plusieurs réponses possibles)', 'Dans une salle informatique, les incendies débutent souvent par une surchauffe lente des composants électroniques avant l''apparition de flammes. Les détecteurs les mieux adaptés sont : le détecteur à aspiration (ou DIF - Détecteur Incendie à aspiration de Fumée) qui aspire l''air dans les conduits et détecte des concentrations infimes de fumée (très haute sensibilité, idéal sous plancher technique et dans les faux-plafonds) ; le détecteur optique linéaire (faisceau infrarouge) pour couvrir de grands volumes. Les détecteurs de flamme et thermovelocimétriques réagissent trop tard (feu déjà développé) dans ce contexte.', null, array[0,3]::integer[], array['theme5','seq4','Types de détecteurs automatiques','Détection incendie']::text[], 36),
('ssiap1-q125', 'ssiap1-partie2', 'quiz', 'Un déclencheur manuel d''alarme incendie (boîtier rouge brise-glace) doit être positionné :', 'Les déclencheurs manuels d''alarme (boîtiers rouges à brise-glace) doivent être placés à chaque niveau du bâtiment, à proximité des escaliers et sorties, accessibles en permanence (jamais derrière une porte fermée à clé). La hauteur de pose est de 1,30 m du sol (accessible à une personne en fauteuil roulant, conforme à l''accessibilité). Tout occupant doit pouvoir atteindre un déclencheur manuel sans parcourir plus de 30 à 40 mètres. Ils sont de couleur rouge normalisé (RAL 3001) et clairement identifiables.', 1, null::integer[], array['theme5','seq4','Types de détecteurs automatiques','Détection incendie']::text[], 37),
('ssiap1-q126', 'ssiap1-partie2', 'quiz', 'Les colonnes sèches dans les bâtiments sont obligatoires à partir de quelle hauteur de plancher ?', 'Les colonnes sèches sont obligatoires dans les bâtiments dont le plancher bas du dernier niveau accessible dépasse 18 m... non, plus précisément : elles sont obligatoires pour les bâtiments dont au moins un niveau est à plus de 18 m de la voie (pour les immeubles d''habitation) ou dans certains ERP selon la réglementation. Pour les IGH, dès 28 m. La règle précise varie selon le type de bâtiment. Pour les ERP, l''obligation de colonne sèche intervient quand certains niveaux ne sont plus accessibles aux engins-pompes. Le plancher à plus de 28 m est le seuil IGH qui déclenche l''obligation systématique.', 2, null::integer[], array['theme3','seq2','RIA et colonnes sèches/humides','Moyens d''extinction']::text[], 38),
('ssiap1-q127', 'ssiap1-partie2', 'quiz', 'Un RIA (Robinet d''Incendie Armé) DN25 peut délivrer un débit d''eau d''environ :', 'Un RIA DN25 (diamètre nominal 25 mm) délivre un débit de 24 litres par minute minimum sous une pression résiduelle de 2,5 bars. Un RIA DN33 délivre environ 53 l/min. Ces débits sont suffisants pour un premier attaque sur un feu naissant de classe A. Pour comparaison, une lance de pompier à main délivre 250 à 500 l/min. Le RIA est conçu pour être utilisé par des non-professionnels avant l''arrivée des pompiers. La pression doit être maintenue dans toute l''installation pour garantir ce débit.', 1, null::integer[], array['theme3','seq2','RIA et colonnes sèches/humides','Moyens d''extinction']::text[], 39)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap1-q50','ssiap1-q51','ssiap1-q52','ssiap1-q53','ssiap1-q85','ssiap1-q86','ssiap1-q87','ssiap1-q88','ssiap1-q89','ssiap1-q90','ssiap1-q91','ssiap1-q92','ssiap1-q93','ssiap1-q121','ssiap1-q122','ssiap1-q123','ssiap1-q124','ssiap1-q125','ssiap1-q126','ssiap1-q127');
commit;

-- ===== ssiap1-partie2-sub03.sql =====
begin;
-- SSIAP 1 — La sécurité incendie (partie 2, sub 3/3, 15 cc_questions)
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap1-q128', 'ssiap1-partie2', 'quiz', 'Le niveau sonore minimum requis pour l''alarme générale d''évacuation dans un ERP est de :', 'La norme NF S 61-936 impose un niveau sonore minimum de 75 dB(A) pour les diffuseurs d''alarme d''évacuation, mesuré à 1 mètre du diffuseur. Le signal doit être perceptible en tout point du bâtiment. Dans les zones bruyantes (cuisines industrielles, ateliers), le signal doit être de 5 à 10 dB(A) supérieur au bruit ambiant. Dans les locaux à sommeil (chambres), des dispositions complémentaires sont prises (diffuseurs dans les chambres). Pour les personnes malentendantes, des dispositifs visuels complémentaires (flashs lumineux) peuvent être exigés.', 2, null::integer[], array['theme6','seq5','Issues de secours et dégagements','Issues de secours et balisage']::text[], 40),
('ssiap1-q129', 'ssiap1-partie2', 'multiple-select', 'Quel est le classement de réaction au feu des matériaux de construction selon la norme européenne Euroclasses ? (plusieurs réponses possibles)', 'Le système Euroclasses (EN 13501-1) classe les matériaux de A1 à F selon leur comportement au feu : A1 : non combustible (béton, acier, verre, pierre) ; A2 : quasi non combustible (légère contribution au feu) ; B : très faible contribution au feu ; C : faible contribution ; D : contribution acceptable ; E : réaction acceptable ; F : pas de performance déterminée (les plus inflammables). Les classes A1 et A2 sont les meilleures. Des critères complémentaires s : s1 (peu de fumée), d0 (pas de gouttes/particules) complètent la classification. La classe B est donc la troisième meilleure, non ''incombustible de type 2''.', null, array[0,1,3]::integer[], array['theme7','seq6','Portes coupe-feu et compartimentage','Compartimentage et cloisonnement']::text[], 41),
('ssiap1-q130', 'ssiap1-partie2', 'quiz', 'En cas d''incendie, les escaliers d''évacuation doivent impérativement être :', 'Les escaliers d''évacuation doivent être protégés (escaliers encloisonnés) pour éviter la pénétration des fumées qui rendraient l''évacuation impossible. Les parois coupe-feu avec des portes CF à fermeture automatique créent une protection physique. Le désenfumage de la cage d''escalier (par ouvrant en façade ou mécanique) empêche l''accumulation de fumées. Ce principe est fondamental : si les escaliers sont envahis par les fumées, les occupants des étages sont piégés. Les escaliers ouverts (non encloisonnés) ne sont admis que dans des cas très limités réglementairement.', 1, null::integer[], array['theme4','seq3','Désenfumage naturel et mécanique','Désenfumage']::text[], 42),
('ssiap1-q162', 'ssiap1-partie2', 'quiz', 'Dans un ERP, les locaux à risques particuliers (chaufferie, local électrique) doivent être :', 'Les locaux à risques particuliers (chaufferie, sous-station électrique, local groupe électrogène, stockage de liquides inflammables, etc.) doivent être isolés du reste du bâtiment par des parois coupe-feu de résistance adaptée (EI 60 ou EI 120 selon le risque). Ils doivent rester fermés à clé en permanence pour éviter les intrusions et limiter l''accès aux seules personnes habilitées. Les clés doivent être disponibles au PC sécurité. Ces locaux sont aussi équipés de moyens de détection et d''extinction adaptés à leurs risques spécifiques. L''agent SSIAP doit connaître leur localisation et les risques associés.', 1, null::integer[], array['theme7','seq6','Portes coupe-feu et compartimentage','Compartimentage et cloisonnement']::text[], 43),
('ssiap1-q163', 'ssiap1-partie2', 'quiz', 'Quel est le principe de fonctionnement d''un système d''extinction automatique à gaz inerte (argon, azote, Inergen) ?', 'Les systèmes d''extinction à gaz inertes (argon, azote, Inergen, mélange argon/azote/CO2) agissent par réduction de la teneur en oxygène de l''atmosphère du local en dessous du seuil de combustion (environ 14-15 %). Le gaz inerte, stocké sous haute pression, est libéré rapidement et remplace l''air dans le volume protégé. Ces systèmes sont utilisés pour protéger les salles informatiques, archives, musées, locaux électriques. Ils sont propres (pas de résidu), compatibles avec les équipements sensibles, mais nécessitent une évacuation préalable du personnel (risque d''asphyxie). Un délai de prédécharge (30 secondes) permet l''évacuation.', 1, null::integer[], array['theme2','seq2','Extincteurs - types et utilisation','Moyens d''extinction']::text[], 44),
('ssiap1-q164', 'ssiap1-partie2', 'quiz', 'L''agent SSIAP effectue une ronde et trouve un extincteur dont la goupille a été retirée mais dont la pression indique toujours le vert. Que doit-il faire ?', 'Une goupille retirée indique que l''extincteur a probablement été déclenché, même partiellement. Même si le manomètre indique encore une pression correcte, l''agent extincteur peut avoir été partiellement utilisé et l''extincteur n''est plus fiable. L''agent SSIAP doit : signaler immédiatement l''anomalie à son responsable ; remplacer l''extincteur par un appareil opérationnel provenant du stock de rechange ; consigner l''incident dans la main courante (date, heure, lieu, description, action prise). L''extincteur défaillant sera envoyé en révision/recharge par le technicien habilité. Ne jamais remettre une goupille et déclarer l''extincteur conforme sans vérification professionnelle.', 1, null::integer[], array['theme2','seq2','Extincteurs - types et utilisation','Moyens d''extinction']::text[], 45),
('ssiap1-q165', 'ssiap1-partie2', 'quiz', 'Quelle est la différence entre ''réaction au feu'' et ''résistance au feu'' d''un matériau ?', 'Ce sont deux notions fondamentalement différentes : la Réaction au feu mesure le comportement d''un matériau par rapport à sa propre combustion : contribue-t-il à l''inflammation et à la propagation du feu ? Elle se mesure par les classes Euroclasses (A1 à F). Elle concerne les matériaux de décoration, revêtements de sol, isolants. La Résistance au feu mesure la capacité d''un élément de construction (mur, plancher, porte) à conserver ses fonctions (portance R, étanchéité E, isolation I) pendant une durée déterminée face à un incendie normalisé. Elle s''exprime en minutes : EI 60, REI 120, etc. Un matériau peut avoir une bonne résistance au feu (acier) mais une mauvaise réaction (acier ne brûle pas mais ce n''est pas un classement de réaction).', 1, null::integer[], array['theme7','seq6','Portes coupe-feu et compartimentage','Compartimentage et cloisonnement']::text[], 46),
('ssiap1-q166', 'ssiap1-partie2', 'quiz', 'Les issues de secours d''un ERP doivent s''ouvrir :', 'Les issues de secours des ERP (hors 5ème catégorie en dessous de certains seuils) doivent s''ouvrir dans le sens de l''évacuation, c''est-à-dire vers l''extérieur du bâtiment. Cette règle est fondamentale : lors d''une panique, la foule se presse contre la porte. Si elle s''ouvre vers l''intérieur, la pression de la foule empêche l''ouverture et peut piéger les personnes (drame du Kiss-nightclub à Santa Maria au Brésil, 2013). L''ouverture vers l''extérieur permet à la pression de la foule d''elle-même pousser la porte dans le bon sens. Les portes doivent également être équipées d''une barre anti-panique.', 1, null::integer[], array['theme6','seq5','Issues de secours et dégagements','Issues de secours et balisage']::text[], 47),
('ssiap1-q167', 'ssiap1-partie2', 'quiz', 'Quel est le rôle de la barre anti-panique (ou barre de poussée) sur une issue de secours ?', 'La barre anti-panique (ou barre de poussée, selon la norme EN 1125) permet l''ouverture de la porte depuis l''intérieur par simple pression sur la barre, sans nécessiter de préhension, de clé ou de manipulation complexe. Elle s''ouvre instantanément même par une foule en mouvement ou une personne paniquée. Elle peut être couplée à un dispositif de verrouillage empêchant l''ouverture depuis l''extérieur (sécurité anti-intrusion), mais qui s''ouvre toujours facilement de l''intérieur. La barre anti-panique est obligatoire sur les portes des ERP dont l''effectif dépasse certains seuils. Lors des rondes, l''agent SSIAP vérifie son bon fonctionnement.', 0, null::integer[], array['theme6','seq5','Issues de secours et dégagements','Issues de secours et balisage']::text[], 48),
('ssiap1-q168', 'ssiap1-partie2', 'multiple-select', 'Quelles vérifications l''agent SSIAP doit-il effectuer sur les BAES (Blocs Autonomes d''Éclairage de Sécurité) lors de ses rondes ? (plusieurs réponses possibles)', 'Lors des rondes, l''agent SSIAP vérifie visuellement les BAES : présence du voyant vert de charge (indique que le BAES est alimenté et sa batterie en charge) ; absence de détérioration physique (coque cassée, fixation arrachée, câble apparent) ; positionnement correct et visibilité (non recouvert, non obstrué par un objet ou du mobilier). Il ne doit PAS tester manuellement la durée d''autonomie à chaque ronde (cela déchargerait les batteries et rendrait les BAES indisponibles pendant leur recharge). Les tests automatiques (SATI) ou les tests manuels périodiques sont planifiés. Le câblage interne est vérifié par le technicien qualifié lors des vérifications annuelles.', null, array[0,1,3]::integer[], array['theme6','seq5','Issues de secours et dégagements','Issues de secours et balisage']::text[], 49),
('ssiap1-q169', 'ssiap1-partie2', 'quiz', 'Combien d''extincteurs faut-il installer au minimum dans un ERP de 200 m² sur un seul niveau avec risques courants ?', 'La règle générale est : 1 extincteur portatif pour 200 à 300 m² de superficie, et au minimum 1 extincteur par niveau. Pour un ERP de 200 m² sur un seul niveau avec risques courants, 1 extincteur est le minimum réglementaire. En pratique, la règle de la distance maximale de 15 mètres peut conduire à en installer davantage. Les risques spéciaux (cuisine professionnelle, local électrique) nécessitent des extincteurs supplémentaires adaptés. L''agent SSIAP doit connaître le nombre et la localisation précise de tous les extincteurs de son établissement.', 0, null::integer[], array['theme2','seq2','Extincteurs - types et utilisation','Moyens d''extinction']::text[], 50),
('ssiap1-q170', 'ssiap1-partie2', 'quiz', 'Le système de détection incendie doit faire l''objet d''un essai mensuel. Quel est le but de cet essai ?', 'L''essai mensuel du système de détection incendie consiste à déclencher manuellement une alarme (via un déclencheur manuel ou un bouton test) pour vérifier que : l''alarme sonore fonctionne (diffuseurs actifs) ; le report d''alarme au PC sécurité est fonctionnel (voyant ou message d''alarme affiché) ; si applicable, la transmission vers un télésurveilleur ou les pompiers fonctionne. Cet essai ne teste pas chaque détecteur individuellement (cela est fait lors de la vérification annuelle). Il est consigné dans le registre de sécurité. L''agent SSIAP prévient les occupants avant l''essai pour éviter une fausse alarme stressante.', 1, null::integer[], array['theme5','seq4','Types de détecteurs automatiques','Détection incendie']::text[], 51),
('ssiap1-q171', 'ssiap1-partie2', 'quiz', 'Les sprinklers résidentiels se déclenchent à une température de :', 'Les sprinklers résidentiels (pour habitations) se déclenchent généralement à 57 °C ou 68 °C selon le modèle. Les sprinklers industriels peuvent se déclencher à des températures plus élevées (79, 93, 141, 182, 204, 260 °C) selon les applications. Les températures nominales de 45 °C, 100 °C et 150 °C ne correspondent pas aux calibrations standard des sprinklers résidentiels. Aucune des propositions n''est correcte.', 3, null::integer[], array['theme8','seq7','Système sprinkler','Sprinklers']::text[], 52),
('ssiap1-q189', 'ssiap1-partie2', 'quiz', 'Parmi les agents extincteurs suivants, lequel agit UNIQUEMENT par refroidissement ?', 'L''eau en jet diffusé agit principalement par refroidissement : elle absorbe une grande quantité de chaleur en s''évaporant (2 257 kJ/kg). La poudre ABC agit par inhibition de la réaction en chaîne et étouffement. Le CO2 agit par étouffement (réduction d''O2) et légèrement par refroidissement. La mousse agit par étouffement et refroidissement. L''halon (aujourd''hui interdit car destructeur de la couche d''ozone) agissait par inhibition chimique. L''eau reste l''agent de refroidissement le plus efficace et le moins coûteux pour les feux de classe A.', 1, null::integer[], array['theme2','seq2','Extincteurs - types et utilisation','Moyens d''extinction']::text[], 53),
('ssiap1-q190', 'ssiap1-partie2', 'multiple-select', 'Quel est le diamètre nominal (DN) standard des tuyaux semi-rigides des RIA les plus répandus ? (plusieurs réponses possibles)', 'Les RIA (Robinets d''Incendie Armés) sont installés avec des tuyaux semi-rigides de deux diamètres standards : DN 25 (25 mm de diamètre interne) pour une décharge minimale de 24 l/min, et DN 33 (33 mm) pour 53 l/min minimum. Le DN 25 est le plus courant dans les ERP. Le DN 19 est utilisé dans les installations domestiques non réglementaires. Le DN 50 et DN 100 correspondent aux tuyaux souples des pompiers (tuyaux plats), non aux RIA. La longueur standard des tuyaux de RIA est de 30 mètres.', null, array[1,2]::integer[], array['theme3','seq2','RIA et colonnes sèches/humides','Moyens d''extinction']::text[], 54)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap1-q128','ssiap1-q129','ssiap1-q130','ssiap1-q162','ssiap1-q163','ssiap1-q164','ssiap1-q165','ssiap1-q166','ssiap1-q167','ssiap1-q168','ssiap1-q169','ssiap1-q170','ssiap1-q171','ssiap1-q189','ssiap1-q190');
commit;

-- ===== ssiap1-partie3-sub01.sql =====
begin;
-- SSIAP 1 — Les installations techniques (partie 3, sub 1/2, 20 cc_questions)
values ('ssiap1-partie3', 1, 'Les installations techniques', '22 cc_questions', '⚙️', 'from-cyan-500 to-blue-600', 2, true)
on conflict (id) do update set title=excluded.title, subtitle=excluded.subtitle, icon=excluded.icon, color=excluded.color, display_order=excluded.display_order;
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap1-q54', 'ssiap1-partie3', 'quiz', 'Que signifie SSI dans le domaine de la sécurité incendie ?', 'Le SSI (Système de Sécurité Incendie) est l''ensemble des équipements automatiques et manuels dont la fonction est d''assurer la mise en sécurité d''un bâtiment en cas d''incendie. Il comprend deux sous-systèmes : le SDI (Système de Détection Incendie) qui détecte le sinistre, et le SMSI (Système de Mise en Sécurité Incendie) qui commande les actions de mise en sécurité (alarme, compartimentage, désenfumage, déverrouillage des issues). La norme NF S 61-931 définit les règles de conception et d''installation.', 1, null::integer[], array['theme1','seq1','SSI - composants et fonctionnement','Système de Sécurité Incendie (SSI)']::text[], 0),
('ssiap1-q55', 'ssiap1-partie3', 'quiz', 'Le SMSI (Système de Mise en Sécurité Incendie) comprend notamment quel équipement central ?', 'Le SMSI comprend notamment l''ECS (Équipement de Contrôle et de Signalisation) qui reçoit les ordres du SDI (via la centrale de détection) et commande les DAS (Dispositifs Actionnés de Sécurité) : fermeture des portes coupe-feu, ouverture des exutoires de désenfumage, mise en route de la ventilation de désenfumage mécanique, déclenchement de l''alarme générale, déverrouillage des issues de secours. L''ECS est généralement implanté dans le poste central de sécurité.', 2, null::integer[], array['theme1','seq1','SSI - composants et fonctionnement','Système de Sécurité Incendie (SSI)']::text[], 1),
('ssiap1-q56', 'ssiap1-partie3', 'quiz', 'Un DAS (Dispositif Actionné de Sécurité) peut être :', 'Un DAS (Dispositif Actionné de Sécurité) est tout équipement commandé par le SMSI pour assurer la mise en sécurité d''un bâtiment lors d''un incendie. Les DAS comprennent : les portes coupe-feu (CF) et leurs blocs portes (BP), les clapets coupe-feu dans les gaines de ventilation, les trappes et exutoires de désenfumage, les volets de désenfumage, les déverrouillages électriques des issues de secours, les arrêts des équipements de ventilation et climatisation. Les DAS fonctionnent généralement en position de sécurité : ils se ferment (CF, clapets) ou s''ouvrent (exutoires) lors d''une coupure de courant.', 1, null::integer[], array['theme1','seq1','SSI - composants et fonctionnement','Système de Sécurité Incendie (SSI)']::text[], 2),
('ssiap1-q57', 'ssiap1-partie3', 'quiz', 'Les SSI sont classés en catégories de A à E. Que signifie un SSI de catégorie A ?', 'Les SSI sont classés de A (le plus exigeant) à E (le plus simple). Un SSI de catégorie A comporte une détection automatique généralisée dans tous les locaux, un SMSI avec ECS, et commande toutes les fonctions de mise en sécurité (compartimentage, désenfumage, alarme). Il est obligatoire dans les ERP de 1ère et 2ème catégorie. Les catégories B, C, D, E ont des niveaux décroissants d''exigence. La catégorie E est la plus simple (alarme seule par déclencheurs manuels dans les petits ERP de 5ème catégorie).', 1, null::integer[], array['theme1','seq1','SSI - composants et fonctionnement','Système de Sécurité Incendie (SSI)']::text[], 3),
('ssiap1-q58', 'ssiap1-partie3', 'quiz', 'Quelle est la différence entre une alarme de type 1 et une alarme de type 4 ?', 'Les systèmes d''alarme incendie sont classés en 4 types : Type 1 : le plus élaboré, comprend un SDI (détection automatique) + SMSI avec ECS, obligatoire dans les grands ERP ; Type 2a : détection automatique + diffuseurs sonores, sans SMSI complet ; Type 2b : déclencheurs manuels + diffuseurs sonores avec centrale ; Type 3 : déclencheurs manuels + diffuseurs sonores sans centrale ; Type 4 : le plus simple, un seul déclencheur manuel relié directement à un ou plusieurs timbres ou cloches (autonome, sans câblage complexe). Adapté aux petits ERP de 5ème catégorie.', 1, null::integer[], array['theme1','seq1','SSI - composants et fonctionnement','Système de Sécurité Incendie (SSI)']::text[], 4),
('ssiap1-q59', 'ssiap1-partie3', 'quiz', 'Lors de sa ronde, un agent SSIAP constate qu''un détecteur de fumée au plafond a son voyant LED rouge allumé en permanence. Cela signifie :', 'Sur la plupart des détecteurs automatiques d''incendie, le voyant LED rouge allumé en permanence indique un état d''alarme ou de défaut. Un clignotement lent du LED (toutes les 5 à 10 secondes) indique un fonctionnement normal en mode de surveillance. Face à un LED rouge permanent, l''agent SSIAP doit : 1) Identifier le détecteur et sa zone sur le tableau de signalisation ; 2) Se rendre sur place pour lever le doute (y a-t-il de la fumée, un début d''incendie ?) ; 3) Informer le PC sécurité ; 4) Consigner l''anomalie dans la main courante.', 1, null::integer[], array['theme1','seq1','SSI - composants et fonctionnement','Système de Sécurité Incendie (SSI)']::text[], 5),
('ssiap1-q94', 'ssiap1-partie3', 'multiple-select', 'Que doit faire l''agent SSIAP lorsqu''une alarme incendie se déclenche au PC sécurité ? (plusieurs réponses possibles)', 'Lors d''une alarme au PC sécurité, la procédure standard est : 1) Identifier la zone d''alarme sur le tableau (quelle boucle, quel détecteur) ; 2) Effectuer la levée de doute en se rendant sur place RAPIDEMENT ; 3) Prévenir son responsable selon le POI. Le déclenchement immédiat de l''alarme générale sans vérification est réservé aux cas où le feu est visuellement confirmé ou si le POI le prescrit. L''appel immédiat aux pompiers sans vérification peut générer des interventions inutiles et mobiliser des ressources sans raison. Le POI de chaque établissement définit précisément la procédure à suivre.', null, array[0,2,4]::integer[], array['theme1','seq1','SSI - composants et fonctionnement','Système de Sécurité Incendie (SSI)']::text[], 6),
('ssiap1-q95', 'ssiap1-partie3', 'quiz', 'Un clapet coupe-feu dans une gaine de ventilation a pour rôle de :', 'Le clapet coupe-feu (CCF) est un DAS (Dispositif Actionné de Sécurité) installé dans les traversées de parois par les gaines de ventilation/climatisation. En temps normal, il est ouvert pour permettre la circulation de l''air. En cas d''incendie, il se ferme automatiquement (par fusion d''un fusible thermique ou par commande électrique du SSI) pour bloquer la propagation du feu et des fumées à travers les gaines. Les gaines de ventilation constituent en effet des voies de propagation redoutables pour les fumées et les flammes. La résistance au feu des clapets est de 30, 60 ou 120 minutes.', 1, null::integer[], array['theme1','seq1','SSI - composants et fonctionnement','Système de Sécurité Incendie (SSI)']::text[], 7),
('ssiap1-q96', 'ssiap1-partie3', 'quiz', 'L''alarme générale d''évacuation dans un ERP doit être perceptible :', 'L''alarme générale d''évacuation doit être audible dans l''ensemble des locaux de l''établissement accessibles au public et dans les locaux de travail. Le niveau sonore minimal est de 75 dB(A) en tout point du bâtiment (ou 5 dB(A) au-dessus du bruit ambiant si celui-ci est élevé). Dans les établissements à sommeil (hôtels, hôpitaux), des diffuseurs sonores sont également installés dans les chambres. Des dispositifs lumineux peuvent compléter le signal sonore pour les personnes malentendantes. L''alarme restreinte (PC sécurité seulement) précède l''alarme générale dans les établissements avec personnel de sécurité.', 1, null::integer[], array['theme1','seq1','SSI - composants et fonctionnement','Système de Sécurité Incendie (SSI)']::text[], 8),
('ssiap1-q97', 'ssiap1-partie3', 'multiple-select', 'Parmi les équipements suivants, lesquels font partie du Système de Mise en Sécurité Incendie (SMSI) ? (plusieurs réponses possibles)', 'Le SSI se divise en deux sous-systèmes : le SDI (Système de Détection Incendie) qui comprend les détecteurs automatiques et les déclencheurs manuels, et le SMSI (Système de Mise en Sécurité Incendie) qui comprend l''ECS (Équipement de Contrôle et de Signalisation qui traite les ordres) et tous les DAS (Dispositifs Actionnés de Sécurité : portes CF, exutoires, clapets, déverrouillages, etc.). Les détecteurs et boîtiers brise-glace appartiennent au SDI, pas au SMSI.', null, array[0,2,4]::integer[], array['theme1','seq1','SSI - composants et fonctionnement','Système de Sécurité Incendie (SSI)']::text[], 9),
('ssiap1-q98', 'ssiap1-partie3', 'quiz', 'Quel est le rôle du Tableau de Report d''Alarme (TRA) dans un hôtel ?', 'Le TRA (Tableau de Report d''Alarme) est un équipement qui reporte les informations d''alarme de la centrale de détection vers un point de permanence humaine (réception d''hôtel, loge de gardien). Il permet au personnel de permanence de visualiser les alarmes sans avoir à se rendre au PC sécurité principal. Dans les hôtels, il est souvent installé à la réception pour que le réceptionniste (présent 24h/24) puisse lever le doute et déclencher les procédures d''évacuation. Il est distinct de la centrale de détection et n''a généralement pas de capacité de commande des DAS.', 1, null::integer[], array['theme1','seq1','SSI - composants et fonctionnement','Système de Sécurité Incendie (SSI)']::text[], 10),
('ssiap1-q131', 'ssiap1-partie3', 'quiz', 'Qu''est-ce qu''un CMSI (Centralisateur de Mise en Sécurité Incendie) ?', 'Le CMSI (Centralisateur de Mise en Sécurité Incendie) est le composant central du SMSI. Il reçoit les informations d''alarme provenant du SDI (centrale de détection) et commande en conséquence les DAS (Dispositifs Actionnés de Sécurité) : fermeture des portes CF, ouverture des exutoires de désenfumage, mise en route du désenfumage mécanique, déverrouillage des issues, arrêt de la ventilation normale. Le CMSI est distinct de la centrale de détection (ECS) et peut être intégré ou séparé selon les configurations. Il est défini par la norme NF S 61-934.', 1, null::integer[], array['theme1','seq1','SSI - composants et fonctionnement','Système de Sécurité Incendie (SSI)']::text[], 11),
('ssiap1-q132', 'ssiap1-partie3', 'multiple-select', 'Le test annuel du SSI doit vérifier quels points ? (plusieurs réponses possibles)', 'La vérification annuelle du SSI par un technicien qualifié comprend : le test de chaque détecteur (par aérosol simulateur de fumée ou source de chaleur pour les thermo) ; la vérification de la transmission des signaux d''alarme et de défaut à la centrale et au PC sécurité ; le test des DAS (vérifier que les portes CF se ferment, que les exutoires s''ouvrent, que le désenfumage mécanique se met en route) ; vérification des batteries de secours de l''alimentation électrique de sécurité (AES). Ces vérifications sont consignées dans le registre de sécurité avec les résultats. La couleur des voyants et le contenu du registre ne font pas partie des vérifications techniques.', null, array[0,1,2]::integer[], array['theme1','seq1','SSI - composants et fonctionnement','Système de Sécurité Incendie (SSI)']::text[], 12),
('ssiap1-q133', 'ssiap1-partie3', 'quiz', 'L''Alimentation Électrique de Sécurité (AES) du SSI doit garantir le fonctionnement du système pendant combien de temps en cas de coupure secteur ?', 'L''AES (Alimentation Électrique de Sécurité) du SSI doit garantir le fonctionnement complet du système pendant au minimum 1 heure en mode alarme (batteries de secours chargées). En veille (surveillance normale), la durée est de 12 heures minimum. Ces durées permettent de gérer la situation le temps de l''intervention des secours et d''une évacuation complète. Les batteries doivent être vérifiées régulièrement et remplacées selon les préconisations du fabricant (généralement tous les 4 à 5 ans). En cas de coupure EDF prolongée, un groupe électrogène peut prendre le relais pour les systèmes critiques.', 2, null::integer[], array['theme1','seq1','SSI - composants et fonctionnement','Système de Sécurité Incendie (SSI)']::text[], 13),
('ssiap1-q134', 'ssiap1-partie3', 'quiz', 'Parmi les propositions suivantes, laquelle décrit un SSI de catégorie B ?', 'Un SSI de catégorie B comporte une détection automatique dans certaines zones seulement (zones à risques particuliers) plus des déclencheurs manuels, avec un SMSI comprenant une centrale et des DAS dans les zones concernées. Aucune des trois propositions ne correspond exactement : la catégorie A est la détection généralisée avec SMSI complet ; la catégorie E ou type 3 correspond aux déclencheurs manuels seuls ; les sprinklers ne constituent pas un SSI à eux seuls. La bonne définition de la catégorie B n''est donc dans aucune des options proposées.', 1, null::integer[], array['theme1','seq1','SSI - composants et fonctionnement','Système de Sécurité Incendie (SSI)']::text[], 14),
('ssiap1-q135', 'ssiap1-partie3', 'quiz', 'Un DAI (Déclencheur d''Alarme Incendie) manuel doit être de quelle couleur réglementaire ?', 'Les déclencheurs manuels d''alarme incendie (boîtiers brise-glace ou à membrane) sont de couleur rouge normalisé (RAL 3001 rouge sécurité) selon la norme EN 54-11 et la réglementation française. Le rouge est la couleur internationale associée à la lutte contre l''incendie et aux équipements de sécurité incendie actifs (extincteurs, colonnes sèches, déclencheurs). Les pictogrammes de signalisation des équipements anti-incendie sont également sur fond rouge. Le vert est la couleur des équipements de secours et d''évacuation (issues de secours, BAES).', 1, null::integer[], array['theme1','seq1','SSI - composants et fonctionnement','Système de Sécurité Incendie (SSI)']::text[], 15),
('ssiap1-q136', 'ssiap1-partie3', 'multiple-select', 'La vidéosurveillance dans le PC sécurité permet à l''agent SSIAP de : (plusieurs réponses possibles)', 'La vidéosurveillance (CCTV) est un outil complémentaire précieux pour l''agent SSIAP : elle permet une levée de doute rapide depuis le PC sur les zones couvertes par les caméras, la surveillance des accès et zones à risques, et l''observation du comportement des occupants (attroupements suspects, comportements dangereux). En revanche, elle ne remplace pas les rondes physiques (zones sans caméras, détails non visibles à l''écran, contact humain) ni les détecteurs automatiques (qui couvrent l''ensemble du bâtiment en permanence, y compris les zones non visibles). Son installation et son utilisation sont encadrées par la réglementation CNIL/RGPD.', null, array[0,1,3]::integer[], array['theme1','seq1','SSI - composants et fonctionnement','Système de Sécurité Incendie (SSI)']::text[], 16),
('ssiap1-q172', 'ssiap1-partie3', 'quiz', 'L''adressage des détecteurs dans un SSI de catégorie A permet :', 'L''adressage des détecteurs (systèmes adressés ou intelligents) permet d''identifier individuellement chaque détecteur sur le tableau de signalisation avec sa localisation précise (ex : ''Détecteur 047 - Bureau 312 - 3ème étage aile B''). Cela permet à l''agent SSIAP de localiser immédiatement la zone exacte d''alarme sans avoir à interpréter une zone groupée. Les systèmes non adressés (conventionnels) indiquent seulement la boucle (zone) en alarme, sans identifier le détecteur précis. Les systèmes adressés facilitent aussi la maintenance et la vérification individuelle. Ils ne remplacent pas les rondes et n''ont pas de connexion internet en standard.', 0, null::integer[], array['theme1','seq1','SSI - composants et fonctionnement','Système de Sécurité Incendie (SSI)']::text[], 17),
('ssiap1-q173', 'ssiap1-partie3', 'quiz', 'Un agent SSIAP est seul au PC et l''alarme incendie se déclenche pour la zone ''sous-sol parking''. La levée de doute prend du temps. Quelles sont les limites temporelles à respecter ?', 'La levée de doute doit être rapide. Le délai généralement admis est de 3 à 5 minutes maximum (selon le POI de l''établissement) avant de déclencher l''alarme générale si aucune information ne permet d''infirmer l''alarme. Pendant ce temps, l''agent se rend sur les lieux (ou y envoie un collègue si l''équipe le permet). Si le feu est confirmé avant ce délai, l''alarme générale est déclenchée immédiatement. Si l''agent est seul au PC et que la zone est éloignée, le POI doit prévoir une procédure adaptée (contact téléphonique avec un occupant de la zone, caméra de surveillance, etc.). En cas de doute persistant = alarme générale.', 1, null::integer[], array['theme1','seq1','SSI - composants et fonctionnement','Système de Sécurité Incendie (SSI)']::text[], 18),
('ssiap1-q174', 'ssiap1-partie3', 'quiz', 'Que signifie l''indication ''DEFAUT'' sur le tableau de signalisation du SSI ?', 'Un signal ''DÉFAUT'' (voyant jaune ou orange sur la plupart des centrales) indique un dysfonctionnement dans le système de détection ou de mise en sécurité : câble coupé ou en court-circuit, détecteur défaillant ou absent de son support, alimentation électrique anormale, batterie déchargée, DAS ne répondant pas. Le défaut ne signifie pas qu''un incendie est en cours (c''est l''ALARME) mais que la surveillance est partiellement compromise. L''agent SSIAP doit consigner le défaut dans la main courante et alerter son responsable pour intervention technique. Un défaut non traité peut conduire à une non-détection d''un incendie réel.', 1, null::integer[], array['theme1','seq1','SSI - composants et fonctionnement','Système de Sécurité Incendie (SSI)']::text[], 19)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap1-q54','ssiap1-q55','ssiap1-q56','ssiap1-q57','ssiap1-q58','ssiap1-q59','ssiap1-q94','ssiap1-q95','ssiap1-q96','ssiap1-q97','ssiap1-q98','ssiap1-q131','ssiap1-q132','ssiap1-q133','ssiap1-q134','ssiap1-q135','ssiap1-q136','ssiap1-q172','ssiap1-q173','ssiap1-q174');
