-- ===== ssiap1-partie3-sub02.sql =====
begin;
-- SSIAP 1 — Les installations techniques (partie 3, sub 2/2, 2 cc_questions)
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap1-q175', 'ssiap1-partie3', 'quiz', 'La mise hors service temporaire (inhibition/isolement) d''un détecteur lors de travaux doit obligatoirement s''accompagner de :', 'L''inhibition d''un détecteur (mise en sécurité temporaire lors de travaux, peinture, poussières) supprime la surveillance automatique d''une zone. Pour compenser cette perte de vigilance, des mesures compensatoires doivent être mises en place : augmentation de la fréquence des rondes dans la zone concernée ; présence physique d''un veilleur lors des travaux ; vérification que la zone est exempte de tout risque à la fin de chaque journée (pas de matériaux combustibles, pas de point chaud résiduel) ; réactivation du détecteur dès que possible. Ces mesures doivent être formalisées dans la main courante et communiquées à l''équipe. L''inhibition sans mesure compensatoire est une faute grave.', 1, null::integer[], array['theme1','seq1','SSI - composants et fonctionnement','Système de Sécurité Incendie (SSI)']::text[], 20),
('ssiap1-q176', 'ssiap1-partie3', 'quiz', 'Quel équipement permet la communication entre la zone de refuge (espace d''attente sécurisé) et le PC sécurité ?', 'Les zones de refuge (espaces d''attente sécurisés) doivent être équipées d''un système de communication bidirectionnelle entre la zone et le PC de sécurité ou un point de permanence humaine. Cet interphone (ou système équivalent défini par la norme NF EN 81-28 ou la réglementation ERP/IGH) permet à la PMR en attente d''indiquer sa présence, son nombre et son état aux secours, et aux secours de communiquer des instructions. Le téléphone portable peut être une solution de secours mais n''est pas le dispositif réglementaire prévu. Ce système doit fonctionner même en cas de coupure d''électricité.', 1, null::integer[], array['theme1','seq1','SSI - composants et fonctionnement','Système de Sécurité Incendie (SSI)']::text[], 21)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap1-q175','ssiap1-q176');
commit;

-- ===== ssiap1-partie4-sub01.sql =====
begin;
-- SSIAP 1 — Rôle et missions de l'agent SSIAP 1 (partie 4, sub 1/2, 20 cc_questions)
values ('ssiap1-partie4', 1, 'Rôle et missions de l''agent SSIAP 1', '37 cc_questions', '👨‍🚒', 'from-emerald-500 to-teal-600', 3, true)
on conflict (id) do update set title=excluded.title, subtitle=excluded.subtitle, icon=excluded.icon, color=excluded.color, display_order=excluded.display_order;
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap1-q60', 'ssiap1-partie4', 'quiz', 'Que signifie le principe des « 3A » en cas d''incendie ?', 'Le principe des 3A est le réflexe fondamental à adopter face à un incendie : 1) ALERTER les secours extérieurs (pompiers : 18 ou 112) et le PC sécurité de l''établissement ; 2) ALARMER les occupants (déclencher l''alarme générale d''évacuation) ; 3) ATTAQUER le feu avec les moyens de premier secours disponibles (extincteurs, RIA) si le feu est naissant et si on peut le faire sans danger. L''ordre peut varier selon les consignes du POI : dans certains établissements, l''agent doit d''abord lever le doute avant de déclencher l''alarme générale.', 1, null::integer[], array['theme1','seq1','Conduite à tenir en cas d''incendie','Les 3A - Alerter, Alarmer, Attaquer']::text[], 0),
('ssiap1-q61', 'ssiap1-partie4', 'quiz', 'Lors d''un appel au 18 (pompiers) pour un incendie, quelles informations essentielles doit communiquer l''agent SSIAP ?', 'Lors d''un appel d''urgence au 18, l''agent SSIAP doit communiquer : 1) Son nom et sa qualité (agent de sécurité de...) ; 2) L''adresse précise (rue, numéro, ville) et éventuellement point de rendez-vous pour les secours ; 3) La nature du sinistre (incendie, fuite de gaz...) ; 4) La localisation précise dans le bâtiment (niveau, aile, salle) ; 5) Les personnes en danger ou blessées éventuelles ; 6) Son numéro de téléphone pour être rappelé. Ne JAMAIS raccrocher en premier : attendre que le CODIS (Centre Opérationnel Départemental d''Incendie et de Secours) raccroche.', 1, null::integer[], array['theme1','seq1','Conduite à tenir en cas d''incendie','Les 3A - Alerter, Alarmer, Attaquer']::text[], 1),
('ssiap1-q62', 'ssiap1-partie4', 'quiz', 'Dans quelle situation un agent SSIAP doit-il renoncer à attaquer un feu avec un extincteur ?', 'L''agent SSIAP doit renoncer à attaquer le feu et évacuer immédiatement dans les cas suivants : le feu est trop important (dépasse 1 m² environ) ; il se propage rapidement ; la fumée est dense et rend l''atmosphère irrespirable ; la voie de retraite est compromise (risque d''être encerclé par les flammes) ; il s''agit d''un feu de gaz (ne jamais éteindre, couper le gaz d''abord) ; risque de backdraft. La règle absolue : la sécurité de l''agent prime toujours sur l''attaque du feu. Un extincteur vide, un agent blessé ou décédé ne peuvent pas aider les autres occupants.', 1, null::integer[], array['theme1','seq1','Conduite à tenir en cas d''incendie','Les 3A - Alerter, Alarmer, Attaquer']::text[], 2),
('ssiap1-q63', 'ssiap1-partie4', 'quiz', 'Quel est l''objectif principal des rondes de sécurité effectuées par l''agent SSIAP ?', 'Les rondes de sécurité ont pour objectifs : 1) Détecter les départs de feu, les risques (portes coupe-feu bloquées ouvertes, extincteurs manquants, blocages des issues) ; 2) Vérifier l''état des équipements de sécurité (BAES, extincteurs, RIA, détecteurs) ; 3) S''assurer de la vacuité des dégagements (issues non encombrées) ; 4) Détecter les intrusions, les comportements suspects ; 5) Prévenir les actes de malveillance. Les rondes sont tracées dans la main courante (heure de départ, itinéraire, anomalies constatées, heure de retour) et peuvent être aléatoires pour éviter les routines.', 1, null::integer[], array['theme2','seq2','Rondes de sécurité','Rondes et levée de doute']::text[], 3),
('ssiap1-q64', 'ssiap1-partie4', 'quiz', 'Qu''est-ce que la « levée de doute » dans les procédures SSI ?', 'La levée de doute consiste, lors du déclenchement d''un détecteur automatique (alarme restreinte au PC sécurité), à envoyer un agent SSIAP sur les lieux pour confirmer ou infirmer la réalité du sinistre avant de déclencher l''alarme générale d''évacuation. Le délai de levée de doute ne peut excéder 3 minutes environ (règle de l''établissement). En cas de doute persistant ou de confirmation d''incendie, l''agent déclenche immédiatement l''alarme générale et alerte les pompiers. La levée de doute évite les évacuations inutiles (coûteuses et stressantes) mais ne doit jamais retarder l''alerte en cas d''incendie réel.', 1, null::integer[], array['theme2','seq2','Rondes de sécurité','Rondes et levée de doute']::text[], 4),
('ssiap1-q65', 'ssiap1-partie4', 'quiz', 'Quel est le rôle du guide-file lors d''une évacuation ?', 'Lors d''une évacuation, le guide-file est la personne désignée qui se place EN TÊTE du groupe pour guider les occupants vers la sortie de secours appropriée, en suivant le chemin d''évacuation prévu. Il connaît les itinéraires d''évacuation, les points de rassemblement et les procédures. Il guide calmement et rapidement, sans précipiter les occupants. À ne pas confondre avec le serre-file qui se place EN QUEUE du groupe pour s''assurer qu''il ne reste personne (il ferme les portes derrière lui).', 1, null::integer[], array['theme3','seq3','Organisation et conduite de l''évacuation','Évacuation']::text[], 5),
('ssiap1-q66', 'ssiap1-partie4', 'quiz', 'Comment évacuer une personne à mobilité réduite (PMR) depuis les étages si l''ascenseur est interdit d''utilisation ?', 'L''utilisation des ascenseurs est strictement interdite lors d''un incendie (risque de blocage). Pour les PMR, la procédure est : 1) Les guider vers une zone de refuge (espace d''attente sécurisé coupe-feu situé dans ou à proximité d''une cage d''escalier) ; 2) Communiquer avec elle (interphone ou téléphone) pour la rassurer ; 3) Informer immédiatement les pompiers de sa localisation exacte (nom, étage, zone de refuge) lors de leur arrivée. L''agent SSIAP doit connaître la liste des personnes en situation de handicap (PSH) présentes dans l''établissement et préparer leur évacuation.', 1, null::integer[], array['theme3','seq3','Organisation et conduite de l''évacuation','Évacuation']::text[], 6),
('ssiap1-q67', 'ssiap1-partie4', 'quiz', 'Pourquoi est-il interdit d''utiliser les ascenseurs lors d''une évacuation incendie ?', 'L''utilisation des ascenseurs est interdite lors d''une évacuation incendie pour plusieurs raisons : 1) En cas de coupure électrique ou de panne provoquée par la chaleur, les occupants se retrouvent piégés dans la cabine ; 2) L''ascenseur peut s''arrêter automatiquement au niveau sinistré (fonctionnement des portes) exposant les occupants aux flammes et fumées ; 3) Les gaines d''ascenseur constituent un vecteur de propagation des fumées entre niveaux ; 4) En cas d''incendie en salle des machines, le câble peut se rompre. En revanche, les ascenseurs dédiés aux pompiers sont mis en mode ''pompiers'' et utilisés par les secours.', 1, null::integer[], array['theme3','seq3','Organisation et conduite de l''évacuation','Évacuation']::text[], 7),
('ssiap1-q68', 'ssiap1-partie4', 'quiz', 'Qu''est-ce que la main courante dans un service de sécurité incendie ?', 'La main courante (ou journal de quart) est tenue en permanence par les agents SSIAP. Elle enregistre chronologiquement : les prises et fins de service, toutes les rondes effectuées (heure départ/retour, anomalies), les interventions techniques, les alarmes (vraies ou fausses), les contacts avec les secours, les travaux en cours, les visiteurs particuliers, toute anomalie constatée. La main courante constitue une preuve juridique en cas d''incident ou de sinistre. Elle doit être claire, lisible, sans rature, signée à chaque prise de service. Elle est distincte du registre de sécurité qui est un document réglementaire.', 1, null::integer[], array['theme4','seq4','Main courante et registre de sécurité','Main courante, registre, permis de feu']::text[], 8),
('ssiap1-q69', 'ssiap1-partie4', 'quiz', 'Le registre de sécurité d''un ERP doit contenir :', 'Le registre de sécurité est un document réglementaire obligatoire dans tout ERP (article R.123-51 CCH). Il doit mentionner : les résultats des vérifications et contrôles périodiques des installations (électricité, gaz, SSI, extincteurs, colonnes sèches...) ; les travaux de mise en conformité ; les dates des exercices d''évacuation et leurs observations ; la liste et la formation du personnel de sécurité ; les événements notables (sinistres, interventions des pompiers). Le registre est présenté à la commission de sécurité lors de ses visites. Il est conservé dans l''établissement et accessible à l''autorité de police.', 1, null::integer[], array['theme4','seq4','Main courante et registre de sécurité','Main courante, registre, permis de feu']::text[], 9),
('ssiap1-q70', 'ssiap1-partie4', 'quiz', 'Qu''est-ce qu''un permis de feu et dans quel cas est-il délivré ?', 'Le permis de feu est un document formel délivré par le responsable de l''établissement (ou son délégué SSIAP) qui autorise des travaux par points chauds (soudure électrique ou autogène, meulage, découpe, chalumeau) dans une zone déterminée. Il précise : la nature des travaux, la localisation, les mesures préventives à mettre en place (protection des matériaux combustibles, présence d''un extincteur, surveillance prolongée après travaux), les intervenants et les durées. La surveillance doit se prolonger 2 heures minimum après la fin des travaux (risque de feu couvant). Le permis de feu est une mesure préventive essentielle car les travaux par points chauds sont une cause majeure d''incendies dans les établissements.', 1, null::integer[], array['theme4','seq4','Main courante et registre de sécurité','Main courante, registre, permis de feu']::text[], 10),
('ssiap1-q71', 'ssiap1-partie4', 'quiz', 'Quelle est la fréquence de recyclage obligatoire pour maintenir la qualification SSIAP 1 ?', 'Conformément à l''arrêté du 2 mai 2005, la qualification SSIAP doit faire l''objet d''un recyclage tous les 3 ans. Après 3 ans d''exercice de la fonction, l''agent doit suivre une formation de maintien et d''actualisation des compétences (MAC). En cas d''interruption d''activité, des dispositions spécifiques s''appliquent. La formation SSIAP 1 initiale dure 70 heures + 35 heures de stage pratique. Le recyclage permet de mettre à jour les connaissances sur les évolutions réglementaires et techniques.', 1, null::integer[], array['theme4','seq4','Main courante et registre de sécurité','Main courante, registre, permis de feu']::text[], 11),
('ssiap1-q72', 'ssiap1-partie4', 'quiz', 'L''agent SSIAP constate en ronde une fuite d''eau dans un local électrique. Que doit-il faire ?', 'Face à une fuite d''eau dans un local électrique, l''agent SSIAP doit : 1) Évaluer le danger immédiat (risque d''électrocution, court-circuit) ; 2) Ne jamais intervenir seul sur les installations électriques (hors de sa compétence si non habilité) ; 3) Couper l''alimentation électrique du local depuis le tableau général si le risque est avéré (et s''il est habilité à le faire) ; 4) Consigner l''anomalie dans la main courante ; 5) Alerter immédiatement son responsable et l''équipe technique ; 6) Baliser la zone si nécessaire. L''agent SSIAP ne doit pas excéder son champ de compétences mais doit toujours réagir et signaler.', 1, null::integer[], array['theme4','seq4','Main courante et registre de sécurité','Main courante, registre, permis de feu']::text[], 12),
('ssiap1-q99', 'ssiap1-partie4', 'quiz', 'L''agent SSIAP 1 découvre un feu naissant dans une poubelle de bureau. Quelle est la séquence correcte d''actions ?', 'Pour un feu naissant en poubelle de bureau, la séquence prioritaire est : 1) Alerter le PC sécurité immédiatement (pour qu''il centralise la gestion et prévienne si nécessaire) ; 2) Attaquer le feu avec un extincteur adapté (eau ou CO2 pour un feu de papier) si le feu est encore limité et si cela ne présente pas de danger ; 3) Surveiller la reprise possible (s''assurer que le foyer est bien éteint). L''alerte au PC doit être prioritaire car si l''agent échoue dans son attaque, le PC peut déclencher l''évacuation. Alerter le 18 immédiatement pour un simple feu de poubelle n''est pas la priorité absolue mais peut se faire en parallèle selon le POI.', 1, null::integer[], array['theme1','seq1','Conduite à tenir en cas d''incendie','Les 3A - Alerter, Alarmer, Attaquer']::text[], 13),
('ssiap1-q100', 'ssiap1-partie4', 'multiple-select', 'Quelles sont les obligations légales de l''agent SSIAP 1 en termes de formation ? (plusieurs réponses possibles)', 'Les obligations de formation pour l''agent SSIAP 1 : posséder le diplôme SSIAP 1 délivré par un organisme agréé (arrêté du 2 mai 2005) ; détenir un certificat de formation aux premiers secours de niveau 1 minimum (PSE1 ou PSC1 - anciennement AFPS/BNS) ; effectuer un recyclage tous les 3 ans pour maintenir la qualification (MAC - Maintien et Actualisation des Compétences). La SST est une formation distincte, utile mais non obligatoire pour le SSIAP. Le permis poids lourd n''est pas requis, les agents SSIAP n''utilisent pas d''engins.', null, array[0,1,3]::integer[], array['theme4','seq4','Main courante et registre de sécurité','Main courante, registre, permis de feu']::text[], 14),
('ssiap1-q101', 'ssiap1-partie4', 'multiple-select', 'Lors de l''accueil des pompiers sur intervention, l''agent SSIAP doit leur fournir : (plusieurs réponses possibles)', 'Lors de l''arrivée des pompiers, l''agent SSIAP doit leur remettre : les clés de l''établissement et les plans du bâtiment (plans d''intervention, localisation des réseaux, risques spéciaux) ; la localisation précise du sinistre et le bilan des personnes : nombre, présence de blessés, de personnes bloquées ; les informations sur les risques particuliers (dépôts de produits dangereux, présence de sources radioactives, locaux sous haute tension, PMR bloquées, etc.). Le registre de sécurité peut être demandé par les pompiers mais n''est pas la première priorité. Les informations d''assurance sont inutiles pour les secours.', null, array[0,2,3]::integer[], array['theme1','seq1','Conduite à tenir en cas d''incendie','Les 3A - Alerter, Alarmer, Attaquer']::text[], 15),
('ssiap1-q102', 'ssiap1-partie4', 'quiz', 'Un visiteur signale à l''agent SSIAP qu''il a vu de la fumée dans les toilettes du 3ème étage mais qu''il n''est pas sûr. L''agent doit :', 'Tout signalement de fumée, aussi incertain soit-il, doit être traité sérieusement. L''agent SSIAP doit : informer immédiatement le PC sécurité du signalement (pour préparation et suivi) et se rendre lui-même sur place pour lever le doute SANS attendre. Les fausses alertes sont possibles (vapeur d''eau, buée) mais un incendie réel non détecté peut devenir catastrophique en quelques minutes. L''agent ne doit jamais attendre un deuxième témoin ni demander à un visiteur de vérifier (risque pour le visiteur). Déclencher l''alarme générale sans vérification préalable est prématuré pour un simple signalement sans certitude.', 2, null::integer[], array['theme2','seq2','Rondes de sécurité','Rondes et levée de doute']::text[], 16),
('ssiap1-q103', 'ssiap1-partie4', 'multiple-select', 'Que doit contenir la consigne de sécurité incendie affichée dans les locaux accessibles au public ?', 'Les consignes de sécurité incendie affichées dans les ERP doivent comporter au minimum : les numéros d''urgence (18 pompiers, 15 SAMU, 17 police, 112 européen) ; la procédure d''évacuation avec les voies d''évacuation et le plan indiquant les sorties de secours et le point de rassemblement ; la localisation des moyens de lutte contre l''incendie (extincteurs, RIA). L''identité du responsable de sécurité et le nom de l''assurance ne sont pas des mentions obligatoires sur les consignes d''affichage public. Le contenu précis est défini par le règlement de sécurité applicable (ERP ou code du travail).', null, array[0,1,3]::integer[], array['theme4','seq4','Main courante et registre de sécurité','Main courante, registre, permis de feu']::text[], 17),
('ssiap1-q104', 'ssiap1-partie4', 'quiz', 'L''agent SSIAP constate qu''une issue de secours est fermée à clé par un cadenas non prévu par la réglementation. Que doit-il faire ?', 'Une issue de secours condamnée par un cadenas non réglementaire constitue une infraction grave à la sécurité et un danger immédiat pour les occupants. L''agent SSIAP doit : retirer immédiatement le cadenas si possible (ou le faire retirer) pour rétablir la sécurité ; signaler l''anomalie en urgence à son responsable hiérarchique et à la direction ; consigner l''incident dans la main courante avec date, heure et lieu. L''absence de sortie de secours peut coûter des vies lors d''une évacuation. L''agent SSIAP a le devoir légal de signaler toute anomalie mettant en danger la sécurité des personnes.', 1, null::integer[], array['theme2','seq2','Rondes de sécurité','Rondes et levée de doute']::text[], 18),
('ssiap1-q137', 'ssiap1-partie4', 'multiple-select', 'Lors d''une ronde, l''agent SSIAP doit vérifier plusieurs points. Parmi les suivants, lesquels sont de sa responsabilité ? (plusieurs réponses possibles)', 'Lors des rondes, l''agent SSIAP est responsable de : vérifier la vacuité des dégagements (couloirs, escaliers, issues de secours non encombrés) ; contrôler visuellement l''état des équipements de sécurité incendie (extincteurs présents et intacts, BAES allumés et fonctionnels, détecteurs sans voyant d''anomalie) ; vérifier les portes coupe-feu (non bloquées ouvertes, ferme-portes fonctionnels). Il n''a pas la compétence pour effectuer des réparations électriques (hors habilitation électrique spécifique). La propreté des sanitaires relève des équipes de nettoyage, pas du SSIAP.', null, array[0,1,3]::integer[], array['theme2','seq2','Rondes de sécurité','Rondes et levée de doute']::text[], 19)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap1-q60','ssiap1-q61','ssiap1-q62','ssiap1-q63','ssiap1-q64','ssiap1-q65','ssiap1-q66','ssiap1-q67','ssiap1-q68','ssiap1-q69','ssiap1-q70','ssiap1-q71','ssiap1-q72','ssiap1-q99','ssiap1-q100','ssiap1-q101','ssiap1-q102','ssiap1-q103','ssiap1-q104','ssiap1-q137');
commit;

-- ===== ssiap1-partie4-sub02.sql =====
begin;
-- SSIAP 1 — Rôle et missions de l'agent SSIAP 1 (partie 4, sub 2/2, 17 cc_questions)
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap1-q138', 'ssiap1-partie4', 'quiz', 'Qu''est-ce que l''EPI (Équipement de Protection Individuelle) que doit porter l''agent SSIAP lors d''une intervention sur un début d''incendie ?', 'L''agent SSIAP n''est pas équipé comme un sapeur-pompier. Sa dotation EPI minimale comprend généralement : des chaussures de sécurité (protection mécanique et thermique des pieds), des gants (protection des mains lors de la manipulation d''extincteurs ou RIA), un casque de protection. Certains établissements dotent leurs agents de cagoules de protection thermique ou d''EPI supplémentaires selon les risques. L''agent SSIAP n''a PAS d''ARI (Appareil Respiratoire Isolant) et ne doit jamais pénétrer dans un local enfumé sans protection respiratoire appropriée : c''est le rôle des pompiers.', 1, null::integer[], array['theme1','seq1','Conduite à tenir en cas d''incendie','Les 3A - Alerter, Alarmer, Attaquer']::text[], 20),
('ssiap1-q139', 'ssiap1-partie4', 'quiz', 'La relation entre l''agent SSIAP et les entreprises extérieures intervenant dans l''établissement se formalise par :', 'Quand des entreprises extérieures interviennent dans un ERP, la prévention des risques est formalisée par : un plan de prévention (obligatoire pour 400 heures/an de travaux ou travaux dangereux, selon le code du travail R.4512-6) qui définit les mesures de prévention pour les risques liés à l''interférence des activités ; un permis de feu pour les travaux par points chauds (soudure, meulage, chalumeau). L''agent SSIAP doit être informé de toute intervention, peut être sollicité pour le permis de feu et doit adapter sa surveillance (rondes plus fréquentes) pendant les travaux.', 1, null::integer[], array['theme4','seq4','Main courante et registre de sécurité','Main courante, registre, permis de feu']::text[], 21),
('ssiap1-q140', 'ssiap1-partie4', 'quiz', 'Face à une personne menaçante ou en état d''ivresse dans l''établissement, l''agent SSIAP doit :', 'L''agent SSIAP n''est pas un agent de sécurité privée (gardien) et ses missions ne comprennent pas la gestion des troubles à l''ordre public par l''usage de la force. Face à une personne menaçante ou en état d''ivresse : assurer la sécurité des autres occupants (les éloigner si nécessaire) ; tenter une approche verbale calme et désamorçante ; prévenir son responsable ; appeler la police (17) si la situation dégénère ou présente un danger. L''agent ne doit jamais se mettre en danger inutilement. Toute l''intervention est consignée dans la main courante.', 1, null::integer[], array['theme2','seq2','Rondes de sécurité','Rondes et levée de doute']::text[], 22),
('ssiap1-q141', 'ssiap1-partie4', 'multiple-select', 'L''agent SSIAP constate une fuite de gaz dans un local technique. Quelles sont les actions à mener en priorité ? (plusieurs réponses possibles)', 'Face à une fuite de gaz : 1) Couper l''alimentation en gaz (fermer la vanne d''arrivée si accessible sans danger) ; 2) Ventiler naturellement le local (ouvrir portes et fenêtres pour diluer le gaz) ; 3) Ne créer AUCUNE étincelle : ne pas actionner d''interrupteur électrique (ni allumer ni éteindre), ne pas utiliser de téléphone portable dans le local (risque d''étincelle), ne pas fumer ; 4) Évacuer tout le personnel de la zone. NE PAS allumer l''éclairage (risque d''étincelle au contacteur). Alerter le fournisseur de gaz, les pompiers si concentration importante. Consigner dans la main courante.', null, array[0,2,3,4]::integer[], array['theme2','seq2','Rondes de sécurité','Rondes et levée de doute']::text[], 23),
('ssiap1-q142', 'ssiap1-partie4', 'multiple-select', 'Le guide-file et le serre-file ont des rôles distincts. Quelles affirmations sont exactes ? (plusieurs réponses possibles)', 'Le guide-file se place EN TÊTE du groupe pour le guider vers la sortie désignée en empruntant l''itinéraire prévu. Le serre-file se place EN QUEUE du groupe pour vérifier que tous ont bien évacué, ferme les portes (CF et autres) derrière lui pour limiter la propagation des fumées et flammes. Chaque groupe (niveau, aile) doit avoir au moins un guide-file et un serre-file désignés et formés. Le guide-file NE reste pas dans le bâtiment après l''évacuation : il mène le groupe au point de rassemblement et fait le bilan des présents. Les rôles de guide-file et serre-file sont exercés par le personnel formé (pas nécessairement SSIAP).', null, array[0,1,2,4]::integer[], array['theme3','seq3','Organisation et conduite de l''évacuation','Évacuation']::text[], 24),
('ssiap1-q143', 'ssiap1-partie4', 'quiz', 'Qu''appelle-t-on ''zone de refuge'' dans le contexte de l''évacuation des personnes à mobilité réduite ?', 'La zone de refuge (ou espace d''attente sécurisé - EAS) est définie par la réglementation accessibilité (ERP et IGH). Il s''agit d''un espace situé dans ou à proximité immédiate d''une cage d''escalier (protégée coupe-feu), offrant à une PMR un abri temporaire à l''abri du feu et des fumées, équipé d''un système de communication bidirectionnelle (interphone) permettant d''alerter les services de secours de la présence et du nombre de personnes en attente. Ces zones sont obligatoires dans les ERP et IGH neufs depuis 2007. La PMR y attend l''intervention des sapeurs-pompiers pour une évacuation assistée.', 1, null::integer[], array['theme3','seq3','Organisation et conduite de l''évacuation','Évacuation']::text[], 25),
('ssiap1-q144', 'ssiap1-partie4', 'multiple-select', 'Quels numéros d''urgence l''agent SSIAP doit-il connaître parfaitement ? (plusieurs réponses possibles)', 'L''agent SSIAP doit connaître et utiliser les numéros d''urgence : 18 (Pompiers / SDIS) pour les incendies et accidents ; 15 (SAMU) pour les urgences médicales graves (arrêt cardiaque, blessé grave) ; 17 (Police/Gendarmerie) pour les menaces, colis suspects, troubles à l''ordre public, accidents ; 112 (numéro européen d''urgence) qui redirige vers les services compétents et fonctionne même sans crédit téléphonique. Le 36 15 est un service météo (non urgence). D''autres numéros utiles : 115 (SAMU social), 119 (enfance en danger), 3114 (prévention suicide).', null, array[0,1,2,3]::integer[], array['theme1','seq1','Conduite à tenir en cas d''incendie','Les 3A - Alerter, Alarmer, Attaquer']::text[], 26),
('ssiap1-q145', 'ssiap1-partie4', 'quiz', 'Les travaux par points chauds doivent être surveillés pendant combien de temps APRÈS la fin des travaux ?', 'Les travaux par points chauds (soudure, meulage, chalumeau, découpe) doivent faire l''objet d''une surveillance des zones de travaux pendant au minimum 2 heures après la fin de l''intervention. Cette durée est imposée car les feux couvants peuvent se développer longtemps après l''arrêt des travaux : une braise ou un point chaud peut s''enflammer bien plus tard en contact avec des matières combustibles (isolation, bois caché dans les cloisons). Certains textes préconisent même 4 à 8 heures pour les travaux lourds. Le permis de feu doit mentionner cette durée de surveillance post-travaux.', 2, null::integer[], array['theme4','seq4','Main courante et registre de sécurité','Main courante, registre, permis de feu']::text[], 27),
('ssiap1-q177', 'ssiap1-partie4', 'quiz', 'L''agent SSIAP constate qu''un conteneur à déchets est en feu dans la cour intérieure du bâtiment, à 5 mètres de la façade. Quelle est la priorité ?', 'Un conteneur en feu à 5 mètres d''une façade présente un risque de propagation par rayonnement thermique et convection (5 mètres est insuffisant pour être protégé). Les priorités sont : 1) alerter les pompiers (18) et le PC sécurité car le feu peut rapidement dépasser les capacités d''intervention de l''agent ; 2) éloigner les personnes de la zone dangereuse ; 3) évaluer si le risque de propagation est imminent (fenêtres ouvertes, façade combustible, stores en plastique). L''attaque au RIA sur un conteneur peut être tentée si l''agent peut le faire en sécurité avec une voie de retraite dégagée. La sécurité de l''agent prime.', 1, null::integer[], array['theme1','seq1','Conduite à tenir en cas d''incendie','Les 3A - Alerter, Alarmer, Attaquer']::text[], 28),
('ssiap1-q178', 'ssiap1-partie4', 'quiz', 'L''agent SSIAP peut-il refuser d''effectuer une mission demandée par son employeur qui lui semble contraire à la réglementation de sécurité ?', 'L''agent SSIAP, comme tout salarié, a le droit de retrait face à un danger grave et imminent. De plus, sa qualification SSIAP l''engage à respecter la réglementation de sécurité incendie. S''il reçoit une instruction contraire à cette réglementation (ex : bloquer une issue de secours, désactiver un détecteur sans mesure compensatoire), il doit signaler l''anomalie à sa hiérarchie, consigner dans la main courante, et peut refuser d''exécuter un ordre manifestement illégal mettant en danger des personnes. En cas de litige persistant, il peut saisir l''inspection du travail ou la commission de sécurité. Sa responsabilité personnelle est engagée s''il exécute consciemment un acte dangereux et contraire à la réglementation.', 1, null::integer[], array['theme4','seq4','Main courante et registre de sécurité','Main courante, registre, permis de feu']::text[], 29),
('ssiap1-q179', 'ssiap1-partie4', 'multiple-select', 'Lors d''une intervention d''urgence médicale dans l''établissement, l''agent SSIAP doit : (plusieurs réponses possibles)', 'Face à une urgence médicale, l''agent SSIAP doit : appeler le 15 (SAMU) ou le 112 en décrivant précisément la situation et en suivant les instructions du médecin régulateur ; appliquer les gestes de premiers secours dans la limite de sa formation (PSC1 ou PSE1 obligatoire pour les agents SSIAP) : mettre en position latérale de sécurité, faire du bouche-à-bouche si nécessaire, utiliser le DEA si disponible et formé ; accueillir et guider les secours à leur arrivée ; consigner l''incident dans la main courante. Il ne doit JAMAIS tenter un diagnostic médical ou administrer un médicament (même de l''aspirine) sans prescription médicale.', null, array[0,1,2,4]::integer[], array['theme1','seq1','Conduite à tenir en cas d''incendie','Les 3A - Alerter, Alarmer, Attaquer']::text[], 30),
('ssiap1-q180', 'ssiap1-partie4', 'quiz', 'La main courante d''un service SSIAP doit être :', 'La main courante doit être tenue en temps réel (chaque événement noté immédiatement à sa survenance, pas de reconstitution a posteriori), avec des informations précises (date, heure, lieu, description de l''événement, actions prises), lisibles et sans rature (biffer en cas d''erreur, sans effacement), signées à chaque prise de service et à chaque événement majeur. Elle est conservée plusieurs années (généralement 5 ans) car elle peut constituer une pièce à conviction en cas de litige ou procédure judiciaire. Elle est accessible aux supérieurs hiérarchiques, à la direction et aux autorités de contrôle. Les notes personnelles ou confidentielles n''ont pas leur place dans la main courante.', 1, null::integer[], array['theme4','seq4','Main courante et registre de sécurité','Main courante, registre, permis de feu']::text[], 31),
('ssiap1-q181', 'ssiap1-partie4', 'multiple-select', 'Quels sont les éléments qui doivent impérativement figurer sur un permis de feu ? (plusieurs réponses possibles)', 'Un permis de feu doit obligatoirement mentionner : la nature des travaux (soudure, meulage, découpe) et leur localisation précise dans le bâtiment ; les mesures de prévention à appliquer (protection des matériaux combustibles, présence d''un extincteur, condamnation des ouvertures vers les zones adjacentes) ; la durée de surveillance post-travaux (minimum 2 heures) ; les noms et signatures du responsable SSIAP (qui accorde l''autorisation) et du responsable de l''entreprise intervenante (qui s''engage à respecter les prescriptions) ; les dates et heures de début et de fin. Le prix de la prestation n''a aucune utilité sur ce document de sécurité.', null, array[0,1,2,4]::integer[], array['theme4','seq4','Main courante et registre de sécurité','Main courante, registre, permis de feu']::text[], 32),
('ssiap1-q182', 'ssiap1-partie4', 'quiz', 'Lors d''un exercice d''évacuation, un occupant refuse catégoriquement de quitter son bureau. L''agent SSIAP doit :', 'Face à un occupant refusant d''évacuer lors d''un exercice, l''agent SSIAP ne doit PAS user de contrainte physique (il n''en a pas le droit légal sauf danger de mort immédiat). Il doit : expliquer l''importance de l''exercice et tenter de le convaincre verbalement ; noter son refus et continuer l''évacuation des autres occupants sans retarder le processus ; signaler immédiatement au PC sécurité l''identité et la localisation de la personne refusant d''évacuer ; mentionner cet incident dans le compte-rendu d''exercice pour que des mesures soient prises (formation, sensibilisation). En cas d''incendie réel, le refus est encore plus dangereux et les mêmes principes s''appliquent avec urgence accrue.', 1, null::integer[], array['theme3','seq3','Organisation et conduite de l''évacuation','Évacuation']::text[], 33),
('ssiap1-q192', 'ssiap1-partie4', 'multiple-select', 'Lors d''un incendie, l''agent SSIAP doit fermer les portes des locaux. Pourquoi ? (plusieurs réponses possibles)', 'Fermer les portes lors d''un incendie (y compris la porte de la pièce en feu si possible) apporte plusieurs bénéfices : retarder la propagation du feu et des fumées vers d''autres zones (une porte standard résiste 20 à 30 minutes, une CF bien plus) ; créer une barrière thermique protégeant les couloirs d''évacuation ; limiter l''apport en oxygène au foyer (réduire le comburant ralentit la combustion) ; confiner le sinistre pour faciliter l''intervention des pompiers (feu localisé plutôt que généralisé). La fermeture des portes n''affecte pas la pression dans les réseaux d''eau. Le serre-file ferme systématiquement les portes derrière lui lors de l''évacuation.', null, array[0,1,3,4]::integer[], array['theme1','seq1','Conduite à tenir en cas d''incendie','Les 3A - Alerter, Alarmer, Attaquer']::text[], 34),
('ssiap1-q195', 'ssiap1-partie4', 'quiz', 'Le ''plan de prévention'' établi avant des travaux d''entreprises extérieures dans un ERP a pour but de :', 'Le plan de prévention (article R.4512-6 à R.4512-12 du code du travail) est un document obligatoire établi conjointement par l''entreprise utilisatrice (l''ERP) et l''entreprise extérieure avant le début des travaux présentant des risques particuliers, ou dès que la durée dépasse 400 heures/an. Il analyse les risques créés par l''interférence des deux activités et définit les mesures de prévention à mettre en place. Il inclut : délimitation des zones de travail, mesures de prévention (permis de feu, consignations électriques, balisage), coordination des secours. L''agent SSIAP doit être informé du plan de prévention et adapter sa surveillance pendant les travaux.', 1, null::integer[], array['theme4','seq4','Main courante et registre de sécurité','Main courante, registre, permis de feu']::text[], 35),
('ssiap1-q196', 'ssiap1-partie4', 'quiz', 'Un agent SSIAP remarque une odeur de brûlé dans un couloir mais ne voit ni flamme ni fumée. Il doit :', 'Une odeur de brûlé sans alarme visible doit TOUJOURS être traitée sérieusement. Les causes possibles sont nombreuses et potentiellement dangereuses : câble électrique surchauffé (feu couvant dans les cloisons), moteur d''équipement grillé, début de feu dans un faux-plafond ou sous-plancher (zones non couvertes par les détecteurs), feu couvant dans un local fermé. L''agent SSIAP doit : rechercher méthodiquement l''origine (tâter les portes, vérifier les locaux techniques proches) ; alerter le PC sécurité ; traiter comme un début d''alarme jusqu''à identification et résolution de la cause. Il ne doit pas ouvrir les portes à la légère (risque backdraft) ni ignorer le signal olfactif.', 1, null::integer[], array['theme2','seq2','Rondes de sécurité','Rondes et levée de doute']::text[], 36)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap1-q138','ssiap1-q139','ssiap1-q140','ssiap1-q141','ssiap1-q142','ssiap1-q143','ssiap1-q144','ssiap1-q145','ssiap1-q177','ssiap1-q178','ssiap1-q179','ssiap1-q180','ssiap1-q181','ssiap1-q182','ssiap1-q192','ssiap1-q195','ssiap1-q196');
commit;

-- ===== ssiap1-partie5-sub01.sql =====
begin;
-- SSIAP 1 — Concrétisation des acquis (partie 5, sub 1/2, 20 cc_questions)
values ('ssiap1-partie5', 1, 'Concrétisation des acquis', '26 cc_questions', '🎯', 'from-purple-500 to-pink-600', 4, true)
on conflict (id) do update set title=excluded.title, subtitle=excluded.subtitle, icon=excluded.icon, color=excluded.color, display_order=excluded.display_order;
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap1-q73', 'ssiap1-partie5', 'quiz', 'Que signifie POI dans le contexte de la sécurité incendie ?', 'Le POI (Plan Opérationnel d''Intervention) est le document interne à l''établissement qui décrit les procédures à suivre en cas d''incendie ou d''accident. Il précise : les missions de chaque membre du personnel de sécurité, les numéros d''urgence, les procédures d''alerte, d''évacuation, de levée de doute, la localisation des équipements, les plans du bâtiment. Le POI est distinct du Plan Particulier d''Intervention (PPI) qui concerne les établissements à risques importants. L''agent SSIAP doit connaître parfaitement le POI de son établissement et y contribuer lors des exercices périodiques.', 1, null::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 0),
('ssiap1-q74', 'ssiap1-partie5', 'quiz', 'La réglementation impose des exercices d''évacuation dans les ERP. Quelle est la fréquence minimale obligatoire ?', 'La réglementation ERP impose la réalisation d''exercices d''évacuation au moins deux fois par an (semestrielle). Ces exercices doivent : être réalisés à des heures différentes (un de jour, un de nuit ou en dehors des heures d''affluence) ; impliquer l''ensemble du personnel ; faire l''objet d''un compte-rendu consigné dans le registre de sécurité (durée d''évacuation, difficultés rencontrées, mesures correctives) ; permettre aux nouveaux arrivants de connaître les procédures. Dans les établissements avec locaux à sommeil (hôtels, hôpitaux), des modalités particulières s''appliquent.', 2, null::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 1),
('ssiap1-q75', 'ssiap1-partie5', 'quiz', 'Lors d''un exercice d''évacuation, le point de rassemblement est :', 'Le point de rassemblement (ou point d''attente) est un endroit défini à l''avance, à l''extérieur et à l''écart du bâtiment sinistré, suffisamment éloigné pour ne pas gêner l''intervention des secours, permettant l''accueil de tous les occupants évacués. Il doit permettre un comptage et un contrôle des présents pour s''assurer que personne n''est resté dans le bâtiment. Son emplacement est indiqué sur les plans d''évacuation. Il doit être connu de tous les occupants. En aucun cas, les évacués ne doivent retourner dans le bâtiment avant l''autorisation des pompiers.', 1, null::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 2),
('ssiap1-q76', 'ssiap1-partie5', 'quiz', 'L''agent SSIAP reçoit un appel signalant la présence d''un colis abandonné suspect dans le hall de l''ERP. Quelle est la procédure correcte ?', 'Face à un colis suspect ou abandonné, la procédure est : 1) Ne jamais toucher, déplacer ou ouvrir le colis ; 2) Éloigner immédiatement les personnes de la zone (rayon de sécurité minimum recommandé : 100 mètres, ou 300 mètres si engin explosif suspecté) ; 3) Ne pas utiliser les téléphones portables à proximité (risque de déclenchement) ; 4) Alerter la police (17) qui prendra la décision ; 5) Informer la direction de l''établissement ; 6) Consigner l''incident dans la main courante. L''agent SSIAP ne prend jamais de décision seul sur ce type d''événement qui relève exclusivement des forces de l''ordre.', 1, null::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 3),
('ssiap1-q105', 'ssiap1-partie5', 'multiple-select', 'À la fin d''un exercice d''évacuation, quels éléments doivent être analysés et consignés dans le registre de sécurité ? (plusieurs réponses possibles)', 'Le compte-rendu d''exercice d''évacuation doit impérativement mentionner : le temps total d''évacuation (objectif : l''ensemble des occupants doit être sorti en moins de 3 minutes pour la plupart des ERP) ; les difficultés et dysfonctionnements observés ; le nombre d''occupants évacués et les personnes ayant refusé ou ignoré l''alarme ; les mesures correctives décidées pour améliorer les performances. Ce compte-rendu est signé par le responsable et conservé dans le registre de sécurité, présenté lors des visites de la commission. Le coût de l''exercice n''est pas une mention réglementaire du registre.', null, array[0,1,3,4]::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 4),
('ssiap1-q106', 'ssiap1-partie5', 'quiz', 'Le PC (Poste Central) de sécurité incendie doit être :', 'Le PC sécurité (Poste Central de sécurité incendie) doit être occupé en permanence par au moins un agent SSIAP qualifié pendant les heures d''ouverture de l''établissement ou d''occupation des locaux. C''est depuis le PC que sont surveillés le tableau de signalisation du SSI, les écrans de vidéosurveillance, et depuis lequel sont coordonnées les interventions. Le PC doit être placé à proximité de l''accès principal pour permettre un accueil efficace des pompiers. Il doit disposer des plans du bâtiment, des registres, des clés et des moyens de communication (téléphone, radio).', 1, null::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 5),
('ssiap1-q107', 'ssiap1-partie5', 'multiple-select', 'Un agent SSIAP en service découvre une personne inconsciente lors de sa ronde. Quelles sont ses actions immédiates ? (plusieurs réponses possibles)', 'Face à une personne inconsciente lors d''une ronde : 1) Évaluer la conscience (appel verbal, stimulation) et la respiration (LVA - Libération des Voies Aériennes, écouter, voir, sentir) ; 2) Alerter immédiatement le 15 (SAMU) ou le 112 et prévenir le PC sécurité ; 3) Appliquer les gestes de premiers secours adaptés : PLS (Position Latérale de Sécurité) si respiration présente, RCP (Réanimation Cardio-Pulmonaire) si arrêt cardiaque, utilisation du DEA (Défibrillateur Automatisé Externe) si disponible. Ne PAS déplacer la victime sauf danger immédiat (risque d''aggraver une lésion de la colonne vertébrale). L''agent SSIAP doit être formé aux premiers secours (PSC1/PSE1 obligatoire).', null, array[0,1,2,4]::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 6),
('ssiap1-q108', 'ssiap1-partie5', 'quiz', 'Quel document l''employeur doit-il obligatoirement tenir dans tout ERP pour y consigner l''ensemble des informations de sécurité ?', 'Le registre de sécurité incendie est obligatoire dans tout ERP (article R.123-51 du CCH). Il centralise toutes les informations de sécurité incendie de l''établissement : résultats des vérifications périodiques de toutes les installations (électrique, gaz, SSI, extincteurs, colonnes sèches, ascenseurs...), travaux de mise en conformité, exercices d''évacuation, incidents et sinistres, formations du personnel. Le DUERP est obligatoire dans tout établissement employeur mais concerne les risques professionnels au sens large, pas uniquement l''incendie. Le registre de sécurité est présenté à chaque visite de la commission de sécurité.', 1, null::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 7),
('ssiap1-q109', 'ssiap1-partie5', 'quiz', 'En cas d''incendie confirmé dans un ERP, dans quel ordre les actions suivantes doivent-elles être effectuées ?', 'Lors d''un incendie confirmé dans un ERP, la séquence prioritaire est : 1) Déclencher l''alarme générale d''évacuation (pour alerter tous les occupants) ; 2) Alerter les pompiers (18 ou 112) sans délai ; 3) Guider et organiser l''évacuation des occupants vers les points de rassemblement ; 4) Accueillir les secours à leur arrivée et leur fournir toutes les informations nécessaires. Les biens mobiliers ne sont JAMAIS prioritaires sur les personnes. Confiner en fermant les portes est une bonne pratique pour limiter la propagation mais ne doit pas retarder l''alarme et l''alerte.', 0, null::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 8),
('ssiap1-q110', 'ssiap1-partie5', 'quiz', 'Quelle est la réglementation imposant les qualifications et missions des agents SSIAP ?', 'L''arrêté du 2 mai 2005 est le texte fondamental qui définit les missions, l''emploi et les qualifications du personnel des Services de Sécurité Incendie et d''Assistance aux Personnes (SSIAP). Il crée les trois niveaux de qualification SSIAP 1 (agent), SSIAP 2 (chef d''équipe) et SSIAP 3 (chef de service). Il définit les programmes de formation, les durées, les conditions d''agrément des organismes de formation, les conditions d''exercice et les obligations de recyclage. Il est complété par une instruction technique (IT SSIAP) qui précise les effectifs réglementaires selon les types d''ERP.', 1, null::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 9),
('ssiap1-q146', 'ssiap1-partie5', 'multiple-select', 'Lors de la passation de consignes entre agents SSIAP, quelles informations doivent obligatoirement être transmises ? (plusieurs réponses possibles)', 'La passation de consignes est une phase essentielle du service SSIAP. L''agent sortant doit transmettre à l''agent entrant : tous les événements survenus (alarmes, interventions, incidents) ; les équipements hors service ou en panne (extincteurs vides, BAES défaillants, détecteurs en défaut) ; les travaux en cours, les zones d''accès restreint, les mesures compensatoires mises en place ; la liste des occupants particuliers (PMR, visiteurs importants) ; les anomalies consignées dans la main courante. Une mauvaise passation de consignes peut avoir des conséquences graves : un agent ignorant qu''un détecteur est en défaut ne peut pas adapter sa surveillance.', null, array[0,1,2,4]::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 10),
('ssiap1-q147', 'ssiap1-partie5', 'multiple-select', 'Les plans d''intervention remis aux pompiers lors de leur arrivée doivent contenir : (plusieurs réponses possibles)', 'Les plans d''intervention (ou plans pompiers) sont des documents standardisés remis aux sapeurs-pompiers à leur arrivée. Ils contiennent : la localisation des accès (voies, portes) et des colonnes sèches/humides ; les vannes d''arrêt de gaz, eau, électricité ; les risques particuliers (zones ATEX, produits chimiques, locaux haute tension, sources radioactives) ; l''emplacement du PC sécurité et de la centrale de détection ; les plans de chaque niveau avec les escaliers, zones et locaux identifiés. La liste des fournisseurs est inutile pour les secours. Ces plans sont mis à jour après chaque modification importante du bâtiment.', null, array[0,1,2,4]::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 11),
('ssiap1-q148', 'ssiap1-partie5', 'quiz', 'La durée de la formation initiale SSIAP 1 est de :', 'La formation initiale SSIAP 1 est de 70 heures de formation théorique et pratique en centre + 35 heures de stage en entreprise (soit 105 heures au total). Aucune des propositions (35h, 50h, 100h) ne correspond. Le SSIAP 2 dure 70 heures + 35 heures de stage. Le SSIAP 3 dure 190 heures + stage. Les durées sont définies par l''arrêté du 2 mai 2005. Le recyclage (MAC) dure 14 heures pour le SSIAP 1.', 1, null::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 12),
('ssiap1-q149', 'ssiap1-partie5', 'quiz', 'L''agent SSIAP reçoit l''instruction de ne pas déclencher l''alarme générale d''évacuation lors d''une alarme incendie dans un hôpital pour ne pas perturber les patients. Cette instruction est :', 'Dans les établissements à sommeil (hôpitaux, EHPAD) où l''évacuation générale immédiate est dangereuse pour les patients (mobilité réduite, sous perfusion, soins intensifs), la réglementation prévoit des procédures alternatives : évacuation horizontale progressive (d''abord vers les zones adjacentes coupe-feu), confinement défensif, évacuation partielle. Le POI de l''établissement peut prévoir ces procédures alternatives qui remplacent l''alarme générale immédiate. Ces dispositions sont validées par la commission de sécurité. En revanche, ne pas déclencher l''alarme sans mesure alternative prévue au POI est illégal et dangereux.', 1, null::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 13),
('ssiap1-q150', 'ssiap1-partie5', 'quiz', 'L''obligation d''afficher les consignes de sécurité incendie dans les ERP concerne :', 'L''affichage des consignes de sécurité incendie (numéros d''urgence, procédure d''évacuation, plan avec issues de secours) est obligatoire dans TOUS les ERP, quelle que soit leur catégorie (1ère à 5ème), dans les locaux et dégagements accessibles au public. Les consignes doivent être lisibles, en français (et éventuellement en anglais dans les lieux touristiques), résistantes et régulièrement vérifiées. Dans les hôtels et structures d''hébergement, elles doivent également être affichées dans chaque chambre. L''obligation découle du règlement de sécurité ERP (MS 51 pour les dispositions générales).', 1, null::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 14),
('ssiap1-q151', 'ssiap1-partie5', 'quiz', 'Quelle est la composition minimale d''une équipe SSIAP dans un ERP de 1ère catégorie ouvert au public ?', 'La composition des équipes SSIAP est définie par l''instruction technique du 22 octobre 2019 (et l''arrêté du 2 mai 2005) selon la catégorie et le type d''ERP. Pour les ERP de 1ère catégorie, l''effectif minimal est généralement de 2 agents SSIAP 1 minimum dont au moins un SSIAP 2 assumant la fonction de chef d''équipe. La règle principale est qu''un SSIAP 2 doit encadrer l''équipe dès qu''il y a plusieurs agents. Le nombre total d''agents varie selon la superficie, le nombre de niveaux, l''effectif du public et le type d''ERP (L, M, O, etc.).', 1, null::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 15),
('ssiap1-q183', 'ssiap1-partie5', 'multiple-select', 'Le plan de masse d''un ERP remis aux pompiers doit impérativement indiquer : (plusieurs réponses possibles)', 'Le plan de masse remis aux pompiers doit contenir toutes les informations nécessaires à leur intervention : les voies d''accès pour les engins (largeur, rayon de braquage, résistance au poids) ; l''emplacement des poteaux incendie et bouches d''incendie (avec leur débit) ; les façades accessibles aux échelles (au moins 2 façades accessibles réglementairement pour les bâtiments de hauteur) ; les prises d''alimentation des colonnes sèches ; les locaux à risques, les coupes d''alimentation électrique et gaz. L''identité des occupants de chaque bureau n''a pas sa place sur le plan de masse (c''est une information personnelle et variables dans le temps).', null, array[0,1,2,4]::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 16),
('ssiap1-q184', 'ssiap1-partie5', 'quiz', 'Un ERP est-il obligé de faire appel à un service de sécurité incendie professionnel (SSIAP) dans tous les cas ?', 'L''obligation de personnel SSIAP ne s''applique pas à tous les ERP. Elle est définie par l''instruction technique du 22 octobre 2019 (ITED et ITGH) selon la catégorie et le type d''ERP. Les ERP de 5ème catégorie n''ont généralement pas d''obligation de personnel SSIAP (équipiers de première intervention du personnel suffisent). Pour les 1ère à 4ème catégories, les exigences varient selon le type (L, M, O, R, U, etc.) et l''effectif. Par exemple, un magasin de vente de grande surface (M1) nécessite plusieurs agents SSIAP, tandis qu''un restaurant de 3ème catégorie peut n''en nécessiter aucun. L''arrêté du 2 mai 2005 et ses instructions techniques définissent les effectifs minimaux.', 1, null::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 17),
('ssiap1-q185', 'ssiap1-partie5', 'quiz', 'Qu''est-ce que le DECI (Défense Extérieure Contre l''Incendie) et quel est son rapport avec les missions de l''agent SSIAP ?', 'Le DECI (Défense Extérieure Contre l''Incendie) est l''ensemble des ressources en eau disponibles pour l''alimentation des engins des sapeurs-pompiers lors de leurs interventions : poteaux incendie, bouches d''incendie, points d''eau naturels (mares, rivières), bâches d''eau, etc. Le décret du 27 février 2015 confie la responsabilité du DECI aux communes et EPCI. L''agent SSIAP doit connaître la localisation des poteaux/bouches d''incendie autour de son établissement pour guider rapidement les pompiers lors de leur arrivée. Il doit aussi s''assurer que les accès aux poteaux ne sont pas obstrués par des véhicules stationnés.', 1, null::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 18),
('ssiap1-q186', 'ssiap1-partie5', 'quiz', 'Dans un hôtel, un client signale à la réception de la fumée sous sa porte. L''agent SSIAP arrive et trouve la porte de la chambre chaude. Il doit :', 'Une porte chaude avec fumée visible est le signe classique d''un backdraft potentiel derrière. L''agent SSIAP doit absolument : 1) Frapper à la porte et s''identifier pour vérifier si quelqu''un est à l''intérieur (peut répondre verbalement) ; 2) NE PAS ouvrir la porte (risque de backdraft explosif) ; 3) Déclencher immédiatement l''alarme générale d''évacuation de l''hôtel ; 4) Appeler les pompiers (18) en décrivant la situation ; 5) Commencer à évacuer l''étage concerné et les étages adjacents. Les pompiers équipés d''ARI (Appareils Respiratoires Isolants) et de matériel adapté interviendront pour ouvrir la porte et secourir une éventuelle victime.', 1, null::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 19)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap1-q73','ssiap1-q74','ssiap1-q75','ssiap1-q76','ssiap1-q105','ssiap1-q106','ssiap1-q107','ssiap1-q108','ssiap1-q109','ssiap1-q110','ssiap1-q146','ssiap1-q147','ssiap1-q148','ssiap1-q149','ssiap1-q150','ssiap1-q151','ssiap1-q183','ssiap1-q184','ssiap1-q185','ssiap1-q186');
commit;

-- ===== ssiap1-partie5-sub02.sql =====
begin;
-- SSIAP 1 — Concrétisation des acquis (partie 5, sub 2/2, 6 cc_questions)
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap1-q187', 'ssiap1-partie5', 'quiz', 'Que signifie l''acronyme TRI dans le contexte de la gestion d''une évacuation d''urgence avec des blessés ?', 'Le triage médical (ou tri) est la procédure de classement des victimes par ordre de priorité de prise en charge médicale lors d''un accident avec de nombreuses victimes (AMV - Accident à Multiples Victimes). Les catégories sont : T1 (urgence absolue, pronostic vital engagé, intervention immédiate) ; T2 (urgence relative, peut attendre quelques heures) ; T3 (urgence différée, blessures légères) ; T4 (décédés ou blessures incompatibles avec la survie). L''agent SSIAP n''effectue pas lui-même le triage médical (c''est le rôle du médecin SAMU) mais doit connaître ce concept pour communiquer efficacement avec les secours et organiser les zones de regroupement des victimes.', 1, null::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 20),
('ssiap1-q188', 'ssiap1-partie5', 'multiple-select', 'L''agent SSIAP est responsable de la sécurité incendie dans son établissement. Quelles sont ses limites de responsabilité ? (plusieurs réponses possibles)', 'La responsabilité de l''agent SSIAP est réelle mais circonscrite : il est responsable de l''exécution correcte de ses missions définies par le POI et sa fiche de poste ; sa responsabilité pénale peut être engagée en cas de faute (non-application des procédures, négligence grave conduisant à un sinistre) ; sa responsabilité se limite à ses actes ou omissions personnels (il n''est pas responsable des défaillances de l''employeur, du matériel non entretenu, des décisions de la direction). La responsabilité est partagée entre l''agent, son responsable SSIAP 2/3, et la direction de l''établissement. L''agent n''est pas le seul responsable mais sa responsabilité propre est bien réelle.', null, array[0,1,3]::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 21),
('ssiap1-q191', 'ssiap1-partie5', 'quiz', 'L''arrêté du 2 mai 2005 est relatif à :', 'L''arrêté du 2 mai 2005 est relatif aux missions, à l''emploi et à la qualification du personnel permanent des Services de Sécurité Incendie et d''Assistance aux Personnes (SSIAP). Il crée les trois niveaux SSIAP 1, 2, 3 et définit leurs missions, formations et conditions d''exercice. Il ne traite ni des risques électriques, ni des ICPE, ni de la construction des IGH (qui font l''objet d''autres textes réglementaires).', 1, null::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 22),
('ssiap1-q193', 'ssiap1-partie5', 'quiz', 'Quel est l''objectif d''un défibrillateur automatisé externe (DEA/DAE) dans un ERP ?', 'Le DEA (Défibrillateur Automatisé Externe ou DAE) est un appareil destiné à analyser le rythme cardiaque et à délivrer un choc électrique (défibrillation) pour rétablir un rythme cardiaque normal lors d''une fibrillation ventriculaire ou d''une tachycardie ventriculaire sans pouls (les deux principales causes d''arrêt cardiaque subitement récupérables). Le DEA guide l''utilisateur par des instructions vocales. Il est utilisable par tout citoyen sans formation médicale. Les ERP de catégorie 1 à 4 sont tenus d''en être équipés. L''agent SSIAP, formé PSC1/PSE1, doit savoir utiliser un DEA.', 1, null::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 23),
('ssiap1-q198', 'ssiap1-partie5', 'quiz', 'La réglementation impose des vérifications périodiques des installations de sécurité par des organismes agréés. Ces vérifications sont différentes des contrôles visuels effectués par l''agent SSIAP car elles :', 'Les vérifications périodiques réglementaires (annuelles, triennales ou quinquennales selon les installations) sont réalisées par des techniciens ou organismes habilités (bureau de contrôle, technicien certifié), avec des instruments de mesure et des procédures normalisées. Elles couvrent toutes les installations : électricité, gaz, SSI, ascenseurs, extincteurs, colonnes sèches, etc. Les rapports de vérification sont consignés dans le registre de sécurité et présentés à la commission de sécurité. Les contrôles visuels de l''agent SSIAP (rondes) sont complémentaires mais n''ont pas la même valeur réglementaire : ils permettent de détecter les anomalies visibles entre deux vérifications professionnelles.', 1, null::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 24),
('ssiap1-q199', 'ssiap1-partie5', 'quiz', 'Dans un ERP comportant des locaux à sommeil (hôtel, résidence), quelle procédure d''évacuation spécifique peut être mise en place ?', 'Dans les ERP avec locaux à sommeil (hôtels, EHPAD, hôpitaux), l''évacuation simultanée de tous les occupants peut être dangereuse et difficile (personnes endormies, mobilité réduite, soins en cours). La réglementation prévoit donc une évacuation progressive ou défensive : évacuation immédiate des personnes dans et autour de la zone sinistrée, puis extension progressive selon le développement du sinistre ; ou confinement défensif dans les chambres (portes fermées) en attendant l''intervention des pompiers. Ces procédures, validées par la commission de sécurité, doivent figurer dans le POI et faire l''objet d''exercices spécifiques. Le compartimentage renforcé de ces établissements est conçu pour permettre ce type de stratégie.', 1, null::integer[], array['theme1','seq1','POI, exercices d''évacuation, plans','Exercices et plans']::text[], 25)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap1-q187','ssiap1-q188','ssiap1-q191','ssiap1-q193','ssiap1-q198','ssiap1-q199');
commit;

-- ===== ssiap2-partie1-sub01.sql =====
begin;
-- SSIAP 2 — Approfondissement - Le feu (partie 1, sub 1/2, 20 cc_questions)
values ('ssiap2-partie1', 2, 'Approfondissement - Le feu', '37 cc_questions', '🔥', 'from-red-500 to-orange-600', 0, true)
on conflict (id) do update set title=excluded.title, subtitle=excluded.subtitle, icon=excluded.icon, color=excluded.color, display_order=excluded.display_order;
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap2-q0', 'ssiap2-partie1', 'quiz', 'En tant que chef d''équipe SSIAP 2, lors d''un feu de nappe de liquide inflammable dans un parking, vous devez choisir le moyen d''extinction. Lequel est le plus adapté ?', 'Pour un feu de nappe de liquide inflammable (classe B), la mousse est l''agent le plus adapté : elle forme un tapis imperméable sur toute la surface de la nappe, supprimant l''accès à l''oxygène (étouffement) et refroidissant. Le RIA avec ajutage mousse permet une intervention à distance sécurisée. L''extincteur CO2 est efficace sur les petites surfaces mais se dissipe rapidement et ne protège pas contre la ré-inflammation. Le jet bâton d''eau risque de projeter le liquide inflammable et d''aggraver l''incendie. La poudre D est réservée aux feux de métaux. En tant que SSIAP 2, vous devez aussi sécuriser la zone, couper la ventilation et alerter immédiatement les pompiers.', 1, null::integer[], array['theme1','seq1','Agents extincteurs et leur mode d''action','Chimie et physique du feu']::text[], 0),
('ssiap2-q1', 'ssiap2-partie1', 'multiple-select', 'Quels facteurs influencent la vitesse de propagation d''un incendie dans un bâtiment ? (plusieurs réponses possibles)', 'La vitesse de propagation d''un incendie est influencée par : la charge calorifique (quantité d''énergie par unité de surface : plus elle est élevée, plus le feu se développe vite) ; la configuration architecturale (les ouvertures apportent de l''air comburant, les gaines et faux-plafonds créent des voies de propagation cachées, les grandes surfaces facilitent le rayonnement) ; le vent (l''apport en oxygène et le transport de brandons accélèrent la propagation, en extérieur comme en intérieur via la ventilation). La couleur des murs et le nombre d''agents n''influencent pas la physique de la propagation. Le SSIAP 2 doit évaluer ces facteurs pour anticiper l''évolution du sinistre et adapter sa stratégie.', null, array[0,1,3]::integer[], array['theme2','seq1','Propagation et développement de l''incendie','Chimie et physique du feu']::text[], 1),
('ssiap2-q2', 'ssiap2-partie1', 'multiple-select', 'La charge calorifique d''un local est exprimée en :', 'La charge calorifique (ou densité de charge) d''un local peut être exprimée de deux manières équivalentes : en MégaJoules par mètre carré (MJ/m²) qui est l''unité SI de l''énergie surfacique ; en kilogrammes d''équivalent bois par mètre carré (kg bois/m²) car le bois sec a un pouvoir calorifique inférieur d''environ 17 MJ/kg, ce qui permet une comparaison intuitive. Par exemple, un bureau standard a une charge calorifique d''environ 400-600 MJ/m² (soit 24-35 kg bois/m²). Cette valeur est utilisée pour dimensionner les systèmes de protection incendie et la résistance au feu requise des structures. Les W/m² représentent un flux thermique (puissance), pas une énergie.', null, array[1,3]::integer[], array['theme2','seq1','Propagation et développement de l''incendie','Chimie et physique du feu']::text[], 2),
('ssiap2-q3', 'ssiap2-partie1', 'quiz', 'La ''courbe ISO 834'' ou ''courbe température-temps normalisée'' est utilisée pour :', 'La courbe ISO 834 (ou courbe température-temps normalisée) représente l''évolution conventionnelle de la température d''un incendie lors des essais de résistance au feu des éléments de construction. Elle débute à 20°C et monte selon la formule T = 345 × log(8t+1) + 20 (t en minutes). Elle est utilisée pour soumettre les éléments de construction (murs, planchers, poutres) à des conditions standardisées lors des tests en laboratoire. Aucune des options proposées (débit extincteurs, toxicité fumées, efficacité sprinklers) ne correspond à son usage réel.', 0, null::integer[], array['theme2','seq1','Propagation et développement de l''incendie','Chimie et physique du feu']::text[], 3),
('ssiap2-q4', 'ssiap2-partie1', 'multiple-select', 'Lors d''une intervention sur un feu dans un local technique de chaufferie au fioul, le SSIAP 2 doit prendre en compte les risques suivants : (plusieurs réponses possibles)', 'Dans une chaufferie au fioul, les risques spécifiques sont : explosion du réservoir de fioul (un réservoir contenant encore des vapeurs de fioul peut exploser même partiellement vide) ; pollution des eaux d''extinction (le fioul flotte sur l''eau et peut se répandre dans les égouts ou le sol) ; retour de flamme lors de l''ouverture de la porte (le local sous pression gazeuse peut laisser échapper une bouffée de gaz enflammés) ; risque lors de la coupure du brûleur (fioul résiduel peut continuer à alimenter le feu). Le BLEVE concerne spécifiquement les récipients contenant un liquide sous pression haute température (GLP, GPL) - le fioul domestique n''est pas sous pression, donc pas de risque BLEVE strict. Le SSIAP 2 doit couper l''alimentation et prévenir les pompiers avant toute intervention.', null, array[0,2,3,4]::integer[], array['theme3','seq2','Risques particuliers d''intervention','Phénomènes dangereux']::text[], 4),
('ssiap2-q5', 'ssiap2-partie1', 'quiz', 'Un backdraft peut survenir quand :', 'Le backdraft (ou explosion de fumées) survient quand un apport soudain d''air frais (ouverture d''une fenêtre, porte, ou trappe) entre dans un local où des fumées riches en gaz combustibles se sont accumulées dans une ambiance sous-oxygénée. Les gaz chauds s''enflamment instantanément au contact de l''oxygène, générant une vague d''explosion pouvant projeter des flammes et des débris. Les signes précurseurs : fumées noires denses sortant sous pression par les interstices, fenêtres noircies, teinte jaune ou grise des fumées, pulsations rythmiques. Le SSIAP 2 doit reconnaître ces signes et ne jamais ouvrir une porte chaude sans précaution. C''est une des principales causes de mort de pompiers et d''intervenants.', 0, null::integer[], array['theme3','seq2','Risques particuliers d''intervention','Phénomènes dangereux']::text[], 5),
('ssiap2-q6', 'ssiap2-partie1', 'quiz', 'Quelle est la différence entre un feu couvant et un feu vif en termes de dangerosité pour l''évacuation ?', 'Paradoxalement, un feu couvant (combustion lente sans flammes) peut être plus dangereux pour les occupants endormis ou non alertés : il produit de grandes quantités de CO (monoxyde de carbone) et de gaz toxiques à des températures relativement basses (sans déclencher forcément les détecteurs thermovelocimétriques) ; les fumées envahissent silencieusement les espaces adjacents ; les victimes sont souvent intoxiquées avant même de percevoir la menace. Les feux couvants se développent particulièrement la nuit dans les établissements à sommeil. C''est pourquoi les détecteurs optiques de fumée et les détecteurs de CO sont particulièrement importants dans ces établissements. Le SSIAP 2 doit adapter les procédures de détection à ces risques.', 2, null::integer[], array['theme3','seq2','Risques particuliers d''intervention','Phénomènes dangereux']::text[], 6),
('ssiap2-q7', 'ssiap2-partie1', 'multiple-select', 'Le SSIAP 2 doit connaître les caractéristiques des matériaux afin d''évaluer les risques. Parmi les affirmations suivantes, lesquelles sont exactes ? (plusieurs réponses possibles)', 'Les caractéristiques des matériaux face au feu : l''acier perd environ 50 % de sa résistance mécanique vers 500-600 °C et peut s''effondrer rapidement sans protection (c''est pourquoi il doit être protégé par peinture intumescente ou encoffrement) ; le bois massif brûle en formant une couche de charbon isolante qui ralentit la pénétration du feu (taux de carbonisation ~0,5-1 mm/min), lui conférant une résistance prévisible supérieure à l''acier nu à haute température ; le verre ordinaire éclate tôt dans l''incendie (choc thermique dès 150-250 °C), créant des ouvertures qui apportent de l''air et accélèrent le feu ; l''aluminium fond vers 660 °C (bien avant l''acier qui fond vers 1540 °C). Le béton armé n''est pas indéfini : la chaleur dégrade les armatures et peut provoquer l''éclatement (spalling).', null, array[0,2,3,4]::integer[], array['theme2','seq1','Propagation et développement de l''incendie','Chimie et physique du feu']::text[], 7),
('ssiap2-q49', 'ssiap2-partie1', 'quiz', 'Le SSIAP 2 doit connaître le concept de ''temps critique d''évacuation''. Qu''est-ce que cela signifie ?', 'Le temps critique d''évacuation (ou Available Safe Egress Time - ASET) est le temps entre l''ignition d''un incendie et le moment où les conditions dans les voies d''évacuation deviennent incompatibles avec la vie humaine : concentration de CO dépassant le seuil létal, température au niveau de la tête dépassant 60-80 °C, visibilité nulle due aux fumées. Ce concept est central dans l''ingénierie de la sécurité incendie : le temps nécessaire à l''évacuation (RSET - Required Safe Egress Time) doit impérativement être inférieur au temps critique. L''ASET dépend des matériaux, de la ventilation, du compartimentage. Le RSET dépend de la détection, de l''alarme et du comportement humain. Le SSIAP 2 doit comprendre ces concepts pour justifier les procédures d''évacuation.', 1, null::integer[], array['theme2','seq1','Propagation et développement de l''incendie','Chimie et physique du feu']::text[], 8),
('ssiap2-q50', 'ssiap2-partie1', 'multiple-select', 'Dans le cadre d''une analyse de risques incendie d''un ERP, quels facteurs le SSIAP 2 doit-il évaluer ? (plusieurs réponses possibles)', 'Une analyse de risques incendie rigoureuse évalue : la probabilité d''ignition (sources d''ignition présentes : équipements électriques vétustes, travaux, comportements des occupants, malveillance) ; la vulnérabilité des occupants (PMR, personnes âgées, enfants, personnes sous traitement médical - leur capacité d''évacuation est réduite) ; la charge calorifique (quantité de matières combustibles par m²) qui détermine la vitesse de développement du feu ; la qualité de la maintenance des équipements de sécurité (un SSI mal maintenu peut ne pas détecter ou alerter à temps). Le chiffre d''affaires est un indicateur commercial sans lien avec l''analyse de risques sécuritaires.', null, array[0,1,2,4]::integer[], array['theme2','seq1','Propagation et développement de l''incendie','Chimie et physique du feu']::text[], 9),
('ssiap2-q51', 'ssiap2-partie1', 'quiz', 'Qu''est-ce que l''ingénierie de sécurité incendie (ISI) ou ''performance-based design'' et comment diffère-t-elle de l''approche prescriptive ?', 'L''approche réglementaire classique est prescriptive : elle impose des solutions techniques définies (EI 60 pour les cloisons, distances max entre issues, type de détecteurs, etc.) qui ont fait leurs preuves mais peuvent être contraignantes pour des architectures innovantes. L''Ingénierie de Sécurité Incendie (ISI) ou approche par la performance démontre, par des calculs, des simulations numériques (CFD - Computational Fluid Dynamics) et des analyses comportementales que des solutions alternatives atteignent le même objectif de sécurité. L''ISI permet d''innover architecturalement tout en maintenant la sécurité. Elle est utilisée pour les bâtiments complexes (gares, stades, musées) et nécessite l''accord de la commission de sécurité. Le SSIAP 2 peut rencontrer des bâtiments conçus selon ces principes.', 1, null::integer[], array['theme2','seq1','Propagation et développement de l''incendie','Chimie et physique du feu']::text[], 10),
('ssiap2-q67', 'ssiap2-partie1', 'multiple-select', 'Le SSIAP 2 doit évaluer le risque incendie lors d''une manifestation avec effets pyrotechniques. Quelles précautions spécifiques sont requises ? (plusieurs réponses possibles)', 'Les effets pyrotechniques dans un ERP nécessitent une préparation rigoureuse : obtenir le plan détaillé des effets (type, quantité, position, timing) pour évaluer les risques d''inflammation des décors et structures ; définir des zones d''exclusion autour des lance-flammes et autres équipements ; prépositionner des moyens d''extinction supplémentaires (extincteurs CO2 ou eau, tuyaux d''arrosage) avec des agents désignés ; inhiber temporairement les détecteurs proches (les éclairs et fumées pyrotechniques déclenchent les alarmes) en compensant par la présence physique d''agents. Il n''existe pas d''interdiction totale des effets pyrotechniques en ERP, mais ils sont soumis à une réglementation stricte et nécessitent souvent une autorisation spécifique.', null, array[0,1,2,3]::integer[], array['theme3','seq3','Risques particuliers d''intervention','Risques spéciaux']::text[], 11),
('ssiap2-q68', 'ssiap2-partie1', 'quiz', 'Dans un bâtiment à structure métallique non protégée, comment le SSIAP 2 évalue-t-il le risque d''effondrement lors d''un incendie ?', 'L''acier structural non protégé présente un risque sérieux d''effondrement lors d''un incendie développé : la résistance mécanique de l''acier chute de 50% vers 500-600°C et peut mener à la ruine structurelle en 10 à 30 minutes selon la charge portée et les dimensions des profilés. C''est pourquoi les structures en acier des ERP doivent être protégées (peintures intumescentes qui gonflent au feu, flocages de laine minérale, encoffrement en plâtre). Le SSIAP 2 doit identifier les zones de son bâtiment avec des structures métalliques non protégées et en informer les pompiers dès leur arrivée pour les alerter sur ce risque et adapter leur tactique d''attaque.', 1, null::integer[], array['theme2','seq1','Propagation et développement de l''incendie','Chimie et physique du feu']::text[], 12),
('ssiap2-q69', 'ssiap2-partie1', 'quiz', 'Quels sont les dangers spécifiques liés à un incendie dans une zone de stockage de lithium-ion (batteries de véhicules électriques, stockage d''énergie) ?', 'Les incendies de batteries lithium-ion présentent des dangers très spécifiques : l''emballement thermique (thermal runaway) est une réaction exothermique auto-entretenue très difficile à stopper ; les batteries dégagent des gaz inflammables et extrêmement toxiques (fluorure d''hydrogène HF, CO, HCN) pouvant être mortels à faible concentration ; une batterie apparemment éteinte peut re-s''enflammer plusieurs heures après (nécessite une surveillance prolongée et une immersion complète) ; l''eau est nécessaire pour refroidir mais en grandes quantités car la batterie produit sa propre chaleur. Les parkings accueillant des VE posent de nouveaux défis pour les services SSIAP (hauteur de plancher, ventilation, temps d''intervention). Le SSIAP 2 doit adapter les procédures d''intervention à ces nouveaux risques.', 1, null::integer[], array['theme3','seq3','Risques particuliers d''intervention','Risques spéciaux']::text[], 13),
('ssiap2-q96', 'ssiap2-partie1', 'quiz', 'Quelle est la différence principale entre un agent SSIAP 1 et un chef d''équipe SSIAP 2 ?', 'Le SSIAP 2 (chef d''équipe) est responsable de l''animation et de l''encadrement des agents SSIAP 1. Il assure la planification des rondes, la coordination des missions, la transmission des informations à la hiérarchie et représente l''interface entre les agents et le SSIAP 3 (chef de service). Il peut animer un PC sécurité.', 1, null::integer[], array['theme1','sequence1']::text[], 14),
('ssiap2-q97', 'ssiap2-partie1', 'quiz', 'Lors d''un conflit entre agents dans l''équipe de sécurité, le SSIAP 2 doit :', 'Le management d''équipe implique la gestion des conflits. Le SSIAP 2 doit intervenir comme médiateur : écouter chaque partie séparément, identifier la cause du conflit, proposer une solution, et si le conflit persiste ou dépasse ses compétences, le signaler au SSIAP 3 ou à la direction. La cohésion d''équipe est essentielle à la sécurité.', 1, null::integer[], array['theme2','sequence1']::text[], 15),
('ssiap2-q98', 'ssiap2-partie1', 'quiz', 'Qu''est-ce que le briefing de prise de poste en début de service ?', 'Le briefing de prise de poste est essentiel pour la continuité du service de sécurité. Le SSIAP 2 communique : l''état des équipements (pannes, consignations), les événements du service précédent, les travaux en cours, les visites prévues, les consignes particulières de la direction. Il s''assure que chaque agent connaît ses missions.', 1, null::integer[], array['theme3','sequence1']::text[], 16),
('ssiap2-q99', 'ssiap2-partie1', 'quiz', 'Comment le SSIAP 2 doit-il communiquer avec les sapeurs-pompiers lors de leur intervention ?', 'À l''arrivée des pompiers, le SSIAP 2 doit : les accueillir à l''entrée principale, remettre les plans d''intervention, indiquer la nature et la localisation du sinistre, informer sur les victimes éventuelles, guider vers le PC sécurité ou le sinistre. Il se met à la disposition du chef d''agrès et ne s''oppose jamais à ses décisions opérationnelles.', 1, null::integer[], array['theme1','sequence2']::text[], 17),
('ssiap2-q100', 'ssiap2-partie1', 'quiz', 'Quelle est la relation professionnelle entre le SSIAP 2 et la direction de l''établissement ?', 'Le SSIAP 2 est l''interface opérationnelle entre les agents de terrain et la direction. Il informe la direction des anomalies et des risques, propose des améliorations, assure l''application des consignes, et peut représenter le service sécurité en l''absence du SSIAP 3. Il maintient une communication professionnelle et régulière avec tous les intervenants.', 1, null::integer[], array['theme2','sequence2']::text[], 18),
('ssiap2-q101', 'ssiap2-partie1', 'quiz', 'Qu''est-ce qu''un rapport d''incident dans le cadre SSIAP ?', 'Le rapport d''incident est un outil de management essentiel. Il documente : date/heure/lieu de l''événement, nature de l''incident, personnes impliquées, actions prises, causes identifiées, et propositions d''amélioration. Il permet d''analyser les incidents récurrents, d''améliorer les procédures et constitue une trace légale.', 1, null::integer[], array['theme1','sequence3']::text[], 19)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap2-q0','ssiap2-q1','ssiap2-q2','ssiap2-q3','ssiap2-q4','ssiap2-q5','ssiap2-q6','ssiap2-q7','ssiap2-q49','ssiap2-q50','ssiap2-q51','ssiap2-q67','ssiap2-q68','ssiap2-q69','ssiap2-q96','ssiap2-q97','ssiap2-q98','ssiap2-q99','ssiap2-q100','ssiap2-q101');
commit;

-- ===== ssiap2-partie1-sub02.sql =====
begin;
-- SSIAP 2 — Approfondissement - Le feu (partie 1, sub 2/2, 17 cc_questions)
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap2-q102', 'ssiap2-partie1', 'quiz', 'Que doit contenir un plan de prévention pour des travaux par tiers dans un établissement ?', 'Le plan de prévention (obligatoire pour travaux >400h ou risques particuliers) analyse les risques d''interférence entre l''activité de l''établissement et les travaux extérieurs. Il définit : les mesures de prévention, les procédures d''urgence spécifiques, la coordination des secours, les restrictions d''accès. Le SSIAP 2 doit s''assurer de son existence et de son application.', 1, null::integer[], array['theme2','sequence3']::text[], 20),
('ssiap2-q125', 'ssiap2-partie1', 'quiz', 'Qu''est-ce que la délégation de responsabilité dans un service SSIAP ?', 'La délégation est un outil de management : on confie une mission précise à un agent compétent (ex: gestion du tableau de signalisation pendant une ronde), tout en maintenant la supervision. En matière pénale, la délégation ne transfère la responsabilité que si elle est réelle, complète, et accordée à une personne compétente et disposant des moyens nécessaires.', 1, null::integer[], array['theme3','sequence1']::text[], 21),
('ssiap2-q126', 'ssiap2-partie1', 'quiz', 'Qu''est-ce que l''habilitation électrique et pourquoi est-elle nécessaire pour certains agents SSIAP ?', 'L''habilitation électrique (norme NF C 18-510) est obligatoire pour toute personne devant intervenir sur ou à proximité d''installations électriques. Certains agents SSIAP, devant manipuler des armoires électriques, coupures d''urgence ou équipements du SSI, doivent être habilités. Elle comprend une formation théorique et pratique, et est délivrée par l''employeur.', 1, null::integer[], array['theme3','sequence3']::text[], 22),
('ssiap2-q127', 'ssiap2-partie1', 'quiz', 'Comment le chef d''équipe SSIAP 2 organise-t-il les plannings de rondes ?', 'Un planning de rondes efficace doit être : aléatoire dans ses horaires (imprévisibilité pour la prévention de la malveillance), systématique dans la couverture (tous les points contrôlés), adapté aux risques (plus fréquent dans les zones à risque ou en travaux), et tracé (émargement, rapport). La fréquence minimale est définie par le registre de sécurité.', 1, null::integer[], array['theme2','sequence1']::text[], 23),
('ssiap2-q128', 'ssiap2-partie1', 'quiz', 'Quelle est la procédure pour signaler une anomalie grave découverte lors d''une ronde ?', 'Toute anomalie grave (issue bloquée, extincteur manquant, équipement défaillant, risque d''incendie immédiat) nécessite : signalement immédiat au PC sécurité par radio, consignation précise dans la main courante (heure, lieu, nature), mesures conservatoires immédiates si nécessaire (dégager une issue, alerter la zone), et remontée à la hiérarchie (SSIAP 3 si grave).', 1, null::integer[], array['theme2','sequence1']::text[], 24),
('ssiap2-q142', 'ssiap2-partie1', 'quiz', 'Lors d''une intervention sur un feu de transformateur électrique contenant du pyralène (PCB), quels risques spécifiques le SSIAP 2 doit-il signaler aux pompiers ?', 'Les transformateurs anciens contenant des huiles au PCB (polychlorobiphényles, aussi appelés pyralène) présentent un danger extrême lors de leur combustion : la chaleur transforme les PCB en dioxines et furanes, parmi les composés les plus toxiques connus (classés cancérigènes certains). Le SSIAP 2 doit signaler immédiatement ce risque aux pompiers qui devront utiliser des ARI et des tenues de protection adaptées, et organiser un périmètre de sécurité étendu. Ces transformateurs sont normalement signalés par une étiquette réglementaire. L''utilisation des PCB dans les transformateurs est interdite depuis 1987, mais certains équipements anciens peuvent encore en contenir.', 1, null::integer[], array['theme3','seq3','Risques particuliers d''intervention','Risques spéciaux']::text[], 25),
('ssiap2-q143', 'ssiap2-partie1', 'quiz', 'Qu''est-ce que le phénomène de ''flashover'' et comment le SSIAP 2 le reconnaît-il ?', 'Le flashover est l''embrasement généralisé instantané d''un local : lorsque la couche de fumées chaudes sous le plafond atteint 500-600°C, le rayonnement thermique vertical chauffe simultanément tous les matériaux combustibles du local jusqu''à leur température d''inflammation, provoquant un embrasement total en quelques secondes. Les signes précurseurs : flammes en langue sous le plafond (rollover), fumées très chaudes sortant sous pression, détérioration rapide de la visibilité. Le SSIAP 2 doit reconnaître ces signes et évacuer immédiatement toute personne dans le local. Après un flashover, la température peut dépasser 1000°C et la survie dans le local est impossible. Contrairement au backdraft (explosion à l''ouverture), le flashover se produit en présence d''air.', 1, null::integer[], array['theme3','seq2','Risques particuliers d''intervention','Phénomènes dangereux']::text[], 26),
('ssiap2-q144', 'ssiap2-partie1', 'multiple-select', 'Quels sont les effets physiologiques du monoxyde de carbone (CO) selon sa concentration dans l''air ? (plusieurs réponses possibles)', 'Le CO est un gaz incolore, inodore et insipide — impossible à détecter sans appareil. Ses effets selon la concentration : 50 ppm (VME en France) : seuil maximal d''exposition professionnelle sur 8h ; 200 ppm : maux de tête après 2-3h ; 400 ppm : maux de tête sévères, risque grave après 3h ; 1000-1200 ppm : perte de conscience et risque de mort en moins d''une heure ; 6400 ppm et plus : mort en 10-15 minutes. Le CO se fixe sur l''hémoglobine avec une affinité 240 fois supérieure à l''oxygène, formant la carboxyhémoglobine (HbCO) qui prive les cellules d''oxygène. Son caractère indétectable par les sens humains le rend particulièrement dangereux lors des incendies couvants nocturnes.', null, array[0,1,3]::integer[], array['theme2','seq1','Propagation et développement de l''incendie','Chimie et physique du feu']::text[], 27),
('ssiap2-q145', 'ssiap2-partie1', 'multiple-select', 'Un feu dans un local de stockage de peintures et solvants nécessite une intervention spécifique. Pourquoi le SSIAP 2 doit-il interdire l''usage d''eau en jet plein ? (plusieurs réponses possibles)', 'Sur un feu de solvants et peintures (classe B - liquides inflammables), le jet plein d''eau est contre-indiqué pour plusieurs raisons : la pression du jet projette les liquides enflammés à distance, agrandissant la surface de la nappe en feu et propageant l''incendie ; en vaporisant brutalement les solvants chauds, le jet peut créer un nuage de vapeurs potentiellement explosif ; les liquides inflammables flottant sur l''eau, la nappe en feu est simplement déplacée sans être éteinte. La mousse (jet diffusé avec ajutage mousse) ou la poudre ABC sont les agents appropriés. L''eau peut être utilisée pour refroidir les parois et les contenants non encore enflammés.', null, array[0,2,3]::integer[], array['theme3','seq3','Risques particuliers d''intervention','Risques spéciaux']::text[], 28),
('ssiap2-q146', 'ssiap2-partie1', 'quiz', 'Dans un feu de câbles électriques en gaine technique, quelle est la particularité du comportement du feu ?', 'Les incendies de câbles en gaine technique présentent des caractéristiques spécifiques et dangereuses : propagation verticale rapide par tirage (l''effet cheminée dans la gaine accélère considérablement la combustion) ; traversée des planchers si les pénétrations ne sont pas correctement colmatées (points de faiblesse fréquents dans les bâtiments anciens) ; production de fumées très toxiques selon le type de gaines : les câbles PVC dégagent du chlorure d''hydrogène (HCl) corrosif et suffocant, certains câbles contenant des retardateurs de flamme halogénés produisent des dioxines. Le SSIAP 2 doit connaître les zones de gaines de son bâtiment, s''assurer de leur calfeutrement et prévoir des procédures d''inspection après tout incident électrique.', 1, null::integer[], array['theme3','seq3','Risques particuliers d''intervention','Risques spéciaux']::text[], 29),
('ssiap2-q147', 'ssiap2-partie1', 'quiz', 'L''indice d''oxygène (IO) d''un matériau est :', 'L''indice d''oxygène (IO) est la concentration minimale en oxygène (en % volumique) dans un mélange O2/N2 permettant de maintenir la combustion d''un matériau dans des conditions standardisées. Un IO > 21% signifie que le matériau ne brûle pas dans l''air ambiant (21% O2) — il s''auto-éteint si la flamme pilote est retirée. Un IO < 21% signifie qu''il brûle facilement dans l''air. Cet indice est utilisé pour classer les matériaux en termes de combustibilité. Aucune des propositions (concentration pour inflammation spontanée, température d''inflammation = température d''auto-inflammation, PCI) ne correspond à la définition correcte.', 0, null::integer[], array['theme2','seq1','Propagation et développement de l''incendie','Chimie et physique du feu']::text[], 30),
('ssiap2-q148', 'ssiap2-partie1', 'multiple-select', 'Le SSIAP 2 doit évaluer le risque d''un feu dans un parking couvert à plusieurs niveaux. Quelles particularités ce type de risque présente-t-il ? (plusieurs réponses possibles)', 'Les parkings couverts présentent des risques incendie très spécifiques : propagation rapide de voiture à voiture (charge calorifique élevée des véhicules modernes : 8 à 15 GJ par véhicule, rayonnement intense pouvant enflammer les véhicules adjacents) ; problèmes de désenfumage, particulièrement en souterrain où il faut des systèmes mécaniques puissants ; risque spécifique des VE avec batteries lithium-ion (thermal runaway, re-ignition possible plusieurs heures après extinction apparente, libération de gaz toxiques HF) ; accès difficile pour les pompiers avec leurs lances dans les espaces confinés. Le béton armé résiste généralement plus de 30-60 min selon les charges et la protection des armatures, pas seulement 10 min.', null, array[0,1,2,4]::integer[], array['theme3','seq3','Risques particuliers d''intervention','Risques spéciaux']::text[], 31),
('ssiap2-q149', 'ssiap2-partie1', 'quiz', 'Quelle est la différence entre la réaction au feu et la résistance au feu d''un matériau ?', 'Ces deux concepts fondamentaux de la sécurité incendie sont souvent confondus mais désignent des propriétés très différentes : Réaction au feu : comportement d''un matériau soumis à une source d''inflammation — mesure sa combustibilité, sa vitesse de propagation de flamme, son dégagement de fumées et de gouttelettes enflammées. Classement européen : Euroclasses A1, A2, B, C, D, E, F avec indicateurs de fumées (s1, s2, s3) et gouttelettes (d0, d1, d2). S''applique aux matériaux de construction et de revêtement. Résistance au feu : capacité d''un élément de construction (mur, plancher, porte) à maintenir ses fonctions (stabilité R, étanchéité E, isolation thermique I) pendant une durée déterminée. Classification : REI 30, EI 60, R 90, etc. Ces deux propriétés sont complémentaires dans la stratégie de sécurité incendie.', 1, null::integer[], array['theme2','seq1','Propagation et développement de l''incendie','Chimie et physique du feu']::text[], 32),
('ssiap2-q150', 'ssiap2-partie1', 'multiple-select', 'Comment le SSIAP 2 gère-t-il la présence d''un local de stockage de gaz médicaux (O2, N2O) dans un établissement de soins ? (plusieurs réponses possibles)', 'Les locaux de gaz médicaux présentent des risques spécifiques que le SSIAP 2 doit maîtriser : surveillance renforcée lors des rondes (une fuite d''oxygène pur enrichit l''atmosphère et rend tout matériau combustible extrêmement inflammable — même les vêtements s''enflamment facilement) ; ventilation permanente du local pour éviter l''accumulation en cas de fuite ; vérification de l''arrimage des bouteilles (chute = risque de rupture et d''emballement) ; en cas d''incident, évacuation et attente des pompiers en évitant tout outil ou équipement susceptible de créer des étincelles dans une atmosphère enrichie en O2 ; connaissance des vannes de coupure des alimentations gazeuses médicales pour pouvoir les fermer en cas de nécessité. L''interdiction totale d''accès est impraticable (ravitaillement des bouteilles nécessaire).', null, array[0,2,3,4]::integer[], array['theme3','seq3','Risques particuliers d''intervention','Risques spéciaux']::text[], 33),
('ssiap2-q151', 'ssiap2-partie1', 'quiz', 'Le SSIAP 2 constate que les matériaux de revêtement d''un couloir ont été remplacés sans son accord préalable par un décorateur. Quelle est sa démarche ?', 'Tout changement de matériaux dans un ERP doit respecter les classements de réaction au feu réglementaires (arrêté du 25 juin 1980 et ses arrêtés complémentaires définissent des exigences selon le type de local et sa position). Un couloir d''évacuation a des exigences strictes (matériaux M1 ou Euroclasse B minimum pour les revêtements muraux dans la plupart des cas). Le SSIAP 2 doit : vérifier les fiches techniques ou les certifications des nouveaux matériaux posés ; si non-conformes, signaler par écrit à la direction et exiger la remise en conformité avec délai ; consigner dans le registre de sécurité. Si le décorateur n''a pas de documentation, les matériaux sont présumés non conformes. C''est une non-conformité réglementaire qui peut conduire à un avis défavorable de la commission.', 1, null::integer[], array['theme2','seq1','Propagation et développement de l''incendie','Chimie et physique du feu']::text[], 34),
('ssiap2-q152', 'ssiap2-partie1', 'quiz', 'Dans un bâtiment à atrium central (grand volume ouvert sur plusieurs niveaux), quels sont les risques spécifiques de propagation du feu que le SSIAP 2 doit anticiper ?', 'Les atriums (grands volumes verticaux communicants sur plusieurs niveaux) présentent des risques incendie complexes : l''effet cheminée thermique aspire et propulse les fumées et la chaleur vers le haut très rapidement, menaçant tous les niveaux donnant sur l''atrium quasi simultanément ; la stratification normale des fumées (couche chaude en haut, air frais en bas) est perturbée dans un grand volume, rendant l''évacuation et l''intervention difficiles ; le désenfumage d''un atrium est complexe et doit être spécifiquement calculé (exutoires en toiture, soufflage en bas). Les bâtiments à atrium importants font souvent l''objet d''études de sécurité incendie spécifiques avec modélisation CFD. Le SSIAP 2 doit connaître les systèmes de désenfumage de l''atrium et leurs modes de commande.', 1, null::integer[], array['theme3','seq2','Risques particuliers d''intervention','Phénomènes dangereux']::text[], 35),
('ssiap2-q153', 'ssiap2-partie1', 'quiz', 'Le SSIAP 2 doit connaître les classes de feu et les agents extincteurs adaptés. Pour un feu de graisse animale dans une cuisine professionnelle (friteuse), quel est l''agent adapté ?', 'Les feux de graisses de cuisson (classe F) sont parmi les plus dangereux en cuisine professionnelle : la graisse chauffée au-delà de son point d''inflammation (300-350°C) s''enflamme et la flamme peut atteindre 1000°C ; jeter de l''eau provoque une explosion de vapeur violente projetant de la graisse enflammée (saponification explosive) ; le CO2 ne refroidit pas suffisamment et la graisse se re-enflamme ; la poudre est inefficace sur ce type de feu à haute température. Les extincteurs de classe F contiennent un agent saponifiant (sel de potassium d''acides gras) qui réagit chimiquement avec la graisse pour former une couche de savon solide imperméable et refroidissante. Les hottes professionnelles équipées de systèmes d''extinction automatique utilisent également ce type d''agent.', 2, null::integer[], array['theme1','seq1','Agents extincteurs et leur mode d''action','Chimie et physique du feu']::text[], 36)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap2-q102','ssiap2-q125','ssiap2-q126','ssiap2-q127','ssiap2-q128','ssiap2-q142','ssiap2-q143','ssiap2-q144','ssiap2-q145','ssiap2-q146','ssiap2-q147','ssiap2-q148','ssiap2-q149','ssiap2-q150','ssiap2-q151','ssiap2-q152','ssiap2-q153');
commit;

-- ===== ssiap2-partie2-sub01.sql =====
begin;
-- SSIAP 2 — Réglementation approfondie (partie 2, sub 1/3, 20 cc_questions)
values ('ssiap2-partie2', 2, 'Réglementation approfondie', '46 cc_questions', '🏛️', 'from-blue-600 to-indigo-700', 1, true)
on conflict (id) do update set title=excluded.title, subtitle=excluded.subtitle, icon=excluded.icon, color=excluded.color, display_order=excluded.display_order;
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap2-q8', 'ssiap2-partie2', 'multiple-select', 'Le SSIAP 2 est responsable de la constitution du dossier de sécurité de l''établissement. Quels documents doit-il impérativement y faire figurer ? (plusieurs réponses possibles)', 'Le dossier de sécurité d''un ERP, tenu à la disposition de la commission de sécurité, doit comprendre : le registre de sécurité (événements, vérifications, formations, incidents) ; les rapports de vérifications périodiques de toutes les installations (SSI, électricité, gaz, sprinklers, extincteurs, ascenseurs, etc.) avec les rapports d''organismes agréés ; les contrats de maintenance des équipements de sécurité (preuves que les équipements font l''objet d''un entretien régulier) ; les comptes-rendus d''exercices d''évacuation avec les bilans et mesures correctives. Les listes des fournisseurs d''alimentation n''ont pas de valeur pour la sécurité incendie. Le SSIAP 2 doit s''assurer de la mise à jour régulière de tous ces documents.', null, array[0,1,2,4]::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 0),
('ssiap2-q9', 'ssiap2-partie2', 'quiz', 'La commission de sécurité compétente pour un ERP de 1ère catégorie est :', 'Les commissions de sécurité compétentes pour les ERP sont structurées ainsi : la Commission Consultative Départementale de Sécurité et d''Accessibilité (CCDSA) et ses sous-commissions traitent les ERP de 1ère à 4ème catégorie selon leur importance ; pour les petits ERP de 5ème catégorie, c''est la commission communale ou intercommunale de sécurité. Ces commissions sont présidées par un représentant de l''État (préfet, sous-préfet) et composent de membres de l''administration, des sapeurs-pompiers, d''un technicien. Elles donnent des avis sur l''ouverture, les travaux et l''exploitation des ERP. L''avis défavorable peut entraîner la fermeture administrative.', 0, null::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 1),
('ssiap2-q10', 'ssiap2-partie2', 'quiz', 'Quelle est la périodicité des visites de la commission de sécurité pour un ERP de 1ère catégorie ?', 'La périodicité des visites de la commission de sécurité varie selon la catégorie et le type d''ERP : 1ère catégorie : tous les 5 ans ; 2ème catégorie : tous les 5 ans ; 3ème catégorie : tous les 5 ans ; 4ème catégorie : pas de visite périodique obligatoire (sauf ouverture ou travaux importants) ; ERP de type J, U, PA, CTS et établissements spéciaux : périodicités adaptées. Les établissements avec locaux à sommeil (O, U, J) peuvent avoir des périodicités plus courtes. La commission peut également effectuer des visites inopinées à tout moment. Le SSIAP 2 doit anticiper et préparer ces visites en s''assurant de la conformité de l''établissement.', 3, null::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 2),
('ssiap2-q11', 'ssiap2-partie2', 'quiz', 'Dans un ERP, le SSIAP 2 constate que les vérifications annuelles du SSI n''ont pas été réalisées depuis 18 mois. Quelle est la conséquence réglementaire et quelle action doit-il prendre ?', 'Les vérifications périodiques des installations de sécurité (SSI, extincteurs, colonnes sèches, etc.) sont des obligations réglementaires. Leur absence constitue une non-conformité pouvant entraîner un avis défavorable de la commission de sécurité et potentiellement la fermeture administrative. Le SSIAP 2 ne peut pas réaliser lui-même ces vérifications (elles nécessitent un organisme ou technicien agréé avec des équipements spécialisés). Il doit : signaler la non-conformité par écrit à la direction ; consigner dans le registre de sécurité ; organiser le rattrapage immédiat de la vérification. La fermeture automatique n''est pas obligatoire (c''est la décision de l''autorité de police), mais la situation est grave et doit être corrigée sans délai.', 2, null::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 3),
('ssiap2-q12', 'ssiap2-partie2', 'multiple-select', 'Lors de travaux de rénovation dans un ERP en exploitation, le SSIAP 2 doit veiller à : (plusieurs réponses possibles)', 'Le SSIAP 2 a un rôle central lors de travaux en ERP en exploitation : établissement du plan de prévention conjointement avec l''entreprise intervenante (obligatoire pour plus de 400 h ou travaux dangereux) ; délivrance des permis de feu pour toute opération par points chauds (soudure, meulage, chalumeau) ; renforcement de la surveillance dans les zones de travaux (rondes plus fréquentes, inhibitions compensées) ; information de la commission de sécurité si les travaux modifient les conditions d''exploitation (suppression d''une issue, indisponibilité d''un secteur du SSI). L''entreprise extérieure ne peut pas être seule responsable de la sécurité dans un ERP : la responsabilité est partagée avec l''exploitant et son service SSIAP.', null, array[0,1,2,3]::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 4),
('ssiap2-q13', 'ssiap2-partie2', 'quiz', 'Qu''est-ce que le ''Programme technique de construction'' (PTC) en matière de sécurité incendie pour un ERP ?', 'Le Programme Technique de Construction intègre les exigences de sécurité incendie dans les phases de conception d''un bâtiment : choix des matériaux (réaction et résistance au feu), dimensionnement des dégagements, implantation des systèmes de détection et d''extinction, organisation du compartimentage, accessibilité pour les secours. L''intégration précoce des contraintes de sécurité incendie est bien moins coûteuse que les adaptations post-construction. Le SSIAP 3 est le plus souvent impliqué dans cette phase de conception, mais le SSIAP 2 doit comprendre ces principes pour gérer efficacement la sécurité de l''établissement existant et anticiper les modifications.', 1, null::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 5),
('ssiap2-q14', 'ssiap2-partie2', 'quiz', 'Quelle est la différence entre une ''mesure compensatoire'' et une ''dérogation'' en matière de réglementation incendie ERP ?', 'Ces deux concepts sont distincts : la Dérogation est une autorisation administrative accordée par la commission de sécurité permettant de s''écarter d''une règle réglementaire, sous condition de mesures alternatives offrant un niveau de sécurité équivalent (ex : dérogation à une distance de dégagement compensée par un sprinkler généralisé). Elle est permanente et formalisée. La Mesure Compensatoire est une disposition temporaire prise lors de l''indisponibilité d''un équipement de sécurité (panne d''un secteur du SSI, fermeture temporaire d''une issue) pour maintenir le niveau de sécurité requis (rondes renforcées, réduction du public, présence d''un veilleur supplémentaire). Le SSIAP 2 gère les mesures compensatoires au quotidien.', 1, null::integer[], array['theme2','seq1','Dérogations et mesures compensatoires','ERP - Réglementation avancée']::text[], 6),
('ssiap2-q15', 'ssiap2-partie2', 'multiple-select', 'La réglementation IGH impose des exigences spécifiques par rapport aux ERP. Quelles sont les caractéristiques propres aux IGH ? (plusieurs réponses possibles)', 'Les IGH (Immeubles de Grande Hauteur, > 28 m hors habitation ou > 50 m habitation) ont des exigences renforcées spécifiques : au moins 2 escaliers encloisonnés désenfumés par secteur, accessibles depuis chaque niveau ; compartimentage strict par niveau avec planchers REI 120 minimum (résistance au feu renforcée) ; service de sécurité incendie permanent 24h/24 7j/7 (contrairement aux ERP qui peuvent n''en avoir que pendant les heures d''ouverture) ; sprinkler généralisé obligatoire dans la majorité des classes d''IGH (GHB, GHC, GHD, etc.). L''interdiction totale des matériaux combustibles n''est pas la règle : ils sont réglementés (classes de réaction au feu) mais pas totalement interdits.', null, array[0,1,2,4]::integer[], array['theme3','seq2','Particularités des IGH','IGH - Réglementation spécifique']::text[], 7),
('ssiap2-q16', 'ssiap2-partie2', 'quiz', 'La réglementation relative aux établissements recevant des travailleurs (code du travail) diffère de la réglementation ERP sur quel point fondamental ?', 'La réglementation incendie du code du travail (articles R4216-1 et suivants) s''applique aux établissements recevant des travailleurs (ERT) et diffère fondamentalement de la réglementation ERP : elle est basée sur l''approche par les risques propres à l''entreprise, formalisée dans le Document Unique d''Évaluation des Risques Professionnels (DUERP) ; elle vise la protection des travailleurs (personnes connaissant les lieux, ayant reçu une formation) et non d''un public non initié ; les équipiers de première intervention (EPI) et de seconde intervention (ESI) sont formés en interne. Un même bâtiment peut être soumis aux deux réglementations simultanément (ex : un centre commercial où travaillent des employés ET reçoit du public).', 2, null::integer[], array['theme4','seq3','ERT vs ERP - Différences réglementaires','Code du travail et sécurité incendie']::text[], 8),
('ssiap2-q17', 'ssiap2-partie2', 'quiz', 'L''effectif d''un ERP est déterminé selon les règles réglementaires. Pour une salle de spectacle, l''effectif du public est calculé :', 'Pour une salle de spectacle avec places assises, l''effectif du public est calculé selon le nombre de places assises (sièges). Pour les salles sans places fixes, on applique une densité d''occupation réglementaire (généralement 1 personne par mètre carré d''espace debout, ou des densités spécifiques selon le type d''usage). La méthode de calcul varie selon le type et la configuration : salle de conférence sans place fixe = 1 personne/m², restaurants = environ 1 personne/m² de salle, etc. Aucune des propositions (places assises, superficie/3 m², billets vendus) ne couvre la totalité des cas réglementaires.', 2, null::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 9),
('ssiap2-q18', 'ssiap2-partie2', 'multiple-select', 'Le SSIAP 2 doit organiser la formation incendie du personnel de l''établissement. Quels éléments doivent figurer dans cette formation ? (plusieurs réponses possibles)', 'La formation du personnel à la sécurité incendie (obligatoire dans les ERP) doit comprendre : l''utilisation pratique des extincteurs et RIA (au moins par simulation ou sur feu réel lors d''exercices) ; les procédures d''évacuation et les rôles de guide-file et serre-file ; la levée de doute et les conditions de déclenchement de l''alarme générale ; les gestes de premiers secours (formation PSC1 recommandée pour une partie du personnel). La conduite de véhicules de secours n''est pas une compétence attendue du personnel d''un ERP standard. Le SSIAP 2 organise et peut animer ces formations, en s''appuyant sur le POI de l''établissement.', null, array[0,1,3,4]::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 10),
('ssiap2-q19', 'ssiap2-partie2', 'quiz', 'Un ERP change d''exploitant. Quelles sont les obligations en matière de sécurité incendie lors de ce changement ?', 'En cas de changement d''exploitant d''un ERP, les obligations sont : mise à jour du registre de sécurité (le nouvel exploitant reprend le registre existant avec ses entrées à la date de la reprise) ; pour les ERP de 1ère à 3ème catégorie, une visite de la commission de sécurité est généralement requise avant la réouverture au public sous le nouveau nom. La commission vérifie que les installations sont conformes et que l''exploitant a pris connaissance de ses obligations. Pour les ERP de 4ème et 5ème catégorie, une demande d''autorisation d''ouverture est adressée au maire. Le SSIAP 2 accompagne le nouvel exploitant dans ces démarches.', 2, null::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 11),
('ssiap2-q20', 'ssiap2-partie2', 'quiz', 'Quel est le fondement légal de la responsabilité pénale du SSIAP 2 en cas de sinistre grave dans son établissement ?', 'La responsabilité pénale du SSIAP 2 peut être engagée sur plusieurs fondements du code pénal : art. 221-6 (homicide involontaire par faute ou négligence, passible de 3 ans d''emprisonnement et 45 000 € d''amende, avec aggravation si faute délibérée) ; art. 222-19 (blessures involontaires) ; art. 223-1 (mise en danger délibérée d''autrui, passible de 1 an et 15 000 €). Sa responsabilité est engagée à proportion de ses attributions et des fautes commises : non-vérification des équipements, non-application des procédures d''évacuation, délivrance imprudente d''un permis de feu. La délégation de responsabilité de l''employeur ne supprime pas sa propre responsabilité.', 1, null::integer[], array['theme5','seq1','Responsabilité juridique du SSIAP 2','ERP - Réglementation avancée']::text[], 12),
('ssiap2-q52', 'ssiap2-partie2', 'multiple-select', 'Le SSIAP 2 doit savoir lire et interpréter les plans d''architecte pour la sécurité incendie. Quels éléments doit-il y identifier ? (plusieurs réponses possibles)', 'Sur les plans d''architecte, le SSIAP 2 doit identifier : le compartimentage coupe-feu (tracé des parois EI, localisation des portes CF) pour comprendre la logique de confinement du feu ; les dégagements (largeurs en UP, sens d''ouverture des portes, distances maximales à parcourir) pour vérifier la conformité réglementaire ; l''emplacement prévu des détecteurs, clapets CF, exutoires et autres DAS ; les accès pompiers (voies, façades accessibles, emplacements des colonnes sèches). Cette lecture de plans est indispensable pour préparer les interventions, guider les pompiers et détecter les non-conformités potentielles. La liste des fournisseurs de matériaux n''est pas un élément de sécurité incendie.', null, array[0,1,2,4]::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 13),
('ssiap2-q53', 'ssiap2-partie2', 'quiz', 'Un ERP reçoit une mise en demeure de la commission de sécurité pour non-conformité. Quelle est la procédure réglementaire suivante ?', 'Une mise en demeure de la commission de sécurité est un acte administratif contraignant. La procédure est : l''exploitant doit répondre dans le délai fixé (généralement 3 à 6 mois selon la gravité) en fournissant un plan de mise en conformité avec des engagements précis (travaux prévus, dates, devis) ; en cas de non-réponse ou de non-exécution, le préfet peut prononcer la fermeture administrative de l''ERP par arrêté ; l''exploitant peut contester la mise en demeure devant le tribunal administratif, mais l''ERP doit rester fermé pendant la procédure si la fermeture a été prononcée. Le SSIAP 2 doit alerter immédiatement la direction à réception d''une mise en demeure et participer à la définition du plan de mise en conformité.', 1, null::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 14),
('ssiap2-q54', 'ssiap2-partie2', 'quiz', 'La réglementation ICPE (Installations Classées pour la Protection de l''Environnement) s''applique dans quels cas en lien avec la sécurité incendie ?', 'La réglementation ICPE (code de l''environnement, nomenclature des ICPE) s''applique aux activités industrielles, agricoles ou de stockage qui présentent des risques pour l''environnement, la santé ou la sécurité publique au-delà de certains seuils quantitatifs. Selon le niveau de risque : Déclaration (D) : régime le plus léger ; Enregistrement (E) : régime intermédiaire ; Autorisation (A) : pour les risques importants, avec étude de dangers obligatoire ; SEVESO seuil bas et haut : pour les établissements présentant les risques les plus élevés. Un ERP peut être simultanément soumis à la réglementation ERP ET ICPE (ex : un supermarché avec stockage important de produits inflammables). Le SSIAP 2 doit identifier ces situations.', 1, null::integer[], array['theme8','seq4','ICPE et réglementations connexes','ICPE et risques industriels']::text[], 15),
('ssiap2-q70', 'ssiap2-partie2', 'quiz', 'Le SSIAP 2 est interrogé sur les règles applicables aux travaux de réhabilitation d''un ERP classé. Quand les règles de sécurité actuelles doivent-elles être appliquées à un bâtiment existant ?', 'Le principe des ''droits acquis'' en matière de réglementation ERP signifie : les bâtiments conformes aux règles en vigueur au moment de leur construction conservent leurs droits acquis et ne sont pas tenus de se mettre en conformité avec les nouvelles règles (sauf exceptions liées à la sécurité urgente) ; lors de travaux de rénovation, extension ou changement d''affectation, les parties nouvelles ou modifiées doivent respecter les règles actuelles, tandis que les parties non modifiées conservent leurs droits acquis. La commission de sécurité évalue au cas par cas si des travaux ponctuels imposent une mise à niveau globale. C''est pourquoi les travaux dans les ERP anciens sont complexes à gérer.', 1, null::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 16),
('ssiap2-q71', 'ssiap2-partie2', 'quiz', 'La règle des ''3 unités'' en matière de dégagement d''évacuation dans les ERP signifie que :', 'La règle de la ''simultanéité des dégagements'' (souvent appelée règle des dégagements par la suppression d''un dégagement) impose que si on retire le dégagement le plus favorable (le plus large), les dégagements restants doivent encore permettre d''évacuer l''effectif total dans les conditions réglementaires. Cette règle garantit qu''en cas de dégagement bloqué (incendie, travaux), l''évacuation reste possible. Elle implique une redondance des voies d''évacuation. Le SSIAP 2 doit vérifier cette règle lors de l''analyse des plans et lors de toute modification des dégagements (fermeture temporaire d''une sortie pour travaux).', 2, null::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 17),
('ssiap2-q72', 'ssiap2-partie2', 'multiple-select', 'Quels sont les principaux textes réglementaires que le SSIAP 2 doit maîtriser ? (plusieurs réponses possibles)', 'Les textes fondamentaux que le SSIAP 2 doit connaître : l''arrêté du 25 juin 1980 et ses arrêtés complémentaires (règlement de sécurité ERP, avec les dispositions générales GN, GE, GU et les dispositions particulières par type : L, M, N, O, P...) ; l''arrêté du 2 mai 2005 (missions, emploi et qualifications des SSIAP 1, 2, 3) ; l''arrêté du 18 octobre 1977 relatif aux IGH (règlement de sécurité spécifique aux bâtiments de grande hauteur) ; les normes NF S 61-930 à 61-936 (SSI, composants, installation, maintenance). Le code civil (anciens articles 1382/1383, maintenant 1240/1241) concerne la responsabilité civile générale mais n''est pas un texte spécifique à la sécurité incendie que le SSIAP 2 doit maîtriser.', null, array[0,1,2,4]::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 18),
('ssiap2-q103', 'ssiap2-partie2', 'quiz', 'Qu''est-ce que l''ECS dans un SSI ?', 'L''ECS (Équipement de Contrôle et de Signalisation), aussi appelé tableau de signalisation, est l''organe central du SDI. Il reçoit les informations des détecteurs et déclencheurs, les traite, signale les alarmes (sonore et visuelle), identifie les zones concernées, et transmet les ordres au CMSI pour déclencher les actions de mise en sécurité.', 0, null::integer[], array['theme1','sequence1']::text[], 19)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap2-q8','ssiap2-q9','ssiap2-q10','ssiap2-q11','ssiap2-q12','ssiap2-q13','ssiap2-q14','ssiap2-q15','ssiap2-q16','ssiap2-q17','ssiap2-q18','ssiap2-q19','ssiap2-q20','ssiap2-q52','ssiap2-q53','ssiap2-q54','ssiap2-q70','ssiap2-q71','ssiap2-q72','ssiap2-q103');
commit;

-- ===== ssiap2-partie2-sub02.sql =====
begin;
-- SSIAP 2 — Réglementation approfondie (partie 2, sub 2/3, 20 cc_questions)
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap2-q104', 'ssiap2-partie2', 'quiz', 'Qu''est-ce que le CMSI dans un SSI ?', 'Le CMSI (Centralisateur de Mise en Sécurité Incendie) est l''organe de commande du SMSI. Il reçoit les informations de l''ECS et commande automatiquement les DAS (Dispositifs Actionnés de Sécurité) : fermeture des portes coupe-feu, activation du désenfumage, arrêt de la ventilation, déverrouillage des issues. Il peut aussi être commandé manuellement.', 1, null::integer[], array['theme1','sequence1']::text[], 20),
('ssiap2-q105', 'ssiap2-partie2', 'quiz', 'Quelle est la différence entre un SSI de catégorie A et un SSI de catégorie E ?', 'Les SSI sont classés de A (le plus complet) à E (le plus simple) : Cat. A = SSI avec détection automatique dans tous les locaux + mise en sécurité automatique ; Cat. B = similaire mais sans certaines zones ; Cat. C, D, E = systèmes simplifiés sans tous les automatismes. La catégorie requise dépend du type et de la catégorie de l''ERP.', 1, null::integer[], array['theme2','sequence1']::text[], 21),
('ssiap2-q106', 'ssiap2-partie2', 'quiz', 'Comment le SSIAP 2 doit-il réagir face à une alarme sur le tableau de signalisation ?', 'La procédure d''exploitation du tableau de signalisation comprend : identifier et mémoriser la zone en alarme, acquitter l''alarme sonore (maintenir visuelle), envoyer un agent sur le terrain pour lever le doute, maintenir le contact radio, et en cas de feu confirmé : alerter les pompiers, déclencher l''alarme d''évacuation, gérer les actions de mise en sécurité.', 1, null::integer[], array['theme1','sequence2']::text[], 22),
('ssiap2-q107', 'ssiap2-partie2', 'quiz', 'Qu''est-ce qu''une consignation d''un équipement de sécurité incendie ?', 'La consignation est la mise hors service temporaire et contrôlée d''un équipement (pour maintenance, travaux, dysfonctionnement) avec mise en place de mesures compensatoires. Elle doit être formalisée (fiche de consignation), validée par le responsable sécurité, et les mesures alternatives (rondes renforcées, personnel supplémentaire) doivent être activées pendant la durée de la consignation.', 0, null::integer[], array['theme2','sequence2']::text[], 23),
('ssiap2-q108', 'ssiap2-partie2', 'quiz', 'Quelle est la fréquence minimale de vérification du bon fonctionnement des détecteurs dans un ERP ?', 'La vérification annuelle du bon fonctionnement du système de détection incendie est obligatoire et doit être réalisée par un organisme ou technicien compétent (qualification APSAD I7). Des vérifications périodiques de surveillance sont également effectuées : hebdomadaires (test d''une tête par zone), mensuels (test manuel). Tout cela doit être consigné dans le registre de sécurité.', 3, null::integer[], array['theme1','sequence3']::text[], 24),
('ssiap2-q109', 'ssiap2-partie2', 'quiz', 'Que doit faire le SSIAP 2 en cas de défaut technique sur le SSI (panne d''un détecteur par exemple) ?', 'En cas de défaut sur le SSI, le SSIAP 2 doit : consigner le défaut dans la main courante et le registre de sécurité, isoler la zone (si possible) pour éviter les fausses alarmes, mettre en place des mesures compensatoires (rondes renforcées dans la zone concernée), contacter le mainteneur agréé, informer le responsable. Le défaut doit être corrigé dans les meilleurs délais.', 1, null::integer[], array['theme2','sequence3']::text[], 25),
('ssiap2-q110', 'ssiap2-partie2', 'quiz', 'Qu''est-ce qu''un tableau répétiteur d''exploitation (TRE) ?', 'Le TRE (Tableau Répétiteur d''Exploitation) est une interface simplifiée du SSI installée dans un lieu facilement accessible (accueil, loge du gardien, PC sécurité). Il affiche l''état des zones (alarme, dérangement) et permet de réaliser certaines commandes. Il ne remplace pas l''ECS principal mais facilite l''exploitation quotidienne.', 1, null::integer[], array['theme3','sequence1']::text[], 26),
('ssiap2-q129', 'ssiap2-partie2', 'quiz', 'Qu''est-ce qu''un déclencheur manuel (bouton poussoir d''alarme) et où doit-il être installé ?', 'Les déclencheurs manuels (DMI ou DAM selon la norme) permettent à toute personne de déclencher manuellement une alarme incendie. La réglementation impose leur implantation à chaque niveau de l''immeuble, dans les dégagements (couloirs, escaliers), à proximité de chaque sortie. Ils doivent être visibles, accessibles et signalés.', 0, null::integer[], array['theme2','sequence1']::text[], 27),
('ssiap2-q130', 'ssiap2-partie2', 'quiz', 'Qu''est-ce que le report de l''alarme incendie en PC sécurité ?', 'Le report d''alarme incendie au PC sécurité est un équipement permettant au personnel de sécurité de visualiser en temps réel les alarmes du SSI (zones déclenchées, type d''alarme, état des équipements). Le PC sécurité peut être équipé d''un tableau répétiteur ou d''un système informatique de supervision permettant une réaction optimale.', 1, null::integer[], array['theme3','sequence1']::text[], 28),
('ssiap2-q131', 'ssiap2-partie2', 'quiz', 'Quelle est la procédure pour remettre en état le SSI après une intervention d''incendie ?', 'Après une intervention incendie, la remise en état du SSI nécessite : l''accord des pompiers avant toute manipulation, l''évaluation des dommages sur les équipements, le contact avec le mainteneur agréé, les tests de vérification du bon fonctionnement de chaque composant, et la consignation de tout dans le registre. Le SSI ne doit être réinitialisé que lorsque tout est contrôlé.', 1, null::integer[], array['theme3','sequence2']::text[], 29),
('ssiap2-q132', 'ssiap2-partie2', 'quiz', 'Qu''est-ce que la surveillance des travaux par points chauds et le rôle du SSIAP ?', 'La surveillance des travaux par points chauds est critique car l''incendie peut démarrer longtemps après la fin des travaux (combustion couvante). Le SSIAP 2 doit : vérifier le permis de feu avant le début, surveiller la zone pendant les travaux, assurer au moins une ronde post-travaux dans l''heure suivante (ou selon prescription du permis), et consigner dans la main courante.', 1, null::integer[], array['theme2','sequence2']::text[], 30),
('ssiap2-q154', 'ssiap2-partie2', 'multiple-select', 'Le SSIAP 2 est responsable de la bonne application du plan de prévention lors de l''intervention d''une entreprise extérieure pour des travaux de percement de murs porteurs. Quels éléments doit-il vérifier sur place ? (plusieurs réponses possibles)', 'Le contrôle terrain du plan de prévention par le SSIAP 2 comprend plusieurs vérifications pratiques : présence du plan de prévention signé sur le chantier (document de référence en cas de question ou d''incident) ; respect des EPI définis dans le plan (casques, lunettes, protection acoustique selon les risques identifiés) ; conformité des équipements aux zones de travail (si percement à proximité d''une gaine électrique ou d''une zone potentiellement ATEX, les outils doivent être adaptés) ; présence du permis de feu si des meuleuses, disqueuses ou autres outils à points chauds sont utilisés en complément. Le Kbis est un document administratif commercial qui ne relève pas des vérifications de sécurité sur le terrain.', null, array[0,1,2,3]::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 31),
('ssiap2-q155', 'ssiap2-partie2', 'quiz', 'Qu''est-ce que le ''classement topographique'' des locaux dans un ERP et pourquoi est-il important pour la sécurité incendie ?', 'Le classement topographique des locaux dans un ERP désigne la classification selon leur position physique dans le bâtiment : au niveau du sol ou en étage (facilité d''évacuation, accessibilité des secours) ; en sous-sol (conditions d''évacuation plus difficiles, désenfumage mécanisé souvent obligatoire, accès pompiers limité) ; accessible ou non au public (les locaux techniques ont des exigences différentes des locaux accueillant du public) ; à simple ou multiple issue. Ce classement conditionne les exigences réglementaires applicables : le nombre minimal de dégagements, les largeurs requises, les types de désenfumage et les résistances au feu des séparations. Le SSIAP 2 doit connaître ce classement pour chaque local de son établissement afin de vérifier et maintenir la conformité.', 1, null::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 32),
('ssiap2-q156', 'ssiap2-partie2', 'quiz', 'Le SSIAP 2 doit expliquer la notion d''Unité de Passage (UP) à un nouveau responsable de l''établissement. Comment la définit-il ?', 'L''Unité de Passage (UP) est l''unité de mesure réglementaire des dégagements dans les ERP : 1 UP = 0,60 m correspond au passage théorique d''une personne. Les règles de calcul des dégagements sont : 1 UP pour les passages normaux (minimum réglementaire) ; 2 UP = 1,20 m minimum pour les sorties accessibles au public et la majorité des dégagements ; au-delà, le nombre d''UP requis est calculé selon l''effectif (par exemple : 1 UP par tranche de 100 personnes à évacuer). Cette unité permet de dimensionner les dégagements de manière cohérente et calculable. Le SSIAP 2 doit vérifier ces largeurs lors de ses rondes (détection de mobilier réduisant une largeur réglementaire).', 1, null::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 33),
('ssiap2-q157', 'ssiap2-partie2', 'multiple-select', 'Dans un ERP de type O (hôtel), quelles obligations spécifiques s''appliquent en matière de sécurité incendie pendant la nuit (locaux à sommeil) ? (plusieurs réponses possibles)', 'Les établissements de type O (hôtels et établissements à sommeil) ont des exigences nocturnes renforcées : surveillance permanente la nuit (selon la catégorie : SSIAP 1 ou personnel habilité en permanence avec des rondes régulières, pour s''assurer que l''alarme est entendue et que l''évacuation peut être organisée) ; portes des chambres CF (coupe-feu) à fermeture automatique (en cas d''incendie dans la chambre, la porte fermée limite la propagation aux couloirs et permet aux pompiers d''intervenir chambre par chambre) ; système d''alarme à puissance sonore suffisante pour réveiller des occupants endormis (la norme impose des niveaux sonores plus élevés pour les établissements à sommeil, testés avec des personnes dormant). L''accompagnement permanent des clients n''est pas obligatoire et la fermeture du service SSIAP la nuit est totalement prohibée.', null, array[0,1,2]::integer[], array['theme4','seq2','ERP type O - Hôtels','Établissements à sommeil']::text[], 34),
('ssiap2-q158', 'ssiap2-partie2', 'multiple-select', 'Comment le SSIAP 2 vérifie-t-il la conformité du balisage d''évacuation dans son établissement ? (plusieurs réponses possibles)', 'Le contrôle du balisage d''évacuation lors des rondes comprend : vérification de la présence et de la lisibilité de tous les pictogrammes réglementaires (ISO 7010 - E001 à E007, fond vert avec homme qui court) aux issues et aux changements de direction ; test fonctionnel des BAES/blocs de signalisation lors du test mensuel (coupure secteur pour vérifier le fonctionnement sur batterie) ; respect de la visibilité maximale (un usager en tout point d''un dégagement doit voir un pictogramme indiquant la direction à suivre - règle des 30 m entre deux panneaux, davantage dans les circulations larges) ; cohérence du balisage (une flèche ne doit jamais pointer vers une issue condamnée ou bloquée). La couleur réglementaire est le vert et non le rouge (le rouge est réservé aux équipements de lutte contre l''incendie).', null, array[0,1,2,4]::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 35),
('ssiap2-q159', 'ssiap2-partie2', 'quiz', 'Quelle est l''obligation du SSIAP 2 lorsqu''il constate que les procédures d''évacuation affichées dans l''établissement sont périmées (ancienne configuration des locaux suite à des travaux) ?', 'Des plans d''évacuation périmés ou incorrects sont potentiellement dangereux : lors d''une évacuation réelle, des occupants non familiers avec le bâtiment (visiteurs, nouveaux employés) se basent sur ces plans pour trouver les sorties. Un plan indiquant une issue qui n''existe plus ou ne montrant pas une nouvelle issue peut les désorienter dans une situation de stress et de visibilité réduite. Le SSIAP 2 doit exiger la mise à jour immédiate des plans d''évacuation affichés après tout réaménagement. Ces plans doivent être conformes à la norme NF ISO 23601 et à la réglementation ERP. Les photos et corrections à la main ne sont pas admises (lisibilité insuffisante, non-conformes). La mise à jour doit être réalisée par un prestataire qualifié ou par le service interne.', 1, null::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 36),
('ssiap2-q160', 'ssiap2-partie2', 'quiz', 'Le SSIAP 2 doit maîtriser la réglementation sur les colonnes sèches. Quelles sont leurs caractéristiques et obligations d''entretien ?', 'Les colonnes sèches sont des canalisations fixes en acier galvanisé installées dans les cages d''escaliers des ERP et IGH à partir d''une certaine hauteur (généralement obligatoires dès R+3 selon le règlement), équipées à chaque niveau de raccords normalisés (DN 65 ou DN 100) permettant aux pompiers d''y brancher leurs propres lances sans avoir à dérouler des tuyaux dans les escaliers. Elles sont ''sèches'' (vides d''eau en temps normal) — les pompiers les alimentent depuis leur camion par le raccord d''alimentation en façade. Leurs obligations d''entretien : vérification annuelle (contrôle de l''état des raccords, absence d''obstruction, signalisation) et épreuve hydraulique tous les 5 ans (mise sous pression à 6 bars pendant 30 min). Leur maintenance est à la charge de l''exploitant ERP.', 1, null::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 37),
('ssiap2-q161', 'ssiap2-partie2', 'quiz', 'Lors d''une inspection de ses rondes, le SSIAP 2 constate qu''une porte coupe-feu est maintenue ouverte par un plot métallique. Quelle est la procédure à suivre ?', 'Une porte coupe-feu maintenue ouverte mécaniquement est une non-conformité grave à traiter immédiatement : action immédiate : retirer le dispositif de blocage pour que la porte retrouve sa fonction de barrière coupe-feu (c''est une urgence sécuritaire) ; consigner l''incident dans la main courante (date, heure, localisation, nature de l''anomalie, action prise) ; identification de la personne responsable pour comprendre la cause (demande de facilitation de passage, méconnaissance de l''importance) et prévenir la récidive ; information de la direction et proposition d''action corrective (formation, signalétique, remplacement par une porte CF à fermeture automatique avec système de déverrouillage magnétique couplé au SSI). Une porte CF ouverte peut permettre la propagation du feu d''une zone à l''autre en quelques minutes, transformant un incendie localisé en sinistre général.', 1, null::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 38),
('ssiap2-q162', 'ssiap2-partie2', 'quiz', 'L''alarme générale d''évacuation dans un ERP doit être audible à une distance de :', 'La réglementation impose que l''alarme soit perçue distinctement en tout point de l''établissement, notamment dans tous les locaux, y compris avec portes fermées. Le niveau sonore minimal requis est généralement de 75 dB(A) en tout point des zones à alerter, et de 65 dB(A) dans les zones de sommeil pour permettre le réveil des occupants. Ces niveaux sont définis par la norme NF S 32-001 et les arrêtés complémentaires au règlement de sécurité ERP. La notion de ''distance minimale audible'' ne correspond pas à la formulation réglementaire — c''est un niveau sonore en dB(A) qui est imposé, pas une distance. Aucune des propositions en distance n''est correcte.', 2, null::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 39)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap2-q104','ssiap2-q105','ssiap2-q106','ssiap2-q107','ssiap2-q108','ssiap2-q109','ssiap2-q110','ssiap2-q129','ssiap2-q130','ssiap2-q131','ssiap2-q132','ssiap2-q154','ssiap2-q155','ssiap2-q156','ssiap2-q157','ssiap2-q158','ssiap2-q159','ssiap2-q160','ssiap2-q161','ssiap2-q162');
commit;

-- ===== ssiap2-partie2-sub03.sql =====
begin;
-- SSIAP 2 — Réglementation approfondie (partie 2, sub 3/3, 6 cc_questions)
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap2-q163', 'ssiap2-partie2', 'multiple-select', 'Quelles informations le SSIAP 2 doit-il impérativement consigner dans la main courante lors de chaque prise de service ? (plusieurs réponses possibles)', 'La main courante est le document de traçabilité central du service SSIAP. Lors de chaque prise de service, le SSIAP 2 doit y consigner : l''heure précise de prise de service et l''identité de l''agent entrant (et sortant, avec signature des deux) pour établir la continuité de responsabilité ; tous les équipements en défaut ou indisponibles (SSI en inhibition, extincteur en recharge, BAES défaillant) avec les mesures compensatoires en place ; les travaux en cours et leurs impacts sur la sécurité (zones avec permis de feu actif, issues temporairement condamnées, modifications du chemin de ronde) ; les consignes particulières (présence de personnalités, événements programmés, interventions techniques attendues). La météo peut être notée si elle a une influence sur la sécurité (tempête, verglas) mais n''est pas une information standard obligatoire.', null, array[0,1,2,3]::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 40),
('ssiap2-q164', 'ssiap2-partie2', 'quiz', 'Le SSIAP 2 doit expliquer à un nouveau gestionnaire la différence entre l''ERP et l''IGH pour un bâtiment donné. Quels critères permettent de classer un bâtiment en IGH ?', 'La classification en IGH (Immeuble de Grande Hauteur) est définie par l''article R122-2 du code de la construction et de l''habitation selon la hauteur du plancher du dernier niveau accessible : habitations (résidentiels) : IGH si ce plancher dépasse 50 m de hauteur ; autres immeubles (bureaux, commerces, hôtels, etc.) : IGH si ce plancher dépasse 28 m. Ces seuils correspondent approximativement à la hauteur maximale d''intervention des échelles des pompiers (30 m environ). Au-dessus, les pompiers ne peuvent plus intervenir en façade et des mesures internes renforcées compensent cette limitation. Un même bâtiment peut être classé IGH ET contenir des ERP : dans ce cas, les deux réglementations s''appliquent simultanément en prenant la plus contraignante. Ce n''est pas le nombre d''étages ni la superficie qui détermine le classement.', 1, null::integer[], array['theme3','seq2','Particularités des IGH','IGH - Réglementation spécifique']::text[], 41),
('ssiap2-q165', 'ssiap2-partie2', 'multiple-select', 'Le registre de sécurité doit mentionner les formations du personnel à la sécurité incendie. Quelles informations doit-il contenir à ce sujet ? (plusieurs réponses possibles)', 'Le registre de sécurité doit comporter un volet formation selon la réglementation ERP (article GE 3 du règlement de sécurité). Les mentions obligatoires concernant les formations : la date de chaque action de formation ; le contenu ou thème de la formation (utilisation extincteurs, procédures d''évacuation, levée de doute...) ; le nom et les qualifications du formateur (formateur SSIAP 2 ou 3, ou intervenant externe habilité) ; la liste des personnes présentes avec leur signature attestant leur participation. Les résultats individuels d''évaluation ne sont généralement pas consignés dans le registre de sécurité (ils peuvent l''être dans les dossiers individuels RH) et la date de la prochaine formation n''est pas une mention obligatoire du registre (elle peut figurer dans un planning de formation).', null, array[0,1,2]::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 42),
('ssiap2-q166', 'ssiap2-partie2', 'multiple-select', 'La ''ronde de fermeture'' réalisée par le SSIAP 2 en fin d''exploitation doit systématiquement vérifier : (plusieurs réponses possibles)', 'La ronde de fermeture est une procédure critique pour la sécurité nocturne, elle doit vérifier : l''absence de personne dans l''établissement (personnes endormies dans un fauteuil, visiteurs attardés dans les sanitaires) ; la fermeture sécurisée des accès (fenêtres, Velux, portes de service) pour prévenir les intrusions et l''exposition au vent (risque de courant d''air sur des flammes) ; l''extinction des sources de chaleur non surveillées (machine à café, bouilloire, four, repasseuse) qui représentent une cause fréquente d''incendie nocturne ; la fermeture des portes CF en position fermée (elles doivent être fermées hors exploitation pour assurer le compartimentage). Désactiver le SSI la nuit est une faute grave qui prive l''établissement de toute protection en cas de départ de feu nocturne.', null, array[0,1,2,3]::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 43),
('ssiap2-q167', 'ssiap2-partie2', 'quiz', 'Le SSIAP 2 est chargé de mettre à jour le registre de sécurité après une visite de la commission de sécurité. Quelles informations doit-il y consigner ?', 'Après une visite de la commission de sécurité, le registre de sécurité doit comporter une entrée complète : la date de la visite et la composition de la commission (présidents et membres présents) ; l''avis global rendu (favorable, favorable avec observations, défavorable) ; la liste exhaustive de toutes les observations et prescriptions émises par la commission (même celles qui semblent mineures) ; les délais impartis pour lever chaque observation ou exécuter chaque prescription ; ultérieurement, les dates et modalités de levée de chaque observation. Ce compte-rendu est généralement joint au registre sous forme du procès-verbal officiel de visite que la commission adresse à l''exploitant. La transparence totale s''impose : toutes les observations, y compris défavorables, doivent être consignées. Ce registre peut être demandé lors d''une enquête judiciaire post-sinistre.', 1, null::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 44),
('ssiap2-q168', 'ssiap2-partie2', 'quiz', 'Dans un ERP, certains locaux sont dits ''à risques particuliers''. Quels locaux entrent généralement dans cette catégorie et quelles exigences spécifiques s''y appliquent ?', 'Les locaux à risques particuliers sont définis par les dispositions générales du règlement de sécurité ERP (article GN 7) et les dispositions par type. Ils regroupent notamment : les chaufferies, sous-stations, locaux de machinerie et de stockage d''énergies ; les locaux électriques (TGBT, groupes électrogènes, locaux onduleurs) ; les cuisines professionnelles et offices ; les locaux de stockage d''archives ou de produits inflammables ; les ateliers et locaux de maintenance. Les exigences spécifiques : isolation par des parois coupe-feu (EI 60 ou EI 120 selon les cas), portes CF avec fermeture automatique, désenfumage adapté, parfois systèmes d''extinction automatique. L''objectif est de confiner un incendie démarrant dans ces zones à fort potentiel calorifique.', 1, null::integer[], array['theme1','seq1','Dossier de sécurité et obligations réglementaires','ERP - Réglementation avancée']::text[], 45)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap2-q163','ssiap2-q164','ssiap2-q165','ssiap2-q166','ssiap2-q167','ssiap2-q168');
commit;

-- ===== ssiap2-partie3-sub01.sql =====
begin;
-- SSIAP 2 — Installations techniques approfondies (partie 3, sub 1/3, 20 cc_questions)
values ('ssiap2-partie3', 2, 'Installations techniques approfondies', '46 cc_questions', '⚙️', 'from-cyan-500 to-blue-600', 2, true)
on conflict (id) do update set title=excluded.title, subtitle=excluded.subtitle, icon=excluded.icon, color=excluded.color, display_order=excluded.display_order;
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap2-q21', 'ssiap2-partie3', 'multiple-select', 'Le SSIAP 2 doit connaître le SSI de son établissement. Quelles sont les catégories du SSI et leurs principales différences ? (plusieurs réponses possibles)', 'Les 5 catégories de SSI (norme NF S 61-931) correspondent à des niveaux décroissants de prestations : A (le plus complet) : détection automatique généralisée, SMSI avec DAS dans toutes les zones, alarme générale ; B : détection auto dans zones à risques + SMSI partiel ; C : détection dans locaux à risques + alarme restreinte (personnel SSIAP seulement) ; D : déclencheurs manuels seulement + diffuseurs sonores dans certaines zones ; E (le moins complet) : signal sonore autonome (timbre ou haut-parleur). La catégorie requise est définie par la réglementation selon le type et la catégorie d''ERP. Le SSIAP 2 doit maîtriser parfaitement la catégorie de SSI de son établissement pour piloter correctement les interventions.', null, array[0,1,2,3,4]::integer[], array['theme1','seq1','Catégories SSI et fonctionnement avancé','SSI - Expertise technique']::text[], 0),
('ssiap2-q22', 'ssiap2-partie3', 'quiz', 'En tant que SSIAP 2, vous devez interpréter le tableau de signalisation du SSI. Une zone indique simultanément ''ALARME'' et ''DÉFAUT''. Quelle est votre analyse ?', 'Un tableau indiquant simultanément ALARME et DÉFAUT présente deux situations indépendantes : une alarme incendie réelle ou potentielle dans une zone (à traiter en priorité absolue par une levée de doute) ; un défaut sur un autre composant du système (câble, détecteur, alimentation) qui devra être traité par un technicien mais ne remet pas en cause la réalité de l''alarme. Le SSIAP 2 traite les deux signaux distinctement : 1) Envoyer un agent en levée de doute sur la zone en alarme ; 2) Consigner le défaut et programmer une intervention technique. Ne jamais arrêter/redémarrer le système pendant un doute d''alarme car cela pourrait masquer une situation dangereuse.', 2, null::integer[], array['theme1','seq1','Catégories SSI et fonctionnement avancé','SSI - Expertise technique']::text[], 1),
('ssiap2-q23', 'ssiap2-partie3', 'multiple-select', 'La mise en place d''un réseau de communication radio dans un ERP pour le service SSIAP doit répondre à quelles exigences ? (plusieurs réponses possibles)', 'Le réseau de communication radio du service SSIAP doit impérativement : couvrir la totalité du bâtiment sans zone d''ombre (y compris les sous-sols et zones en béton armé épais où les ondes sont atténuées, nécessitant parfois des répéteurs ou des antennes déportées) ; être compatible avec les communications des sapeurs-pompiers (liaisons avec le réseau ANTARES des SDIS dans certains IGH et ERP importants) ; disposer d''une alimentation sur batterie assurant le fonctionnement lors d''une coupure secteur. Le chiffrement n''est pas une exigence réglementaire pour les radios SSIAP. La résistance aux interférences électromagnétiques est souhaitable mais n''est pas une norme spécifique imposée.', null, array[0,1,3]::integer[], array['theme2','seq2','Communications et coordination','Équipements de communication et sécurité']::text[], 2),
('ssiap2-q24', 'ssiap2-partie3', 'quiz', 'Qu''est-ce qu''un système de détection automatique d''incendie ''analogique'' par opposition à un système ''conventionnel'' ?', 'La différence fondamentale entre les deux technologies est la nature de l''information transmise : Système conventionnel : le détecteur envoie un signal binaire (alarme ou pas d''alarme) ; toute la boucle est en alarme si un détecteur se déclenche, sans identification individuelle. Système analogique (ou adressé) : chaque détecteur a une adresse unique et transmet en continu sa valeur mesurée (ex: 15% de fumée, 42°C) à la centrale qui analyse ces valeurs ; la centrale peut moduler les seuils de déclenchement (réduire les fausses alarmes), détecter la pré-alarme avant le seuil critique, localiser précisément le détecteur en cause. Les systèmes analogiques permettent une gestion plus intelligente et sont recommandés pour les ERP importants.', 1, null::integer[], array['theme1','seq1','Catégories SSI et fonctionnement avancé','SSI - Expertise technique']::text[], 3),
('ssiap2-q25', 'ssiap2-partie3', 'quiz', 'Le SSIAP 2 supervise la maintenance du SSI. Quelle est la fréquence minimale des vérifications réglementaires et qui peut les réaliser ?', 'La vérification périodique du SSI est annuelle, réalisée par un technicien ou organisme agréé possédant les qualifications requises (qualification APSAD Q18 pour les systèmes de détection, ou qualification équivalente). Cette vérification comprend le test individuel de chaque détecteur, le test des DAS, la vérification des alimentations électriques de sécurité, et donne lieu à un rapport consigné dans le registre de sécurité. Des vérifications plus fréquentes (essais mensuels) sont effectuées par le SSIAP mais ne remplacent pas la vérification annuelle par un technicien agréé. La règle APSAD R7 (règle de certification des systèmes de détection) précise les exigences de vérification.', 1, null::integer[], array['theme3','seq1','Maintenance et vérification des installations','SSI - Expertise technique']::text[], 4),
('ssiap2-q26', 'ssiap2-partie3', 'quiz', 'Dans un système de désenfumage mécanique d''un couloir d''ERP, le SSIAP 2 constate que la centrale de désenfumage indique un défaut sur un volet de désenfumage. Quelle est sa procédure ?', 'Un défaut sur un volet de désenfumage (DAS) compromet partiellement le désenfumage de la zone concernée. La procédure du SSIAP 2 est : 1) Signaler le défaut immédiatement à la direction et au responsable technique ; 2) Consigner dans le registre de sécurité (date, heure, nature du défaut, actions prises) ; 3) Programmer une intervention technique urgente par un technicien qualifié ; 4) Mettre en place des mesures compensatoires pendant l''indisponibilité : rondes plus fréquentes dans la zone, réduction éventuelle du public si le risque est majeur, notification de la commission de sécurité si la situation perdure. Ne pas réinitialiser sans raison (cela masquerait le problème) ni désactiver tout le système (cela aggraverait la situation).', 1, null::integer[], array['theme4','seq3','Exploitation du désenfumage','Désenfumage - Maîtrise technique']::text[], 5),
('ssiap2-q27', 'ssiap2-partie3', 'multiple-select', 'Quelles sont les exigences de documentation que le SSIAP 2 doit maintenir concernant les installations techniques ? (plusieurs réponses possibles)', 'La documentation technique que le SSIAP 2 doit maintenir à jour comprend : les plans et schémas des installations (plans du SSI, plans de désenfumage, plans des réseaux d''extinction) essentiels pour guider les interventions et les techniciens ; les procédures d''exploitation (comment mettre en service, arrêter, inhiber chaque installation) ; les contrats de maintenance avec les coordonnées des prestataires pour intervention rapide ; le registre de sécurité complet. Cette documentation doit être accessible au PC sécurité et une copie conservée en lieu sûr. Les catalogues commerciaux ne sont pas des documents de sécurité au sens strict, bien qu''utiles pour la maintenance.', null, array[0,1,2,3]::integer[], array['theme3','seq1','Maintenance et vérification des installations','SSI - Expertise technique']::text[], 6),
('ssiap2-q28', 'ssiap2-partie3', 'quiz', 'La norme APSAD R7 concerne :', 'La règle APSAD R7 (aujourd''hui référentiel CNPP 7) concerne les installations fixes d''extinction automatique à eau de type sprinkler. Elle définit les règles de conception, d''installation, de réception et de maintenance des installations sprinkler. Les règles APSAD incluent : R1 (extincteurs), R4 (RIA), R6 (détection incendie - remplacée par Q18), R7 (sprinklers), R13 (détection gaz), etc. Aucune des propositions (sprinklers bien qu''une option le mentionne, gaz, colonnes sèches) ne représente à elle seule l''ensemble R7.', 1, null::integer[], array['theme3','seq1','Maintenance et vérification des installations','SSI - Expertise technique']::text[], 7),
('ssiap2-q29', 'ssiap2-partie3', 'multiple-select', 'Le SSIAP 2 doit comprendre le fonctionnement du groupe électrogène de sécurité. Quels sont ses rôles dans un ERP ? (plusieurs réponses possibles)', 'Le groupe électrogène de sécurité (GES) est une source électrique de sécurité qui prend le relais en cas de coupure prolongée du réseau électrique public. Ses rôles dans un ERP : alimentation du SSI au-delà de l''autonomie des batteries (1 heure) ; maintien de l''éclairage des dégagements et du PC sécurité ; alimentation des ascenseurs de pompiers et des dispositifs de mise en sécurité (DAS, pompes sprinkler) ; dans les établissements de santé, maintien des équipements médicaux vitaux (blocs opératoires, réanimation). Le GES n''alimente généralement pas la totalité des équipements du bâtiment (climatisation bureaux, éclairage bureaux non essentiels) car sa puissance est dimensionnée pour les usages critiques.', null, array[0,1,2,4]::integer[], array['theme5','seq4','Groupe électrogène et AES','Alimentations électriques de sécurité']::text[], 8),
('ssiap2-q30', 'ssiap2-partie3', 'quiz', 'Dans un ERP, un système de détection gaz est installé dans la chaufferie. Comment ce système s''interface-t-il avec le SSI ?', 'Un système de détection gaz (SDG) dans une chaufferie s''interface avec d''autres systèmes de sécurité via des interfaces électriques : il génère une alarme spécifique ''gaz'' au PC sécurité (différenciée de l''alarme incendie) pour que l''agent SSIAP identifie immédiatement le type de danger ; il commande automatiquement la fermeture de la vanne de coupure de gaz (action primordiale pour stopper l''alimentation) ; il peut couper la ventilation de la chaufferie pour éviter la dispersion du gaz dans d''autres zones, ou au contraire l''activer pour purger (selon la conception). Il ne déclenche pas l''alarme générale d''évacuation automatiquement (c''est une décision humaine) ni les sprinklers (inefficaces sur un risque gaz). Le SSIAP 2 doit connaître ces interfaces.', 1, null::integer[], array['theme6','seq5','Détection gaz et interfaces avec le SSI','Systèmes connexes de détection']::text[], 9),
('ssiap2-q31', 'ssiap2-partie3', 'multiple-select', 'Le SSIAP 2 doit gérer les modifications du SSI lors de travaux d''extension. Quelles précautions sont indispensables ? (plusieurs réponses possibles)', 'Lors de modifications du SSI, les précautions indispensables sont : vérifier la compatibilité des nouveaux équipements avec la centrale (tous les détecteurs ne sont pas universels, notamment dans les systèmes analogiques adressés) ; mettre à jour les plans, schémas de câblage et la documentation opérationnelle après travaux ; faire réaliser les modifications par un installateur certifié (qualification APSAD ou équivalent) qui produira un rapport de réception ; informer la commission de sécurité si les modifications altèrent significativement les conditions de sécurité (ajout d''une zone, suppression d''un secteur). Augmenter les effectifs SSIAP pendant les travaux peut être utile mais n''est pas systématiquement obligatoire.', null, array[0,1,2,3]::integer[], array['theme3','seq1','Maintenance et vérification des installations','SSI - Expertise technique']::text[], 10),
('ssiap2-q32', 'ssiap2-partie3', 'quiz', 'Quelles sont les caractéristiques d''un désenfumage de cage d''escalier en surpression (mise en pression) ?', 'La mise en surpression d''une cage d''escalier est une technique de protection du chemin d''évacuation : un ventilateur insuffle de l''air extérieur frais dans la cage d''escalier, créant une pression légèrement supérieure à celle des paliers. Quand une porte de palier est ouverte lors de l''évacuation, l''air s''écoule de l''escalier vers le couloir, empêchant les fumées de pénétrer dans l''escalier. Cette technique est notamment utilisée dans les IGH et les bâtiments de grande hauteur où le désenfumage naturel est insuffisant. Elle nécessite un calcul précis de la pression (ni trop fort ce qui rendrait les portes impossibles à ouvrir, ni trop faible ce qui serait inefficace).', 0, null::integer[], array['theme4','seq3','Exploitation du désenfumage','Désenfumage - Maîtrise technique']::text[], 11),
('ssiap2-q33', 'ssiap2-partie3', 'multiple-select', 'Le SSIAP 2 reçoit un rapport de vérification annuelle des extincteurs indiquant que 3 extincteurs sont à recharger et 1 doit être mis au rebut (corrosion avancée). Que doit-il faire ? (plusieurs réponses possibles)', 'Face à des extincteurs défaillants identifiés dans un rapport de vérification, le SSIAP 2 doit : retirer immédiatement du service les 4 extincteurs (3 à recharger + 1 à réformer) car ils ne sont plus fiables ; les remplacer avant de les envoyer en recharge, en utilisant le stock de remplacement ou en commandant des extincteurs de remplacement en urgence (la zone ne doit jamais se retrouver sans couverture) ; consigner toutes les actions dans le registre de sécurité avec les dates et références. Il ne doit pas attendre la commission de sécurité (risque immédiat) ni négliger le remplacement. Informer la direction des coûts est une bonne pratique de gestion mais pas une obligation de sécurité immédiate.', null, array[0,1,2]::integer[], array['theme3','seq1','Maintenance et vérification des installations','SSI - Expertise technique']::text[], 12),
('ssiap2-q55', 'ssiap2-partie3', 'quiz', 'Le SSIAP 2 doit comprendre le principe de la redondance dans les systèmes de sécurité. Qu''est-ce que cela implique ?', 'La redondance dans les systèmes de sécurité consiste à prévoir des solutions de secours en cas de défaillance : une deuxième alimentation électrique (AES + GES) en cas de coupure réseau ; des moyens d''extinction redondants (sprinklers + RIA + colonnes sèches) ; des voies d''évacuation redondantes (au moins 2 escaliers dans les ERP importants) ; des boucles de détection redondantes dans les zones critiques. La redondance améliore la fiabilité et la disponibilité du système de sécurité. Elle ne réduit pas les obligations de maintenance (un système redondant doit être maintenu avec autant de rigueur que le système principal). Le SSIAP 2 doit s''assurer que les systèmes de secours fonctionnent réellement en cas de besoin.', 1, null::integer[], array['theme1','seq1','Catégories SSI et fonctionnement avancé','SSI - Expertise technique']::text[], 13),
('ssiap2-q56', 'ssiap2-partie3', 'quiz', 'Comment fonctionne un système de gestion technique centralisée (GTC/GTB) en lien avec la sécurité incendie ?', 'La GTC/GTB (Gestion Technique Centralisée/Bâtiment) est un système informatique qui supervise l''ensemble des équipements techniques d''un bâtiment : chauffage/climatisation, éclairage, électricité, contrôle d''accès, et peut intégrer des informations du SSI. En matière de sécurité incendie, la GTC peut afficher les alarmes du SSI, permettre des actions de commande à distance, et fournir des historiques utiles pour l''analyse des incidents. Cependant, elle ne remplace PAS le SSI réglementaire : le SSI conserve ses obligations normatives indépendantes. Le SSIAP 2 utilise la GTC comme outil d''information complémentaire, mais ses décisions s''appuient sur le SSI certifié. L''intervention manuelle reste toujours possible et souvent nécessaire.', 1, null::integer[], array['theme1','seq1','Catégories SSI et fonctionnement avancé','SSI - Expertise technique']::text[], 14),
('ssiap2-q57', 'ssiap2-partie3', 'multiple-select', 'Quelles sont les caractéristiques d''un poteau incendie normalisé et comment le SSIAP 2 doit-il en connaître l''utilisation ?', 'Les poteaux incendie normalisés (NF EN 14384) sont des équipements de la DECI (Défense Extérieure Contre l''Incendie) : ils doivent délivrer un débit minimum de 60 m³/h (certains 120 m³/h selon les risques) sous une pression résiduelle de 1 bar minimum, et être implantés à moins de 100-150 m de l''accès pompiers. Bien qu''utilisés exclusivement par les pompiers (raccordements standardisés ∅ 65 et 100 mm), le SSIAP 2 a un rôle important : connaître la localisation précise de tous les poteaux et bouches incendie dans le périmètre de son établissement ; s''assurer de leur signalisation (poteau ou plaque rouge avec indication de distance/côté) ; vérifier que leur accès n''est pas obstrué par des véhicules. Ces informations doivent figurer sur les plans remis aux pompiers.', null, array[0,2]::integer[], array['theme9','seq6','Ressources en eau et DECI','DECI et ressources en eau']::text[], 15),
('ssiap2-q73', 'ssiap2-partie3', 'multiple-select', 'Comment le SSIAP 2 gère-t-il une indisponibilité prolongée de l''installation sprinkler pour maintenance ? (plusieurs réponses possibles)', 'L''indisponibilité de l''installation sprinkler est une situation sérieuse car les sprinklers constituent souvent la principale barrière active contre l''incendie. Le SSIAP 2 doit : informer la commission de sécurité (obligation réglementaire pour les ERP où les sprinklers compensent des dérogations) et les assurances (risque assurantiel accru) ; mettre en place des rondes renforcées continues dans les zones sans protection ; selon la durée et l''importance, réduire l''effectif du public (mesure compensatoire réglementaire) ; assurer une présence humaine permanente dans les zones à risque. La durée maximale admissible dépend des conditions d''exploitation de l''établissement. Ne rien faire serait une faute grave.', null, array[0,1,2,3]::integer[], array['theme3','seq1','Maintenance et vérification des installations','SSI - Expertise technique']::text[], 16),
('ssiap2-q74', 'ssiap2-partie3', 'quiz', 'Qu''est-ce qu''une ''peinture intumescente'' et quel est son rôle dans la protection structurelle ?', 'Les peintures intumescentes sont des revêtements de protection passive contre l''incendie : lorsque la température atteint environ 150-250°C, la peinture entre en expansion (intumescence) et gonfle jusqu''à 30-50 fois son épaisseur initiale, formant une couche de mousse carbonisée légère qui isole thermiquement la structure (acier, bois, bois d''œuvre) des flammes et de la chaleur. Cette couche réduit considérablement la vitesse d''élévation de température de la structure, lui permettant de conserver sa résistance mécanique pendant la durée requise (30, 60 ou 90 minutes selon l''épaisseur). Les peintures intumescentes sont une solution esthétique et économique par rapport au flocage. Le SSIAP 2 doit identifier ces protections sur les structures de son établissement.', 1, null::integer[], array['theme10','seq7','Protections passives des structures','Protection passive']::text[], 17),
('ssiap2-q75', 'ssiap2-partie3', 'quiz', 'Dans le cadre de la surveillance d''un établissement multi-sites, comment le SSIAP 2 organise-t-il la télésurveillance à distance ?', 'La télésurveillance à distance (report des alarmes SSI vers un centre de télésurveillance ou un agent en astreinte) est admise dans certaines configurations avec des conditions strictes : accord préalable de la commission de sécurité (ou du préfet pour certains établissements) ; procédures d''intervention rapide garantissant qu''en cas d''alarme, un agent qualifié peut intervenir sur site dans un délai compatible avec la sécurité (généralement < 15-20 min) ; mesures compensatoires techniques (SSI performant, sprinklers, etc.). Elle ne remplace jamais complètement la présence humaine pour les établissements ouverts au public. Le SSIAP 2 gère ces dispositifs en s''assurant de leur conformité réglementaire.', 1, null::integer[], array['theme2','seq2','Communications et coordination','Équipements de communication et sécurité']::text[], 18),
('ssiap2-q76', 'ssiap2-partie3', 'quiz', 'Quels sont les principes de base du compartimentage coupe-feu et comment le SSIAP 2 l''exploite-t-il lors d''un incendie ?', 'Le compartimentage coupe-feu est la division du bâtiment en secteurs délimités par des parois et planchers résistant au feu (REI ou EI) et des portes coupe-feu, afin de : confiner le feu dans le secteur d''origine et limiter sa propagation aux autres zones (protection des biens) ; protéger les voies d''évacuation en maintenant des couloirs et escaliers sans fumée pendant le temps nécessaire à l''évacuation. En exploitation, le SSIAP 2 exploite le compartimentage lors d''un incendie : il guide l''évacuation vers les compartiments non touchés, s''assure que les portes CF sont fermées (confirmation par le serre-file), et informe les pompiers des limites des compartiments pour concentrer leur attaque. Un compartimentage défaillant (portes CF bloquées ouvertes) peut transformer un incendie localisé en sinistre général.', 0, null::integer[], array['theme10','seq7','Protections passives des structures','Protection passive']::text[], 19)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap2-q21','ssiap2-q22','ssiap2-q23','ssiap2-q24','ssiap2-q25','ssiap2-q26','ssiap2-q27','ssiap2-q28','ssiap2-q29','ssiap2-q30','ssiap2-q31','ssiap2-q32','ssiap2-q33','ssiap2-q55','ssiap2-q56','ssiap2-q57','ssiap2-q73','ssiap2-q74','ssiap2-q75','ssiap2-q76');
commit;

-- ===== ssiap2-partie3-sub02.sql =====
begin;
-- SSIAP 2 — Installations techniques approfondies (partie 3, sub 2/3, 20 cc_questions)
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap2-q88', 'ssiap2-partie3', 'multiple-select', 'Quels sont les signes d''un détecteur de fumée optique encrassé ou défaillant ? (plusieurs réponses possibles)', 'Un détecteur de fumée optique encrassé ou défaillant peut présenter plusieurs signes : fausses alarmes répétées dues à l''encrassement de la chambre optique (poussières diffusant la lumière comme si c''était de la fumée) ; voyant rouge ou orange clignotant indiquant une autodiagnostication de défaut interne ; absence de réponse lors d''un test par aérosol simulateur (la chambre est si encrassée ou obstruée qu''elle ne détecte plus rien) ; présence visible de poussière, toiles d''araignée ou d''insectes dans la chambre de détection. Un état ''normal'' sans anomalie ne signifie pas forcément que le détecteur est encrassé (il peut fonctionner normalement). Le nettoyage ou le remplacement s''impose dans tous les cas de signes d''encrassement.', null, array[0,1,2,3]::integer[], array['theme3','seq1','Maintenance et vérification des installations','SSI - Expertise technique']::text[], 20),
('ssiap2-q90', 'ssiap2-partie3', 'quiz', 'La NF S 61-932 est la norme française définissant :', 'La norme NF S 61-932 concerne les règles d''installation des Systèmes de Sécurité Incendie (SSI). La série NF S 61-930 à 61-940 couvre l''ensemble du SSI : 61-930 (vocabulaire), 61-931 (règles de conception), 61-932 (règles d''installation), 61-933 (règles d''exploitation et maintenance), 61-934 (CMSI), 61-935 (DAS), 61-936 (diffuseurs sonores). Les extincteurs relèvent des normes NF EN 3 et règle APSAD R1. Les colonnes sèches relèvent d''autres normes. La réaction au feu des matériaux est couverte par la série NF EN 13501.', 0, null::integer[], array['theme3','seq1','Maintenance et vérification des installations','SSI - Expertise technique']::text[], 21),
('ssiap2-q111', 'ssiap2-partie3', 'quiz', 'Quels sont les principaux risques professionnels spécifiques au métier d''agent SSIAP ?', 'Le métier SSIAP expose à de multiples risques : risques liés à l''incendie (fumées toxiques, chaleur, flammes), risques physiques (manutention lors d''interventions, chutes lors de rondes), risques psychosociaux (travail de nuit, stress, agressivité), risques biologiques (premiers secours). L''évaluation des risques professionnels doit conduire à des mesures de prévention adaptées.', 1, null::integer[], array['theme1','sequence1']::text[], 22),
('ssiap2-q112', 'ssiap2-partie3', 'quiz', 'Quels Équipements de Protection Individuelle (EPI) peut porter un agent SSIAP lors d''une première intervention incendie ?', 'Pour une première intervention limitée (utilisation extincteur, RIA), les EPI adaptés comprennent : des gants de protection contre la chaleur, une cagoule anti-fumée (protection respiratoire minimale), des chaussures de sécurité avec embout acier, une lampe de poche. Les Appareils Respiratoires Isolants (ARI) sont réservés aux pompiers. Une première intervention qui tourne mal doit conduire à l''abandon immédiat et l''évacuation.', 1, null::integer[], array['theme2','sequence1']::text[], 23),
('ssiap2-q113', 'ssiap2-partie3', 'quiz', 'Qu''est-ce que le droit de retrait d''un agent SSIAP ?', 'Le droit de retrait (articles L4131-1 et suivants du Code du travail) permet à tout salarié de se retirer d''une situation de travail dont il a un motif raisonnable de penser qu''elle présente un danger grave et imminent pour sa vie ou sa santé. L''agent SSIAP ne peut être sanctionné pour cet exercice, mais il doit informer son employeur. Ce droit ne s''applique pas quand l''abandon du poste crée un danger pour d''autres.', 1, null::integer[], array['theme3','sequence1']::text[], 24),
('ssiap2-q114', 'ssiap2-partie3', 'quiz', 'Dans le cadre du Document Unique d''Évaluation des Risques (DUER), quel est le rôle du SSIAP 2 ?', 'Le DUER est obligatoire dans toute entreprise. Le SSIAP 2, de par son expertise et sa connaissance du terrain, peut contribuer à identifier les risques liés à l''activité de sécurité incendie. Il peut participer à la démarche d''évaluation et s''assure que les mesures de prévention définies sont effectivement appliquées par son équipe.', 1, null::integer[], array['theme3','sequence1']::text[], 25),
('ssiap2-q115', 'ssiap2-partie3', 'quiz', 'Qu''est-ce que le Sauveteur Secouriste du Travail (SST) ?', 'Le SST est un salarié formé (formation de 14h recyclée tous les 2 ans) aux gestes de premiers secours adapté au milieu professionnel. Il peut alerter les secours, réaliser les gestes d''urgence, et participe à la prévention des risques. La présence d''un SST est recommandée dans tout établissement. Beaucoup d''agents SSIAP sont également SST.', 1, null::integer[], array['theme1','sequence3']::text[], 26),
('ssiap2-q116', 'ssiap2-partie3', 'quiz', 'Lors d''une intervention auprès d''une victime inconsciente qui respire, quelle est la position à adopter ?', 'La Position Latérale de Sécurité (PLS) est la position à adopter pour une victime inconsciente qui respire normalement. Elle libère les voies aériennes, évite que la victime s''étouffe avec ses vomissements, et maintient une respiration efficace. Il faut alerter les secours (15 ou 18) et surveiller la victime jusqu''à leur arrivée.', 1, null::integer[], array['theme2','sequence3']::text[], 27),
('ssiap2-q133', 'ssiap2-partie3', 'quiz', 'Quels sont les effets physiologiques du monoxyde de carbone (CO) sur le corps humain lors d''une exposition prolongée ?', 'Le CO provoque des symptômes progressifs : 200 ppm → maux de tête en 2-3h ; 400 ppm → maux de tête, vertiges, nausées en 2h ; 800 ppm → convulsions, inconscience en 45 min ; 1600 ppm → mort en 1h. L''insidiosité du CO (incolore, inodore) en fait un danger particulièrement grave : les victimes ne réalisent pas le danger avant d''être inconscientes.', 1, null::integer[], array['theme2','sequence1']::text[], 28),
('ssiap2-q134', 'ssiap2-partie3', 'quiz', 'Comment prévenir les Troubles Musculo-Squelettiques (TMS) liés aux rondes et patrouilles en SSIAP ?', 'Les TMS sont une préoccupation réelle dans la profession SSIAP (station debout prolongée, ports de charges lors d''exercices, interventions physiques). La prévention comprend : équipements de protection adaptés (chaussures de sécurité ergonomiques), formation aux gestes et postures, organisation alternant rondes actives et surveillance statique, suivi médical, et démarche de prévention collective.', 1, null::integer[], array['theme1','sequence1']::text[], 29),
('ssiap2-q135', 'ssiap2-partie3', 'quiz', 'Quels sont les risques psychosociaux (RPS) spécifiques au travail de nuit pour les agents SSIAP ?', 'Le travail de nuit (défini entre 21h et 6h) expose les agents SSIAP à des risques spécifiques : désynchronisation du rythme biologique (troubles du sommeil, digestifs, cardiovasculaires), isolement social et familial, difficultés de vigilance aux heures creuses (3-5h), fatigue chronique. Des mesures préventives s''imposent : suivi médical renforcé, organisation des rotations, locaux de repos adaptés.', 1, null::integer[], array['theme3','sequence1']::text[], 30),
('ssiap2-q169', 'ssiap2-partie3', 'quiz', 'Un détecteur linéaire de chaleur (câble thermosensible) est installé dans un tunnel de convoyeur. Comment fonctionne-t-il et quels sont ses avantages ?', 'Le détecteur linéaire de chaleur (ou câble thermosensible) est une technologie de détection particulièrement adaptée aux environnements difficiles et aux grandes longueurs : c''est un câble dont les propriétés électriques (résistance ou capacité selon la technologie) changent de manière mesurable lorsque la température dépasse un seuil sur n''importe quel point de sa longueur. La centrale peut localiser la zone en alarme avec une précision de l''ordre du mètre. Avantages : couverture continue sur de grandes longueurs sans angle mort, résistance aux environnements poussiéreux ou humides (tunnels, parkings), détection en tout point de la longueur surveillée. Applications typiques : convoyeurs industriels, câblages en gaine, toitures végétalisées, tunnels, stations de relevage. Son entretien est simple (test fonctionnel annuel) et ne nécessite pas d''étalonnage hebdomadaire.', 1, null::integer[], array['theme1','seq1','Catégories SSI et fonctionnement avancé','SSI - Expertise technique']::text[], 31),
('ssiap2-q170', 'ssiap2-partie3', 'quiz', 'Le SSIAP 2 supervise un essai mensuel du SSI. Quelles opérations minimales cet essai doit-il comprendre ?', 'L''essai mensuel du SSI (prescrit par la norme NF S 61-933 et les dispositions d''exploitation) comprend au minimum : déclenchement d''au moins un déclencheur manuel ou d''un détecteur par zone (en rotation mensuelle pour tester toutes les zones sur l''année) ; vérification que la signalisation au tableau central correspond bien (zone identifiée, pas de défaut masqué) ; test des diffuseurs sonores dans les zones en alarme pour vérifier leur audibilité ; vérification du bon fonctionnement des principaux DAS commandés (au moins quelques portes CF, exutoires) ; contrôle des alimentations électriques (niveau de charge des batteries) ; consignation complète dans le registre de sécurité avec signature. Ces essais mensuels ne remplacent pas la vérification annuelle par un organisme agréé qui couvre tous les équipements de manière exhaustive.', 1, null::integer[], array['theme3','seq1','Maintenance et vérification des installations','SSI - Expertise technique']::text[], 32),
('ssiap2-q171', 'ssiap2-partie3', 'quiz', 'Dans quels cas l''inhibition d''un détecteur du SSI est-elle justifiée et quelles mesures compensatoires le SSIAP 2 doit-il mettre en place ?', 'L''inhibition (mise hors service temporaire) d''un ou plusieurs détecteurs est parfois nécessaire pour éviter des fausses alarmes dues à des travaux (meulage, soudure, travaux de peinture) ou à des conditions d''exploitation particulières (cuisson, vapeur). Pour être justifiée et sécurisée, elle nécessite : une durée limitée au strict nécessaire (journée de travaux, pas au-delà) ; une autorisation formelle du SSIAP 2 consignée dans la main courante avec heure début/fin ; la mise en place d''une surveillance humaine renforcée dans la zone non couverte (présence d''un agent ou rondes très fréquentes) ; un affichage sur le tableau de signalisation indiquant clairement quelle zone est inhibée ; la vérification du retour en service après la fin des travaux. Une inhibition non compensée est une faute grave pouvant engager la responsabilité en cas de sinistre.', 1, null::integer[], array['theme1','seq1','Catégories SSI et fonctionnement avancé','SSI - Expertise technique']::text[], 33),
('ssiap2-q172', 'ssiap2-partie3', 'quiz', 'Quelle est la différence entre un exutoire de désenfumage naturel (EFC) et un volet de transfert d''air ?', 'Ces deux éléments ont des rôles complémentaires dans le système de désenfumage naturel par balayage : l''Exutoire de Fumée et de Chaleur (EFC) est un ouvrant en toiture ou en partie haute des façades qui s''ouvre vers l''extérieur pour extraire les fumées et la chaleur — c''est la sortie du système ; le Volet de Transfert d''Air (VTA) est un ouvrant entre deux locaux (souvent entre un couloir et un local à désenfumer) permettant l''entrée d''air frais dans la zone à désenfumer, sans ouverture directe vers l''extérieur — c''est l''entrée d''air neuf qui ''pousse'' les fumées vers les exutoires. Un désenfumage efficace nécessite les deux : des exutoires pour l''extraction et des amenées d''air pour créer le balayage. Sans amenée d''air, les exutoires ne fonctionnent pas correctement (dépression dans le local).', 1, null::integer[], array['theme4','seq3','Exploitation du désenfumage','Désenfumage - Maîtrise technique']::text[], 34),
('ssiap2-q173', 'ssiap2-partie3', 'quiz', 'Comment le SSIAP 2 gère-t-il un déclenchement intempestif des sprinklers (dû à un choc accidentel ou à un pic de chaleur d''origine non incendie) ?', 'Un déclenchement intempestif de sprinkler (sprinkler fissuré par choc mécanique, dysfonctionnement suite à une chaleur anormale non incendie) doit être géré avec méthode : vérification préalable obligatoire qu''il ne s''agit pas d''un vrai sinistre (examen visuel de la zone, absence de fumée, de feu, de chaleur anormale persistante) — ne jamais fermer une vanne avant cette vérification ; fermeture de la vanne d''arrêt sectorielle du secteur concerné (chaque installation sprinkler comporte des vannes sectorielles, le SSIAP 2 doit connaître leur localisation) pour stopper l''écoulement d''eau et limiter les dégâts des eaux ; actions de protection des équipements et denrées mouillés ; signalement au gestionnaire de maintenance pour remplacement du sprinkler et réarmement du secteur. La coupure de l''alimentation générale priverait l''ensemble du bâtiment de protection.', 1, null::integer[], array['theme3','seq1','Maintenance et vérification des installations','SSI - Expertise technique']::text[], 35),
('ssiap2-q174', 'ssiap2-partie3', 'multiple-select', 'Lors de sa ronde, le SSIAP 2 constate que le local technique hébergeant le tableau général de sécurité (TGBT) est à une température anormalement élevée. Quelle est sa procédure ? (plusieurs réponses possibles)', 'Une température anormalement élevée dans un local TGBT est un signal d''alarme précoce d''un risque incendie électrique : vérification visuelle de l''absence de feu ou de fumée avant toute autre action ; identification des sources possibles (armoire en surcharge thermique, fusible ou disjoncteur défaillant, câble mal dimensionné, ventilation insuffisante du local) par inspection visuelle et olfactive (odeur de plastique chaud, traces de noircissement) ; consignation immédiate et alerte à l''électricien ou au responsable technique (intervention urgente nécessaire) ; surveillance renforcée du local jusqu''à l''intervention. Utiliser un extincteur à eau sur un équipement électrique sous tension est extrêmement dangereux (risque d''électrocution) — si un feu est déclaré, utiliser un extincteur CO2 ou à poudre et couper l''alimentation si possible en sécurité.', null, array[0,1,2,3]::integer[], array['theme5','seq4','Groupe électrogène et AES','Alimentations électriques de sécurité']::text[], 36),
('ssiap2-q175', 'ssiap2-partie3', 'quiz', 'Le SSIAP 2 doit connaître les SATI (Système d''Alarme de Type Interne). Dans quels établissements ce type d''alarme est-il utilisé et comment fonctionne-t-il ?', 'Le Système d''Alarme de Type Interne (SATI) est un dispositif d''alarme à deux niveaux utilisé dans des ERP de grande capacité (centres commerciaux, grands hôtels) : en cas de détection, une première alarme restreinte est diffusée uniquement auprès du personnel formé (SSIAP, personnel d''accueil) sans alarme générale immédiate pour le public, permettant une levée de doute rapide (2-3 minutes maximum) ; si le sinistre est confirmé, l''alarme générale d''évacuation est alors déclenchée ; si c''est une fausse alarme, elle est annulée sans avoir déclenché d''évacuation inutile du public. Ce système est admis par la réglementation (arrêté du 25 juin 1980) car il améliore la gestion des fausses alarmes dans les grands ERP tout en maintenant la réactivité. La levée de doute doit être courte et conduite par des personnels formés.', 1, null::integer[], array['theme1','seq1','Catégories SSI et fonctionnement avancé','SSI - Expertise technique']::text[], 37),
('ssiap2-q176', 'ssiap2-partie3', 'multiple-select', 'Comment le SSIAP 2 s''assure-t-il que le système de désenfumage des escaliers fonctionne correctement lors de l''essai mensuel ? (plusieurs réponses possibles)', 'L''essai mensuel du désenfumage d''escaliers comprend plusieurs vérifications fonctionnelles : déclenchement manuel depuis la commande dédiée (généralement une boîte à clé ou un interrupteur identifié) et vérification que tous les composants du système s''activent dans les délais prévus ; pour les systèmes naturels : vérification que les exutoires s''ouvrent correctement (pivotent, coulissent ou s''effacent selon le type) et ne sont pas bloqués par un obstacle, une peinture ou une déformation ; pour les escaliers avec portes palières à fermeture automatique : vérification que la commande de désenfumage déclenche bien la fermeture des portes CF ; chronométrage du délai d''activation pour détecter tout ralentissement anormal (moteur qui faiblit, câble de commande usé). La mesure de pression différentielle est pertinente pour les systèmes en surpression mais nécessite un manomètre.', null, array[0,1,2,3]::integer[], array['theme4','seq3','Exploitation du désenfumage','Désenfumage - Maîtrise technique']::text[], 38),
('ssiap2-q177', 'ssiap2-partie3', 'quiz', 'La norme française relative aux extincteurs portatifs est :', 'La norme NF EN 3 est la série de normes européennes relatives aux extincteurs portatifs (conception, performances, marquage, essais). La règle APSAD R1 définit les règles d''installation. La norme NF S 61-919 n''existe pas en tant que telle pour les extincteurs. La norme NF ISO 14520 concerne les systèmes d''extinction à gaz. Cependant, la réponse ''NF EN 3'' mentionnée dans les options n''est pas strictement ''aucune de ces réponses n''est correcte'' — mais le format de la question place ''Aucune'' en position aléatoire. Ici la bonne réponse est NF EN 3 pour les extincteurs portatifs.', 2, null::integer[], array['theme3','seq1','Maintenance et vérification des installations','SSI - Expertise technique']::text[], 39)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap2-q88','ssiap2-q90','ssiap2-q111','ssiap2-q112','ssiap2-q113','ssiap2-q114','ssiap2-q115','ssiap2-q116','ssiap2-q133','ssiap2-q134','ssiap2-q135','ssiap2-q169','ssiap2-q170','ssiap2-q171','ssiap2-q172','ssiap2-q173','ssiap2-q174','ssiap2-q175','ssiap2-q176','ssiap2-q177');
commit;

-- ===== ssiap2-partie3-sub03.sql =====
begin;
-- SSIAP 2 — Installations techniques approfondies (partie 3, sub 3/3, 6 cc_questions)
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap2-q178', 'ssiap2-partie3', 'quiz', 'Lors d''une inspection, le SSIAP 2 constate qu''une cloison en plâtre a été percée pour faire passer une gaine de ventilation, mais le passage n''a pas été rebouché avec un matériau coupe-feu. De quelle non-conformité s''agit-il et quelle est son importance ?', 'Le calfeutrement des pénétrations dans les parois coupe-feu est une obligation réglementaire fondamentale : une paroi EI 60 percée pour faire passer une gaine sans rebouchage coupe-feu perd totalement sa résistance au feu sur ce point — en quelques minutes, les flammes et les gaz chauds peuvent traverser par le vide annulaire entre la gaine et la paroi. Les matériaux de calfeutrement (mousse intumescente, manchons coupe-feu sur les gaines plastiques, mortier coupe-feu, blocs préfabriqués à insert intumescent) reconstituent la résistance au feu requise. Les gaines de ventilation elles-mêmes ne sont pas exemptées : si elles traversent une paroi CF, elles doivent être équipées d''un clapet coupe-feu (DAS) qui se ferme en cas de sinistre. Cette non-conformité doit être signalée et corrigée en urgence avec un matériau certifié.', 1, null::integer[], array['theme10','seq7','Protections passives des structures','Protection passive']::text[], 40),
('ssiap2-q179', 'ssiap2-partie3', 'multiple-select', 'Le SSIAP 2 doit expliquer à la direction pourquoi les extincteurs CO2 doivent être vérifiés et rechargés périodiquement même s''ils n''ont jamais été utilisés. Quels sont les arguments ? (plusieurs réponses possibles)', 'Les extincteurs CO2 nécessitent une maintenance régulière malgré leur non-utilisation pour plusieurs raisons : la pression interne peut diminuer progressivement par micro-fuites (des tests de pesée permettent de détecter une perte de charge) — un extincteur sous-pressurisé ne projette pas le CO2 à la distance et durée requises ; la bouteille en acier haute pression peut se corroder intérieurement (condensation) ou extérieurement (environnement humide), créant un risque de rupture à la prochaine utilisation ou lors d''une recharge ; la réglementation (arrêté du 5 janvier 2016 et norme NF EN 3) impose une vérification périodique annuelle par un technicien habilité et une recharge basée sur la pesée. Le CO2 en lui-même ne se dégrade pas chimiquement, et la vérification de marquage seule ne justifie pas la périodicité.', null, array[1,2,3]::integer[], array['theme3','seq1','Maintenance et vérification des installations','SSI - Expertise technique']::text[], 41),
('ssiap2-q180', 'ssiap2-partie3', 'quiz', 'Qu''est-ce qu''un ''clapet coupe-feu'' (CCF) et où est-il installé dans un bâtiment ?', 'Le clapet coupe-feu (CCF), aussi appelé volet coupe-feu ou DAS (Dispositif Actionné de Sécurité), est un volet métallique installé dans les conduits de ventilation ou de climatisation au passage des parois coupe-feu. Son rôle est de reconstituer la barrière coupe-feu que le conduit de ventilation perceraient sinon. En temps normal, il est ouvert pour permettre la circulation d''air. En cas de sinistre, il se ferme : soit thermiquement (un élément fusible fond à 70°C libérant le volet qui se ferme par ressort) ; soit par commande électrique déclenchée par le SSI (DAS électrothermique ou électrique). Sa vérification doit être effectuée régulièrement (test d''ouverture/fermeture) et son positionnement exact doit figurer sur les plans. C''est un élément clé du compartimentage dans les bâtiments ventilés.', 1, null::integer[], array['theme1','seq1','Catégories SSI et fonctionnement avancé','SSI - Expertise technique']::text[], 42),
('ssiap2-q181', 'ssiap2-partie3', 'multiple-select', 'Le SSIAP 2 doit assurer le suivi des RIA (Robinets d''Incendie Armés). Lors de la vérification annuelle, quels éléments sont contrôlés ? (plusieurs réponses possibles)', 'La vérification annuelle des RIA (règle APSAD R4) comprend : mesure de la pression et du débit disponibles au robinet (le débit minimal exigé est de 24 l/min avec une pression résiduelle de 2,5 bars pour les DN 25, 45 l/min pour les DN 33) pour s''assurer que le réseau est correctement dimensionné et sans obstruction ; inspection visuelle complète du dévidoir (rotation fluide, absence de grippage ou de déformation), du tuyau semi-rigide (absence de détérioration, de rigidification, de craquelures sur toute la longueur), du jet/lance (non obstrué, joint intact) ; test du robinet d''arrêt (manœuvre pour s''assurer qu''il s''ouvre et se ferme correctement sans fuite). Le mode d''emploi est recommandé mais n''est pas un critère de vérification réglementaire standard. Il n''y a pas de bac de rétention réglementaire sous les RIA.', null, array[0,1,3]::integer[], array['theme3','seq1','Maintenance et vérification des installations','SSI - Expertise technique']::text[], 43),
('ssiap2-q182', 'ssiap2-partie3', 'quiz', 'Lors d''une panne du réseau électrique principal, comment le SSI est-il alimenté et pendant combien de temps doit-il fonctionner ?', 'La norme NF S 61-930 et les dispositions réglementaires imposent que le SSI dispose de sa propre Alimentation Électrique de Sécurité (AES) indépendante du réseau principal : les centrales de détection et les CMSI doivent être équipés de batteries permettant : 12 heures de fonctionnement en veille (surveillance normale sans alarme) + 1 heure de fonctionnement en état d''alarme (toutes les sirènes actives, tous les DAS commandés). Cette autonomie garantit que le SSI reste opérationnel lors d''une coupure électrique suffisamment longtemps pour permettre une intervention et une évacuation complète. Au-delà, si la coupure persiste, un groupe électrogène de sécurité (GES) prend le relais. Les batteries doivent être testées régulièrement (test de décharge) pour vérifier leur capacité réelle.', 1, null::integer[], array['theme5','seq4','Groupe électrogène et AES','Alimentations électriques de sécurité']::text[], 44),
('ssiap2-q183', 'ssiap2-partie3', 'quiz', 'Le SSIAP 2 doit gérer un défaut d''alimentation électrique de sécurité (AES) du SSI signalé par la centrale. Quelle est sa procédure ?', 'Un défaut AES (problème de batteries : batterie faible, déconnectée, défaillante, ou chargeur défaillant) est une non-conformité grave car elle prive le SSI de son autonomie en cas de coupure secteur. La procédure du SSIAP 2 : ne pas réinitialiser (cela masquerait le problème sans le résoudre) ; signaler immédiatement à la direction et au prestataire de maintenance du SSI pour intervention urgente ; consigner dans le registre (date, heure, nature du défaut, actions prises) ; pendant l''indisponibilité de l''AES, augmenter la surveillance humaine du bâtiment (rondes plus fréquentes) et vérifier l''état du réseau électrique de l''établissement (si le réseau est instable, le risque de coupure est plus élevé). Un défaut AES non traité peut conduire à une coupure complète du SSI lors d''une coupure secteur, au pire moment possible.', 1, null::integer[], array['theme5','seq4','Groupe électrogène et AES','Alimentations électriques de sécurité']::text[], 45)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap2-q178','ssiap2-q179','ssiap2-q180','ssiap2-q181','ssiap2-q182','ssiap2-q183');
commit;

-- ===== ssiap2-partie4-sub01.sql =====
begin;
-- SSIAP 2 — Management et organisation (partie 4, sub 1/4, 20 cc_questions)
values ('ssiap2-partie4', 2, 'Management et organisation', '71 cc_questions', '👨‍🚒', 'from-emerald-500 to-teal-600', 3, true)
on conflict (id) do update set title=excluded.title, subtitle=excluded.subtitle, icon=excluded.icon, color=excluded.color, display_order=excluded.display_order;
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap2-q34', 'ssiap2-partie4', 'multiple-select', 'Le SSIAP 2, chef d''équipe, est le responsable hiérarchique direct des agents SSIAP 1 de son équipe. Quelles sont ses responsabilités managériales ? (plusieurs réponses possibles)', 'Le SSIAP 2 exerce une véritable fonction de management opérationnel : organisation des plannings (en tenant compte des règles sur la durée du travail, les temps de repos entre deux postes, les jours fériés, les relèves) ; évaluation régulière des agents (entretiens, observation sur le terrain, identification des points à améliorer et des besoins de formation complémentaire) ; mise à jour des procédures opérationnelles (POI adapté à la réalité du terrain, fiches réflexes claires et accessibles) ; maintien de la cohésion et discipline de l''équipe (gestion des conflits, communication, motivation). La gestion du budget commercial est de la compétence du SSIAP 3 ou de la direction, pas du SSIAP 2.', null, array[0,1,2,3]::integer[], array['theme1','seq1','Management opérationnel de l''équipe SSIAP','Encadrement de l''équipe']::text[], 0),
('ssiap2-q35', 'ssiap2-partie4', 'quiz', 'Un agent SSIAP 1 de votre équipe arrive en retard répétitivement à son poste. En tant que SSIAP 2, quelle est votre démarche ?', 'La gestion des retards répétitifs d''un agent suit une démarche progressive et documentée : 1) Entretien individuel informel pour comprendre les causes (problème de transport, personnel, organisationnel) et rappeler les obligations contractuelles et de sécurité (un poste non couvert crée un risque) ; 2) Définir un plan d''amélioration avec des objectifs clairs et un délai de réévaluation ; 3) Documenter l''échange (même informellement) en cas de procédure ultérieure ; 4) Si les retards persistent malgré l''avertissement, escalader au SSIAP 3 ou à la direction RH pour une procédure disciplinaire formelle. Ignorer crée un précédent négatif. La mise à pied immédiate sans avertissement préalable peut être contestée.', 2, null::integer[], array['theme1','seq1','Management opérationnel de l''équipe SSIAP','Encadrement de l''équipe']::text[], 1),
('ssiap2-q36', 'ssiap2-partie4', 'multiple-select', 'Comment le SSIAP 2 doit-il organiser les rondes de son équipe pour optimiser la couverture de sécurité ? (plusieurs réponses possibles)', 'L''organisation optimale des rondes comprend : des itinéraires définis couvrant tous les secteurs selon leur niveau de risque (locaux techniques, stockages, zones publiques) ; une variation des horaires et itinéraires (une ronde systématiquement à la même heure est prévisible et donc moins efficace) ; un système de traçabilité des passages (lecteurs de badges, QR codes, NFC, ou points de contrôle avec horodatage) permettant de prouver les rondes effectuées et d''identifier les manquements ; une adaptation en cas d''événements particuliers (travaux, manifestations, conditions météo dégradées). Concentrer les rondes uniquement aux heures de pointe laisse les périodes creuses sans surveillance, ce qui est contraire à la logique de sécurité permanente.', null, array[0,1,2,4]::integer[], array['theme2','seq2','Planification des rondes et surveillance','Organisation opérationnelle']::text[], 2),
('ssiap2-q37', 'ssiap2-partie4', 'multiple-select', 'En situation de sinistre grave, le SSIAP 2 coordonne son équipe et fait l''interface avec les sapeurs-pompiers. Quelles informations doit-il être capable de communiquer au chef des opérations de secours (COS) à leur arrivée ? (plusieurs réponses possibles)', 'Lors de l''arrivée du COS (Chef des Opérations de Secours), le SSIAP 2 doit pouvoir fournir immédiatement : la localisation et l''évolution du sinistre (zone touchée, extension probable, foyer visible) ; le bilan des personnes (combien ont évacué, combien peuvent être encore dans les zones concernées, présence de blessés, PMR en zone de refuge) ; les caractéristiques du bâtiment (plans, nombre de niveaux, type de construction, locaux dangereux, risques spéciaux) ; l''état des systèmes actifs (sprinklers déclenché dans quelle zone, colonnes sèches alimentées, SSI en mode alarme généralisée). Ces informations sont préparées à l''avance dans les plans d''intervention. Les informations commerciales sont totalement inutiles.', null, array[0,1,2,3]::integer[], array['theme3','seq3','Interface avec les sapeurs-pompiers','Coordination opérationnelle sinistre']::text[], 3),
('ssiap2-q38', 'ssiap2-partie4', 'multiple-select', 'Le SSIAP 2 doit rédiger un rapport d''incident après un déclenchement de l''alarme incendie. Ce rapport doit contenir : (plusieurs réponses possibles)', 'Un rapport d''incident de qualité comprend : les éléments factuels objectifs (date, heure précise, durée, zone concernée) ; l''analyse de la cause (fausse alarme due à la fumée de cuisine, à des travaux, à un mauvais entretien du détecteur, ou feu réel) ; la chronologie des actions (qui a fait quoi, à quelle heure : levée de doute, alerte PC, appel pompiers, évacuation, extinction) ; les mesures correctives recommandées pour prévenir la récidive (nettoyage des détecteurs, modification du seuil de sensibilité, formation du personnel, revision des procédures). L''opinion personnelle sur la qualité du matériel n''a pas sa place dans un rapport factuel et peut nuire à sa crédibilité. Ces rapports sont conservés et peuvent être examinés lors des visites de commission.', null, array[0,1,2,3]::integer[], array['theme4','seq2','Rapports et documentation','Organisation opérationnelle']::text[], 4),
('ssiap2-q39', 'ssiap2-partie4', 'quiz', 'Comment le SSIAP 2 doit-il gérer une situation de conflit entre deux agents SSIAP 1 de son équipe ?', 'La gestion d''un conflit interpersonnel au sein de l''équipe est une compétence managériale clé du SSIAP 2. La démarche recommandée : entretiens individuels séparés avec chaque partie (sans témoin, pour libérer la parole) ; écoute active et impartiale des deux points de vue ; tentative de médiation (réunion des deux parties, recherche d''un terrain d''entente) ; si le conflit persiste ou affecte le service, escalade au SSIAP 3 ou aux ressources humaines. Un conflit non géré peut dégrader le fonctionnement de l''équipe, créer un risque sécuritaire (agents qui ne se parlent plus en situation d''urgence) et s''aggraver. La mutation immédiate sans démarche préalable peut sembler une sanction injuste pour les deux.', 2, null::integer[], array['theme1','seq1','Management opérationnel de l''équipe SSIAP','Encadrement de l''équipe']::text[], 5),
('ssiap2-q40', 'ssiap2-partie4', 'quiz', 'Qu''est-ce que la gestion prévisionnelle des compétences (GPEC) dans le contexte d''un service SSIAP 2 ?', 'La GPEC dans un service SSIAP consiste à anticiper et planifier les besoins en compétences : suivi des dates d''expiration des certifications SSIAP de chaque agent (recyclage tous les 3 ans) pour planifier les formations MAC avant l''échéance ; suivi des habilitations électriques, des certificats premiers secours (PSC1/PSE1) ; identification des agents en cours d''évolution professionnelle (SSIAP 1 souhaitant devenir SSIAP 2) ; planification des formations spécifiques à l''établissement (nouvelles installations, nouveaux risques). Un SSIAP 2 qui ne surveille pas ces échéances risque de se retrouver avec des agents dont les qualifications sont expirées, ce qui est une non-conformité réglementaire grave.', 1, null::integer[], array['theme5','seq1','Gestion des compétences et formations','Encadrement de l''équipe']::text[], 6),
('ssiap2-q41', 'ssiap2-partie4', 'multiple-select', 'Lors d''un grand événement (concert, conférence internationale) dans votre ERP, quelles mesures supplémentaires le SSIAP 2 doit-il mettre en place ? (plusieurs réponses possibles)', 'Pour un grand événement, le SSIAP 2 adapte son dispositif : renforcement des effectifs proportionnel à l''augmentation du public (en respectant les ratios réglementaires) ; reconnaissance préalable des lieux avec l''organisateur (placement des scènes, câbles, équipements pyrotechniques éventuels, emplacement des loges, configuration du public) ; définition des points de rassemblement adaptés à l''événement et communication au public et au personnel ; briefing complet de l''équipe (effectif attendu, risques spécifiques, contacts organisateurs, procédures d''évacuation adaptées). Interdire les extincteurs pendant l''événement est absurde et dangereux. Une communication écrite (ordre d''opération) formalise le dispositif.', null, array[0,1,2,4]::integer[], array['theme3','seq3','Interface avec les sapeurs-pompiers','Coordination opérationnelle sinistre']::text[], 7),
('ssiap2-q42', 'ssiap2-partie4', 'multiple-select', 'Le SSIAP 2 est responsable de l''élaboration du POI (Plan Opérationnel d''Intervention). Quels éléments essentiels ce document doit-il contenir ? (plusieurs réponses possibles)', 'Le POI (Plan Opérationnel d''Intervention) est le document de référence opérationnel du service SSIAP. Il doit contenir : les procédures d''alerte et d''alarme (schéma décisionnel clair : à partir de quel signal, qui appelle le 18, qui déclenche l''alarme générale) ; les fiches de poste de chaque agent (agent PC, agent terrain, équipier d''intervention) ; les plans du bâtiment annotés (localisation SSI, extincteurs, colonnes sèches, zones de refuge, points de rassemblement) ; les procédures d''évacuation spécifiques (protocole PMR, établissements à sommeil). Le POI doit être tenu à jour, testé lors des exercices, et accessible à tous les agents. Les tarifs commerciaux n''ont pas leur place dans ce document opérationnel.', null, array[0,1,2,4]::integer[], array['theme4','seq2','Rapports et documentation','Organisation opérationnelle']::text[], 8),
('ssiap2-q43', 'ssiap2-partie4', 'quiz', 'Comment le SSIAP 2 doit-il gérer la transition lors d''une prise de service (relève) ?', 'La relève (passation de service) est un moment critique que le SSIAP 2 doit structurer rigoureusement. Elle comprend : une passation de consignes orale couvrant tous les événements du service précédent (alarmes, incidents, interventions), les équipements en défaut ou indisponibles avec les mesures compensatoires en place, les travaux en cours et les zones concernées, les consignes particulières (visiteurs VIP, événements prévus, contacts à prendre) ; une revue du tableau de signalisation (état actuel du SSI) ; une signature conjointe dans la main courante attestant que la relève a bien eu lieu. Cette procédure garantit la continuité de la surveillance et la responsabilité du SSIAP entrant.', 1, null::integer[], array['theme1','seq1','Management opérationnel de l''équipe SSIAP','Encadrement de l''équipe']::text[], 9),
('ssiap2-q44', 'ssiap2-partie4', 'quiz', 'Un agent SSIAP 1 de votre équipe commet une erreur lors d''une intervention (il a déclenché l''alarme générale pour une fausse alarme manifeste sans effectuer de levée de doute). Comment traitez-vous cet incident ?', 'La gestion pédagogique des erreurs est fondamentale dans le management SSIAP : un débriefing structuré permet à l''agent de comprendre son erreur sans être humilié ; l''analyse identifie si l''erreur vient d''un manque de formation, d''une procédure peu claire, d''un stress ponctuel ou d''une négligence caractérisée ; si la procédure du POI est ambiguë, il faut la corriger ; si c''est un manque de compétence, une formation ciblée s''impose ; si c''est une négligence délibérée, une démarche disciplinaire graduée est appropriée. Ignorer l''erreur crée un précédent, la sanctionner sans analyse ne règle pas la cause. Une fausse alarme évitable a des conséquences opérationnelles (mobilisation des secours inutiles, stress des occupants, coût image).', 2, null::integer[], array['theme1','seq1','Management opérationnel de l''équipe SSIAP','Encadrement de l''équipe']::text[], 10),
('ssiap2-q45', 'ssiap2-partie4', 'quiz', 'La durée minimale de formation initiale du SSIAP 2 est de :', 'La formation SSIAP 2 dure 70 heures de formation en centre (théorique et pratique) plus 35 heures de stage en entreprise, soit 105 heures au total. Le SSIAP 2 nécessite également de détenir le SSIAP 1 depuis au moins 1 an. Aucune des propositions (35h, 100h, 200h) ne correspond exactement. Le recyclage MAC SSIAP 2 est de 21 heures tous les 3 ans. La durée de 200h serait celle d''un SSIAP 3 (environ 190h).', 3, null::integer[], array['theme5','seq1','Gestion des compétences et formations','Encadrement de l''équipe']::text[], 11),
('ssiap2-q46', 'ssiap2-partie4', 'quiz', 'Dans quels cas le SSIAP 2 peut-il faire appel à des renforts humains extérieurs à son équipe permanente lors d''un sinistre ou d''un événement exceptionnel ?', 'Le SSIAP 2 peut faire appel à plusieurs ressources complémentaires : les EPI (Équipiers de Première Intervention) sont des salariés de l''établissement formés à l''utilisation des extincteurs et RIA, à l''alerte et aux procédures d''évacuation ; ils constituent une ressource précieuse pour les premières minutes d''intervention avant l''arrivée des pompiers ; ils sont placés sous la coordination du SSIAP 2 lors d''un sinistre. Les ESI (Équipiers de Seconde Intervention) ont une formation plus avancée. Le SSIAP 2 ne peut pas mobiliser du personnel non formé (risque pour ces personnes). La coordination avec ces équipes doit être prévue dans le POI.', 1, null::integer[], array['theme6','seq3','Coordination avec équipiers et secours','Coordination opérationnelle sinistre']::text[], 12),
('ssiap2-q47', 'ssiap2-partie4', 'multiple-select', 'Comment le SSIAP 2 évalue-t-il les performances de son service ? Quels indicateurs peut-il utiliser ? (plusieurs réponses possibles)', 'Les indicateurs de performance d''un service SSIAP incluent : le taux de fausses alarmes (un taux élevé indique des problèmes de détecteurs mal positionnés, mal entretenus, ou du personnel peu sensibilisé) ; le délai de levée de doute (doit être inférieur à 3-5 min selon les POI) ; le taux de conformité des équipements lors des vérifications (extincteurs à recharger, BAES défectueux) ; le taux de présence et ponctualité des agents (absentéisme, retards). Ces indicateurs permettent au SSIAP 2 d''identifier les axes d''amélioration et de justifier des investissements auprès de la direction. Le nombre de visites clients est un indicateur commercial sans lien avec la performance sécurité.', null, array[0,1,3,4]::integer[], array['theme7','seq2','Indicateurs de performance','Organisation opérationnelle']::text[], 13),
('ssiap2-q48', 'ssiap2-partie4', 'multiple-select', 'Lors d''une visite impromptue de la commission de sécurité, comment le SSIAP 2 doit-il réagir ? (plusieurs réponses possibles)', 'Lors d''une visite de la commission de sécurité (qu''elle soit programmée ou impromptue), le SSIAP 2 doit : mettre immédiatement à disposition le registre de sécurité et les derniers rapports de vérification (ces documents doivent toujours être disponibles) ; accompagner la commission dans sa visite et répondre précisément à leurs cc_questions techniques ; signaler proactivement toute non-conformité connue (cacher un problème à la commission peut aggraver les sanctions et engage la responsabilité personnelle). Refuser la visite n''est pas une option légale : la commission a un droit d''accès légal. Prévenir la direction est souhaitable mais ne doit pas retarder l''accueil de la commission.', null, array[0,1,2,4]::integer[], array['theme4','seq2','Rapports et documentation','Organisation opérationnelle']::text[], 14),
('ssiap2-q58', 'ssiap2-partie4', 'multiple-select', 'Le SSIAP 2 doit s''assurer que son équipe est en mesure de gérer une situation de multi-sinistres simultanés. Comment peut-il préparer son équipe à cette situation ? (plusieurs réponses possibles)', 'La gestion de multi-sinistres (plusieurs alarmes simultanées, sinistre + évacuation difficile, sinistre + urgence médicale) nécessite une préparation spécifique : exercices et simulations de scénarios complexes (les pompiers et le SSIAP 2 pratiquent ces exercices de mise en situation) ; hiérarchie claire des priorités dans le POI (la vie humaine prime toujours sur la protection des biens, une zone non surveillée peut être acceptable pour sauver des vies) ; formation à la décision sous stress (techniques de communication en crise, gestion cognitive de la surcharge) ; procédures de renfort clairement définies (qui appeler, quand, comment). Les exercices difficiles renforcent la confiance et l''efficacité en situation réelle.', null, array[0,1,2,3]::integer[], array['theme3','seq3','Interface avec les sapeurs-pompiers','Coordination opérationnelle sinistre']::text[], 15),
('ssiap2-q59', 'ssiap2-partie4', 'quiz', 'Quel est le rôle du SSIAP 2 dans la communication de crise lors d''un sinistre majeur ?', 'Dans la gestion de crise, les rôles en communication sont bien définis : le SSIAP 2 assure la communication opérationnelle interne (coordonner son équipe par radio, communiquer avec le PC sécurité, transmettre les informations au COS des pompiers) et participe à la remontée d''informations vers la direction. La communication externe (avec les médias, le public, les familles) relève de la direction de l''établissement ou d''un porte-parole désigné. Le SSIAP 2 ne doit jamais s''improviser porte-parole auprès des médias : il risque de communiquer des informations prématurées, inexactes ou confidentielles. En revanche, il doit être capable de rédiger un rapport factuel précis pour alimenter la communication de la direction.', 1, null::integer[], array['theme3','seq3','Interface avec les sapeurs-pompiers','Coordination opérationnelle sinistre']::text[], 16),
('ssiap2-q60', 'ssiap2-partie4', 'multiple-select', 'Comment le SSIAP 2 assure-t-il le retour d''expérience (REX) après un incident ou un exercice ? (plusieurs réponses possibles)', 'Le retour d''expérience (REX) est une démarche d''amélioration continue fondamentale dans la gestion de la sécurité : débriefing collectif rapide (pendant que les mémoires sont fraîches, dans un climat bienveillant non punitif pour favoriser l''expression) ; analyse structurée des points positifs et des dysfonctionnements (chronologie des événements, décisions prises, résultats obtenus) ; actions correctives SMART (Spécifiques, Mesurables, Atteignables, Réalistes, Temporellement définies) et suivi de leur mise en œuvre ; rapport formel dans le registre de sécurité. La sanction comme seule réponse à une erreur est contre-productive : elle empêche les agents de signaler leurs erreurs futures par peur, dégradant la culture de sécurité. Un environnement REX de qualité améliore la performance à long terme.', null, array[0,1,2,3]::integer[], array['theme7','seq2','Indicateurs de performance','Organisation opérationnelle']::text[], 17),
('ssiap2-q61', 'ssiap2-partie4', 'quiz', 'Qu''est-ce que la ''sécurité comportementale'' et pourquoi est-elle importante dans la gestion d''un service SSIAP ?', 'La sécurité comportementale (ou BBS - Behavior-Based Safety) est une approche qui reconnaît que la majorité des accidents et incidents résultent de comportements humains (agents et occupants) et non uniquement de défaillances techniques. Dans le contexte SSIAP : comportements des occupants (non-respect des consignes, propping des portes CF, utilisation des escaliers de secours comme zone de pause) ; comportements des agents (raccourcis dans les procédures, sous-déclaration des anomalies). Le SSIAP 2 utilise cette approche pour : adapter les formations aux comportements réels observés ; modifier les procédures si elles génèrent des contournements systématiques ; créer une culture de sécurité positive basée sur la responsabilisation plutôt que la sanction.', 1, null::integer[], array['theme1','seq1','Management opérationnel de l''équipe SSIAP','Encadrement de l''équipe']::text[], 18),
('ssiap2-q62', 'ssiap2-partie4', 'quiz', 'Le Code du travail impose une durée minimale de repos quotidien entre deux postes de travail de :', 'Le Code du travail français impose une durée minimale de repos quotidien de 11 heures consécutives entre la fin d''un poste et le début du suivant (article L.3131-1). Cette règle s''applique à tous les salariés, y compris les agents SSIAP. Aucune des propositions (8h, 10h, 14h) n''est correcte. Des dérogations existent pour certains secteurs sous conditions. Le SSIAP 2 doit en tenir compte lors de l''élaboration des plannings pour ne pas exposer l''employeur à des risques juridiques et maintenir la vigilance de ses agents.', 3, null::integer[], array['theme1','seq1','Management opérationnel de l''équipe SSIAP','Encadrement de l''équipe']::text[], 19)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap2-q34','ssiap2-q35','ssiap2-q36','ssiap2-q37','ssiap2-q38','ssiap2-q39','ssiap2-q40','ssiap2-q41','ssiap2-q42','ssiap2-q43','ssiap2-q44','ssiap2-q45','ssiap2-q46','ssiap2-q47','ssiap2-q48','ssiap2-q58','ssiap2-q59','ssiap2-q60','ssiap2-q61','ssiap2-q62');
commit;

-- ===== ssiap2-partie4-sub02.sql =====
begin;
-- SSIAP 2 — Management et organisation (partie 4, sub 2/4, 20 cc_questions)
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap2-q63', 'ssiap2-partie4', 'multiple-select', 'Le SSIAP 2 souhaite améliorer les procédures d''évacuation des PMR dans son établissement. Quelles actions peut-il entreprendre ? (plusieurs réponses possibles)', 'Pour améliorer la prise en charge des PMR lors d''une évacuation, le SSIAP 2 peut : établir un registre des PMR permanentes ou habituelles de l''établissement (avec leurs localisations habituelles et besoins spécifiques) ; s''assurer que les EAS (Espaces d''Attente Sécurisés, anciennement zones de refuge) sont équipés et fonctionnels (interphones opérationnels) ; former les agents aux techniques d''assistance à l''évacuation (utilisation des fauteuils d''évacuation, techniques de portage sécurisées pour descendre les escaliers) ; intégrer des PMR réelles ou simulées dans les exercices d''évacuation pour tester les procédures. Il est formellement interdit de laisser les PMR isolées sans assistance lors d''une évacuation.', null, array[0,1,2,4]::integer[], array['theme6','seq3','Coordination avec équipiers et secours','Coordination opérationnelle sinistre']::text[], 20),
('ssiap2-q64', 'ssiap2-partie4', 'quiz', 'Quelle est la différence entre un ''ordre d''opération'' et un POI dans la gestion d''un événement ou d''une manifestation dans un ERP ?', 'Ces deux documents ont des portées différentes mais complémentaires : le POI (Plan Opérationnel d''Intervention) est le document permanent de référence de l''établissement, décrivant les procédures standard pour tout type de sinistre dans la configuration habituelle du bâtiment ; l''Ordre d''Opération est un document préparé pour un événement spécifique (concert, salon, conférence) précisant les dispositions adaptées à cet événement : effectifs renforcés, répartition des postes, contacts spécifiques, risques particuliers liés à l''événement (pyrotechnie, grande affluence, invités VIP avec protection rapprochée). L''ordre d''opération complète le POI sans le remplacer. Il est rédigé par le SSIAP 2 ou le SSIAP 3 en coordination avec l''organisateur.', 1, null::integer[], array['theme4','seq2','Rapports et documentation','Organisation opérationnelle']::text[], 21),
('ssiap2-q65', 'ssiap2-partie4', 'quiz', 'Comment le SSIAP 2 intègre-t-il les risques cyber dans la sécurité incendie de son établissement ?', 'Les systèmes de sécurité incendie modernes sont de plus en plus connectés (SSI en réseau, GTC/GTB, systèmes d''accès contrôlés). Une cyberattaque ciblant ces systèmes peut : désactiver des alarmes à distance ; prendre le contrôle de DAS (ouvrir/fermer des portes CF, inhiber des exutoires) ; neutraliser la supervision du PC sécurité. Le SSIAP 2 doit collaborer avec la DSI (Direction des Systèmes d''Information) pour s''assurer de l''existence de procédures de fonctionnement en mode dégradé (fonctionnement sans réseau informatique) et de la sauvegarde des configurations. Les SSI réglementaires doivent rester fonctionnels indépendamment des systèmes informatiques. La sécurité numérique des équipements connectés est un enjeu croissant.', 1, null::integer[], array['theme4','seq2','Rapports et documentation','Organisation opérationnelle']::text[], 22),
('ssiap2-q66', 'ssiap2-partie4', 'multiple-select', 'Le SSIAP 2 doit assurer la continuité du service lors des périodes de faible effectif (nuits, week-ends). Quelles dispositions peut-il prendre ? (plusieurs réponses possibles)', 'La gestion des périodes de faible effectif nécessite une organisation adaptée : un protocole de service réduit clair (quelles procédures en cas d''alarme avec 1 ou 2 agents seulement, comment gérer simultanément la surveillance du PC et la levée de doute) ; une augmentation de la fréquence des rondes pour compenser la réduction de la présence physique ; l''activation éventuelle d''une télésurveillance avec astreinte d''un prestataire ou du SSIAP 2 ; un briefing spécifique des agents de nuit sur les particularités du service réduit (contacts d''urgence, procédures spécifiques). La fermeture systématique n''est pas une option pour les établissements à sommeil ou en exploitation 24/7. Ces dispositions doivent être validées par la commission de sécurité pour les ERP importants.', null, array[0,1,2,4]::integer[], array['theme2','seq2','Planification des rondes et surveillance','Organisation opérationnelle']::text[], 23),
('ssiap2-q77', 'ssiap2-partie4', 'multiple-select', 'Comment le SSIAP 2 gère-t-il l''intégration d''un nouvel agent SSIAP 1 dans l''équipe ? (plusieurs réponses possibles)', 'L''intégration d''un nouvel agent est une étape cruciale pour la qualité et la sécurité du service : visite du bâtiment (le nouvel agent doit connaître parfaitement les lieux avant toute prise de poste autonome) ; formation sur le POI spécifique à l''établissement (les procédures générales SSIAP ne suffisent pas, chaque établissement a ses particularités) ; remise des documents de référence (plans annotés, fiches de poste, numéros d''urgence, procédures spécifiques) ; accompagnement par un agent expérimenté pendant une période probatoire (compagnonnage) permettant d''observer les bonnes pratiques et de poser des cc_questions. Un agent mis seul dès le premier jour représente un risque pour lui-même et pour la sécurité de l''établissement.', null, array[0,1,3,4]::integer[], array['theme5','seq1','Gestion des compétences et formations','Encadrement de l''équipe']::text[], 24),
('ssiap2-q78', 'ssiap2-partie4', 'multiple-select', 'Le SSIAP 2 doit animer une réunion de service mensuelle avec son équipe. Quel est le contenu idéal de cette réunion ? (plusieurs réponses possibles)', 'Une réunion de service mensuelle efficace inclut : bilan des incidents et événements (alarmes, interventions, anomalies détectées) pour maintenir une mémoire collective et identifier des tendances ; rappels ou annonces de changements (modifications du POI, nouvelles procédures, travaux impactant la sécurité, visites de commission à venir) ; débriefing des exercices réalisés avec identification des points d''amélioration ; suivi des formations et qualifications (qui passe son recyclage SSIAP, qui renouvelle son PSE1, habilitation électrique expirée). Les cc_questions personnelles et privées des agents n''ont pas leur place dans une réunion de service (elles sont traitées lors d''entretiens individuels). Ces réunions renforcent la cohésion et la culture sécurité de l''équipe.', null, array[0,1,2,4]::integer[], array['theme1','seq1','Management opérationnel de l''équipe SSIAP','Encadrement de l''équipe']::text[], 25),
('ssiap2-q79', 'ssiap2-partie4', 'quiz', 'Dans le cadre de la gestion de la fatigue des agents (gardes de nuit, longues périodes), quelles sont les obligations du SSIAP 2 ?', 'La fatigue est un facteur de risque majeur dans les métiers de la sécurité : une vigilance réduite peut conduire à des erreurs d''interprétation, des retards de réaction ou des omissions lors des rondes. Le SSIAP 2 a des obligations : respecter strictement les durées légales de repos (11h entre deux postes, repos hebdomadaire) ; détecter les signes de fatigue chez ses agents (bâillements excessifs, erreurs répétées, lenteur de réaction, irritabilité) ; adapter les plannings en cas de fatigue visible ; ne jamais laisser un agent manifestement épuisé seul sur un poste critique (PC de nuit). La responsabilité partagée entre le SSIAP 2 (organisation) et l''agent (hygiène de vie) est réelle, mais le SSIAP 2 a un devoir de vigilance.', 1, null::integer[], array['theme1','seq1','Management opérationnel de l''équipe SSIAP','Encadrement de l''équipe']::text[], 26),
('ssiap2-q80', 'ssiap2-partie4', 'quiz', 'Le SSIAP 2 reçoit une plainte d''un occupant de l''ERP qui affirme qu''un agent SSIAP a eu un comportement déplacé à son égard. Quelle est sa démarche ?', 'La gestion d''une plainte contre un agent est une situation délicate nécessitant professionnalisme et impartialité : écouter l''occupant plaignant avec attention et bienveillance, recueillir les faits précis (date, heure, lieu, nature des actes reprochés, témoins éventuels) sans prendre parti a priori ; mener une investigation équitable en entendant l''agent mis en cause (droit à la défense) et en consultant les éventuels témoins ; rédiger un rapport factuel objectif consignant les éléments recueillis ; transmettre le rapport à la hiérarchie (SSIAP 3 ou direction) pour la décision finale. Le SSIAP 2 ne prend pas seul la décision disciplinaire mais est responsable de l''instruction des faits. La discrétion est impérative pour protéger toutes les parties.', 1, null::integer[], array['theme1','seq1','Management opérationnel de l''équipe SSIAP','Encadrement de l''équipe']::text[], 27),
('ssiap2-q81', 'ssiap2-partie4', 'quiz', 'Le taux légal de personnel travaillant de nuit dans un service SSIAP est limité à :', 'Il n''existe pas de taux légal spécifique limitant le pourcentage du personnel travaillant de nuit dans les services SSIAP. La réglementation sur le travail de nuit (code du travail L.3122-1 et suivants) définit les conditions et contreparties du travail nocturne (suivi médical renforcé, majoration de salaire, limitation de la durée du travail de nuit), mais ne fixe pas de quota. Les contraintes portent sur les individus (durée maximale de travail de nuit par jour/semaine/an) et non sur des pourcentages d''équipe. Aucune des propositions n''est donc correcte.', 1, null::integer[], array['theme1','seq1','Management opérationnel de l''équipe SSIAP','Encadrement de l''équipe']::text[], 28),
('ssiap2-q82', 'ssiap2-partie4', 'multiple-select', 'Comment le SSIAP 2 prépare-t-il une formation incendie pratique (maniement d''extincteurs sur feu réel) pour le personnel de l''établissement ? (plusieurs réponses possibles)', 'Une formation incendie pratique sur feux réels doit être soigneusement organisée : choisir un lieu approprié (espace extérieur ouvert, éloigné de tout bâtiment, véhicule, végétation combustible, avec sol non combustible) ; préparer le matériel (extincteurs en nombre suffisant pour chaque participant, bac à feu ou feu de poubelle contrôlé, eau pour extinction complète après exercice) ; informer préalablement les pompiers locaux (SDIS) pour éviter une intervention inutile et parfois obtenir leur participation ou conseils ; réaliser d''abord une démonstration par le formateur avant de faire pratiquer les stagiaires. Un exercice uniquement théorique en salle ne prépare pas aux réflexes et à la gestion du stress face à un feu réel. Certains établissements font appel à des prestataires spécialisés pour ces formations.', null, array[0,1,2,3]::integer[], array['theme5','seq1','Encadrement de l''équipe']::text[], 29),
('ssiap2-q83', 'ssiap2-partie4', 'quiz', 'La transmission de savoir-faire entre un SSIAP 2 expérimenté et un SSIAP 1 en progression s''appelle :', 'Le compagnonnage (ou tutorat professionnel) est la transmission de savoir-faire et d''expérience professionnelle entre un professionnel expérimenté (tuteur/maître de stage) et un professionnel en développement. Dans le contexte SSIAP, cela implique qu''un SSIAP 2 accompagne un SSIAP 1 souhaitant évoluer vers le niveau 2 en lui montrant les aspects opérationnels du métier (gestion du PC, coordination d''équipe, lecture du SSI, interface avec les pompiers) que la formation initiale ne peut pas entièrement couvrir. Le compagnonnage complète avantageusement la formation théorique. La formation initiale et le recyclage MAC sont des formations formelles. Le télétravail n''est évidemment pas applicable au SSIAP.', 1, null::integer[], array['theme5','seq1','Gestion des compétences et formations','Encadrement de l''équipe']::text[], 30),
('ssiap2-q84', 'ssiap2-partie4', 'multiple-select', 'Un SSIAP 2 fraîchement nommé prend la direction d''une équipe dans un nouvel établissement. Quelles sont ses priorités dans les premières semaines ? (plusieurs réponses possibles)', 'Un SSIAP 2 qui prend un nouveau poste doit prioriser la découverte avant la transformation : visite approfondie du bâtiment avec étude des plans, essais des équipements et identification de toutes les spécificités techniques ; lecture attentive du POI, des procédures existantes et des derniers rapports (incidents, vérifications) pour comprendre l''état des lieux avant de proposer des améliorations ; rencontre individuelle de chaque agent pour évaluer les compétences, comprendre la culture de l''équipe et établir une relation de confiance ; prise de contact avec le SDIS local (visite possible, échange sur les procédures d''intervention, communication des plans). Modifier brutalement toutes les procédures sans comprendre d''abord le contexte est contre-productif et peut générer des résistances et des erreurs.', null, array[0,1,2,4]::integer[], array['theme1','seq1','Management opérationnel de l''équipe SSIAP','Encadrement de l''équipe']::text[], 31),
('ssiap2-q85', 'ssiap2-partie4', 'quiz', 'Qu''est-ce que le ''tableau de bord de sécurité'' qu''un SSIAP 2 peut présenter à la direction de l''établissement ?', 'Un tableau de bord de sécurité est un outil de management permettant de piloter le service SSIAP et de rendre compte à la direction. Il synthétise les indicateurs clés sur une période : nombre et types d''alarmes (vraies alarmes vs fausses alarmes), incidents et interventions, taux de conformité des équipements (lors des vérifications mensuelles), formations réalisées vs prévues, qualifications expirées ou à renouveler, anomalies signalées et leur état de résolution. Ce document facilite la communication avec la direction (qui obtient une vision synthétique de l''état de la sécurité) et justifie les demandes d''investissement (remplacement d''équipements, formations). C''est aussi une preuve de professionnalisme et de rigueur du service SSIAP.', 1, null::integer[], array['theme7','seq2','Indicateurs de performance','Organisation opérationnelle']::text[], 32),
('ssiap2-q86', 'ssiap2-partie4', 'quiz', 'La formation de ''Sauveteur Secouriste du Travail'' (SST) est-elle obligatoire pour un agent SSIAP 2 ?', 'L''arrêté du 2 mai 2005 impose aux agents SSIAP 2 de posséder un certificat de formation aux premiers secours (PSC1 niveau 1 minimum, ou PSE1 recommandé). La formation SST (Sauveteur Secouriste du Travail) est un référentiel différent, orienté vers les accidents du travail dans l''entreprise. Elle n''est pas obligatoire pour le diplôme SSIAP 2 mais constitue un complément très utile. Certains employeurs l''exigent en plus du PSE1. Le PSE2 (équivalent à l''Auxiliaire Ambulancier) est très apprécié pour les agents SSIAP en établissements de soins.', 1, null::integer[], array['theme5','seq1','Gestion des compétences et formations','Encadrement de l''équipe']::text[], 33),
('ssiap2-q87', 'ssiap2-partie4', 'multiple-select', 'Lors d''un incendie, le SSIAP 2 décide de procéder à une évacuation partielle d''un seul niveau. Sur quels critères prend-il cette décision ? (plusieurs réponses possibles)', 'L''évacuation partielle est une décision opérationnelle qui ne peut être prise que si plusieurs critères sont réunis : le sinistre est clairement localisé et ne menace pas encore les autres zones (risque de propagation évalué comme faible à court terme) ; le POI de l''établissement prévoit explicitement cette possibilité (notamment dans les établissements à sommeil ou de soins) ; les voies d''évacuation des niveaux non concernés restent disponibles et sûres (non envahies par les fumées) ; dans les établissements de soins, l''impossibilité de déplacer certains patients justifie une évacuation horizontale progressive. La consultation téléphonique des pompiers ne suffit pas car elle se base sur des informations incomplètes. L''évacuation totale reste la décision par défaut si ces conditions ne sont pas réunies.', null, array[0,1,2,4]::integer[], array['theme3','seq3','Interface avec les sapeurs-pompiers','Coordination opérationnelle sinistre']::text[], 34),
('ssiap2-q89', 'ssiap2-partie4', 'quiz', 'Comment le SSIAP 2 s''assure-t-il que le plan de prévention avec une entreprise extérieure est bien respecté sur le terrain ?', 'Signer un plan de prévention n''est que la première étape : son efficacité dépend de son application sur le terrain. Le SSIAP 2 doit réaliser des contrôles terrain réguliers (au moins une fois par jour de travaux) pour vérifier : que les mesures de prévention prévues sont effectivement mises en œuvre (port des EPI, respect des zones d''exclusion, présence des extincteurs requis) ; que les permis de feu sont signés et disponibles sur place ; que la surveillance post-travaux est assurée. Toute anomalie constatée est signalée immédiatement au responsable de l''entreprise extérieure, consignée dans la main courante et peut justifier l''arrêt des travaux. Déléguer entièrement sans contrôle engage la responsabilité de l''exploitant.', 1, null::integer[], array['theme4','seq2','Rapports et documentation','Organisation opérationnelle']::text[], 35),
('ssiap2-q91', 'ssiap2-partie4', 'quiz', 'Dans un ERP avec présence d''œuvres d''art ou de collections précieuses (musée, galerie), quelles précautions spécifiques le SSIAP 2 doit-il prendre ?', 'La protection des musées et galeries d''art impose une approche spécifique : les systèmes d''extinction doivent être compatibles avec la préservation des œuvres (les systèmes à eau pulvérisée ou mousse abîment irrémédiablement les tableaux, sculptures, documents) ; des systèmes à gaz inertes (argonite, inergen, CO2 dans les zones sans personnel) sont préférés pour les zones de stockage et les réserves ; le POI doit inclure des procédures de sauvegarde des œuvres (ordre de priorité d''évacuation des pièces maîtresses, contacts des équipes de conservation) ; les agents SSIAP doivent être sensibilisés à ne pas endommager les œuvres lors des interventions. Ces établissements nécessitent une concertation étroite entre le SSIAP 2, les conservateurs et les assureurs.', 1, null::integer[], array['theme6','seq3','Coordination avec équipiers et secours','Coordination opérationnelle sinistre']::text[], 36),
('ssiap2-q92', 'ssiap2-partie4', 'multiple-select', 'Le SSIAP 2 est informé qu''un système de reconnaissance faciale va être installé à l''entrée de l''ERP. Quels points de sécurité incendie doit-il vérifier ? (plusieurs réponses possibles)', 'L''installation d''un système de contrôle biométrique en entrée d''ERP soulève plusieurs enjeux sécurité incendie que le SSIAP 2 doit anticiper : les portiques ou équipements ne doivent pas réduire la largeur des dégagements en dessous des seuils réglementaires (ni bloquer les portes) ; en cas d''alarme incendie, le système doit basculer en mode ''libre passage'' pour que toutes les personnes puissent sortir sans délai (y compris sans être reconnues, car lors d''une évacuation les gens peuvent avoir des masques, des enfants dans les bras, etc.) ; les procédures d''évacuation doivent être mises à jour pour inclure la gestion de ce nouveau système. Il n''y a pas d''incompatibilité intrinsèque avec la sécurité incendie si ces points sont correctement traités.', null, array[0,1,2,4]::integer[], array['theme4','seq2','Rapports et documentation','Organisation opérationnelle']::text[], 37),
('ssiap2-q93', 'ssiap2-partie4', 'quiz', 'Quelle est la principale différence entre le rôle du SSIAP 2 chef d''équipe et du SSIAP 3 chef de service ?', 'Les deux qualifications ont des responsabilités distinctes et complémentaires : le SSIAP 2 est le chef d''équipe opérationnel : il encadre directement les agents SSIAP 1, organise les rondes et les postes, assure les relèves, gère les incidents au quotidien et est le premier niveau de commandement sur le terrain lors d''un sinistre. Le SSIAP 3 est le chef de service : il assure la relation stratégique avec la direction de l''établissement, conçoit et met à jour le POI et les procédures, représente le service lors des visites de commission, gère les budgets et les ressources humaines à un niveau supérieur, et est responsable de la conformité réglementaire globale. Le SSIAP 3 ne remplace pas le SSIAP 2 mais pilote le service à un niveau plus stratégique.', 1, null::integer[], array['theme1','seq1','Management opérationnel de l''équipe SSIAP','Encadrement de l''équipe']::text[], 38),
('ssiap2-q94', 'ssiap2-partie4', 'multiple-select', 'Dans le cadre du bien-être au travail des agents SSIAP, quels risques psychosociaux (RPS) le SSIAP 2 doit-il surveiller ? (plusieurs réponses possibles)', 'Les agents SSIAP sont exposés à plusieurs facteurs de risques psychosociaux que le SSIAP 2 doit identifier et prévenir : le stress des gardes de nuit (perturbation du rythme circadien, vigilance dans l''isolement nocturne) ; la charge émotionnelle des interventions (secours à des victimes, décès, blessures graves) pouvant conduire à un trauma ou burn-out ; l''isolement du travail de nuit solitaire (absence de collègues, relation minimum avec les autres salariés) ; les agressions du public (verbal ou physique) générateurs d''anxiété ; la faible reconnaissance sociale du métier. Le SSIAP 2 doit être attentif à ces facteurs, faciliter l''expression des agents, organiser des débriefings après les interventions difficiles et orienter vers les ressources d''aide psychologique si nécessaire (médecine du travail, psychologue).', null, array[0,1,2,3,4]::integer[], array['theme1','seq1','Management opérationnel de l''équipe SSIAP','Encadrement de l''équipe']::text[], 39)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap2-q63','ssiap2-q64','ssiap2-q65','ssiap2-q66','ssiap2-q77','ssiap2-q78','ssiap2-q79','ssiap2-q80','ssiap2-q81','ssiap2-q82','ssiap2-q83','ssiap2-q84','ssiap2-q85','ssiap2-q86','ssiap2-q87','ssiap2-q89','ssiap2-q91','ssiap2-q92','ssiap2-q93','ssiap2-q94');
commit;

-- ===== ssiap2-partie4-sub03.sql =====
begin;
-- SSIAP 2 — Management et organisation (partie 4, sub 3/4, 20 cc_questions)
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap2-q95', 'ssiap2-partie4', 'multiple-select', 'Le SSIAP 2 est sollicité pour rédiger le cahier des charges d''une prestation de vérification annuelle du SSI. Quels éléments doit-il y inclure ? (plusieurs réponses possibles)', 'Un cahier des charges de vérification annuelle du SSI doit préciser : la liste exhaustive de tous les équipements à vérifier (nombre de détecteurs par zone, liste des DAS, centrale, AES, répétiteurs) pour que le devis soit complet et comparable ; les référentiels applicables (NF S 61-933 pour la maintenance, APSAD Q18 pour la qualification) définissant les opérations minimales obligatoires ; les délais d''intervention pour les anomalies (délai de transmission du rapport, délai d''intervention pour les défauts critiques vs mineurs) ; la qualification requise du technicien et de son entreprise (certification, assurance). Le prix maximum n''appartient pas au cahier des charges technique (il appartient au cahier des clauses financières) et le mettre pourrait biaiser les offres.', null, array[0,1,2,3]::integer[], array['theme4','seq2','Rapports et documentation','Organisation opérationnelle']::text[], 40),
('ssiap2-q117', 'ssiap2-partie4', 'quiz', 'Quelles sont les missions prioritaires du PC sécurité lors d''une situation d''urgence ?', 'En situation d''urgence, le PC sécurité est le centre névralgique. Ses missions sont : recevoir et analyser les informations (alarmes, remontées terrain), coordonner l''équipe de sécurité, alerter les secours extérieurs, commander l''évacuation, accueillir et guider les pompiers, maintenir la communication avec la direction, consigner tous les événements.', 1, null::integer[], array['theme1','sequence1']::text[], 41),
('ssiap2-q118', 'ssiap2-partie4', 'quiz', 'Qu''est-ce que la main courante informatisée en PC sécurité ?', 'La main courante informatisée enregistre chronologiquement tous les événements avec horodatage automatique : alarmes, rondes, incidents, contacts. Elle facilite les recherches ultérieures, génère des statistiques, et constitue une preuve fiable en cas de litige. Elle doit être sécurisée pour éviter toute modification a posteriori.', 1, null::integer[], array['theme2','sequence1']::text[], 42),
('ssiap2-q119', 'ssiap2-partie4', 'quiz', 'Lors de l''accueil des sapeurs-pompiers, quelles informations le SSIAP 2 doit-il leur transmettre en priorité ?', 'À l''arrivée des pompiers, le SSIAP 2 transmet en priorité : nature et localisation précise du sinistre, nombre et localisation des victimes éventuelles, risques particuliers (produits dangereux, personnes confinées), état des DAS (portes fermées, désenfumage activé), accès pompiers, actions déjà entreprises. Cette information rapide est cruciale pour l''efficacité de leur intervention.', 1, null::integer[], array['theme1','sequence2']::text[], 43),
('ssiap2-q120', 'ssiap2-partie4', 'quiz', 'Qu''est-ce que le Plan d''Organisation de la Réponse de SEcurité Civile (ORSEC) ?', 'ORSEC est le plan gouvernemental de gestion des situations d''urgence de grande ampleur (catastrophes naturelles, accidents technologiques majeurs). Il est déclenché par le préfet. Le SSIAP 2 doit connaître son existence pour comprendre l''articulation entre les procédures internes de l''établissement et l''organisation générale des secours.', 1, null::integer[], array['theme1','sequence3']::text[], 44),
('ssiap2-q121', 'ssiap2-partie4', 'quiz', 'Qu''est-ce qu''un exercice de crise dans un établissement et quel est le rôle du SSIAP 2 ?', 'L''exercice de crise (POI exercice, exercice d''évacuation) est une simulation réaliste pour tester les procédures d''urgence. Le SSIAP 2 y joue un rôle clé : préparer le scénario, briefer l''équipe, coordonner l''exercice, observer les réactions, et réaliser le débriefing pour identifier les points d''amélioration. Les résultats sont consignés dans le registre.', 1, null::integer[], array['theme2','sequence3']::text[], 45),
('ssiap2-q122', 'ssiap2-partie4', 'quiz', 'Comment le SSIAP 2 gère-t-il la communication avec les médias lors d''un incident ?', 'La communication de crise externe est toujours gérée par la direction ou le service communication de l''entreprise. Le SSIAP 2 ne doit jamais s''exprimer avec les médias (risque de divulgation d''informations sensibles, de contredire la communication officielle). Il doit systématiquement orienter les journalistes vers le porte-parole désigné.', 1, null::integer[], array['theme3','sequence2']::text[], 46),
('ssiap2-q123', 'ssiap2-partie4', 'quiz', 'Qu''est-ce que la gestion des flux de personnes lors d''une évacuation, et comment le SSIAP 2 l''organise-t-il ?', 'Une évacuation efficace nécessite une gestion active des flux : le SSIAP 2 coordonne les guides-files et serre-files, dirige les personnes vers les issues les moins encombrées, gère les points de congestion, s''assure de la prise en charge des PMR et personnes vulnérables, et maintient la communication radio avec son équipe et le PC sécurité.', 1, null::integer[], array['theme2','sequence2']::text[], 47),
('ssiap2-q124', 'ssiap2-partie4', 'quiz', 'Qu''est-ce que le plan particulier d''évacuation dans un ERP multi-sites ou complexe ?', 'Le plan particulier d''évacuation adapte les procédures générales aux spécificités du site : localisation des points de rassemblement, itinéraires d''évacuation selon les zones, rôles des acteurs (guide-file, serre-file, chargé d''évacuation des EAS), procédures pour les visiteurs, prise en charge des PMR. Il est régulièrement mis à jour et testé lors des exercices.', 1, null::integer[], array['theme3','sequence3']::text[], 48),
('ssiap2-q136', 'ssiap2-partie4', 'quiz', 'Comment le SSIAP 2 prépare-t-il le PC sécurité pour accueillir les pompiers lors de leur arrivée ?', 'La préparation du PC sécurité pour l''accueil pompiers comprend : extraction des plans du bâtiment (niveaux avec localisation des équipements), identification des zones en alarme sur le tableau, synthèse des informations (sinistre, victimes, mesures déjà prises), désignation d''un agent à l''entrée du site pour guider les véhicules, et maintien d''une ligne téléphonique disponible.', 1, null::integer[], array['theme3','sequence1']::text[], 49),
('ssiap2-q137', 'ssiap2-partie4', 'quiz', 'Qu''est-ce que la gestion post-sinistre et quel est le rôle du SSIAP 2 ?', 'La gestion post-sinistre implique : la sécurisation immédiate de la zone (interdiction d''accès, signalisation), l''évaluation des dommages sur les équipements de sécurité, le maintien d''une surveillance renforcée, la contribution au rapport d''incident détaillé, l''accompagnement des experts et assureurs, et la participation à la remise en conformité du SSI avec le mainteneur.', 1, null::integer[], array['theme2','sequence2']::text[], 50),
('ssiap2-q138', 'ssiap2-partie4', 'quiz', 'Quelles informations le SSIAP 2 doit-il recueillir lors d''un incident impliquant des matières dangereuses ?', 'En présence de matières dangereuses, le SSIAP 2 doit collecter sans s''exposer : identification du produit (code ONU, étiquettes de risque), quantités estimées, localisation précise, état du contenant (intact, endommagé, fuite), conditions de l''incident. Ces informations sont transmises aux pompiers qui ont des équipements et formations spécifiques pour ces interventions (NRBC).', 1, null::integer[], array['theme1','sequence2']::text[], 51),
('ssiap2-q139', 'ssiap2-partie4', 'quiz', 'Comment le SSIAP 2 gère-t-il l''alerte au PC sécurité face à une menace à la bombe ou un colis suspect ?', 'Protocole colis suspect : NE PAS TOUCHER, ne pas utiliser les radios ou téléphones mobiles à proximité (risque de déclenchement), alerter direction et police (17), décider de l''évacuation ou confinement selon les consignes préfectorales, maintenir l''accès libre pour les services de déminage, et consigner tous les événements dans la main courante.', 1, null::integer[], array['theme2','sequence1']::text[], 52),
('ssiap2-q140', 'ssiap2-partie4', 'quiz', 'Qu''est-ce que le Plan de Mise en Sécurité (PMS) d''un établissement ?', 'Le PMS définit l''organisation à mettre en place lors d''un sinistre : qui décide de l''évacuation, qui alerte les secours, qui gère les EAS, qui accueille les pompiers, qui prend en charge les PMR. Il décrit les procédures pour chaque type d''incident (incendie, inondation, attentat) et les rôles précis de chaque acteur du service de sécurité.', 1, null::integer[], array['theme1','sequence3']::text[], 53),
('ssiap2-q141', 'ssiap2-partie4', 'quiz', 'Lors d''un exercice d''évacuation, quels éléments le SSIAP 2 doit-il évaluer ?', 'L''évaluation d''un exercice d''évacuation par le SSIAP 2 comprend : chronomètre du début à l''appel nominal au point de rassemblement, observation du comportement des occupants (panique, retours en arrière, utilisation portable), efficacité des guide/serre-files, prise en charge des PMR aux EAS, communication radio PC↔terrain, et identification de tous les dysfonctionnements pour amélioration.', 1, null::integer[], array['theme2','sequence3']::text[], 54),
('ssiap2-q184', 'ssiap2-partie4', 'multiple-select', 'Le SSIAP 2 doit organiser un exercice d''évacuation pour un ERP de 800 personnes. Quelles sont les étapes préparatoires indispensables ? (plusieurs réponses possibles)', 'La préparation d''un exercice d''évacuation efficace comprend : définition du scénario (type de sinistre simulé, zone de départ, heure choisie pour tester différentes configurations de présence) en gardant l''heure confidentielle pour les occupants (mais pas pour tous les agents SSIAP) ; briefing des guides-files et serre-files qui ont un rôle actif dans l''orientation et la fermeture des portes ; définition préalable des critères d''évaluation (pour pouvoir analyser objectivement l''exercice : temps d''évacuation, comportement aux issues, comptage au point de rassemblement) ; information préalable des pompiers locaux (pour éviter leur mobilisation sur une fausse alarme lors du déclenchement de l''alarme) et le cas échéant de la police ou du SAMU si l''exercice est complexe. La météo est un facteur à anticiper mais un ''plan de repli si l''exercice se déroule mal'' n''est pas une étape préparatoire standard.', null, array[0,1,2,3]::integer[], array['theme3','seq3','Interface avec les sapeurs-pompiers','Coordination opérationnelle sinistre']::text[], 55),
('ssiap2-q185', 'ssiap2-partie4', 'multiple-select', 'Comment le SSIAP 2 rédige-t-il un compte-rendu d''exercice d''évacuation utile et exploitable ? (plusieurs réponses possibles)', 'Un compte-rendu d''exercice d''évacuation utile doit contenir : la chronologie précise (heure de déclenchement de l''alarme, heure du début effectif de l''évacuation, heure de clôture avec dernier occupant au point de rassemblement - le délai entre alarme et démarche effective est souvent révélateur) ; l''analyse équilibrée des points positifs (comportements conformes à valoriser) et des points à améliorer (dysfonctionnements, comportements dangereux) ; des recommandations priorisées et opérationnelles (pas de généralités : ''améliorer la formation des guides-files du niveau 2 sur la procédure de fermeture des portes'' plutôt que ''former mieux'') ; la comparaison avec l''exercice précédent pour mesurer le progrès. Une liste nominative à des fins disciplinaires serait contre-productive pour la culture sécurité et découragerait la participation honnête.', null, array[0,1,3,4]::integer[], array['theme4','seq2','Rapports et documentation','Organisation opérationnelle']::text[], 56),
('ssiap2-q186', 'ssiap2-partie4', 'multiple-select', 'Le SSIAP 2 constate que son équipe manque de motivation et effectue les rondes de manière routinière sans véritable vigilance. Comment peut-il remédier à cette situation ? (plusieurs réponses possibles)', 'La lutte contre la routine dans les rondes est un défi managérial important pour le SSIAP 2 : variation des itinéraires et horaires (une ronde prévisible est une ronde moins vigilante : varier les sens de parcours, les heures) ; rondes tests avec anomalies placées volontairement (un feu de poubelle simulé avec un objet anomal, une porte CF bloquée ouverte) pour vérifier la qualité de l''observation — à utiliser avec pédagogie et non à des fins répressives ; communication sur les incidents réels ou vécus par d''autres établissements pour donner du sens à la vigilance (''voici pourquoi cette porte CF doit être fermée'') ; reconnaissance des comportements positifs (signalement d''une anomalie, qualité du rapport de ronde) qui renforcent la motivation. La sanction systématique est contre-productive et nuit à l''engagement.', null, array[0,1,2,4]::integer[], array['theme1','seq1','Management opérationnel de l''équipe SSIAP','Encadrement de l''équipe']::text[], 57),
('ssiap2-q187', 'ssiap2-partie4', 'multiple-select', 'En situation de crise, le SSIAP 2 est le responsable sur site en l''absence du SSIAP 3. Quelles décisions peut-il prendre de sa propre initiative ? (plusieurs réponses possibles)', 'Le SSIAP 2 dispose d''une autonomie opérationnelle pour les décisions urgentes ne pouvant attendre : déclenchement de l''alarme générale (c''est sa responsabilité première en cas de sinistre confirmé) ; appel des secours (décision opérationnelle immédiate relevant de sa compétence) ; fermeture et condamnation d''une zone à risque (décision de sécurité relevant de ses attributions) ; coordination de l''évacuation jusqu''à l''arrivée des pompiers puis transfert de commandement au COS. En revanche, la décision de réouverture de l''établissement après un sinistre ne relève pas du SSIAP 2 seul : elle implique une inspection technique des installations, l''accord de la direction et potentiellement de la commission de sécurité ou des pompiers — c''est une décision stratégique qui dépasse ses attributions opérationnelles.', null, array[0,1,2,4]::integer[], array['theme3','seq3','Interface avec les sapeurs-pompiers','Coordination opérationnelle sinistre']::text[], 58),
('ssiap2-q188', 'ssiap2-partie4', 'quiz', 'Un stagiaire SSIAP 1 en formation pratique est sous la supervision du SSIAP 2. Quelle est la responsabilité de ce dernier ?', 'La tutelle d''un stagiaire SSIAP 1 engage la responsabilité du SSIAP 2 : en tant que tuteur sur site, il est responsable de la qualité de la formation pratique dispensée et co-responsable des actes du stagiaire dans le cadre de son apprentissage supervisé. Il ne peut pas laisser un stagiaire seul prendre des décisions opérationnelles (intervention, déclenchement d''alarme) sans avoir évalué et validé ses compétences. Ses obligations : formation aux spécificités de l''établissement (bâtiment, SSI, POI) ; accompagnement progressif vers l''autonomie ; évaluation régulière des compétences et signalement au centre de formation si des lacunes importantes sont identifiées. Le stagiaire n''est pas un agent à part entière et ne peut pas compter dans les effectifs SSIAP réglementaires.', 1, null::integer[], array['theme5','seq1','Gestion des compétences et formations','Encadrement de l''équipe']::text[], 59)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap2-q95','ssiap2-q117','ssiap2-q118','ssiap2-q119','ssiap2-q120','ssiap2-q121','ssiap2-q122','ssiap2-q123','ssiap2-q124','ssiap2-q136','ssiap2-q137','ssiap2-q138','ssiap2-q139','ssiap2-q140','ssiap2-q141','ssiap2-q184','ssiap2-q185','ssiap2-q186','ssiap2-q187','ssiap2-q188');
commit;

-- ===== ssiap2-partie4-sub04.sql =====
begin;
-- SSIAP 2 — Management et organisation (partie 4, sub 4/4, 11 cc_questions)
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap2-q189', 'ssiap2-partie4', 'quiz', 'Comment le SSIAP 2 gère-t-il la transition d''un système de rondes papier vers un système de contrôle de rondes électronique (NFC/QR code) ?', 'La mise en place d''un système de contrôle de rondes électronique est un changement d''outil qui doit être géré avec méthode : formation préalable des agents à l''outil (utilisation du lecteur NFC ou scan QR code, synchronisation des données, que faire en cas de panne de batterie) ; période de transition avec double enregistrement (papier + électronique) pour vérifier la couverture et détecter les bugs avant de supprimer l''ancien système ; vérification exhaustive que les points de contrôle électroniques couvrent bien tous les points de sécurité critiques (le prestataire peut avoir oublié certains locaux) ; migration progressive après validation. Un déploiement brutal sans formation génère des résistances et des erreurs opérationnelles. Le prestataire doit également prévoir une procédure de secours en cas de panne du système électronique.', 1, null::integer[], array['theme2','seq2','Planification des rondes et surveillance','Organisation opérationnelle']::text[], 60),
('ssiap2-q190', 'ssiap2-partie4', 'multiple-select', 'Le SSIAP 2 est responsable de la qualité de la main courante. Quelles erreurs courantes doit-il corriger dans les pratiques de son équipe ? (plusieurs réponses possibles)', 'La main courante est un document officiel pouvant être utilisé dans des enquêtes judiciaires — sa qualité rédactionnelle est donc cruciale. Les erreurs à corriger : les entrées rétroactives (écrire des heures après les faits compromet la crédibilité du document et peut masquer des omissions) ; les formulations vagues (''anomalie constatée'' doit être remplacé par ''porte CF du couloir A niveau 2 maintenue ouverte par un plot — retrait immédiat du plot à 14h23'') ; les abréviations non standardisées (chaque agent utilise ses propres codes, illisibles par un tiers ou lors d''une enquête). La signature de chaque entrée est une bonne pratique à maintenir, pas une erreur à corriger. L''inscription de données personnelles non pertinentes sur des tiers peut être une violation du RGPD mais n''est pas toujours erronée (un agent peut noter qu''un visiteur particulier a été admis si c''est pertinent pour la sécurité).', null, array[0,1,3]::integer[], array['theme4','seq2','Rapports et documentation','Organisation opérationnelle']::text[], 61),
('ssiap2-q191', 'ssiap2-partie4', 'multiple-select', 'Le SSIAP 2 doit gérer l''arrivée d''une équipe de tournage TV dans l''ERP pendant 3 jours. Quelles mesures de sécurité spécifiques doit-il prévoir ? (plusieurs réponses possibles)', 'Un tournage TV dans un ERP présente des risques spécifiques que le SSIAP 2 doit anticiper : risques électriques (les projecteurs de tournage consomment beaucoup et peuvent surcharger des circuits non prévus pour cet usage) ; effets spéciaux (fumée artificielle, flammes, flashs) pouvant déclencher des alarmes ou créer de vrais risques — nécessitent une autorisation préalable du SSIAP 2 et un permis de feu si points chauds ; désignation d''un référent sécurité dans l''équipe de tournage qui connaît les consignes et peut transmettre les instructions du SSIAP 2 ; maintien absolu de la largeur réglementaire des dégagements (les câbles traversant un couloir ou le matériel stocké dans une issue sont formellement interdits). Inhiber l''ensemble du SSI est inacceptable — une inhibition sélective des détecteurs proches des effets spéciaux avec surveillance compensatoire est la bonne approche.', null, array[0,1,2,4]::integer[], array['theme3','seq3','Interface avec les sapeurs-pompiers','Coordination opérationnelle sinistre']::text[], 62),
('ssiap2-q192', 'ssiap2-partie4', 'multiple-select', 'Le SSIAP 2 doit évaluer les risques liés à l''accueil de groupes scolaires (enfants de 6 à 10 ans) dans un ERP culturel. Quelles adaptations sont nécessaires ? (plusieurs réponses possibles)', 'L''accueil de jeunes enfants dans un ERP nécessite des adaptations spécifiques au niveau de la gestion des risques : renforcement de l''encadrement lors des exercices ou en cas de sinistre réel (les enfants paniquent plus facilement et peuvent se disperser) ; briefing impératif des enseignants accompagnateurs (ils deviennent de facto des guides-files responsables de leur groupe — ils doivent connaître les sorties et les points de rassemblement) ; communication adaptée lors de l''alarme (un message vocal simple et rassurant adapté aux enfants aide à canaliser la réaction) . Les poignées et équipements sont généralement conformes aux normes PMR et accessible à hauteur adulte — ce n''est pas une adaptation spécifique obligatoire dans la plupart des ERP. Réduire l''effectif en dessous du seuil réglementaire n''est pas une obligation spécifique aux groupes scolaires si le ratio d''encadrement est respecté.', null, array[0,1,3]::integer[], array['theme6','seq3','Coordination avec équipiers et secours','Coordination opérationnelle sinistre']::text[], 63),
('ssiap2-q193', 'ssiap2-partie4', 'quiz', 'Comment le SSIAP 2 applique-t-il les principes de la gestion des priorités (matrice d''Eisenhower) dans son travail quotidien ?', 'La matrice d''Eisenhower (urgent/important) est un outil de gestion du temps applicable à la gestion d''un service SSIAP : Urgent ET Important : non-conformité critique détectée, incident en cours, équipement défaillant mettant en danger — traitement immédiat personnel ; Important mais PAS urgent : mise à jour du POI, organisation des formations, analyse des indicateurs de performance — à planifier avec soin pour ne pas se faire déborder par l''urgence ; Urgent mais PAS important : certains appels téléphoniques, demandes administratives non critiques — à traiter rapidement ou à déléguer ; Ni urgent Ni important : à éliminer ou à différer. Cette approche permet au SSIAP 2 de ne pas se laisser submerger par les urgences du quotidien au détriment des actions de fond qui améliorent durablement la sécurité.', 1, null::integer[], array['theme7','seq2','Indicateurs de performance','Organisation opérationnelle']::text[], 64),
('ssiap2-q194', 'ssiap2-partie4', 'quiz', 'Le SSIAP 2 doit gérer un agent qui présente régulièrement des signes d''anxiété importante avant les rondes de nuit seul. Quelle est son approche ?', 'La gestion d''un agent anxieux est une situation managériale qui requiert empathie et pragmatisme : dialogue ouvert et bienveillant pour comprendre les causes (incident traumatisant lors d''une ronde précédente, problème de santé, situation personnelle difficile) sans juger ; adaptation temporaire si possible (intégrer l''agent à des binômes pour quelques semaines, réduire les rondes solo en attendant) ; orientation vers la médecine du travail (qui peut identifier si c''est un risque psychosocial professionnel, proposer un suivi ou des aménagements de poste) ; formation à la gestion du stress ou aux premiers secours psychologiques si pertinent. L''ignorance du problème crée un agent démotivé et potentiellement en danger lors de ses rondes. La sanction et la mutation sans dialogue sont des réponses inadaptées qui n''adressent pas la cause.', 1, null::integer[], array['theme1','seq1','Management opérationnel de l''équipe SSIAP','Encadrement de l''équipe']::text[], 65),
('ssiap2-q195', 'ssiap2-partie4', 'multiple-select', 'Le SSIAP 2 doit mettre en place un protocole pour les interventions sur les personnes sans connaissance dans l''établissement. Quels éléments ce protocole doit-il contenir ? (plusieurs réponses possibles)', 'Le protocole d''intervention sur personne sans connaissance (ou en détresse médicale) dans un ERP doit couvrir : le bilan initial par l''agent formé PSE1 ou PSC1 (protection du périmètre, état de conscience par stimulation verbale et physique, bilan respiratoire, position latérale de sécurité si respiration présente) ; l''alerte immédiate du 15 (SAMU) avec transmission du bilan (localisation précise, âge estimé, état, antécédents connus) et des consignes du régulateur médical ; la mise en place du DAE (défibrillateur automatisé externe) si disponible en cas d''absence de pouls et absence de respiration, en association avec la RCP ; la gestion de la présence de témoins (éloigner le public pour protéger la dignité de la victime et permettre une intervention efficace). Le diagnostic médical est strictement réservé aux professionnels de santé — l''agent SSIAP fait un bilan, pas un diagnostic.', null, array[0,1,2,3]::integer[], array['theme6','seq3','Coordination avec équipiers et secours','Coordination opérationnelle sinistre']::text[], 66),
('ssiap2-q196', 'ssiap2-partie4', 'quiz', 'Comment le SSIAP 2 gère-t-il la coordination avec le service de sûreté (vigiles, contrôle d''accès) de son établissement ?', 'La coordination entre sécurité incendie (SSIAP) et sûreté (vigiles, agents de contrôle d''accès) est essentielle car leurs missions se recoupent dans plusieurs situations : un vigile peut être le premier à détecter un départ de feu ou un début de panique — il doit savoir exactement comment alerter le PC SSIAP ; le SSIAP peut avoir besoin de l''appui de la sûreté pour gérer une foule lors d''une évacuation ; la sûreté doit connaître les procédures d''évacuation pour ne pas bloquer les issues en cas d''incident. Le SSIAP 2 définit avec le responsable de sûreté : les canaux d''alerte croisée, les rôles respectifs lors d''un sinistre, les procédures de signalement des anomalies. Les deux services restent sous des chaînes de commandement distinctes mais coordonnées. Lors d''un sinistre incendie, c''est la procédure SSIAP qui prime.', 1, null::integer[], array['theme6','seq3','Coordination avec équipiers et secours','Coordination opérationnelle sinistre']::text[], 67),
('ssiap2-q197', 'ssiap2-partie4', 'multiple-select', 'Le SSIAP 2 doit rédiger une fiche de poste pour un agent SSIAP 1 au PC sécurité. Quels éléments doit-elle contenir ? (plusieurs réponses possibles)', 'Une fiche de poste PC sécurité bien rédigée doit impérativement mentionner : les missions précises (surveillance continue du tableau de signalisation, prise en compte des alarmes, gestion des communications radio, traçabilité temps réel dans la main courante) ; la procédure de levée de doute avec délai maximal (généralement 3 à 5 minutes selon le POI avant déclenchement de l''alarme générale si le terrain ne répond pas) ; les contacts d''urgence (18, 15, 17, astreinte technique, responsable de garde, SSIAP 2 de permanence) facilement accessibles ; les consignes de relève (quoi transmettre, comment signer la passation dans la main courante). La description physique du bureau n''a pas de valeur opérationnelle dans une fiche de poste sécurité.', null, array[0,1,2,3]::integer[], array['theme4','seq2','Rapports et documentation','Organisation opérationnelle']::text[], 68),
('ssiap2-q198', 'ssiap2-partie4', 'quiz', 'Dans le contexte d''un sinistre nocturne avec un seul agent SSIAP 1 de service, comment le SSIAP 2 d''astreinte doit-il organiser sa réponse à distance avant son arrivée ?', 'L''astreinte téléphonique du SSIAP 2 lors d''un sinistre nocturne implique un protocole précis : décrocher immédiatement et établir un contact radio ou téléphonique avec l''agent sur site pour obtenir un premier bilan (type d''alarme, zone concernée, éléments visuels) ; guider l''agent dans la levée de doute et la prise de décision (si sinistre confirmé : déclencher l''alarme et appeler le 18 sans attendre) ; communiquer son délai d''arrivée estimé à l''agent et lui donner les consignes à suivre jusqu''à cette arrivée ; prévenir la direction de l''établissement en parallèle. L''agent de service réduit ne peut pas gérer seul un sinistre confirmé (levée de doute ET gestion du tableau ET coordination évacuation simultanément) — le SSIAP 2 en astreinte est une ressource critique dans ce contexte.', 1, null::integer[], array['theme3','seq3','Interface avec les sapeurs-pompiers','Coordination opérationnelle sinistre']::text[], 69),
('ssiap2-q199', 'ssiap2-partie4', 'quiz', 'Le contrat de travail d''un agent SSIAP 1 peut-il prévoir des heures supplémentaires au-delà de :', 'La durée maximale hebdomadaire de travail est encadrée par le code du travail : durée maximale absolue de 48 heures par semaine (sauf dérogation préfectorale exceptionnelle, plafonnée à 60h sur 12 semaines maximum dans des secteurs spécifiques) ; durée moyenne de 44 heures sur 12 semaines consécutives. Au-delà de 35 heures (ou de la durée conventionnelle), des heures supplémentaires peuvent être effectuées dans ces limites. La réponse ''35 heures par semaine sans limite'' est incorrecte (il y a des limites légales). ''60 heures'' n''est pas la limite légale générale (c''est un plafond exceptionnel encadré). ''48 heures par semaine en durée moyenne'' n''est pas non plus exact — 44h est la moyenne sur 12 semaines. Aucune des formulations proposées n''est strictement correcte.', 0, null::integer[], array['theme1','seq1','Management opérationnel de l''équipe SSIAP','Encadrement de l''équipe']::text[], 70)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap2-q189','ssiap2-q190','ssiap2-q191','ssiap2-q192','ssiap2-q193','ssiap2-q194','ssiap2-q195','ssiap2-q196','ssiap2-q197','ssiap2-q198','ssiap2-q199');
commit;

-- ===== ssiap3-partie1-sub01.sql =====
begin;
-- SSIAP 3 — Réglementation et expertise avancée (partie 1, sub 1/3, 20 cc_questions)
values ('ssiap3-partie1', 3, 'Réglementation et expertise avancée', '54 cc_questions', '🔥', 'from-red-500 to-orange-600', 0, true)
on conflict (id) do update set title=excluded.title, subtitle=excluded.subtitle, icon=excluded.icon, color=excluded.color, display_order=excluded.display_order;
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap3-q0', 'ssiap3-partie1', 'quiz', 'En tant que SSIAP 3 chef de service, vous prenez vos fonctions dans un ERP de 1ère catégorie. Quelle est votre première action réglementaire ?', 'La prise de poste d''un SSIAP 3 commence obligatoirement par un état des lieux exhaustif : audit de conformité réglementaire (vérification de tous les équipements, installations, documents réglementaires), analyse du dossier de sécurité (registre à jour, rapports de vérifications, comptes-rendus des exercices), évaluation des compétences de l''équipe en place, et revue du POI. Ce diagnostic initial permet d''identifier les non-conformités, de prioriser les actions correctives et de présenter un plan d''action argumenté à la direction. Agir sans diagnostic expose à des erreurs de priorité. Attendre passivement est irresponsable. Un chef de service assume immédiatement ses responsabilités.', 1, null::integer[], array['theme1','seq1','Responsabilités du chef de service','ERP/IGH - Maîtrise réglementaire complète']::text[], 0),
('ssiap3-q1', 'ssiap3-partie1', 'quiz', 'La direction d''un ERP vous demande d''accepter un effectif du public supérieur de 20 % à la capacité d''accueil autorisée lors d''un événement exceptionnel. Quelle est votre réponse ?', 'La capacité d''accueil autorisée d''un ERP est une limite réglementaire absolue, fixée par arrêté préfectoral. La dépasser constitue une infraction pénale (mise en danger d''autrui, non-respect des conditions d''ouverture) engageant la responsabilité pénale de l''exploitant et pouvant aussi engager celle du SSIAP 3 s''il a validé ou permis cette situation. Le SSIAP 3 doit refuser catégoriquement et le formaliser par écrit. Il peut proposer des alternatives : répartir sur plusieurs créneaux, utiliser des espaces supplémentaires conformes, obtenir une autorisation spéciale de la commission (délai long), ou sécuriser un espace adjacent. Une lettre écrite de la direction ne protège pas le SSIAP 3 de sa propre responsabilité pénale s''il a connaissance de l''infraction.', 2, null::integer[], array['theme1','seq1','Responsabilités du chef de service','ERP/IGH - Maîtrise réglementaire complète']::text[], 1),
('ssiap3-q2', 'ssiap3-partie1', 'multiple-select', 'Quels sont les rôles et pouvoirs de la commission de sécurité vis-à-vis d''un ERP ? (plusieurs réponses possibles)', 'La commission de sécurité est un organe consultatif dont les pouvoirs sont définis par le code de la construction et de l''habitation : elle donne des avis consultatifs (favorables ou défavorables) sur l''ouverture, les travaux et le maintien en exploitation des ERP ; elle peut proposer à l''autorité de police (maire ou préfet) la fermeture administrative d''un ERP non conforme - mais c''est bien l''autorité de police qui prononce la fermeture, pas la commission elle-même ; elle effectue des visites périodiques programmées et peut effectuer des visites inopinées ; elle constate et signale les infractions à la réglementation. La commission n''a pas de pouvoir de fermeture directe (c''est une erreur fréquente) : son rôle est consultatif et sa force vient du fait que ses avis sont quasi systématiquement suivis.', null, array[0,1,2,4]::integer[], array['theme2','seq1','Commission de sécurité - pouvoirs et procédures','ERP/IGH - Maîtrise réglementaire complète']::text[], 2),
('ssiap3-q3', 'ssiap3-partie1', 'multiple-select', 'Le SSIAP 3 doit rédiger un avis technique sur un projet d''aménagement intérieur. Quels points de la réglementation ERP doit-il impérativement vérifier ? (plusieurs réponses possibles)', 'Un avis technique SSIAP 3 sur un projet d''aménagement doit couvrir : les dégagements (toute modification peut réduire une largeur, créer un cul-de-sac ou allonger la distance d''évacuation) ; la réaction au feu des matériaux (revêtements muraux, mobiliers, cloisons doivent respecter les classes réglementaires selon le type d''ERP et leur localisation) ; le compartimentage (une cloison déplacée peut percer une paroi coupe-feu sans reconstitution adéquate) ; la détection (un nouveau cloisonnement peut créer des zones non couvertes par les détecteurs existants ou modifier les flux de fumées). Le style décoratif est affaire de goût, non de sécurité. Cet avis doit être formalisé par écrit et conservé dans le dossier de sécurité.', null, array[0,1,2,3]::integer[], array['theme3','seq1','Avis techniques et dossiers travaux','ERP/IGH - Maîtrise réglementaire complète']::text[], 3),
('ssiap3-q4', 'ssiap3-partie1', 'quiz', 'Dans le cadre d''un ERP de type U (établissement de soins), quelle spécificité majeure le SSIAP 3 doit-il intégrer dans son POI ?', 'Les établissements de soins (type U) présentent une contrainte fondamentale : une partie des patients est dans l''impossibilité d''être évacuée rapidement (sous anesthésie, en réanimation, sous perfusion, immobiles). Le POI du SSIAP 3 doit intégrer une stratégie d''évacuation horizontale progressive (evacuation par secteur de compartimentage, les patients mobiles ou semi-mobiles étant déplacés vers les secteurs coupe-feu adjacents en attendant l''intervention des pompiers) plutôt qu''une évacuation totale immédiate impossible. Le compartimentage EI 30 ou EI 60 entre secteurs devient l''outil central de la stratégie de défense. Des exercices partiels simulés sont réalisés pour tester ces procédures sans perturber les soins.', 1, null::integer[], array['theme4','seq2','ERP type U - Établissements de soins','Établissements spéciaux - Réglementation']::text[], 4),
('ssiap3-q5', 'ssiap3-partie1', 'quiz', 'Qu''est-ce qu''une ''étude de sécurité incendie'' ou ''notice de sécurité'' exigée lors d''une demande d''autorisation de travaux pour un ERP ?', 'La notice de sécurité (ou étude de sécurité incendie) est un document technique obligatoire joint à toute demande d''autorisation de travaux pour un ERP. Elle décrit de manière exhaustive et argumentée comment le projet satisfait aux exigences réglementaires : nature et classement de réaction au feu de tous les matériaux utilisés ; résistance au feu des parois et planchers (avec justification REI ou EI) ; calcul et description des dégagements (UP par UP) ; description du système de détection, d''extinction et de désenfumage prévu ; conformité aux dispositions particulières du type d''ERP concerné. Le SSIAP 3 est compétent pour rédiger ou vérifier cette notice. Elle est soumise à la commission de sécurité qui l''examine avant d''émettre son avis.', 1, null::integer[], array['theme3','seq1','Avis techniques et dossiers travaux','ERP/IGH - Maîtrise réglementaire complète']::text[], 5),
('ssiap3-q6', 'ssiap3-partie1', 'quiz', 'La formation initiale SSIAP 3 dure :', 'La formation initiale SSIAP 3 est de 190 heures en centre de formation, auxquelles s''ajoute un stage en entreprise. Le SSIAP 3 nécessite de détenir le SSIAP 2 depuis au moins 1 an. Le recyclage MAC SSIAP 3 est de 28 heures tous les 3 ans. Aucune des propositions (70h = SSIAP 1 ou 2, 105h = total SSIAP 1/2 avec stage, 240h = aucun niveau) ne correspond exactement.', 2, null::integer[], array['theme1','seq1','Responsabilités du chef de service','ERP/IGH - Maîtrise réglementaire complète']::text[], 6),
('ssiap3-q24', 'ssiap3-partie1', 'multiple-select', 'Le SSIAP 3 doit préparer et animer une visite de la commission de sécurité dans son ERP. Quelle est sa méthodologie de préparation ? (plusieurs réponses possibles)', 'La préparation d''une visite de commission par le SSIAP 3 est une démarche rigoureuse : vérification préalable complète de tous les équipements et installations (l''idéal est de réaliser une pré-visite interne) ; mise à jour et vérification du registre de sécurité (tous les rapports de vérification, comptes-rendus d''exercices, suites données aux précédentes observations) ; préparation d''un exposé de présentation de l''établissement incluant les modifications apportées depuis la dernière visite et les améliorations réalisées ; formation des agents susceptibles d''être interrogés. Masquer des non-conformités connues est une faute grave pouvant engager la responsabilité pénale et, si découverte lors de la visite, aggrave l''avis défavorable. La transparence sur les non-conformités avec un plan d''action crédible est toujours préférable.', null, array[0,1,2,4]::integer[], array['theme2','seq1','Commission de sécurité - pouvoirs et procédures','ERP/IGH - Maîtrise réglementaire complète']::text[], 7),
('ssiap3-q25', 'ssiap3-partie1', 'quiz', 'Le SSIAP 3 reçoit notification d''une circulaire modifiant l''interprétation d''un article du règlement de sécurité ERP. Quelle démarche adopte-t-il ?', 'La veille réglementaire active est une obligation du SSIAP 3. Lors d''une modification réglementaire ou d''une circulaire d''interprétation : analyser précisément l''impact sur l''établissement (quels locaux, quels équipements, quelles procédures sont concernés) ; évaluer les actions correctives nécessaires (modification d''installation, mise à jour du POI, formation des agents) et les délais d''application ; informer la direction des implications et des éventuels coûts ; consigner l''analyse et les actions dans le registre de sécurité (preuve de la veille réglementaire). Les circulaires, même si elles n''ont pas la force juridique d''un arrêté, constituent des instructions d''application des textes que les commissions de sécurité et les tribunaux prennent en compte.', 1, null::integer[], array['theme5','seq1','Veille réglementaire et technique','ERP/IGH - Maîtrise réglementaire complète']::text[], 8),
('ssiap3-q26', 'ssiap3-partie1', 'multiple-select', 'Dans un ERP comportant des zones Atex (atmosphères explosives), quelles obligations spécifiques s''imposent au SSIAP 3 ? (plusieurs réponses possibles)', 'La réglementation ATEX (directive 1999/92/CE, transposée en droit français) impose des obligations croisées avec la sécurité incendie : classification et balisage des zones explosives (zone 0 : présence continue ; zone 1 : présence occasionnelle ; zone 2 : présence rare pour gaz/vapeurs ; 20, 21, 22 pour poussières) ; équipements électriques et mécaniques certifiés ATEX adaptés à chaque zone (marquage Ex) ; procédures d''intervention SSIAP adaptées (les agents ne peuvent pas intervenir dans une zone ATEX en atmosphère explosive avec un équipement non certifié : risque d''explosion) ; formation des agents aux signaux d''alerte ATEX et aux comportements adaptés. L''interdiction permanente d''accès n''est pas la règle : l''accès est possible avec des équipements adaptés et des procédures strictes (permis d''entrée).', null, array[0,1,3,4]::integer[], array['theme6','seq3','Zones ATEX et risques spéciaux','Réglementations spéciales']::text[], 9),
('ssiap3-q27', 'ssiap3-partie1', 'multiple-select', 'Le SSIAP 3 d''un centre commercial multi-enseignes doit gérer la coordination de la sécurité incendie avec les locataires. Quels mécanismes contractuels et opérationnels peut-il utiliser ? (plusieurs réponses possibles)', 'La coordination de la sécurité incendie dans un ERP multi-locataires est une mission stratégique du SSIAP 3 : clauses sécurité dans les baux commerciaux (obligation de respecter le règlement de sécurité, d''informer le SSIAP 3 de tout travaux, de former leur personnel) ; réunions périodiques de coordination (informer les référents sécurité de chaque enseigne, partager les procédures d''évacuation, retours d''expérience des incidents) ; délivrance d''autorisations de travaux après vérification de conformité (un locataire ne peut pas réaménager sans accord SSIAP 3 qui vérifie l''impact sur la sécurité) ; règlement intérieur de sécurité signé par chaque locataire (document contractuel précisant les obligations). Imposer des SSIAP indépendants par enseigne n''est pas réglementaire et créerait une fragmentation dangereuse de la sécurité.', null, array[0,1,2,4]::integer[], array['theme7','seq1','ERP multi-locataires - coordination','ERP/IGH - Maîtrise réglementaire complète']::text[], 10),
('ssiap3-q28', 'ssiap3-partie1', 'quiz', 'Le classement en ERP de 1ère catégorie correspond à un effectif supérieur à :', 'La 1ère catégorie ERP correspond à un effectif du public supérieur à 1 500 personnes. Les catégories sont : 1ère : > 1 500 personnes ; 2ème : de 701 à 1 500 ; 3ème : de 301 à 700 ; 4ème : ≤ 300 (hors 5ème) ; 5ème : en dessous des seuils définis pour chaque type. Aucune des propositions (1 000, 3 000, 5 000) ne correspond exactement au seuil de la 1ère catégorie.', 1, null::integer[], array['theme8','seq1','Catégories ERP et seuils','ERP/IGH - Maîtrise réglementaire complète']::text[], 11),
('ssiap3-q29', 'ssiap3-partie1', 'multiple-select', 'Dans le cadre d''un ERP recevant un public vulnérable (EHPAD, établissement pour personnes handicapées), le SSIAP 3 doit adapter le POI. Quelles adaptations spécifiques sont requises ? (plusieurs réponses possibles)', 'Dans un ERP accueillant un public très vulnérable, le SSIAP 3 doit développer un POI spécifiquement adapté : procédures différenciées selon le type de dépendance (personne âgée désorientée, fauteuil électrique, patient sous oxygène, déficience cognitive) avec des protocoles clairs pour chaque situation ; liste nominative des résidents les plus dépendants avec leur localisation habituelle (chambre, salle d''activité) mise à jour régulièrement ; formation spécifique des agents aux techniques de déplacement sécurisées (portage à deux, utilisation des chaises d''évacuation dans les escaliers) pour éviter blessures lors de l''évacuation ; matériel d''évacuation disponible à chaque niveau (chaises d''évacuation certifiées, brancards de descente). Laisser les personnes valides seules est insuffisant car même une personne partiellement valide peut avoir besoin d''un guidage dans la panique.', null, array[0,1,2,3]::integer[], array['theme9','seq2','Établissements vulnérables - EHPAD, handicap','Établissements spéciaux - Réglementation']::text[], 12),
('ssiap3-q44', 'ssiap3-partie1', 'multiple-select', 'Le SSIAP 3 doit rédiger un Plan Opérationnel Interne (POI) pour un ERP de 1ère catégorie. Quels éléments sont obligatoirement intégrés dans ce document ? (plusieurs réponses)', 'Le POI est le document de référence opérationnel du service SSIAP. Il doit contenir : l''organigramme de crise précisant qui commande quoi selon les scénarios ; les procédures opérationnelles pour chaque type de sinistre (incendie, attentat, accident de personne, panique) ; le recensement des ressources humaines et matérielles disponibles avec leur localisation ; les contacts externes (pompiers, SAMU, préfecture, prestataires d''astreinte). Le bilan financier ne relève pas du POI mais du budget du service.', null, array[0,1,2,3]::integer[], array['theme1','seq1']::text[], 13),
('ssiap3-q45', 'ssiap3-partie1', 'quiz', 'Lors de la conception d''un nouvel ERP, à quelle phase le SSIAP 3 intervient-il de manière optimale pour intégrer la sécurité incendie ?', 'L''intervention du SSIAP 3 en phase de programmation (avant permis de construire) est le moment le plus efficace car les décisions architecturales majeures peuvent encore être modifiées sans surcoût : implantation des escaliers, position des issues, compartimentage, cheminements d''évacuation. Intervenir uniquement à la réception ou pendant les travaux contraint à des adaptations coûteuses ou impossibles.', 1, null::integer[], array['theme1','seq1']::text[], 14),
('ssiap3-q46', 'ssiap3-partie1', 'quiz', 'Quelle est la différence entre une ''solution de substitution'' et une ''solution alternative'' au sens de la réglementation ERP ?', 'La distinction est importante : la solution de substitution (article GN 4 du règlement ERP) est une mesure compensatoire proposée à la commission lorsqu''une disposition réglementaire ne peut être respectée — elle doit offrir un niveau de sécurité équivalent et requiert l''accord explicite de la commission. La solution alternative (ou approche performancielle) relève de l''ingénierie de sécurité incendie : elle utilise des outils de modélisation (RSET/ASET, CFD) pour démontrer que la solution proposée atteint les objectifs de sécurité, même si elle dévie des prescriptions. Les deux nécessitent validation par la commission.', 1, null::integer[], array['theme2','seq2']::text[], 15),
('ssiap3-q47', 'ssiap3-partie1', 'quiz', 'Le SSIAP 3 est interpellé par un avocat dans le cadre d''une enquête sur un incendie passé dans l''établissement. Quels documents doit-il être en mesure de produire ?', 'En cas d''enquête judiciaire, le SSIAP 3 doit pouvoir produire l''intégralité de la documentation traçant l''état de sécurité de l''établissement : registre de sécurité (contrôles, vérifications, incidents), main courantes (traçabilité opérationnelle quotidienne), rapports de vérifications périodiques des installations (SSI, extincteurs, désenfumage), comptes-rendus d''exercices d''évacuation. Ces documents peuvent déterminer sa responsabilité pénale. La consultation d''un avocat est recommandée avant toute déposition mais les documents doivent être conservés et communicables.', 1, null::integer[], array['theme2','seq2']::text[], 16),
('ssiap3-q48', 'ssiap3-partie1', 'quiz', 'Dans le cadre d''une étude RSET/ASET, que signifient ces deux acronymes et quel est leur rôle dans la démonstration de sécurité ?', 'RSET (Required Safe Egress Time) est le temps nécessaire pour que tous les occupants atteignent un lieu sûr depuis le début de l''incendie. ASET (Available Safe Egress Time) est le temps disponible avant que les conditions dans les voies d''évacuation deviennent intenables (chaleur, fumées, visibilité). La démonstration de sécurité par ISI (Ingénierie de Sécurité Incendie) impose RSET < ASET avec une marge de sécurité. Si cette condition n''est pas satisfaite, des mesures compensatoires (désenfumage renforcé, sprinklers, réduction de l''effectif) doivent être intégrées jusqu''à ce qu''elle le soit.', 1, null::integer[], array['theme3','seq3']::text[], 17),
('ssiap3-q49', 'ssiap3-partie1', 'quiz', 'La norme française de référence pour les études de désenfumage par ingénierie est :', 'La norme NF EN 12101-6 concerne les systèmes de contrôle des fumées et de la chaleur (ventilation mécanique de désenfumage). La NF S 61-938 n''existe pas en tant que telle. La EN 1838 concerne l''éclairage de secours. Pour les études de désenfumage par ingénierie en France, c''est le guide CTICM/INRS associé aux IT (Instructions Techniques) 246 et 263 qui font référence, et non une seule norme. Aucune des propositions ne répond correctement à la question.', 2, null::integer[], array['theme3','seq3']::text[], 18),
('ssiap3-q50', 'ssiap3-partie1', 'quiz', 'Le SSIAP 3 doit définir les objectifs de sécurité d''un établissement selon une approche performancielle. Quels sont les objectifs fondamentaux reconnus par la réglementation française ?', 'Les objectifs de sécurité incendie reconnus par la réglementation ERP française (et par l''approche performancielle) sont : permettre l''évacuation des occupants dans un temps raisonnable et en sécurité (RSET < ASET) ; limiter la propagation du feu et des fumées aux locaux d''origine (compartimentage, désenfumage) ; permettre l''accès et l''intervention efficace des services de secours ; maintenir la stabilité structurelle suffisamment longtemps pour permettre l''évacuation et l''intervention. La prévention absolue du départ de feu n''est pas un objectif réglementaire (tout feu peut démarrer — on gère ses conséquences).', 1, null::integer[], array['theme1','seq1']::text[], 19)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap3-q0','ssiap3-q1','ssiap3-q2','ssiap3-q3','ssiap3-q4','ssiap3-q5','ssiap3-q6','ssiap3-q24','ssiap3-q25','ssiap3-q26','ssiap3-q27','ssiap3-q28','ssiap3-q29','ssiap3-q44','ssiap3-q45','ssiap3-q46','ssiap3-q47','ssiap3-q48','ssiap3-q49','ssiap3-q50');
commit;

-- ===== ssiap3-partie1-sub02.sql =====
begin;
-- SSIAP 3 — Réglementation et expertise avancée (partie 1, sub 2/3, 20 cc_questions)
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap3-q58', 'ssiap3-partie1', 'quiz', 'Le référentiel professionnel SSIAP est défini par :', 'L''arrêté du 2 mai 2005 modifié (plusieurs fois, dont en 2021) définit les missions, qualifications et conditions d''emploi des agents SSIAP. La norme NF X50-760 concerne la formation professionnelle. Le décret du 20 février 1992 concerne les prescriptions de sécurité et de santé pour les travaux effectués dans un établissement par une entreprise extérieure. L''arrêté du 2 mai 2005 est bien la bonne réponse et figure dans les options.', 3, null::integer[], array['theme2','seq2']::text[], 20),
('ssiap3-q59', 'ssiap3-partie1', 'multiple-select', 'Le SSIAP 3 doit gérer un bâtiment classé Monument Historique avec des contraintes patrimoniales fortes. Quels défis spécifiques cela représente-t-il ? (plusieurs réponses)', 'Les Monuments Historiques présentent des défis sécurité incendie spécifiques et complexes : les installations de sécurité standard (câblages apparents, détecteurs visibles, sprinklers) peuvent être refusées pour des raisons patrimoniales — des solutions discrètes ou intégrées doivent être trouvées avec dérogation ; l''Architecte des Bâtiments de France (ABF) doit valider tout travaux pouvant affecter le patrimoine ; les charpentes en bois massif des bâtiments anciens brûlent rapidement et peuvent s''effondrer sans les traitements ignifuges modernes ; les matériaux d''époque (tapisseries, boiseries, peintures historiques) ont souvent des réactions au feu très défavorables. La sécurité incendie reste possible dans les MH mais nécessite des approches sur-mesure avec l''ensemble des parties prenantes.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 21),
('ssiap3-q61', 'ssiap3-partie1', 'quiz', 'Quelle est la procédure du SSIAP 3 lorsque la commission de sécurité émet un avis défavorable à l''ouverture d''un nouvel établissement ?', 'Un avis défavorable de la commission de sécurité empêche légalement l''ouverture au public. La démarche du SSIAP 3 : analyse détaillée et documentée de chaque observation (certaines peuvent être facilement levées, d''autres nécessitent des travaux importants) ; construction d''un plan d''action priorisé avec délais réalistes et chiffrage ; présentation à la direction pour validation des investissements et arbitrage des délais ; suivi de l''avancement des travaux ; demande de nouvelle visite ou de visa sur dossier selon les dispositions de la commission. L''ouverture malgré un avis défavorable est une infraction pénale grave. La contestation juridique est possible mais longue et ne résout pas les problèmes techniques.', 1, null::integer[], array['theme2','seq2']::text[], 22),
('ssiap3-q64', 'ssiap3-partie1', 'multiple-select', 'Le SSIAP 3 doit rédiger une notice de sécurité pour un projet de transformation d''un immeuble de bureaux en hôtel. Quels points essentiels doit-elle aborder ? (plusieurs réponses)', 'La notice de sécurité pour une transformation en hôtel doit traiter : la classification ERP type O avec la catégorie déterminée par la capacité d''accueil totale (chambres + salles communes) ; le compartimentage des chambres (parois EI 60 minimum, portes CF à fermeture automatique — pour confiner un feu dans une chambre) ; le SSI adapté aux locaux à sommeil (détection automatique généralisée obligatoire, niveau sonore de l''alarme suffisant pour réveiller les dormeurs) ; les procédures d''évacuation (guidage des occupants désorientés la nuit, liste des PMR pour évacuation assistée). Le plan de financement est un document commercial sans lien avec la notice de sécurité.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 23),
('ssiap3-q69', 'ssiap3-partie1', 'multiple-select', 'Dans le cadre d''une mission d''assistance à maîtrise d''ouvrage (AMO) sécurité, quelles prestations le SSIAP 3 peut-il apporter ? (plusieurs réponses)', 'En AMO sécurité incendie, le SSIAP 3 apporte une expertise technique au maître d''ouvrage : rédaction des CCTP (Cahiers des Clauses Techniques Particulières) pour les lots SSI, sprinklers, désenfumage — garantissant des exigences techniques précises et conformes ; analyse critique des études produites par les BET (Bureau d''Études Techniques) pour vérifier leur conformité réglementaire et technique ; participation aux réunions de conception pour intégrer la sécurité dès les premières décisions ; assistance à la réception (vérification que les installations réalisées correspondent aux études validées, participation aux essais de fonctionnement). En revanche, il ne peut pas signer les plans d''exécution à la place d''un bureau d''études agréé (responsabilité et assurance spécifiques).', null, array[0,1,2,4]::integer[], array['theme3','seq3']::text[], 24),
('ssiap3-q78', 'ssiap3-partie1', 'multiple-select', 'Le SSIAP 3 doit gérer la coexistence de deux ERP dans un même bâtiment (un restaurant en RDC et des bureaux aux étages). Quels problèmes spécifiques doit-il résoudre ? (plusieurs réponses)', 'La cohabitation de plusieurs ERP dans un même bâtiment génère des problèmes spécifiques de coordination : définition des responsabilités sur les parties communes (escaliers, ascenseurs, façades) — une convention entre exploitants est indispensable ; interconnexion des systèmes d''alarme (un incendie dans le restaurant doit déclencher l''alarme dans les bureaux et réciproquement, même si les SSI sont gérés séparément) ; gestion des plages horaires décalées (le restaurant peut être ouvert quand les bureaux sont vides, modifiant le service SSIAP nécessaire) ; vérification du compartimentage entre les deux entités (parois et portes CF entre RDC ERP et étages bureaux). L''interdiction de communication entre entités aggraverait les risques au lieu de les réduire.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 25),
('ssiap3-q81', 'ssiap3-partie1', 'multiple-select', 'Quelles sont les obligations du SSIAP 3 en matière de veille réglementaire dans son domaine ? (plusieurs réponses)', 'La veille réglementaire est une obligation professionnelle permanente du SSIAP 3 : suivi des modifications du règlement de sécurité ERP (arrêtés modificatifs, nouveaux types, modifications des dispositions générales) ; mise à jour des connaissances sur les normes NF et EN applicables aux installations (SSI, sprinklers, désenfumage — ces normes évoluent régulièrement) ; lecture des circulaires et instructions techniques de la DGSCGC (Direction Générale de la Sécurité Civile et de la Gestion des Crises) qui précisent l''application de la réglementation ; participation à des réseaux professionnels (CNPP, FFMI, associations sectorielles) pour anticiper les évolutions. Limiter la veille aux visites de commission est insuffisant et crée un risque de retard réglementaire.', null, array[0,1,2,3]::integer[], array['theme2','seq2']::text[], 26),
('ssiap3-q90', 'ssiap3-partie1', 'multiple-select', 'Dans un IGH de classe GHW (hôtel de grande hauteur), quelles obligations spécifiques s''ajoutent par rapport à un hôtel ERP classique ? (plusieurs réponses)', 'Un IGH de classe GHW (immeuble de grande hauteur à usage hôtelier) impose des exigences renforcées par rapport à un hôtel ERP classique : service de sécurité SSIAP permanent et dimensionné pour les spécificités de la hauteur (intervention sur plusieurs niveaux simultanément, coordination avec les pompiers qui ne peuvent pas intervenir en façade au-delà de 28m) ; détection automatique généralisée dans la totalité de l''immeuble, chambres incluses (contrairement à certains ERP hôteliers de petite taille) ; compartimentage horizontal par niveau (les planchers REI 120 et les portes palières coupe-feu permettent le confinement d''un sinistre à un niveau). L''évacuation par façade avec échelles est impossible au-dessus de 28m (hauteur limite des échelles pompiers) — c''est précisément pourquoi les IGH nécessitent une stratégie de défense en place (confinement) plutôt que d''évacuation totale. Les exercices trimestriels ne sont pas une obligation générale des IGH.', null, array[0,1,2]::integer[], array['theme1','seq1']::text[], 27),
('ssiap3-q92', 'ssiap3-partie1', 'quiz', 'Comment le SSIAP 3 détermine-t-il l''effectif SSIAP réglementaire requis pour un ERP de 1ère catégorie de type N (restaurant) de 800 places avec cuisine professionnelle ?', 'L''effectif SSIAP pour un ERP de type N (restaurant) de 1ère catégorie (plus de 1500 personnes) ou 2ème catégorie (700 à 1500 personnes) est déterminé par les dispositions spécifiques de l''arrêté du 2 mai 2005 modifié en fonction de la catégorie ERP : les articles définissent le nombre minimal d''agents SSIAP selon la catégorie. Pour un restaurant de 800 places (2ème catégorie), la présence d''une cuisine à feux nus constitue un risque majoré pouvant justifier un effectif renforcé ou des dispositions particulières. Les horaires tardifs (service du soir) maintiennent l''obligation de présence SSIAP pendant toute la durée d''exploitation. Le SSIAP 3 doit consulter les tableaux de l''arrêté et adapter si les risques particuliers le justifient.', 1, null::integer[], array['theme2','seq2']::text[], 28),
('ssiap3-q97', 'ssiap3-partie1', 'quiz', 'Quelle est la responsabilité pénale du SSIAP 3 en cas de sinistre mortel dans un ERP où il exerce ses fonctions ?', 'La responsabilité pénale du SSIAP 3 est engageable selon les articles 221-6 et 222-19 du Code pénal (homicide et blessures involontaires par maladresse, imprudence, négligence ou manquement à une obligation de prudence ou de sécurité) : même sans intention de nuire, une faute non-intentionnelle (négligence caractérisée, non-respect d''une obligation réglementaire, défaut de surveillance) peut engager sa responsabilité si le lien de causalité avec le dommage est établi. Cette responsabilité s''ajoute à celle du propriétaire et de l''exploitant sans se substituer à elle (cumul possible). Elle peut exister même s''il n''était pas physiquement présent si une faute dans son organisation est identifiée. La jurisprudence des sinistres de discothèques et hôtels illustre ce risque.', 1, null::integer[], array['theme2','seq2']::text[], 29),
('ssiap3-q99', 'ssiap3-partie1', 'multiple-select', 'Dans le cadre d''une étude de danger pour un ERP avec stockage de matières dangereuses (laboratoire de recherche), quelles étapes le SSIAP 3 doit-il conduire ? (plusieurs réponses)', 'Une étude de danger pour un laboratoire avec matières dangereuses suit une méthodologie structurée : inventaire des matières dangereuses (fiches de données de sécurité, quantités maximales stockées, conditions de conservation — températures, incompatibilités chimiques) ; identification des scénarios d''accident (incendie d''un stockage de solvants, explosion d''un récipient sous pression, fuite de gaz toxique, réaction chimique accidentelle suite à un mauvais stockage) ; évaluation des effets (distances d''effets thermiques, de surpression, toxiques selon les modèles de dispersion — logiciels Phast, ALOHA ou méthodes simplifiées) ; définition et dimensionnement des barrières de prévention (organisation du stockage, compatibilité chimique) et de protection (détection gaz, extinction spécifique, confinement des effluents). Le calcul d''assurance relève du service financier, pas de l''étude de danger.', null, array[0,1,2,3]::integer[], array['theme3','seq3']::text[], 30),
('ssiap3-q102', 'ssiap3-partie1', 'multiple-select', 'Le SSIAP 3 doit choisir entre une stratégie d''évacuation totale immédiate et une évacuation différée par zones pour un ERP de type W (bureaux) de 3 000 personnes sur 15 niveaux. Quels critères orientent ce choix ? (plusieurs réponses)', 'Le choix entre évacuation totale et évacuation différée (par zones ou par niveaux) dépend de critères techniques précis : le compartimentage coupe-feu doit être suffisamment fiable pour garantir que le feu restera confiné le temps que les zones éloignées soient évacuées progressivement (sans compartimentage, l''évacuation différée est dangereuse) ; la capacité des escaliers est un critère déterminant — 3 000 personnes dans les mêmes escaliers simultanément crée un risque de bousculade mortelle (phénomène de foule) ; la fiabilité du SSI conditionne la pertinence d''une stratégie différée (si la détection est peu fiable, on ne peut pas se permettre de ne pas évacuer immédiatement) ; au-delà de 50 m (IGH), l''évacuation totale simultanée est reconnue comme dangereuse et irréaliste — les IGH utilisent systématiquement une stratégie de défense en place avec évacuation par tranches.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 31),
('ssiap3-q103', 'ssiap3-partie1', 'quiz', 'Lors d''une inspection de routine, le SSIAP 3 constate que des travaux de peinture ont été réalisés sur des portes coupe-feu, colmatant les joints intumescents. Quelle est la gravité de cette situation et sa réaction ?', 'Les joints intumescents des portes coupe-feu ont une fonction critique : en cas d''incendie, ils gonflent sous l''effet de la chaleur pour combler le jeu entre la porte et le cadre, empêchant le passage des fumées toxiques. Si de la peinture obstrue les cellules du joint intumescent, il ne peut plus gonfler correctement et perd sa performance. Cette non-conformité est grave car elle compromet l''étanchéité coupe-feu de la porte. Actions immédiates : arrêt du chantier de peinture sur les portes CF, identification exhaustive de toutes les portes concernées (inspection visuelle de tous les joints), remplacement des joints intumescents colmatés par des joints neufs conformes. Gratter la peinture ne restaure pas les propriétés du joint (les micro-alvéoles sont détruites). La couleur de la peinture est sans rapport.', 1, null::integer[], array['theme2','seq2']::text[], 32),
('ssiap3-q104', 'ssiap3-partie1', 'quiz', 'La durée de recyclage réglementaire des agents SSIAP 2 est de :', 'Le recyclage des agents SSIAP est défini par l''arrêté du 2 mai 2005 modifié. Pour les SSIAP 1, 2 et 3, le recyclage est obligatoire tous les 3 ans. Aucune des durées proposées (2 ans, 5 ans, 10 ans) ne correspond à la durée réglementaire de 3 ans.', 3, null::integer[], array['theme2','seq2']::text[], 33),
('ssiap3-q114', 'ssiap3-partie1', 'quiz', 'Dans le cadre d''une inspection inopinée de la commission de sécurité, le SSIAP 3 constate en temps réel plusieurs non-conformités. Comment gère-t-il cette situation ?', 'Une inspection inopinée teste la réalité de l''état de sécurité de l''établissement. Le SSIAP 3 doit adopter une posture de transparence professionnelle : reconnaître clairement les non-conformités constatées (la commission les verra de toute façon) ; démontrer sa maîtrise en présentant les actions correctives déjà en cours (si une non-conformité est connue et un plan d''action existe, le présenter immédiatement) ; pour les non-conformités urgentes découvertes pendant la visite, engager immédiatement l''action corrective si possible (retirer un obstacle dans une issue, faire fermer une porte CF) ; s''engager sur un plan d''action précis et daté pour les autres points. Cette posture démontre la compétence et la bonne foi du SSIAP 3, ce qui influence positivement l''appréciation de la commission.', 1, null::integer[], array['theme2','seq2']::text[], 34),
('ssiap3-q126', 'ssiap3-partie1', 'quiz', 'Comment le SSIAP 3 intègre-t-il la notion de ''défense en profondeur'' dans sa stratégie de sécurité incendie ?', 'La défense en profondeur (defense in depth) est un principe fondamental de la sécurité des systèmes complexes, applicable à la sécurité incendie : au lieu de miser sur une seule mesure parfaite, on superpose plusieurs barrières indépendantes dont chacune peut compenser la défaillance des autres. Pour la sécurité incendie : prévention (interdire les sources d''ignition, utiliser des matériaux peu inflammables, former le personnel) ; détection précoce (SSI avec détection automatique, rondes, surveillance humaine) ; confinement (compartimentage coupe-feu, portes CF, désenfumage pour ralentir la progression) ; extinction active (sprinklers, RIA, intervention SSIAP) ; évacuation (dégagements conformes, balisage, alarme). Si la prévention échoue (feu allumé), la détection prend le relais ; si la détection est lente, le compartimentage donne du temps, etc. Cette approche est plus robuste qu''une seule mesure parfaite.', 1, null::integer[], array['theme1','seq1']::text[], 35),
('ssiap3-q129', 'ssiap3-partie1', 'quiz', 'Quels sont les rôles respectifs du SSIAP 3 et de l''inspection du travail en matière de sécurité incendie dans les locaux de travail ?', 'La sécurité incendie dans les locaux de travail relève de deux cadres réglementaires distincts : le code du travail (articles R4227-1 à R4227-57) impose à l''employeur des obligations en matière d''évacuation, de formation du personnel, de matériels d''extinction — l''inspection du travail vérifie le respect de ces obligations et peut mettre en demeure l''employeur ou dresser un procès-verbal en cas d''infraction grave ; le règlement de sécurité ERP (si les locaux sont accessibles au public) relève de la commission de sécurité. Le SSIAP 3 met en œuvre opérationnellement les deux réglementations. Ces deux cadres sont cumulatifs et non exclusifs. L''inspection du travail est une autorité de contrôle externe indépendante, pas une autorité hiérarchique du SSIAP 3.', 1, null::integer[], array['theme2','seq2']::text[], 36),
('ssiap3-q132', 'ssiap3-partie1', 'quiz', 'Quelle est la différence entre un ''scénario conventionnel'' et un ''scénario majorant'' dans une étude de sécurité incendie par ISI ?', 'Dans une étude ISI (Ingénierie de Sécurité Incendie), le choix des scénarios est déterminant pour la robustesse des conclusions : le scénario conventionnel est un feu de référence paramétré selon des normes ou des prescriptions réglementaires (courbe ISO 834 pour les structures, feu de calcul EN 1991-1-2 pour les éléments structurels) — il permet la comparaison entre études et la conformité réglementaire ; le scénario majorant (ou scénario du pire cas) est le feu le plus sévère physiquement plausible dans le local considéré (localisation, combustibles, ouvertures les plus défavorables) — il est utilisé pour s''assurer que les systèmes de protection fonctionnent même dans les conditions les plus difficiles. Un système validé sur le scénario majorant est plus robuste qu''un système validé uniquement sur un scénario conventionnel.', 1, null::integer[], array['theme3','seq3']::text[], 37),
('ssiap3-q139', 'ssiap3-partie1', 'quiz', 'La résistance au feu minimale des planchers d''un IGH de type GHB (bureaux) est :', 'La résistance au feu des planchers dans les IGH est définie par le règlement de sécurité IGH. Pour les IGH de type GHB (immeubles de grande hauteur à usage de bureaux), la résistance au feu des planchers est fixée à REI 120 (stabilité, étanchéité et isolation thermique pendant 120 minutes). Aucune des valeurs proposées (REI 60, REI 90, REI 180) ne correspond à l''exigence réglementaire de REI 120.', 0, null::integer[], array['theme2','seq2']::text[], 38),
('ssiap3-q144', 'ssiap3-partie1', 'quiz', 'Le SSIAP 3 doit expliquer à la direction les implications d''un avis favorable avec réserves de la commission de sécurité. Que signifie concrètement cet avis ?', 'Un avis favorable avec réserves de la commission de sécurité est une décision nuancée : l''établissement est autorisé à ouvrir au public (contrairement à l''avis défavorable qui bloque l''ouverture) ; les réserves sont des observations assorties d''une obligation de mise en conformité dans un délai précisé par la commission (généralement 3 à 6 mois pour les réserves mineures, parfois moins pour les réserves importantes) ; le non-respect des délais peut conduire à une nouvelle visite et à une remise en cause de l''autorisation d''ouverture (avis défavorable rétroactif) ; le SSIAP 3 doit tracker les réserves, planifier leur levée et fournir les justificatifs à la commission dans les délais impartis. Les réserves ne sont pas purement indicatives — elles ont une force contraignante.', 1, null::integer[], array['theme2','seq2']::text[], 39)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap3-q58','ssiap3-q59','ssiap3-q61','ssiap3-q64','ssiap3-q69','ssiap3-q78','ssiap3-q81','ssiap3-q90','ssiap3-q92','ssiap3-q97','ssiap3-q99','ssiap3-q102','ssiap3-q103','ssiap3-q104','ssiap3-q114','ssiap3-q126','ssiap3-q129','ssiap3-q132','ssiap3-q139','ssiap3-q144');
commit;

-- ===== ssiap3-partie1-sub03.sql =====
begin;
-- SSIAP 3 — Réglementation et expertise avancée (partie 1, sub 3/3, 14 cc_questions)
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap3-q149', 'ssiap3-partie1', 'quiz', 'Quelle est la portée de la responsabilité du SSIAP 3 concernant la sécurité incendie des locaux techniques non accessibles au public (chaufferies, locaux électriques, archives) ?', 'La responsabilité du SSIAP 3 couvre l''intégralité de l''établissement sans exception de zone : les locaux techniques (chaufferies, TGBT, locaux SSI, archives, stockages) présentent souvent des risques incendie plus élevés que les zones publiques (charge calorifique élevée, présence d''équipements sous tension, stockages de produits inflammables) et leur sinistre peut rapidement se propager aux zones publiques adjacentes ; ils doivent faire l''objet de rondes régulières (même si l''accès est restreint), de procédures d''intervention spécifiques (risques électriques, présence de produits dangereux) et de vérifications périodiques de leurs équipements de sécurité propres (extincteurs spécifiques, détection adaptée). Le partage de responsabilité avec le service maintenance ne diminue pas la responsabilité du SSIAP 3 — les deux services ont des responsabilités complémentaires.', 1, null::integer[], array['theme2','seq2']::text[], 40),
('ssiap3-q158', 'ssiap3-partie1', 'quiz', 'Le SSIAP 3 doit évaluer la nécessité d''un local de mise en sécurité (LMS ou zone de refuge) dans son ERP. Dans quels cas ce dispositif est-il obligatoire ou fortement recommandé ?', 'Les zones de refuge (anciennement LMS - Locaux de Mise en Sécurité) sont des espaces coupe-feu permettant aux personnes ne pouvant pas emprunter les escaliers (PMR, blessés, personnes âgées dépendantes) d''attendre en sécurité l''arrivée des secours. Leur obligation dépend du type d''établissement : dans les IGH (obligatoire réglementairement par niveaux) ; dans les ERP neufs accessibles aux PMR comportant des niveaux en hauteur (la réglementation accessibilité impose des espaces d''attente sécurisés depuis 2007) ; fortement recommandés dans tout ERP où l''évacuation totale vers l''extérieur est physiquement difficile pour certains occupants (hôpitaux, EHPAD, établissements psychiatriques). Ces espaces doivent être coupe-feu, disposer d''un moyen de communication avec les secours et être signalés.', 1, null::integer[], array['theme1','seq1']::text[], 41),
('ssiap3-q161', 'ssiap3-partie1', 'multiple-select', 'Le SSIAP 3 doit conduire une analyse de risques incendie selon la méthode EBIOS Risk Manager adaptée à la sécurité incendie. Quelles étapes composent cette démarche ? (plusieurs réponses)', 'La méthode EBIOS Risk Manager (Expression des Besoins et Identification des Objectifs de Sécurité), adaptée à la sécurité incendie, suit une démarche structurée : identification des valeurs métier et biens essentiels (personnes, collections, données, équipements critiques — ce qu''on cherche à protéger) ; recensement des sources de menace (défaillances électriques, comportement imprudent des occupants, malveillance, catastrophe naturelle — qui ou quoi peut générer un sinistre) ; élaboration des scénarios de risque (combinaison source de menace × bien essentiel avec estimation de la vraisemblance et de la gravité) ; définition des mesures de traitement pour ramener le risque à un niveau acceptable (mesures techniques, organisationnelles, humaines). Le calcul exact du coût financier d''un sinistre est une démarche assurantielle complémentaire mais distincte de l''analyse de risques.', null, array[0,1,2,3]::integer[], array['theme3','seq3']::text[], 42),
('ssiap3-q165', 'ssiap3-partie1', 'quiz', 'Quelles sont les obligations du SSIAP 3 en cas de découverte d''une non-conformité grave lors d''une vérification périodique par un organisme agréé ?', 'La découverte d''une non-conformité grave lors d''une vérification périodique impose une réaction immédiate et documentée : information de la direction (la direction doit être informée des risques juridiques et financiers liés à la non-conformité — elle doit arbitrer l''allocation des ressources pour la corriger) ; mesures immédiates selon la gravité (si la non-conformité crée un risque immédiat : mesures compensatoires temporaires telles que rondes renforcées, réduction de l''occupation du local, inhibition contrôlée ; si la non-conformité est moins urgente : planification des travaux) ; consignation dans le registre de sécurité (traçabilité obligatoire de la découverte et des actions engagées) ; planification de la levée avec délai réaliste et engagements financiers. Demander à l''organisme de ne pas mentionner une non-conformité est une tentative de falsification de document officiel — illégale et éthiquement inacceptable.', 1, null::integer[], array['theme2','seq2']::text[], 43),
('ssiap3-q166', 'ssiap3-partie1', 'multiple-select', 'Le SSIAP 3 doit évaluer l''impact d''une modification de la destination d''un local (transformation d''un bureau en salle de réunion de 50 personnes) sur la sécurité incendie. Quels éléments vérifie-t-il ? (plusieurs réponses)', 'Une modification de destination de local, même apparemment mineure, peut avoir des impacts significatifs sur la sécurité incendie : dégagements (50 personnes dans une salle de réunion nécessitent plus de largeur de sortie qu''un bureau individuel — vérification du calcul UP) ; désenfumage (un local de réunion > 300 m² ou > 100 personnes peut nécessiter un désenfumage que le bureau ne nécessitait pas) ; dossier modificatif (si la modification change le type ou la catégorie ERP ou affecte significativement les installations de sécurité, un dossier doit être soumis à la commission avant travaux) ; charge calorifique (les salles de réunion ont souvent plus de matériaux combustibles que les bureaux : chaises capitonnées, tentures, écrans, câblages) ; classification ERP (si l''effectif augmente significativement, cela peut faire passer l''ERP dans une catégorie supérieure avec des exigences renforcées). Toutes ces vérifications sont nécessaires.', null, array[0,1,2,3,4]::integer[], array['theme2','seq2']::text[], 44),
('ssiap3-q168', 'ssiap3-partie1', 'quiz', 'Dans le cadre d''une approche de sécurité incendie basée sur les performances (ISI), comment le SSIAP 3 démontre-t-il l''équivalence d''une solution alternative au prescriptif réglementaire ?', 'La démonstration d''équivalence en ISI est un processus technique rigoureux reconnu par la réglementation française (article GN 4 du règlement ERP et circulaire d''application) : modélisation des scénarios de sinistre représentatifs du bâtiment (localisation, charge calorifique, occupants) par simulation numérique (FDS pour la thermique des fumées, logiciels d''évacuation pour le RSET) ; calcul RSET (temps nécessaire à l''évacuation sûre) vs ASET (temps disponible avant conditions intenables) avec vérification que RSET < ASET avec marge de sécurité ; démonstration que tous les objectifs de sécurité réglementaires sont atteints (ou dépassés) par la solution proposée ; validation par un bureau d''études ISI spécialisé et indépendant, puis par un organisme de contrôle agréé avant soumission à la commission de sécurité. Une copie d''étude non adaptée ne tient pas compte des spécificités du bâtiment et est inacceptable.', 1, null::integer[], array['theme3','seq3']::text[], 45),
('ssiap3-q173', 'ssiap3-partie1', 'quiz', 'La durée minimale de conservation du registre de sécurité d''un ERP est :', 'La réglementation ne fixe pas explicitement une durée minimale de conservation du registre de sécurité dans le règlement ERP. Cependant, les délais de prescription pénale (jusqu''à 6 ans pour les délits, 20 ans pour les crimes) et civile guident la pratique professionnelle : le registre doit être conservé au minimum pendant la durée d''exploitation de l''établissement et plusieurs années après. Les durées de 1 an, 5 ans ou 10 ans proposées ne correspondent pas à une norme réglementaire précise — la bonne pratique est de conserver le registre sans limite de durée tant que l''établissement est en activité.', 2, null::integer[], array['theme2','seq2']::text[], 46),
('ssiap3-q175', 'ssiap3-partie1', 'quiz', 'Comment le SSIAP 3 prend-il en compte les risques spécifiques liés à la présence d''un restaurant avec cuisine ouverte sur la salle dans un ERP de type N de grande capacité ?', 'Une cuisine ouverte sur la salle dans un restaurant de grande capacité présente des risques spécifiques : l''absence de paroi CF entre la cuisine et la salle signifie qu''un incendie de cuisson peut immédiatement se propager vers le public sans barrière physique — la stratégie de sécurité repose alors sur la détection et l''extinction rapide plutôt que sur le compartimentage ; le système d''extraction des graisses (hotte, conduits) est un point critique (les dépôts de graisses dans les conduits non nettoyés peuvent s''enflammer et propager le feu en toiture) — vérification de la fréquence de nettoyage et des certifications ; les extincteurs de classe F (saponifiants) doivent être accessibles immédiatement par les cuisiniers pour faire face à un feu de friteuse ou de sauteuse ; un système d''extinction automatique dans la hotte est fortement recommandé voire obligatoire selon la configuration. La cuisine ouverte est admise si les mesures compensatoires sont en place.', 1, null::integer[], array['theme1','seq1']::text[], 47),
('ssiap3-q179', 'ssiap3-partie1', 'multiple-select', 'Le SSIAP 3 est sollicité pour expertiser la sécurité incendie d''un immeuble mixte comportant des logements au-dessus d''un centre commercial. Quelles problématiques spécifiques à cette configuration doit-il analyser ? (plusieurs réponses)', 'Un immeuble mixte ERP/habitation est soumis aux deux réglementations simultanément, créant des interfaces complexes : application cumulative des deux codes (CCH pour la partie habitation, règlement ERP pour la partie commerciale) — le compartimentage entre les deux parties doit satisfaire aux deux réglementations, en retenant la plus contraignante ; plancher de séparation (la dalle entre la partie commerciale et les logements doit avoir une résistance au feu garantissant que le feu de la partie commerciale — à charge calorifique élevée — ne se propage pas aux logements) ; système d''alarme différencié (l''alarme du centre commercial doit pouvoir alerter les résidents en cas d''incendie se propageant vers leur partie — les résidents peuvent être endormis la nuit) ; coordination des procédures d''évacuation (un feu dans le centre commercial peut nécessiter l''évacuation des résidents et vice versa — les procédures doivent être connues de toutes les parties). Les deux réglementations s''appliquent cumulativement.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 48),
('ssiap3-q187', 'ssiap3-partie1', 'quiz', 'Dans le cadre d''une mission de conseil, le SSIAP 3 est sollicité pour évaluer la sécurité incendie d''un bâtiment existant en vue de sa vente. Quels éléments essentiels doit couvrir son audit ?', 'Un audit de due diligence sécurité incendie avant cession d''un ERP est une mission à forte valeur ajoutée : état de conformité des installations (SSI en catégorie, fonctionnement, date de dernière vérification ; extincteurs, conformité et périodicité ; désenfumage, essais ; éclairage de sécurité) — identification des équipements non conformes ou obsolètes ; état documentaire (registre de sécurité complet et à jour, rapports de vérifications périodiques, historique des visites de commission, procès-verbaux de réception) ; analyse des risques cachés (non-conformités non signalées, modifications non autorisées, équipements inhibés) ; estimation des travaux de mise en conformité (chiffrage pour les négociations de prix de cession ou les conditions suspensives). Cet audit protège l''acquéreur contre les surprises post-acquisition et aide le cédant à valoriser les investissements réalisés.', 1, null::integer[], array['theme3','seq3']::text[], 49),
('ssiap3-q189', 'ssiap3-partie1', 'quiz', 'Quelle est la procédure du SSIAP 3 lorsqu''il reçoit une mise en demeure préfectorale de fermeture d''un ERP pour non-conformité grave ?', 'Une mise en demeure préfectorale de fermeture est une décision administrative exécutoire : l''établissement doit fermer au public jusqu''à levée de la mise en demeure. Le SSIAP 3 doit : informer immédiatement la direction (décision stratégique d''entreprise avec impact commercial majeur) ; analyser précisément les motifs (chaque point doit être traité — certains peuvent être levés rapidement, d''autres nécessitent des travaux) ; engager en urgence les actions correctives priorisées selon leur impact sur la sécurité et la faisabilité dans les délais ; constituer un dossier documenté des actions réalisées (photos, PV d''essais, attestations) ; demander une contre-visite à la commission ou au préfet dès que les points sont levés. Le délai est critique car chaque jour de fermeture génère des pertes d''exploitation. La contestation sans action est inefficace.', 1, null::integer[], array['theme2','seq2']::text[], 50),
('ssiap3-q190', 'ssiap3-partie1', 'quiz', 'Le classement au feu des produits de construction en Europe utilise les Euroclasses. La classe la plus performante est :', 'Le système de classification européen des produits de construction selon leur réaction au feu (Euroclasses) comporte les classes A1, A2, B, C, D, E et F par ordre décroissant de performance. La classe A1 est la plus performante (matériaux incombustibles comme le béton, l''acier, la brique — aucune contribution au feu). La classe A2 est la seconde meilleure classe. La réponse ''A1'' (la plus performante) n''est pas proposée dans les options.', 3, null::integer[], array['theme1','seq1']::text[], 51),
('ssiap3-q195', 'ssiap3-partie1', 'multiple-select', 'Le SSIAP 3 doit gérer la sécurité incendie d''un établissement de nuit (discothèque, ERP de type P) en tenant compte des spécificités de ce type d''exploitation. Quels risques spécifiques doit-il analyser ? (plusieurs réponses)', 'Les établissements de nuit de type P (discothèques, salles de danse) présentent des risques spécifiques cumulatifs : obscurité + forte densité (la combinaison de l''obscurité et de la densité humaine crée des conditions propices à la panique et aux bousculades lors d''une évacuation — les dégagements doivent être sur-dimensionnés et le balisage lumineux très visible) ; effets spéciaux (la fumée artificielle peut déclencher le SSI ou au contraire masquer la fumée réelle — les détecteurs doivent être adaptés ; les stroboscopes peuvent provoquer des crises chez les épileptiques) ; alcool (la réactivité et le comportement rationnel sont réduits — l''encadrement humain de l''évacuation est crucial) ; niveau sonore (100 à 110 dB en discothèque — une alarme standard à 85 dB est inaudible — des dispositifs d''alarme spécifiques à très haute puissance ou des coupures musicales automatiques sont nécessaires). Les discothèques sont bien soumises à la réglementation ERP type P.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 52),
('ssiap3-q197', 'ssiap3-partie1', 'multiple-select', 'Le SSIAP 3 doit concevoir le dispositif SSIAP pour un ERP de type J (établissement pour personnes âgées dépendantes - EHPAD) de 120 résidents. Quelles spécificités réglementaires et opérationnelles s''appliquent ? (plusieurs réponses)', 'Un EHPAD de type J présente des contraintes spécifiques majeures : la détection automatique généralisée est obligatoire (chambres incluses) pour compenser l''impossibilité des résidents à percevoir et réagir à une alarme ; l''évacuation horizontale progressive est la stratégie réglementaire (les résidents sont déplacés vers les compartiments coupe-feu adjacents au même niveau plutôt qu''évacués vers l''extérieur — médicalement et physiquement plus réalisable) ; l''effectif SSIAP nocturne doit être dimensionné pour la vulnérabilité des résidents endormis (certains ne peuvent pas être réveillés par l''alarme sonore) ; la formation du personnel soignant est prioritaire car ils sont les premiers intervenants auprès des résidents. L''évacuation totale de 120 résidents dépendants vers l''extérieur en 3 minutes est physiquement impossible — ce n''est pas l''objectif réglementaire.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 53)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap3-q149','ssiap3-q158','ssiap3-q161','ssiap3-q165','ssiap3-q166','ssiap3-q168','ssiap3-q173','ssiap3-q175','ssiap3-q179','ssiap3-q187','ssiap3-q189','ssiap3-q190','ssiap3-q195','ssiap3-q197');
commit;

-- ===== ssiap3-partie2-sub01.sql =====
begin;
-- SSIAP 3 — Direction du service - Management stratégique (partie 2, sub 1/4, 20 cc_questions)
values ('ssiap3-partie2', 3, 'Direction du service - Management stratégique', '80 cc_questions', '🏛️', 'from-blue-600 to-indigo-700', 1, true)
on conflict (id) do update set title=excluded.title, subtitle=excluded.subtitle, icon=excluded.icon, color=excluded.color, display_order=excluded.display_order;
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap3-q7', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 doit établir le budget annuel du service de sécurité incendie. Quels postes de dépenses doit-il intégrer ? (plusieurs réponses possibles)', 'Le budget du service sécurité incendie d''un SSIAP 3 couvre : les contrats de maintenance des équipements (SSI annuel, extincteurs, RIA, colonnes sèches, sprinklers, BAES - coûts récurrents prévisibles) ; les vérifications périodiques réglementaires par organismes agréés (électricité, gaz, ascenseurs, SSI - coûts planifiables sur l''année) ; les formations et recyclages du personnel (MAC SSIAP tous les 3 ans, PSE1, formations spécifiques, nouveaux recrutements) ; le renouvellement des équipements (extincteurs réformés, détecteurs en fin de vie, BAES à remplacer). Ces dépenses doivent être argumentées avec les obligations réglementaires pour être acceptées par la direction. Les frais de communication commerciale relèvent d''un autre budget.', null, array[0,1,2,3]::integer[], array['theme1','seq1','Budget et ressources du service','Gestion du service']::text[], 0),
('ssiap3-q8', 'ssiap3-partie2', 'quiz', 'Comment le SSIAP 3 doit-il piloter la politique de prévention des incendies dans un ERP, au-delà de la seule réponse aux sinistres ?', 'La prévention est au cœur de la mission du SSIAP 3, qui doit développer une approche proactive et globale : audits réguliers des risques incendie (identification des zones à risque, matériaux défaillants, comportements dangereux) ; formation de tous les occupants (pas seulement le personnel SSIAP : chaque salarié doit connaître les consignes de base) ; suivi rigoureux des non-conformités (liste, délais de résolution, escalade à la direction si blocage) ; analyse systématique des retours d''expérience après chaque incident ou exercice ; communication proactive avec la direction pour justifier les investissements de sécurité et anticiper les besoins. Un SSIAP 3 qui ne fait que réagir sans anticiper laisse son établissement vulnérable.', 1, null::integer[], array['theme2','seq2','Stratégie de prévention incendie','Politique de prévention']::text[], 1),
('ssiap3-q9', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 doit définir l''organisation du service SSIAP pour un centre commercial de 50 000 m². Quels critères déterminent les effectifs nécessaires ? (plusieurs réponses possibles)', 'Le dimensionnement du service SSIAP est régi par l''instruction technique du 22 octobre 2019 (et l''arrêté du 2 mai 2005) selon des critères précis : la superficie développée et le nombre de niveaux (plus un bâtiment est grand et haut, plus la surveillance nécessite d''agents) ; l''effectif maximal du public autorisé (le ratio agents/public est encadré) ; la catégorie et le type d''ERP (un ERP de type M = magasin commercial est régi différemment d''un type O = hôtel) ; les horaires (les règles diffèrent entre les périodes d''exploitation avec public, les périodes de fermeture avec personnel et les périodes de nuit sans public). Le nombre de restaurants est un facteur de risque mais n''est pas un critère réglementaire direct pour les effectifs SSIAP.', null, array[0,1,2,3]::integer[], array['theme3','seq1','Dimensionnement des équipes SSIAP','Gestion du service']::text[], 2),
('ssiap3-q10', 'ssiap3-partie2', 'quiz', 'Le SSIAP 3 est sollicité pour contribuer à un plan de continuité d''activité (PCA) de l''établissement. Quelle est sa contribution spécifique ?', 'Le Plan de Continuité d''Activité (PCA) vise à maintenir ou reprendre rapidement l''activité après un sinistre majeur. Le SSIAP 3 contribue en expert sécurité incendie : identification des scénarios de sinistre pouvant interrompre l''activité (incendie localisé, sinistre généralisé, dégâts des eaux suite à intervention sprinkler) et leur probabilité ; définition des procédures de retour à la normale (inspection post-sinistre, remise en service des équipements, conditions de réouverture) ; analyse des zones critiques dont l''indisponibilité impacterait le plus l''activité et des mesures de protection renforcées à prévoir. Cette contribution transverse positionne le SSIAP 3 comme un acteur stratégique de la résilience de l''établissement.', 1, null::integer[], array['theme2','seq2','Stratégie de prévention incendie','Politique de prévention']::text[], 3),
('ssiap3-q11', 'ssiap3-partie2', 'quiz', 'Comment le SSIAP 3 justifie-t-il auprès d''une direction réticente un investissement important dans la mise à niveau du SSI ?', 'Pour convaincre une direction réticente, le SSIAP 3 utilise un argumentaire structuré : présentation chiffrée de l''analyse coût/risque (l''investissement dans le SSI est toujours inférieur au coût potentiel d''un sinistre grave : pertes matérielles, coût d''une interruption d''activité, primes d''assurance, responsabilité pénale de la direction, atteinte à l''image) ; mise en évidence des obligations légales et des risques juridiques en cas de non-conformité ; benchmarking avec des sinistres survenus dans des établissements similaires. En dernier recours, si la direction maintient son refus, le SSIAP 3 doit formaliser son avis défavorable par écrit (pour protéger sa propre responsabilité) et peut saisir la commission de sécurité si la situation présente un danger grave.', 1, null::integer[], array['theme1','seq1','Budget et ressources du service','Gestion du service']::text[], 4),
('ssiap3-q30', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 doit évaluer un prestataire de maintenance du SSI dans le cadre d''un renouvellement de contrat. Sur quels critères base-t-il son évaluation ? (plusieurs réponses possibles)', 'L''évaluation d''un prestataire de maintenance SSI ne doit pas se réduire au prix. Le SSIAP 3 analyse : les qualifications (certification Q18 ou équivalent de l''entreprise et de ses techniciens, assurance RC professionnelle) ; les garanties de délais d''intervention (un SSI défaillant la nuit nécessite une intervention rapide : astreinte 24h/24 contractualisée avec délais garantis) ; la qualité des rapports de vérification (exhaustivité, clarté, recommandations argumentées, photos des anomalies) ; les références vérifiables dans des établissements comparables (complexité similaire du SSI). Le seul critère du prix le plus bas peut conduire à choisir un prestataire sous-qualifié dont les vérifications bâclées ne détecteront pas les défauts réels. Le mieux-disant qualitatif prime sur le moins-disant financier pour des équipements de sécurité vitaux.', null, array[0,1,2,4]::integer[], array['theme5','seq3','Sélection et évaluation des prestataires','Gestion des prestataires']::text[], 5),
('ssiap3-q31', 'ssiap3-partie2', 'quiz', 'Comment le SSIAP 3 intègre-t-il la dimension RSE (Responsabilité Sociétale des Entreprises) dans la gestion de son service ?', 'La RSE (Responsabilité Sociétale des Entreprises) croise de manière croissante les métiers de la sécurité : dimension environnementale : réduction des fausses alarmes (chaque intervention des pompiers consomme des ressources et génère du CO2), choix d''agents extincteurs moins polluants (remplacement des halons, agents propres pour les gaz d''extinction, recyclage des extincteurs usagés) ; dimension sociale : bien-être des agents (gestion de la fatigue, risques psychosociaux, formation continue), intégration de personnes en situation de handicap dans l''équipe ; dimension de gouvernance : transparence des rapports de sécurité, communication honnête sur les non-conformités avec la direction et les parties prenantes. Le SSIAP 3 peut valoriser ces pratiques dans le rapport RSE de l''établissement et contribuer à la politique développement durable.', 1, null::integer[], array['theme6','seq4','RSE appliquée à la sécurité incendie','RSE et développement durable']::text[], 6),
('ssiap3-q32', 'ssiap3-partie2', 'quiz', 'Un grand groupe hôtelier souhaite standardiser les pratiques SSIAP dans ses 50 établissements répartis sur tout le territoire. Quel rôle le SSIAP 3 de la direction générale peut-il jouer ?', 'Le SSIAP 3 au niveau d''un groupe multi-sites peut jouer un rôle de coordinateur stratégique : définir un référentiel groupe (procédures communes, standards de formation, indicateurs de performance, chartes de maintenance) qui assure un niveau de sécurité homogène et professionnel à travers tout le réseau ; s''assurer que ce référentiel est compatible avec les réglementations locales (un ERP en zone de montagne ou un IGH en zone sismique ont des exigences spécifiques que le référentiel national doit permettre d''intégrer) ; animer la communauté des SSIAP 3 de sites (réseau d''échange, partage des retours d''expérience entre établissements) ; auditer les sites pour vérifier l''application du référentiel. Imposer un POI identique sans adaptation serait une erreur grave (chaque bâtiment a ses spécificités).', 1, null::integer[], array['theme7','seq5','Coordination SSIAP à l''échelle d''un groupe','Management multi-sites']::text[], 7),
('ssiap3-q33', 'ssiap3-partie2', 'quiz', 'Le SSIAP 3 doit gérer un conflit entre ses obligations réglementaires de sécurité et les impératifs économiques de l''établissement (réduction des coûts imposée). Comment gère-t-il cette tension ?', 'La gestion de la tension entre impératifs économiques et obligations de sécurité est une situation fréquente et délicate pour le SSIAP 3 : documentation formelle des risques induits par les réductions demandées (exemple : réduire un agent de nuit sous le minimum réglementaire crée une non-conformité et un risque grave documenté) ; proposition d''alternatives permettant de satisfaire les deux objectifs (optimisation des plannings, mutualisation des ressources, renégociation des contrats de maintenance, priorisation des investissements) ; si la direction maintient une décision dangereuse malgré l''avis contraire du SSIAP 3, ce dernier doit formuler son avis contraire par écrit (courriel recommandé) pour protéger sa propre responsabilité pénale. Céder sans résistance expose le SSIAP 3 à une mise en cause en cas de sinistre ultérieur.', 1, null::integer[], array['theme8','seq1','Gestion des conflits direction/sécurité','Gestion du service']::text[], 8),
('ssiap3-q40', 'ssiap3-partie2', 'quiz', 'Comment le SSIAP 3 contribue-t-il à la culture sécurité incendie de l''ensemble des occupants de son établissement ?', 'La culture sécurité incendie est un enjeu collectif que le SSIAP 3 doit développer sur l''ensemble du site : formations régulières adaptées aux différents profils (employés, résidents, visiteurs fréquents) avec des messages clairs et mémorisables ; affichages pédagogiques (plans d''évacuation lisibles, pictogrammes, numéros d''urgence) régulièrement entretenus et mis à jour ; exercices d''évacuation organisés à des fréquences permettant la mémorisation des procédures (bi-annuels au minimum) ; communication transparente sur les incidents passés et les leçons apprises ; intégration de la sécurité dans l''accueil de chaque nouvel arrivant. Une culture sécurité forte réduit le temps de réaction lors d''un sinistre réel, limite la panique et rend l''ensemble du dispositif plus efficace. Sanctionner sans expliquer génère la peur et tue la culture.', 1, null::integer[], array['theme2','seq2','Stratégie de prévention incendie','Politique de prévention']::text[], 9),
('ssiap3-q51', 'ssiap3-partie2', 'quiz', 'Le SSIAP 3 gère un service de 12 agents SSIAP 1 et 3 SSIAP 2. Comment calcule-t-il les besoins en formation continue annuelle de son équipe ?', 'Le plan de formation du SSIAP 3 doit dépasser la simple obligation de recyclage réglementaire (SSIAP 1 : recyclage tous les 3 ans, SSIAP 2 et 3 : idem). Il doit intégrer : les lacunes identifiées lors des exercices d''évacuation et des audits internes (si les guide-files ne maîtrisent pas la procédure de fermeture des portes CF, une formation ciblée s''impose) ; les évolutions des installations (nouveau SSI, nouveau système de désenfumage) ; les retours d''expérience d''incidents survenus dans l''établissement ou dans des établissements comparables. Cette approche différencie un management sécurité proactif d''une simple gestion administrative.', 1, null::integer[], array['theme1','seq1']::text[], 10),
('ssiap3-q52', 'ssiap3-partie2', 'quiz', 'Quelle est la responsabilité du SSIAP 3 en matière de sous-traitance de la maintenance des installations de sécurité incendie ?', 'Le SSIAP 3 reste responsable de l''état des installations même s''il sous-traite leur maintenance. Ses obligations : vérifier les qualifications des prestataires (qualification Q18 APSAD pour les entreprises de maintenance SSI, certifications spécifiques pour les extincteurs, sprinklers, etc.) ; définir contractuellement les niveaux de service (délais d''intervention, compte-rendus d''intervention, gestion des pièces de rechange) ; contrôler la qualité des interventions et leurs comptes-rendus ; signaler les défauts persistants. En cas de sinistre, si une installation défaillante mal entretenue est en cause, la responsabilité du SSIAP 3 qui a signé les bons d''intervention peut être engagée.', 1, null::integer[], array['theme1','seq1']::text[], 11),
('ssiap3-q53', 'ssiap3-partie2', 'quiz', 'Le SSIAP 3 doit justifier à la direction générale un investissement de 180 000 € pour la mise à niveau du SSI. Quelle approche adopte-t-il ?', 'Pour convaincre une direction générale d''un investissement sécurité important, le SSIAP 3 doit adopter un langage business : quantifier le coût de la non-conformité (amende pénale jusqu''à 150 000 € pour une personne morale, fermeture administrative pouvant générer des pertes d''exploitation importantes, coût d''un sinistre — reconstruction, responsabilité civile, atteinte à l''image) versus le coût de la mise en conformité. Un plan de financement pluriannuel (investissement échelonné) peut rendre le montant plus acceptable. Imposer sans justifier génère de la résistance. Attendre la commission est risqué et démontre un manque de proactivité.', 1, null::integer[], array['theme2','seq2']::text[], 12),
('ssiap3-q54', 'ssiap3-partie2', 'multiple-select', 'Quelles sont les caractéristiques d''un bon indicateur de performance (KPI) pour un service SSIAP ? (plusieurs réponses)', 'Un bon KPI pour un service SSIAP doit être : mesurable objectivement (pas d''appréciation subjective : taux de rondes effectuées/planifiées, délai moyen de levée de doute, taux d''équipements conformes) ; lié aux objectifs de sécurité (le taux de fausses alarmes est pertinent car elles détériorent la réactivité du personnel) ; compréhensible par la direction pour qu''elle puisse décider en connaissance de cause ; permettant une analyse de tendance (l''évolution dans le temps est plus informative qu''une valeur instantanée). Les indicateurs qualitatifs (qualité perçue des rondes par les managers, culture sécurité du personnel) sont aussi pertinents même s''ils sont plus difficiles à mesurer.', null, array[0,1,2,4]::integer[], array['theme2','seq2']::text[], 13),
('ssiap3-q55', 'ssiap3-partie2', 'quiz', 'Comment le SSIAP 3 organise-t-il la continuité du service lors de congés simultanés de plusieurs agents SSIAP 2 ?', 'La continuité du service SSIAP est une obligation réglementaire permanente : les effectifs minimaux définis par l''arrêté d''exploitation de l''ERP doivent être maintenus 365 jours/an. Le SSIAP 3 doit : planifier les congés en amont pour éviter les chevauchements incompatibles avec les effectifs minimaux ; identifier et former des remplaçants qualifiés SSIAP 2 aux spécificités de l''établissement (SSI, POI, procédures locales) — un SSIAP 2 qualifié mais non formé à l''établissement est insuffisant ; documenter les procédures essentielles pour réduire le temps d''appropriation des remplaçants. Demander à un SSIAP 1 d''assurer les responsabilités SSIAP 2 est une non-conformité réglementaire.', 1, null::integer[], array['theme1','seq1']::text[], 14),
('ssiap3-q56', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 doit mener un entretien annuel d''évaluation avec un SSIAP 2. Quels axes doit couvrir cet entretien ? (plusieurs réponses)', 'L''entretien annuel d''évaluation est un outil de management RH qui doit couvrir : le bilan objectif des missions et des objectifs fixés l''année précédente (atteints, partiellement atteints, non atteints avec analyse des causes) ; les besoins de formation identifiés conjointement (compétences techniques à renforcer, évolutions réglementaires) ; les aspirations professionnelles de l''agent (le SSIAP 3 peut identifier des profils à fort potentiel ou des risques de départ) ; les objectifs de la période suivante (SMART : spécifiques, mesurables, atteignables, réalistes, temporels). Le rappel menaçant des sanctions n''est pas une composante d''un entretien d''évaluation constructif — les sanctions disciplinaires relèvent de procédures séparées.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 15),
('ssiap3-q57', 'ssiap3-partie2', 'multiple-select', 'Dans un contexte de transformation digitale, comment le SSIAP 3 intègre-t-il les outils numériques dans la gestion de son service ? (plusieurs réponses)', 'La transformation digitale offre des outils utiles au SSIAP 3 : supervision à distance via GTB/SCADA (utile pour les campus multi-bâtiments ou multi-sites, permet une vision centralisée des états du SSI) ; GMAO pour la planification et le suivi des vérifications périodiques (alertes automatiques d''échéances, historique complet) ; rondes NFC/QR code avec rapport automatique (preuve de passage, détection des anomalies directement saisie sur terminal mobile, transmission instantanée) ; tableaux de bord KPI partagés avec la direction. En revanche, aucun outil numérique ne remplace la présence humaine réglementairement requise — les capteurs connectés sont des outils d''aide, pas des substituts aux agents SSIAP.', null, array[0,1,2,4]::integer[], array['theme2','seq2']::text[], 16),
('ssiap3-q60', 'ssiap3-partie2', 'quiz', 'Comment le SSIAP 3 prépare-t-il son service à faire face à un sinistre pendant un grand événement exceptionnel (concert, salon, gala avec 2 000 personnes) ?', 'Un grand événement exceptionnel nécessite une adaptation spécifique du dispositif SSIAP : renforcement des effectifs proportionnel à l''affluence et à la configuration (file d''attente, zone scène, gradins, sorties) ; adaptation du POI (point de rassemblement adapté à 2 000 personnes, procédures de gestion des foules, coordination avec l''organisateur et ses agents de sûreté) ; briefing complet de tous les agents (dispositions particulières, postes, signaux de communication) ; postes fixes supplémentaires aux points de concentration de public (issues, bar, scène) ; communication redondante (radio, téléphone, zone morte identifiée). La délégation totale à l''organisateur est inadmissible — le SSIAP 3 reste responsable de la sécurité incendie.', 1, null::integer[], array['theme2','seq2']::text[], 17),
('ssiap3-q62', 'ssiap3-partie2', 'quiz', 'Le SSIAP 3 supervise un audit de sécurité incendie réalisé par un organisme externe. Quelle est son attitude optimale lors de cet audit ?', 'Un audit externe est une opportunité d''évaluation indépendante que le SSIAP 3 doit exploiter positivement : faciliter l''accès complet (un audit partiel ne donne pas une image réelle de la situation et peut dissimuler des problèmes graves) ; transparence totale (les auditeurs découvriront les lacunes — les dissimuler aggrave la situation lors d''un sinistre ultérieur et la responsabilité) ; écoute active des observations pour en tirer des actions d''amélioration concrètes. Un SSIAP 3 qui accueille positivement les audits externes démontre une maturité professionnelle et une culture sécurité avancée. Minimiser les lacunes ou bloquer l''accès sont des comportements contraires à l''éthique professionnelle.', 1, null::integer[], array['theme2','seq2']::text[], 18),
('ssiap3-q63', 'ssiap3-partie2', 'multiple-select', 'Comment le SSIAP 3 gère-t-il le départ en retraite simultané de deux SSIAP 2 expérimentés ? (plusieurs réponses)', 'Le départ simultané de deux SSIAP 2 expérimentés représente une perte importante de compétences et de mémoire opérationnelle. Le SSIAP 3 doit anticiper : identification et formation des successeurs bien en amont (12 à 18 mois permettent une montée en compétences progressive et réaliste) ; organisation d''une période de tuilage (période où ancien et nouveau travaillent ensemble pour transmission des connaissances sur les spécificités de l''établissement : particularités du SSI, procédures locales, relations avec les prestataires) ; documentation des procédures et savoir-faire tacites (ce que les agents savent mais n''ont pas forcément écrit). Le recrutement en urgence génère du risque opérationnel et des coûts plus élevés. Les bénévoles ne sont pas admis dans un service SSIAP réglementé.', null, array[0,1,2]::integer[], array['theme1','seq1']::text[], 19)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap3-q7','ssiap3-q8','ssiap3-q9','ssiap3-q10','ssiap3-q11','ssiap3-q30','ssiap3-q31','ssiap3-q32','ssiap3-q33','ssiap3-q40','ssiap3-q51','ssiap3-q52','ssiap3-q53','ssiap3-q54','ssiap3-q55','ssiap3-q56','ssiap3-q57','ssiap3-q60','ssiap3-q62','ssiap3-q63');
commit;

-- ===== ssiap3-partie2-sub02.sql =====
begin;
-- SSIAP 3 — Direction du service - Management stratégique (partie 2, sub 2/4, 20 cc_questions)
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap3-q71', 'ssiap3-partie2', 'quiz', 'Le SSIAP 3 doit participer à une réunion du CHSCT (ou CSE avec délégation SSCT) sur la sécurité incendie. Quel est son rôle dans cette instance ?', 'Le CHSCT (aujourd''hui intégré dans la Commission Santé Sécurité et Conditions de Travail du CSE) est l''instance représentative du personnel compétente en matière de sécurité. Le SSIAP 3 y contribue en tant qu''expert technique : présentation du bilan sécurité incendie (incidents, exercices, résultats des vérifications, non-conformités et plans d''action) ; réponse aux cc_questions des représentants sur les équipements et procédures ; information sur les évolutions réglementaires ou les projets de modification des installations. La présidence appartient à l''employeur (ou son représentant). La participation du SSIAP 3 renforce la transparence sur les sujets de sécurité et associe les représentants du personnel aux décisions.', 1, null::integer[], array['theme1','seq1']::text[], 20),
('ssiap3-q72', 'ssiap3-partie2', 'quiz', 'Comment le SSIAP 3 traite-t-il une situation où il identifie un risque grave et imminent que la direction refuse de traiter par souci d''économie ?', 'Face à un refus de la direction de traiter un risque grave, le SSIAP 3 doit protéger sa responsabilité professionnelle et la sécurité des personnes : formalisation écrite obligatoire — une note interne datée et signée décrivant précisément le risque, les conséquences prévisibles et les mesures recommandées constitue une trace en cas d''accident ultérieur (elle démontre qu''il a rempli son obligation d''alerte) ; conservation d''une copie personnelle ; si le risque est immédiat et met en danger des vies humaines, le SSIAP 3 a une obligation morale et peut avoir une obligation légale de signalement à l''autorité administrative compétente (préfet, commission de sécurité). L''acceptation silencieuse engage sa responsabilité. L''action unilatérale sans mandat est risquée juridiquement. Les médias ne sont pas un recours adapté.', 1, null::integer[], array['theme2','seq2']::text[], 21),
('ssiap3-q73', 'ssiap3-partie2', 'multiple-select', 'Quelles sont les obligations du SSIAP 3 en matière de gestion des entreprises extérieures intervenant sur les installations de sécurité incendie ? (plusieurs réponses)', 'La gestion des entreprises extérieures est réglementée par le décret du 20 février 1992 : plan de prévention obligatoire avant tout travail dangereux ou dépassant 400 heures/an dans l''établissement (signature conjointe employeur/entreprise extérieure) ; inspection commune préalable pour identifier les risques d''interférences et définir les mesures de prévention ; information des entreprises extérieures sur les risques de l''établissement (présence de produits dangereux, zones ATEX, protocoles spécifiques) ; mesures compensatoires si des installations de sécurité sont mises hors service pendant les travaux (rondes renforcées, inhibition temporaire documentée avec surveillance humaine). Interdire toute intervention extérieure rendrait impossible la maintenance réglementaire des installations.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 22),
('ssiap3-q74', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 doit rédiger le cahier des charges pour le renouvellement du contrat de maintenance du SSI. Quelles clauses essentielles doit-il inclure ? (plusieurs réponses)', 'Un cahier des charges de maintenance SSI rigoureux doit inclure : exigences de qualification (Q18 APSAD ou équivalent, techniciens certifiés constructeur pour les équipements spécifiques) ; SLA (Service Level Agreement) avec délais garantis différenciés selon l''urgence (panne totale du CMSI = intervention immédiate, défaut mineur = 48h) avec pénalités contractuelles en cas de non-respect ; format standardisé des rapports (équipements testés, résultats, non-conformités, actions réalisées, pièces changées) pour permettre la traçabilité dans le registre de sécurité ; stock minimum de pièces critiques chez le prestataire ou sur site. Un prix fixe sans clause de révision est économiquement irréaliste sur plusieurs années et risque d''amener le prestataire à réduire la qualité.', null, array[0,1,2,3]::integer[], array['theme2','seq2']::text[], 23),
('ssiap3-q77', 'ssiap3-partie2', 'quiz', 'Comment le SSIAP 3 intègre-t-il le retour d''expérience (REX) des sinistres d''autres établissements dans sa pratique professionnelle ?', 'Le retour d''expérience (REX) des sinistres d''autres établissements est une source d''apprentissage précieuse pour le SSIAP 3 : l''INRS, la FFSA (Fédération Française des Sociétés d''Assurances), le CSTB (Centre Scientifique et Technique du Bâtiment) et les publications spécialisées publient des analyses de sinistres avec les causes et les enseignements. Le SSIAP 3 doit : lire et analyser ces publications régulièrement ; identifier si les causes du sinistre analysé (porte CF maintenue ouverte, détecteur inhibé non compensé, exercice non réalisé) pourraient exister dans son établissement ; adapter proactivement ses procédures sans attendre une réglementation ou un accident personnel. Cette démarche proactive distingue un professionnel réactif d''un gestionnaire proactif.', 1, null::integer[], array['theme2','seq2']::text[], 24),
('ssiap3-q80', 'ssiap3-partie2', 'quiz', 'Lors d''un sinistre de grande ampleur nécessitant l''intervention du SDIS, comment le SSIAP 3 organise-t-il le transfert de commandement au Commandant des Opérations de Secours (COS) ?', 'Le transfert de commandement au COS est un moment clé de la gestion du sinistre : dès l''arrivée du premier officier pompier, le SSIAP 3 se présente et lui fournit un bilan structuré selon le principe METHANE ou équivalent (localisation et étendue du sinistre, nombre de personnes impliquées ou évacuées, manquants éventuels, état du SSI, caractéristiques particulières du bâtiment — zones ATEX, stockages dangereux) ; il remet les plans du bâtiment (plan masse, plans par niveau, schéma du SSI) ; il reste à disposition du COS comme expert du bâtiment tout au long de l''opération. Le COS assume dès lors le commandement des opérations de secours. Le SSIAP 3 ne commande pas les pompiers mais est une ressource indispensable pour le COS.', 1, null::integer[], array['theme3','seq3']::text[], 25),
('ssiap3-q82', 'ssiap3-partie2', 'quiz', 'Le SSIAP 3 est sollicité pour participer à une enquête publique sur un projet immobilier voisin susceptible d''impacter les voies d''accès des secours à son établissement. Quelle est sa démarche ?', 'L''accès des secours est un élément critique de la sécurité incendie qui justifie l''intervention du SSIAP 3 dans une enquête publique : analyse de l''impact (réduction de la voie d''accès, suppression d''une aire de stationnement des engins, création d''un obstacle) sur les délais d''intervention des pompiers ; quantification (temps d''intervention allongé de X minutes, impossibilité d''utiliser les échelles pour les niveaux supérieurs) ; dépôt d''une contribution motivée à l''enquête publique (procédure légale ouverte à tout citoyen et a fortiori à un professionnel de la sécurité) avec copie à la commission de sécurité pour information. La commission peut à son tour formuler des observations. Attendre les pompiers ou ignorer l''enquête sont des postures insuffisantes au regard des enjeux.', 1, null::integer[], array['theme2','seq2']::text[], 26),
('ssiap3-q87', 'ssiap3-partie2', 'multiple-select', 'Comment le SSIAP 3 gère-t-il la sécurité incendie lors de travaux de rénovation lourde sur une partie d''un ERP resté en exploitation ? (plusieurs réponses)', 'La cohabitation travaux/exploitation est une situation à haut risque incendie nécessitant des mesures spécifiques : séparation physique de la zone de travaux par des parois provisoires ayant une résistance au feu suffisante pour ne pas compromettre le compartimentage général (pas de simple bâche plastique) ; permis de feu systématique pour tout travail générant des points chauds (soudure, meulage, disqueuse, chalumeau) avec les 8 règles du permis de feu (protection, surveillance, extinction, délai après travaux) ; mise à jour immédiate des plans d''évacuation (issues modifiées, zones inaccessibles, point de rassemblement adapté) et information de tout le personnel ; rondes renforcées dans et autour du chantier (risque d''incendie couvant, matériaux combustibles stockés, intervenants extérieurs peu sensibilisés). Fermer l''établissement entier n''est pas une solution opérationnelle si des travaux partiels sont possibles.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 27),
('ssiap3-q88', 'ssiap3-partie2', 'quiz', 'Le SSIAP 3 est responsable d''un établissement recevant régulièrement des délégations étrangères ne parlant pas français. Comment adapte-t-il les procédures d''évacuation ?', 'L''accueil de visiteurs ne maîtrisant pas la langue des consignes est une situation à risque spécifique : les pictogrammes réglementaires (ISO 7010) sont internationalement reconnus et constituent la base d''une signalétique compréhensible par tous ; des consignes multilingues (anglais minimum, autres langues selon les délégations fréquentes) renforcent la compréhension ; la formation des agents d''accueil au guidage actif des visiteurs étrangers (ils ne liront pas les consignes affichées mais suivront instinctivement quelqu''un qui leur fait signe de le suivre) est la mesure la plus efficace ; l''accompagnement systématique des groupes par un agent formé lors des évacuations est la solution la plus sûre. L''obligation d''évacuation s''applique à tous les occupants quelle que soit leur nationalité.', 1, null::integer[], array['theme1','seq1']::text[], 28),
('ssiap3-q91', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 doit rédiger une politique de prévention des risques incendie pour son établissement. Quelles composantes essentielles cette politique doit-elle contenir ? (plusieurs réponses)', 'Une politique de prévention des risques incendie est un document stratégique qui structure l''action du SSIAP 3 : engagement formel de la direction (sans soutien de la direction générale, aucune politique sécurité ne peut être mise en œuvre efficacement — cet engagement doit être visible et communiqué) ; programme de formation structuré et planifié couvrant tous les niveaux (SSIAP, personnel d''accueil, employés) avec objectifs et évaluation ; dispositif de remontée des anomalies permettant à n''importe quel employé de signaler un problème de sécurité sans crainte (culture de signalement positive) ; processus d''amélioration continue (REX des incidents, analyse des tendances, ajustement des procédures). Une politique centrée sur les sanctions génère une culture de la peur qui inhibe les signalements et dégrade la sécurité réelle.', null, array[0,1,2,4]::integer[], array['theme2','seq2']::text[], 29),
('ssiap3-q93', 'ssiap3-partie2', 'multiple-select', 'Lors de la mise en place d''un système de vidéosurveillance couplé au SSI dans un ERP, quelles précautions le SSIAP 3 doit-il prendre ? (plusieurs réponses)', 'L''installation d''un système de vidéosurveillance dans un ERP est soumise à plusieurs obligations : déclaration CNIL (désormais tenue d''un registre des activités de traitement selon le RGPD, avec désignation d''un DPO si l''organisme en est doté) ; affichage obligatoire informant les personnes filmées (pictogramme caméra, identité du responsable de traitement, durée de conservation, droits d''accès) ; contrôle strict des accès aux images (liste nominative des personnes autorisées à visionner, traçabilité des consultations) ; durée maximale de conservation limitée (1 mois maximum selon la CNIL pour la vidéosurveillance standard, sauf procédure judiciaire en cours) ; procédure de destruction sécurisée des images arrivées à échéance. La conservation illimitée est illégale au regard du RGPD.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 30),
('ssiap3-q94', 'ssiap3-partie2', 'quiz', 'Le SSIAP 3 est confronté à un désaccord technique avec un bureau de contrôle sur la conformité d''une installation. Quelle est la procédure appropriée ?', 'Un désaccord technique avec un bureau de contrôle doit être traité de manière professionnelle et structurée : analyse précise des observations avec références aux textes réglementaires applicables (article exact du règlement de sécurité, norme, IT) pour comprendre le fondement technique du désaccord ; présentation d''une argumentation technique documentée (note technique, avis d''un BET, référence à une jurisprudence de commission similaire) ; si le désaccord persiste malgré l''échange contradictoire, solliciter un avis auprès de la commission de sécurité (elle est l''autorité d''interprétation du règlement) ou d''un expert technique indépendant. L''imposition unilatérale ou l''acceptation sans analyse sont également inadaptées. Le recours judiciaire immédiat est disproportionné.', 1, null::integer[], array['theme2','seq2']::text[], 31),
('ssiap3-q96', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 doit élaborer un plan de formation pour intégrer un nouveau SSIAP 2 recruté extérieurement. Quels cc_modules sont indispensables ? (plusieurs réponses)', 'L''intégration d''un nouveau SSIAP 2 dans un établissement spécifique nécessite une formation d''adaptation complète, même si le candidat est expérimenté : maîtrise du SSI de l''établissement (chaque installation a ses spécificités — zones de détection, procédures d''exploitation, inhibitions programmées, asservissements particuliers) ; connaissance du bâtiment (points critiques, locaux à risques, zones complexes, accès des secours) par une visite guidée approfondie ; appropriation du POI (rôle du SSIAP 2 dans chaque scénario, seuils de décision, contacts d''urgence) avec simulation pratique ; management de l''équipe SSIAP 1 (style de management attendu, procédures disciplinaires, gestion des plannings selon les règles de l''établissement) ; connaissance des prestataires (qui appeler pour quel équipement, délais contractuels, procédures d''urgence hors heures ouvrées).', null, array[0,1,2,3,4]::integer[], array['theme1','seq1']::text[], 32),
('ssiap3-q98', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 doit mettre en place un processus de gestion documentaire pour son service. Quels principes doit-il respecter ? (plusieurs réponses)', 'Un système de gestion documentaire rigoureux pour un service SSIAP doit respecter : le versionnage (chaque document a un numéro de version et une date — on sait toujours quelle est la version en vigueur et on peut retrouver les versions antérieures en cas d''enquête) ; l''accessibilité opérationnelle (le POI et les fiches réflexes doivent être disponibles en permanence au PC sécurité, pas uniquement dans un classeur du bureau du SSIAP 3) ; la validation avant diffusion (un document non validé peut contenir des erreurs et créer de la confusion) ; les durées de conservation légales (le registre de sécurité et les documents annexes doivent être conservés plusieurs années — les délais de prescription pénale courent jusqu''à 6 ans pour certaines infractions). La destruction immédiate des documents obsolètes priverait de toute traçabilité historique.', null, array[0,1,2,4]::integer[], array['theme2','seq2']::text[], 33),
('ssiap3-q100', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 supervise la mise en place d''un Plan de Continuité d''Activité (PCA) intégrant les risques incendie. Quels scénarios doit-il modéliser ? (plusieurs réponses)', 'Le PCA intégrant les risques incendie doit modéliser plusieurs niveaux de scénarios : sinistre localisé (incendie d''une zone : comment maintenir l''exploitation dans les zones non sinistrées, quelles activités peuvent continuer, quels clients/usagers informer) ; sinistre total (incendie détruisant une partie significative : plan de repli sur site alternatif, préservation des données et des équipements critiques, communication de crise) ; défaillance du SSI (panne de la centrale, batteries HS : mesures compensatoires permettant de maintenir l''ouverture sans le niveau normal de sécurité automatique — rondes renforcées, réduction temporaire de l''effectif public) ; défaillance prestataire (le mainteneur SSI en astreinte est lui-même indisponible : prestataire de substitution identifié à l''avance). Le coût de l''énergie est un risque financier non lié à la continuité sécurité.', null, array[0,1,2,3]::integer[], array['theme2','seq2']::text[], 34),
('ssiap3-q101', 'ssiap3-partie2', 'quiz', 'Comment le SSIAP 3 s''assure-t-il que les procédures du POI sont réellement connues et maîtrisées par l''ensemble des agents SSIAP de son équipe ?', 'La maîtrise réelle du POI ne se décrète pas par la signature d''un document : les exercices sur table (tabletop exercises) permettent de tester la connaissance des procédures dans différents scénarios sans mobiliser les installations (simulation d''un incendie en cuisine un samedi soir avec 300 clients : qui fait quoi, dans quel ordre, qui appelle qui) ; les simulations pratiques testent le comportement réel en conditions proches du réel (déclenchement surprise d''une alarme avec évaluation de la réponse) ; les évaluations individuelles (cc_questions orales ou écrites sur les procédures) identifient les lacunes de chaque agent ; la mise à jour du POI en fonction des lacunes découvertes lors des exercices est la boucle d''amélioration continue. Un POI lu mais non pratiqué sera oublié ou mal appliqué sous le stress d''un sinistre réel.', 1, null::integer[], array['theme1','seq1']::text[], 35),
('ssiap3-q105', 'ssiap3-partie2', 'multiple-select', 'Comment le SSIAP 3 gère-t-il la sécurité incendie lors d''un événement se déroulant partiellement en extérieur (festival avec scène couverte et public en plein air) ? (plusieurs réponses)', 'La sécurité incendie d''un événement mixte intérieur/extérieur implique des risques spécifiques : périmètre de sécurité autour des sources d''ignition potentielles (câblages électriques de scène, groupes électrogènes à distance des matériaux combustibles, générateurs de fumée d''effets spéciaux) ; vérification des structures temporaires (une chute de chapiteau sous le vent peut propager un incendie ou créer des blessés obstruant les issues) ; maintien des voies d''évacuation dégagées (le public en plein air peut naturellement se concentrer près des entrées/sorties en obstruant les issues de secours) ; moyens d''extinction adaptés aux risques réels de l''événement (extincteurs CO2 près des armoires électriques, extincteurs classe B/F près des cuisines de restauration). La réglementation ERP s''applique aux parties couvertes, mais le SSIAP 3 est responsable de la sécurité globale de l''événement.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 36),
('ssiap3-q107', 'ssiap3-partie2', 'quiz', 'Quelle est la procédure du SSIAP 3 pour gérer une découverte de produits chimiques non répertoriés dans un local de son établissement ?', 'La découverte de produits chimiques non répertoriés est une situation à risque nécessitant une démarche rigoureuse : identification obligatoire avant toute manipulation (les FDS sont accessibles auprès du fournisseur ou via des bases de données professionnelles — INRS, ICPE) ; évaluation des risques spécifiques (inflammabilité, toxicité, réactivité, incompatibilités avec les produits voisins — certains mélanges sont explosifs ou génèrent des gaz toxiques) ; régularisation du stockage selon les prescriptions des FDS (séparation des incompatibles, conditions de température, ventilation) ou évacuation via une filière de déchets dangereux agréée. Regrouper tous les produits inconnus dans le même local est potentiellement catastrophique (risque de réactions chimiques entre produits incompatibles). La mise en décharge ordinaire est illégale pour les produits chimiques.', 1, null::integer[], array['theme1','seq1']::text[], 37),
('ssiap3-q108', 'ssiap3-partie2', 'multiple-select', 'Comment le SSIAP 3 mesure-t-il l''efficacité de sa politique de réduction des fausses alarmes ? (plusieurs réponses)', 'La réduction des fausses alarmes est un enjeu majeur : trop de fausses alarmes créent un effet de lassitude chez le personnel (qui n''évacue plus sérieusement) et peuvent entraîner des coûts de mobilisation des pompiers (certains SDIS facturent les interventions pour fausses alarmes répétées). Indicateurs pertinents : nombre et fréquence des déclenchements par zone et par cause (détecteur en cuisine mal positionné, zone de travaux mal inhibée, acte de malveillance) ; taux de fausses alarmes pour identifier les zones problématiques ; évaluation comportementale (lors des exercices, observe-t-on une moindre réactivité liée à la lassitude ?) ; coût financier des interventions pompiers. Rendre les détecteurs moins sensibles est une fausse solution qui risque de manquer un vrai sinistre — la bonne approche est d''adapter les détecteurs au contexte (détecteurs multicritères, seuils adaptés).', null, array[0,1,2,3]::integer[], array['theme2','seq2']::text[], 38),
('ssiap3-q110', 'ssiap3-partie2', 'multiple-select', 'Lors d''une réunion de direction, le SSIAP 3 doit présenter le bilan annuel du service. Quels éléments essentiels ce bilan doit-il contenir ? (plusieurs réponses)', 'Le bilan annuel du SSIAP 3 présenté à la direction doit permettre une décision éclairée sur les investissements et les priorités : synthèse des incidents (nombre, nature, gravité, causes identifiées et actions correctives prises — démontre la veille et la réactivité) ; état de conformité des installations (résultats des vérifications annuelles, non-conformités en cours et délais de levée, état du registre de sécurité) ; résultats des exercices d''évacuation (temps d''évacuation, points faibles identifiés, évolution vs années précédentes — mesure l''efficacité des formations) ; proposition budgétaire argumentée (renouvellement d''équipements vieillissants, investissements de mise en conformité, formations). La liste des salaires est une information RH confidentielle sans rapport avec le bilan de sécurité.', null, array[0,1,2,3]::integer[], array['theme2','seq2']::text[], 39)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap3-q71','ssiap3-q72','ssiap3-q73','ssiap3-q74','ssiap3-q77','ssiap3-q80','ssiap3-q82','ssiap3-q87','ssiap3-q88','ssiap3-q91','ssiap3-q93','ssiap3-q94','ssiap3-q96','ssiap3-q98','ssiap3-q100','ssiap3-q101','ssiap3-q105','ssiap3-q107','ssiap3-q108','ssiap3-q110');
commit;

-- ===== ssiap3-partie2-sub03.sql =====
begin;
-- SSIAP 3 — Direction du service - Management stratégique (partie 2, sub 3/4, 20 cc_questions)
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap3-q111', 'ssiap3-partie2', 'multiple-select', 'Comment le SSIAP 3 intègre-t-il les principes de l''accessibilité aux personnes en situation de handicap dans la gestion de l''évacuation ? (plusieurs réponses)', 'L''évacuation des personnes en situation de handicap nécessite une approche spécifique intégrée dans le POI : recensement préalable (pour les handicaps permanents connus : employés, résidents — un fichier nominatif avec localisation habituelle et type d''aide nécessaire) ; espaces d''attente sécurisés (EAS) : zones coupe-feu en dehors des voies d''évacuation, aux étages, où les PMR peuvent attendre l''arrivée des pompiers en sécurité — obligatoires dans les ERP neufs depuis la loi de 2005 ; formation des agents SSIAP aux techniques d''assistance (utilisation des chaises d''évacuation, techniques de portage en sécurité pour l''agent et la personne) ; dispositifs d''alerte adaptés (flash lumineux pour les personnes sourdes, boucles à induction pour malentendants, messages en braille ou pictogrammes). L''interdiction d''accès aux étages pour les PMR est discriminatoire et illégale.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 40),
('ssiap3-q115', 'ssiap3-partie2', 'quiz', 'Quelle est l''approche du SSIAP 3 pour gérer la sécurité incendie d''un ERP accueillant des personnes sous curatelle ou tutelle (type établissement psychiatrique ou ESAT) ?', 'Les établissements accueillant des personnes dont l''autonomie est réduite (psychiatrie, handicap mental, ESAT) nécessitent une approche spécifique : certains résidents peuvent ne pas comprendre ou ne pas réagir à l''alarme sonore (adaptation avec signaux lumineux supplémentaires, accompagnement physique systématique) ; certains peuvent avoir des comportements imprévisibles sous stress (fugue, agitation) nécessitant des procédures de suivi nominatif strict ; le personnel soignant est le premier intervenant auprès des résidents — sa formation aux procédures d''évacuation incendie est indispensable (il connaît chaque résident et peut l''accompagner efficacement) ; des listes nominatives de résidents avec leur localisation habituelle et leurs besoins spécifiques permettent un contrôle exhaustif au point de rassemblement. Le SSIAP 3 coordonne avec l''équipe soignante mais ne peut pas tout déléguer.', 1, null::integer[], array['theme1','seq1']::text[], 41),
('ssiap3-q116', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 participe à la rédaction d''une convention de mise à disposition de personnels SSIAP entre deux entreprises. Quels points essentiels doit couvrir cette convention ? (plusieurs réponses)', 'Une convention de mise à disposition de personnels SSIAP doit couvrir plusieurs aspects : définition précise des missions (les agents mis à disposition doivent savoir exactement ce qu''on attend d''eux dans l''établissement d''accueil) et des responsabilités (qui est responsable de quoi en cas d''incident) ; l''entreprise utilisatrice reste responsable de la sécurité et de la santé des travailleurs mis à disposition sur son site (code du travail art. L1251-21 à 23) — elle doit les informer des risques spécifiques de l''établissement ; formation obligatoire aux spécificités (SSI, POI, bâtiment) avant toute prise de poste autonome ; modalités de signalement (comment un agent mis à disposition remonte-t-il une anomalie ? à qui ? dans quel délai ?). Le transfert total de responsabilité est illégal — l''entreprise utilisatrice conserve des obligations.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 42),
('ssiap3-q117', 'ssiap3-partie2', 'multiple-select', 'Quelle est la différence entre un Permis de Feu et une Autorisation de Travail dans le contexte de la gestion d''une zone sensible ? (plusieurs réponses)', 'Permis de feu et autorisation de travail sont deux documents complémentaires mais distincts : le permis de feu est un document spécifiquement dédié aux travaux par points chauds (tout travail générant des étincelles, flammes ou projections de métal en fusion : soudure TIG/MIG, meulage, découpe plasma) — il comporte les 8 règles spécifiques anti-incendie (protection des matériaux combustibles, surveillance pendant et après les travaux, vérification finale) et est visé par le SSIAP 2/3 ; l''autorisation de travail est un permis générique couvrant tout travail dangereux (hauteur, espace confiné, électrique, chimique) avec les mesures de sécurité adaptées à chaque risque ; les deux documents peuvent coexister (une autorisation de travail pour des travaux en espace confiné incluant un permis de feu si de la soudure est nécessaire). Leur contenu n''est pas identique.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 43),
('ssiap3-q119', 'ssiap3-partie2', 'multiple-select', 'Quelle est la démarche du SSIAP 3 pour évaluer et améliorer la culture sécurité incendie du personnel non-SSIAP d''un établissement ? (plusieurs réponses)', 'La culture sécurité incendie d''un établissement dépasse la seule équipe SSIAP et nécessite une démarche spécifique : audits comportementaux lors des exercices (observer le comportement réel plutôt que les déclarations — les gens agissent-ils vraiment comme ils ont été formés, ou retournent-ils chercher leurs affaires, utilisent-ils les ascenseurs ?) ; mesure du taux de signalement spontané d''anomalies par le personnel non-SSIAP (un personnel sensibilisé signale les portes CF bloquées, les extincteurs manquants, les issues obstruées — c''est un indicateur puissant de culture sécurité) ; formations participatives et interactives (mises en situation, manipulation d''extincteur, simulation d''évacuation) plus efficaces que les cours magistraux ; valorisation des comportements exemplaires (créer des modèles positifs). La sanction systématique crée de la peur et inhibe les signalements.', null, array[0,1,2,4]::integer[], array['theme2','seq2']::text[], 44),
('ssiap3-q120', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 doit concevoir un exercice d''évacuation pour un hôpital (type U) de 400 lits. Quelles contraintes spécifiques doit-il intégrer ? (plusieurs réponses)', 'L''exercice d''évacuation dans un hôpital présente des contraintes radicalement différentes d''un ERP standard : l''évacuation horizontale progressive est la stratégie réglementaire pour les établissements de soins (type U) — les patients sont déplacés vers des compartiments coupe-feu adjacents au même niveau, évitant le danger des escaliers pour des personnes alitées ; certains patients réanimés ou sous assistance respiratoire ne peuvent absolument pas être déplacés (protocole spécifique avec l''équipe médicale pour leur protection sur place) ; le SAMU doit être informé pour ne pas mobiliser les équipes d''urgence sur une fausse alerte ; les équipes soignantes sont les premiers intervenants auprès des patients — leur formation est prioritaire. L''évacuation totale vers l''extérieur de 400 patients est impraticable et dangereuse médicalement.', null, array[0,1,2,3]::integer[], array['theme1','seq1']::text[], 45),
('ssiap3-q121', 'ssiap3-partie2', 'quiz', 'Comment le SSIAP 3 gère-t-il la problématique des espaces confinés dans son établissement (cuves, galeries techniques, vides sanitaires) en matière de sécurité incendie ?', 'Les espaces confinés (cuves, galeries, vides sanitaires, égouts) cumulent des risques spécifiques : atmosphère appauvrie en O2 ou enrichie en gaz toxiques/inflammables (fermentation, fuite de gaz, produits chimiques) ; difficultés d''évacuation en cas d''accident (géométrie contraignante, absence d''éclairage) ; risque d''incendie aggravé (présence possible de gaz inflammables, accumulation de poussières). Le permis d''entrée en espace confiné impose : mesure de l''atmosphère avant entrée (O2 entre 19,5% et 23%, absence de gaz inflammables > 10% LIE, absence de gaz toxiques > VLE) avec détecteur multigaz ; surveillance extérieure permanente par un agent ne pénétrant pas ; moyens d''extraction prévus (harnais, treuil, ARI). Entrer seul sans surveillance extérieure est une des principales causes d''accidents mortels en espace confiné.', 1, null::integer[], array['theme1','seq1']::text[], 46),
('ssiap3-q125', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 est sollicité pour auditer un prestataire de maintenance SSI suite à plusieurs rapports d''intervention incomplets. Comment conduit-il cet audit ? (plusieurs réponses)', 'Un audit de prestataire de maintenance SSI doit être rigoureux et contradictoire : vérification documentaire des qualifications (les techniciens intervenants doivent avoir la qualification Q18 et les certifications constructeur pour les équipements spécifiques — demander les attestations nominatives) ; contrôle croisé terrain (comparer ce que les rapports déclarent avoir testé avec l''état réel des équipements : un détecteur déclaré testé mais encrassé révèle un rapport falsifié) ; analyse des indicateurs de performance contractuels (délais d''intervention garantis respectés ?, non-conformités levées dans les délais ?) ; entretiens techniques avec les techniciens (leur niveau de connaissance de l''installation révèle la qualité du suivi). L''acceptation sans vérification des explications du prestataire n''est pas un audit — c''est une validation de façade.', null, array[0,1,2,3]::integer[], array['theme2','seq2']::text[], 47),
('ssiap3-q128', 'ssiap3-partie2', 'quiz', 'Le SSIAP 3 doit analyser les causes d''un incendie survenu dans son établissement après extinction par les pompiers. Quelle méthodologie d''analyse utilise-t-il ?', 'L''analyse post-sinistre par le SSIAP 3 doit aller au-delà de la cause directe pour identifier les causes profondes et prévenir la récurrence : l''arbre des causes part du sinistre et remonte en posant ''pourquoi ce phénomène a-t-il pu se produire ?'' à chaque niveau ; la méthode des 5 Pourquoi déroule la chaîne causale (incendie → câble électrique surchargé → protection fusible inadaptée → remplacement non conforme → absence de procédure de vérification des travaux électriques → pas de plan de prévention pour l''intervenant). Cette analyse révèle souvent des défaillances organisationnelles (absence de procédure, formation insuffisante, supervision inexistante) que la seule identification de la cause directe masque. L''analyse SSIAP 3 est complémentaire et non substituable à celle des pompiers ou des assureurs.', 1, null::integer[], array['theme2','seq2']::text[], 48),
('ssiap3-q131', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 doit définir le contenu d''une formation ''sécurité incendie'' destinée aux managers d''un établissement tertiaire. Quels objectifs pédagogiques prioritaires retient-il ? (plusieurs réponses)', 'Une formation sécurité incendie pour managers doit cibler leurs responsabilités spécifiques : rôle de vecteur de culture sécurité (un manager qui prend la sécurité au sérieux influence positivement son équipe — s''il contourne les consignes, son équipe fait de même) ; connaissance des procédures d''évacuation et de leur rôle propre (guide-file, serre-file selon désignation dans le POI, point de rassemblement, comptage de leur équipe) ; identification des comportements à risque (porte CF bloquée par un collaborateur, issue encombrée) et capacité à y répondre (signaler, corriger, sensibiliser) ; compréhension des enjeux de responsabilité (un manager qui tolère des comportements dangereux peut voir sa responsabilité personnelle engagée). La maîtrise intégrale de la réglementation ERP est le domaine du SSIAP 3, pas des managers.', null, array[0,1,3,4]::integer[], array['theme1','seq1']::text[], 49),
('ssiap3-q133', 'ssiap3-partie2', 'quiz', 'Comment le SSIAP 3 intègre-t-il les exigences de la norme ISO 45001 (management de la santé et sécurité au travail) dans son service ?', 'La norme ISO 45001 (management de la santé et sécurité au travail, successeur d''OHSAS 18001) offre un cadre structuré que le SSIAP 3 peut intégrer à son service : politique SST formalisée incluant les risques incendie ; identification et évaluation systématique des risques (Document Unique d''Évaluation des Risques Professionnels intégrant les risques incendie pour les agents SSIAP) ; objectifs mesurables avec plans d''action (réduction du taux de fausses alarmes, amélioration du temps d''évacuation) ; indicateurs de performance suivis régulièrement ; revue de direction périodique pour évaluer l''efficacité du système. Bien que la certification ne soit pas obligatoire pour un service SSIAP, l''approche ISO 45001 améliore la structuration et la crédibilité du management sécurité. ISO 45001 complète la réglementation ERP sans la remplacer.', 1, null::integer[], array['theme2','seq2']::text[], 50),
('ssiap3-q134', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 doit concevoir le dispositif de sécurité incendie pour un stade de football de 40 000 places. Quelles problématiques spécifiques aux grandes foules doit-il traiter ? (plusieurs réponses)', 'Les grandes enceintes sportives posent des défis spécifiques de gestion des foules en situation d''évacuation : les flux d''entrée/sortie sont critiques — les calculs montrent que 40 000 personnes ne peuvent pas évacuer simultanément sans risque de compression mortelle aux issues (gestion par secteurs, ouverture séquentielle des sorties) ; la coordination avec les forces de l''ordre est essentielle (en cas d''incident, les forces de sécurité peuvent involontairement bloquer des issues avec leurs cordons) ; la sonorisation et l''affichage permettent de diriger les flux vers les sorties disponibles et d''éviter la saturation de certaines (messages ciblés par secteur) ; positionnement des agents SSIAP aux points névralgiques (entrées/sorties, tribunes debout) pour intervenir rapidement et guider. L''objectif de 8 minutes n''est pas une norme universelle — le dimensionnement des sorties vise généralement 8 à 12 minutes selon les configurations.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 51),
('ssiap3-q135', 'ssiap3-partie2', 'multiple-select', 'Lors d''une revue annuelle du Plan d''Organisation Interne (POI), le SSIAP 3 identifie que certaines procédures sont devenues obsolètes suite à des réorganisations. Quelle est sa démarche ? (plusieurs réponses)', 'La mise à jour du POI est un processus formel qui doit garantir la qualité des procédures révisées : mise à jour documentaire des procédures (nouveaux organigrammes, nouveaux contacts, nouvelles zones suite aux réaménagements) ; test des nouvelles procédures (une procédure sur papier peut sembler correcte mais révéler des incohérences à l''exercice pratique — un exercice tabletop ou une simulation valide les nouvelles procédures avant leur mise en vigueur officielle) ; validation formelle de la direction (les modifications majeures engagent la responsabilité de l''établissement — une validation avec signature donne un caractère officiel au document révisé) ; communication et formation de tous les agents (un POI modifié non communiqué est inutile — chaque agent doit connaître les changements qui le concernent). Supprimer les procédures non testées dans l''année risque de créer des lacunes dans la couverture des scénarios.', null, array[0,1,3,4]::integer[], array['theme2','seq2']::text[], 52),
('ssiap3-q137', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 doit intégrer la sécurité incendie dans le Document Unique d''Évaluation des Risques Professionnels (DUERP). Quels risques spécifiques aux agents SSIAP doit-il y faire figurer ? (plusieurs réponses)', 'Le DUERP des agents SSIAP doit recenser les risques professionnels spécifiques à leur métier : exposition aux fumées toxiques (CO, HCN, particules) lors des levées de doute et interventions sur sinistre — le port de l''ARI est une mesure de protection mais pas toujours disponible ou utilisé pour de courtes levées de doute ; TMS liés aux équipements (l''ARI pèse 12-15 kg, les tenues de protection sont lourdes, les postures dans les espaces confinés sont contraignantes) ; risques psychosociaux (travail isolé nocturne, confrontation à des situations traumatisantes : accidents de personnes, décès, incendies importants) ; risque électrique lors des interventions à proximité d''équipements sous tension (armoires électriques, tableaux de distribution). La contamination alimentaire est un risque professionnel général non spécifique aux agents SSIAP.', null, array[0,1,2,3]::integer[], array['theme1','seq1']::text[], 53),
('ssiap3-q140', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 supervise l''élaboration d''un Plan de Sauvegarde des Œuvres (PSO) pour un musée national. Quels éléments ce plan doit-il contenir ? (plusieurs réponses)', 'Le Plan de Sauvegarde des Œuvres (PSO) est un document spécifique aux musées et établissements patrimoniaux, élaboré en coordination avec les conservateurs et le SSIAP 3 : hiérarchisation des collections (les œuvres irremplaçables ou à risque de destruction rapide par le feu ou l''eau sont prioritaires — une liste de priorité 1, 2, 3 est établie par les conservateurs) ; cartographie précise (plans annotés indiquant l''emplacement exact de chaque œuvre ou collection, mis à jour à chaque réaménagement ou prêt) ; procédures de manipulation d''urgence (certaines œuvres ne peuvent pas être déplacées sans équipement spécial — les pompiers doivent être informés) ; zones de dépôt temporaire sécurisées (espaces coupe-feu identifiés à l''extérieur ou à l''abri pour recevoir les œuvres évacuées). L''évaluation financière relève de l''assurance, pas du PSO opérationnel.', null, array[0,1,2,3]::integer[], array['theme1','seq1']::text[], 54),
('ssiap3-q141', 'ssiap3-partie2', 'quiz', 'Comment le SSIAP 3 justifie-t-il le maintien d''un effectif SSIAP 2 lors d''une période de très faible affluence (fermeture partielle, travaux, vacances scolaires) où la direction souhaite réduire les coûts ?', 'La réduction des effectifs SSIAP lors de faible affluence est une demande fréquente de la direction mais juridiquement impossible si l''établissement reste ouvert : l''effectif SSIAP minimal est défini par l''arrêté d''exploitation (qui précise les conditions d''exploitation incluant les effectifs SSIAP requis) — cet effectif s''applique dès l''ouverture de l''établissement quel que soit l''effectif public présent ; la présence de travailleurs (même en petit nombre) dans un ERP impose le maintien des obligations de sécurité incendie ; les travaux augmentent souvent le risque incendie (permis de feu, inhibitions SSI) justifiant un effectif maintenu voire renforcé. Le SSIAP 3 doit tenir cette position fermement par écrit, en précisant les risques juridiques d''une non-conformité.', 1, null::integer[], array['theme2','seq2']::text[], 55),
('ssiap3-q143', 'ssiap3-partie2', 'quiz', 'Comment le SSIAP 3 conçoit-il un exercice de crise impliquant plusieurs services (SSIAP, accueil, soignants, sécurité, direction) pour un grand ERP de type U ?', 'Un exercice de crise multi-acteurs pour un grand ERP de type U nécessite une préparation rigoureuse : définition d''un scénario réaliste (incendie dans une zone précise à un moment précis) avec des injectables (informations injectées au fil de l''exercice pour faire évoluer la situation) ; attribution de rôles précis à chaque service (SSIAP : détection et coordination ; accueil : gestion du public ; soignants : évacuation des patients ; direction : décision de fermeture partielle ; sécurité : contrôle des accès) ; briefing des observateurs (personnes qui ne jouent pas mais notent les comportements pour le débriefing) ; déroulement en temps réel avec chronométrage ; débriefing structuré (à chaud : ressenti de chaque acteur ; à froid : analyse des écarts entre procédures et comportements réels, points forts et axes d''amélioration). Un exercice uniquement SSIAP ne teste pas les interfaces critiques avec les autres services.', 1, null::integer[], array['theme1','seq1']::text[], 56),
('ssiap3-q146', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 doit rédiger un rapport de synthèse après un sinistre important avec intervention des pompiers. Quels éléments essentiels ce rapport doit-il contenir ? (plusieurs réponses)', 'Le rapport de synthèse post-sinistre est un document de retour d''expérience (REX) essentiel qui doit contenir : chronologie détaillée (heure de départ de feu estimée, heure de première détection, heure d''alarme, heure d''appel pompiers, heure d''arrivée pompiers, heure de maîtrise, heure de fin d''intervention) pour identifier les délais et les éventuels retards ; analyse causale (cause directe + facteurs contributifs : défaut de maintenance, procédure non respectée, formation insuffisante) ; évaluation de la performance (le SSI a-t-il détecté rapidement ? l''alarme a-t-elle fonctionné ? l''évacuation s''est-elle déroulée correctement ?) ; plan d''action correctif concret (pour chaque dysfonctionnement identifié : mesure corrective, responsable désigné, délai de réalisation). Un rapport centré sur les sanctions individuelles est contre-productif et crée une culture de la peur qui nuit au REX futur.', null, array[0,1,2,4]::integer[], array['theme2','seq2']::text[], 57),
('ssiap3-q148', 'ssiap3-partie2', 'quiz', 'Le SSIAP 3 est responsable de la sécurité incendie d''un site multi-bâtiments (campus universitaire de 15 bâtiments). Comment organise-t-il la coordination entre les différents services SSIAP locaux ?', 'La gestion multi-sites requiert une organisation spécifique : un PC sécurité central supervisant l''ensemble du campus (via GTB/SCADA ou réseau radio) permettant une vision globale et une coordination des ressources en cas de sinistre sur un bâtiment (possibilité de faire appel aux agents des bâtiments voisins) ; procédures communes standardisées pour tous les bâtiments (même codification radio, mêmes fiches réflexes, même structure de POI) facilitant les renforts mutuels ; exercices multi-bâtiments testant les interfaces (coordination PC local/PC central, gestion des flux d''évacuation entre bâtiments proches) ; communication permanente (réseau radio commun, canaux téléphoniques dédiés entre PC locaux et PC central). L''indépendance totale des bâtiments priverait le campus de la capacité de mutualiser ses ressources en cas de sinistre grave.', 1, null::integer[], array['theme1','seq1']::text[], 58),
('ssiap3-q150', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 est chargé de former les futurs SSIAP 2 en stage pratique dans son établissement. Quelles compétences prioritaires doit-il développer chez les stagiaires ? (plusieurs réponses)', 'La formation pratique des futurs SSIAP 2 doit prioritairement développer les compétences opérationnelles qui font la différence sur le terrain : lecture du tableau SSI (un SSIAP 2 doit décoder instantanément un état d''alarme, de défaut ou d''inhibition sur une centrale catégorie A avec ses multiples zones et fonctions) ; prise de décision en situation ambiguë (la levée de doute, la décision de déclencher ou non l''alarme générale, l''arbitrage entre fausse alarme probable et sinistre à ne pas manquer) ; management de l''équipe SSIAP 1 (donner des instructions claires sous pression, gérer les priorités entre plusieurs tâches simultanées en situation de sinistre) ; rédaction rigoureuse (main courante, rapport de levée de doute, rapport de fin de service). La réglementation ICPE (Installations Classées pour la Protection de l''Environnement) est un domaine spécialisé qui dépasse le champ d''application standard du SSIAP 2.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 59)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap3-q111','ssiap3-q115','ssiap3-q116','ssiap3-q117','ssiap3-q119','ssiap3-q120','ssiap3-q121','ssiap3-q125','ssiap3-q128','ssiap3-q131','ssiap3-q133','ssiap3-q134','ssiap3-q135','ssiap3-q137','ssiap3-q140','ssiap3-q141','ssiap3-q143','ssiap3-q146','ssiap3-q148','ssiap3-q150');
commit;

-- ===== ssiap3-partie2-sub04.sql =====
begin;
-- SSIAP 3 — Direction du service - Management stratégique (partie 2, sub 4/4, 20 cc_questions)
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap3-q153', 'ssiap3-partie2', 'multiple-select', 'Lors d''une revue de direction annuelle sur la sécurité incendie, quelles données le SSIAP 3 doit-il présenter pour permettre à la direction de prendre des décisions éclairées ? (plusieurs réponses)', 'La revue de direction est l''instance de pilotage stratégique de la sécurité incendie où le SSIAP 3 joue un rôle de reporting et de conseil : tableau de bord des KPI (indicateurs quantifiés permettant à la direction de situer le niveau de sécurité sans expertise technique : 95% des installations conformes, 3 fausses alarmes/mois en baisse vs 7 l''an passé, temps moyen d''évacuation de 4 min vs objectif 5 min) ; analyse des tendances (une vision pluriannuelle révèle des dégradations progressives invisibles sur une année) ; risques résiduels (quels risques subsistent malgré les mesures en place — information décisive pour les arbitrages d''investissement) ; proposition budgétaire argumentée avec ROI (Retour sur Investissement) pour les grands projets (coût de l''investissement vs coût du risque évité). Les salaires comparatifs sont une information RH utile mais hors périmètre d''une revue de direction sécurité.', null, array[0,1,2,4]::integer[], array['theme2','seq2']::text[], 60),
('ssiap3-q154', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 doit mettre en place une procédure de gestion des clés donnant accès aux locaux sensibles (chaufferie, local SSI, locaux électriques). Quels principes doit-elle respecter ? (plusieurs réponses)', 'La gestion des clés des locaux sensibles est un enjeu de sécurité physique directement lié à la sécurité incendie : traçabilité (registre de remise des clés avec identité du demandeur, heure, motif, signature — permet d''identifier qui avait accès en cas d''incident) ; principe du besoin d''en connaître (seules les personnes ayant une raison légitime d''accéder au local disposent d''une clé — liste nominative maintenue à jour) ; procédure de perte/vol (signalement immédiat, remplacement des cylindres si nécessaire pour éviter l''accès non autorisé) ; double jeu sécurisé accessible aux secours (le PC sécurité doit pouvoir fournir rapidement les clés aux pompiers lors d''une intervention — coffret à clés avec code connu des pompiers ou double jeu au PC). Remettre les clés à toute personne en uniforme sans vérification est une faille de sécurité grave.', null, array[0,1,3,4]::integer[], array['theme1','seq1']::text[], 61),
('ssiap3-q157', 'ssiap3-partie2', 'quiz', 'Comment le SSIAP 3 gère-t-il la transition entre deux prestataires de maintenance du SSI (fin de contrat / nouveau prestataire) pour assurer la continuité de service ?', 'La transition entre prestataires de maintenance SSI est une période à risque si elle n''est pas gérée rigoureusement : visite conjointe (ancien et nouveau prestataire ensemble pour transmission des connaissances spécifiques sur l''installation : historique des pannes, pièces de rechange en stock, particularités de configuration) ; transfert documentaire complet (plans as-built, notices des équipements, historique des interventions, liste des non-conformités en cours) ; état zéro documenté (le nouveau prestataire réalise une inspection complète et documente l''état de chaque composant avant prise en charge — pour ne pas hériter de responsabilité sur des défauts antérieurs non déclarés) ; période de transition supervisée (le SSIAP 3 vérifie que le nouveau prestataire maîtrise réellement l''installation avant de signer le bon de prise en charge). Une transition bâclée peut laisser des défauts non suivis entre les deux contrats.', 1, null::integer[], array['theme2','seq2']::text[], 62),
('ssiap3-q159', 'ssiap3-partie2', 'quiz', 'Lors d''un audit de son service, le SSIAP 3 constate que les fiches réflexes opérationnelles n''ont pas été mises à jour depuis 3 ans malgré plusieurs modifications du bâtiment. Quelle est la gravité de cette situation et sa réaction ?', 'Des fiches réflexes obsolètes représentent un risque opérationnel réel lors d''un sinistre : un agent qui suit une fiche indiquant d''envoyer quelqu''un dans une zone de détection qui correspond maintenant à un local transformé perd du temps précieux ; des numéros de téléphone périmés (mainteneur SSI, responsable de permanence) retardent l''activation de l''aide extérieure ; des procédures d''évacuation caduques (point de rassemblement déplacé, issue modifiée) peuvent désorganiser l''évacuation. La mise à jour doit être immédiate et rigoureuse : révision complète de toutes les fiches, validation par le SSIAP 3, impression et remplacement physique de toutes les copies (PC sécurité, directeur de garde, SSIAP 2 de permanence), formation des agents aux changements significatifs. Les annotations manuscrites ne sont pas acceptables (illisibles, non officielles).', 1, null::integer[], array['theme2','seq2']::text[], 63),
('ssiap3-q162', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 doit gérer la sécurité incendie lors d''un chantier de désamiantage dans un bâtiment en exploitation partielle. Quelles mesures spécifiques s''imposent ? (plusieurs réponses)', 'Le désamiantage dans un bâtiment en exploitation partielle cumule des risques spécifiques qui se superposent : le confinement hermétique (nécessaire pour éviter la dispersion des fibres d''amiante) crée un espace confiné avec des risques propres (accumulation de gaz, difficultés d''évacuation) ; les équipements électriques du chantier (aspirateurs, éclairages temporaires, outils) peuvent créer des points chauds ou des courts-circuits dans un environnement où les protections normales peuvent être altérées ; les travaux par points chauds sont incompatibles avec la présence de matériaux en cours de désamiantage (les fibres d''amiante en suspension peuvent être projetées par les flammes) ; le SSI de la zone peut être perturbé par la dépression ou les matériaux de confinement — une surveillance compensatoire est obligatoire si des détecteurs sont inhibés. Les opérateurs de désamiantage doivent être intégrés aux procédures d''évacuation de l''établissement.', null, array[0,1,2,3]::integer[], array['theme1','seq1']::text[], 64),
('ssiap3-q170', 'ssiap3-partie2', 'multiple-select', 'Comment le SSIAP 3 aborde-t-il la question de la sécurité incendie lors des réunions avec les locataires d''un immeuble de bureaux multi-locataires ? (plusieurs réponses)', 'La coordination sécurité incendie dans un immeuble multi-locataires est une mission spécifique du SSIAP 3 : information des obligations (chaque locataire est responsable de la sécurité dans ses propres locaux — formation de son personnel, respect des consignes, signalement des anomalies) ; coordination des systèmes d''alarme (les SSI indépendants de chaque locataire doivent être interconnectés ou un protocole doit garantir que l''alarme d''un locataire est bien portée à la connaissance des autres occupants de l''immeuble) ; contrôle des travaux locataires (toute modification des cloisons, du plafond, des gaines peut affecter le compartimentage ou le désenfumage de l''ensemble de l''immeuble — un accord préalable du gestionnaire est nécessaire) ; règlement intérieur de sécurité (document commun définissant les règles applicables à tous les locataires : stockage interdit dans les couloirs, permis de feu obligatoire, procédures d''évacuation communes). L''interdiction totale des travaux est impraticable.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 65),
('ssiap3-q172', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 supervise la mise en conformité d''un ERP suite à un avis défavorable de la commission. Comment organise-t-il le suivi des travaux de mise en conformité ? (plusieurs réponses)', 'Le suivi des travaux de mise en conformité après avis défavorable est une responsabilité directe du SSIAP 3 : planification structurée (décomposition en lots avec jalons intermédiaires, responsables désignés pour chaque lot, planning prévisionnel vs réel) permettant d''anticiper les retards ; vérifications intermédiaires (un contrôle à mi-parcours détecte les malfaçons avant qu''elles soient cachées par les finitions — un câblage SSI mal posé découvert avant les faux plafonds est plus facile à corriger) ; documentation photographique (photos datées de chaque étape clé : installation des câbles, pose des détecteurs, réalisation des calfeutrements coupe-feu) constituant les preuves pour la commission lors de la demande de levée de réserves ; préparation du dossier de levée (rapport de fin de travaux, essais fonctionnels, attestations des entreprises). La délégation totale sans contrôle expose le SSIAP 3 à des mauvaises surprises lors de la visite de levée.', null, array[0,1,2,4]::integer[], array['theme2','seq2']::text[], 66),
('ssiap3-q177', 'ssiap3-partie2', 'multiple-select', 'Quelle approche le SSIAP 3 adopte-t-il pour intégrer la sécurité incendie dans la démarche RSE (Responsabilité Sociétale des Entreprises) de son établissement ? (plusieurs réponses)', 'L''intégration de la sécurité incendie dans la RSE crée des synergies pertinentes : dimension environnementale (réduction des fausses alarmes = moins de déplacements de véhicules pompiers = moins d''émissions CO2 ; choix des agents extincteurs : les gaz inertes naturels comme l''argon ou l''azote ont un PRG nul contrairement aux HFC ; gestion responsable des déchets des opérations de maintenance comme les batteries usagées) ; dimension sociale (la formation incendie contribue au sentiment de sécurité des employés, à leur engagement et à leur bien-être — un salarié qui sait quoi faire en cas d''incendie est moins anxieux) ; dimension gouvernance (transparence sur les indicateurs de sécurité dans les rapports extra-financiers démontre la maturité de la gestion des risques). La suppression des extinctions automatiques pour économiser l''eau est une fausse économie qui augmente les risques.', null, array[0,1,2,4]::integer[], array['theme2','seq2']::text[], 67),
('ssiap3-q178', 'ssiap3-partie2', 'quiz', 'Le SSIAP 3 doit mettre en place un système de management de la sécurité incendie (SMSI) au sens organisationnel du terme. Sur quel modèle peut-il s''appuyer ?', 'Le SMSI (Système de Management de la Sécurité Incendie) au sens organisationnel s''appuie sur le cycle PDCA (roue de Deming) universel aux systèmes de management : Plan (planifier) — définir la politique sécurité incendie, les objectifs mesurables, les ressources nécessaires, les procédures et le plan d''action ; Do (faire) — mettre en œuvre les procédures, former les agents, réaliser les exercices, effectuer les vérifications ; Check (vérifier) — mesurer les indicateurs de performance, réaliser des audits internes, analyser les incidents et exercices ; Act (ajuster) — identifier les axes d''amélioration, corriger les dérives, mettre à jour les procédures, adapter les ressources. Ce cycle itératif garantit l''amélioration continue du niveau de sécurité incendie. Il est applicable indépendamment de toute certification ISO — c''est une approche de management universelle.', 1, null::integer[], array['theme2','seq2']::text[], 68),
('ssiap3-q181', 'ssiap3-partie2', 'multiple-select', 'Comment le SSIAP 3 gère-t-il la situation où plusieurs alarmes se déclenchent simultanément dans des zones différentes de l''établissement ? (plusieurs réponses)', 'Des alarmes simultanées dans plusieurs zones sont un scénario grave nécessitant une réponse structurée : la simultanéité de plusieurs alarmes réduit fortement la probabilité de fausses alarmes multiples — le déclenchement de l''alarme générale sans attendre la levée de doute est justifié ; priorisation des ressources humaines (avec plusieurs zones simultanées, les agents ne peuvent pas toutes les couvrir — les zones à fort effectif public et les voies d''évacuation principales sont prioritaires) ; appel immédiat des pompiers (plusieurs foyers simultanés dépassent les capacités d''une équipe SSIAP) ; signalement aux forces de l''ordre (plusieurs départs de feu simultanés dans un ERP sont caractéristiques d''un acte malveillant — attentat incendiaire — la police doit être alertée parallèlement aux pompiers). Disperser tous les agents simultanément peut laisser le PC sans coordination centrale.', null, array[0,1,3,4]::integer[], array['theme3','seq3']::text[], 69),
('ssiap3-q183', 'ssiap3-partie2', 'quiz', 'Le SSIAP 3 doit participer à l''élaboration du Plan Local d''Urbanisme (PLU) de sa commune en tant qu''expert sécurité incendie d''un grand établissement. Quel est son apport spécifique ?', 'Le SSIAP 3 d''un grand établissement peut légitimement contribuer aux discussions d''urbanisme qui impactent la sécurité incendie de son établissement : participation aux enquêtes publiques et concertations sur les projets modifiant les voies d''accès, la densification du voisinage ou l''implantation de nouvelles activités (ICPE, dépôts inflammables) à proximité ; signalement des enjeux d''accessibilité des secours (un projet de construction obstruant la voie d''accès principale des pompiers doit être signalé) ; contribution sur les délais d''intervention (une densification du trafic augmente les délais d''intervention des secours — les distances d''effet en cas de sinistre augmentent proportionnellement). Cette participation s''effectue dans le cadre des procédures légales (enquêtes publiques, consultations) sans droit d''imposition unilatérale.', 1, null::integer[], array['theme2','seq2']::text[], 70),
('ssiap3-q184', 'ssiap3-partie2', 'multiple-select', 'Comment le SSIAP 3 conçoit-il les procédures d''évacuation pour un établissement recevant régulièrement des groupes de personnes âgées dépendantes en visite (musée, site touristique) ? (plusieurs réponses)', 'L''accueil de groupes de personnes âgées dépendantes nécessite une préparation spécifique : recensement à l''accueil (combien de personnes nécessitent une assistance à l''évacuation, quelle nature de limitation) pour adapter les ressources SSIAP en temps réel ; formation des accompagnateurs du groupe (ils sont présents avec les personnes et peuvent être les premiers à agir — ils doivent connaître le signal d''alarme, la direction des sorties et comment guider les personnes dépendantes) ; agent SSIAP dédié si le groupe est important ou si les limitations sont sévères (accompagnement proactif pendant toute la visite) ; équipements d''évacuation adaptés (chaises d''évacuation dans les escaliers, espaces d''attente sécurisés accessibles en fauteuil roulant). L''interdiction d''accueil est discriminatoire et illégale — l''accessibilité universelle est un droit.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 71),
('ssiap3-q185', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 doit produire une analyse de risques pour justifier l''augmentation de l''effectif SSIAP lors d''un événement exceptionnel. Quels facteurs de risque augmenté doit-il documenter ? (plusieurs réponses)', 'L''analyse de risques justifiant un renforcement des effectifs SSIAP lors d''un événement exceptionnel doit documenter l''augmentation objective des facteurs de risque : sureffectif (plus de personnes à évacuer = délai d''évacuation plus long = risque accru si le RSET augmente) ; configurations inhabituelles (structures temporaires non prévues dans le calcul de charge des planchers, câblages électriques supplémentaires, générateurs de fumée d''effets spéciaux, réductions de dégagements) ; délais d''intervention des secours allongés (si l''événement crée des embouteillages autour de l''établissement, le délai d''arrivée des pompiers augmente, justifiant une capacité d''intervention interne renforcée) ; réduction des dégagements disponibles (le matériel de scène peut bloquer des issues, réduisant les UP disponibles à l''évacuation). L''expérience de l''organisateur est un facteur positif mais ne suffit pas à compenser objectivement une augmentation des risques.', null, array[0,1,2,3]::integer[], array['theme2','seq2']::text[], 72),
('ssiap3-q186', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 est responsable d''un établissement situé dans une zone classée SEVESO (risque technologique majeur à proximité). Quelles adaptations de ses procédures sont nécessaires ? (plusieurs réponses)', 'La proximité d''un site SEVESO impose des adaptations spécifiques du dispositif de sécurité incendie : intégration des scénarios SEVESO dans le POI (un nuage toxique peut imposer le confinement tandis qu''une explosion peut imposer l''évacuation — la nature du risque détermine la stratégie, ce qui peut être contra-intuitif par rapport aux réflexes incendie) ; connexion aux systèmes d''alerte publics (sirènes PPRT, applications d''alerte préfectorale) pour recevoir les alertes en temps réel ; formation des agents aux risques technologiques spécifiques (comportement en cas de nuage toxique : fermer les ouvrants, se réfugier en hauteur pour les produits plus lourds que l''air) ; coordination avec l''exploitant SEVESO (réunions régulières, exercices communs, partage d''informations sur les scénarios d''accident) et avec la préfecture (PPRT - Plan de Prévention des Risques Technologiques). L''évacuation systématique peut aggraver la situation selon la nature du risque.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 73),
('ssiap3-q188', 'ssiap3-partie2', 'quiz', 'Le SSIAP 3 doit justifier auprès de la direction le renouvellement du contrat d''un organisme de contrôle agréé plus cher qu''un concurrent. Quels arguments avance-t-il ?', 'Le choix d''un organisme de contrôle agréé ne doit pas reposer uniquement sur le prix : la qualification (agrément ministériel spécifique aux types d''installations contrôlées) est un critère incompressible ; la connaissance de l''installation (un organisme qui suit l''établissement depuis plusieurs années détecte plus facilement les dérives et évolutions non déclarées) ; la qualité des rapports (un rapport exhaustif et précis est un outil de gestion pour le SSIAP 3 et une protection juridique — un rapport superficiel peut manquer des non-conformités graves). Un organisme moins cher produisant des rapports de faible qualité peut coûter bien plus cher en cas de sinistre sur une installation non conforme. Le SSIAP 3 doit défendre cette position avec des arguments concrets.', 1, null::integer[], array['theme2','seq2']::text[], 74),
('ssiap3-q191', 'ssiap3-partie2', 'quiz', 'Le SSIAP 3 doit évaluer les besoins en formation pour faire face à l''introduction de nouvelles technologies dans son service (tablettes tactiles pour les rondes, supervision SSI sur écran). Quelle approche adopte-t-il ?', 'L''introduction de nouvelles technologies dans un service SSIAP nécessite une gestion du changement structurée : diagnostic des compétences numériques existantes (certains agents peuvent avoir des difficultés avec les interfaces tactiles ou les logiciels de supervision — l''identifier permet d''adapter la formation) ; analyse des écarts (compétences actuelles vs compétences requises pour chaque outil) ; plan de formation progressif (formation théorique sur les fonctionnalités, pratique sur simulateur ou bac de test avant déploiement réel, accompagnement en binôme lors des premiers jours d''utilisation opérationnelle) ; accompagnement individualisé des agents les moins à l''aise (tutorat par un collègue, cc_sessions supplémentaires). Imposer sans former crée des erreurs opérationnelles dangereuses. Remplacer les agents est une réponse disproportionnée et socialement problématique.', 1, null::integer[], array['theme1','seq1']::text[], 75),
('ssiap3-q192', 'ssiap3-partie2', 'multiple-select', 'Comment le SSIAP 3 assure-t-il la cohérence entre le POI (Plan Opérationnel Interne) et le PCS (Plan Communal de Sauvegarde) de sa commune ? (plusieurs réponses)', 'La cohérence POI/PCS est un enjeu de coordination sécurité civile : le POI de l''établissement doit s''articuler avec le PCS de la commune (Plan Communal de Sauvegarde) pour éviter les contradictions ou les lacunes lors d''une crise touchant simultanément l''établissement et la commune ; transmission du POI (ou d''un résumé opérationnel) à la mairie permet l''intégration dans le PCS communal et informe les autorités sur les capacités et besoins de l''établissement en cas de crise ; participation aux exercices communaux (les exercices inter-services testent les interfaces entre l''établissement et les secours communaux) ; vérification de compatibilité (si le PCS prévoit une évacuation de masse de la commune, les procédures d''évacuation de l''établissement doivent s''y intégrer et non y faire obstruction) ; référent de liaison facilitant la communication en temps de crise. Le POI et le PCS sont deux documents complémentaires et non substituables.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 76),
('ssiap3-q193', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 doit concevoir un programme de sensibilisation à la sécurité incendie pour les nouveaux arrivants d''un grand établissement tertiaire. Quels cc_modules prioritaires inclut-il ? (plusieurs réponses)', 'Le programme de sensibilisation des nouveaux arrivants doit être efficace et concis (1 à 2 heures maximum pour ne pas décourager) en couvrant l''essentiel : reconnaissance du signal d''alarme (sonore et lumineux) et comportement associé (évacuation sans panique, ne pas utiliser les ascenseurs, se rendre au point de rassemblement) ; localisation des issues depuis son poste de travail spécifique (le nouvel arrivant doit faire le trajet physiquement ou l''identifier sur le plan affiché) ; notions de base sur les extincteurs (comment reconnaître le type adapté, comment l''utiliser en 3 étapes PASS - Piquer, Armer, Sweep sur Sinistre — une démonstration pratique est idéale) ; présentation du service SSIAP (qui appeler, le numéro interne, le rôle des agents). Une formation de 2 jours sur la réglementation ERP est totalement inadaptée pour des non-spécialistes.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 77),
('ssiap3-q194', 'ssiap3-partie2', 'multiple-select', 'Le SSIAP 3 est confronté à un agent SSIAP 2 qui conteste publiquement ses décisions auprès des autres agents. Comment gère-t-il cette situation ? (plusieurs réponses)', 'La contestation publique des décisions du SSIAP 3 par un agent SSIAP 2 est une situation managériale sérieuse affectant l''autorité et la cohésion du service : entretien privé en premier lieu (comprendre le fond du désaccord — il peut être légitime et révéler une erreur du SSIAP 3, ou être infondé mais doit être traité sérieusement) ; distinction claire entre désaccord exprimé en interne (encouragé — un agent qui soulève des problèmes en privé contribue à l''amélioration) et contestation publique (sapant l''autorité et déstabilisant l''équipe — incompatible avec les exigences d''une organisation de sécurité) ; si après entretien le comportement persiste, la procédure disciplinaire formelle (avertissement, mise à pied) est la voie appropriée. La sanction immédiate sans entretien est contraire aux principes du droit du travail. L''ignorance laisse le problème s''aggraver.', null, array[1,2,4]::integer[], array['theme1','seq1']::text[], 78),
('ssiap3-q198', 'ssiap3-partie2', 'quiz', 'Le SSIAP 3 reçoit une demande d''un assureur d''accéder aux registres de sécurité suite à un sinistre. Quelle est sa procédure ?', 'La communication des registres de sécurité à un assureur après sinistre est une démarche sensible avec des enjeux juridiques et financiers importants : consultation préalable de la direction et du service juridique (les documents peuvent être utilisés pour déterminer la responsabilité et l''indemnisation — leur communication doit être encadrée) ; communication dans le cadre légal (la police d''assurance définit les obligations de communication — l''assuré a généralement l''obligation de communiquer les informations pertinentes pour la liquidation du sinistre) ; traçabilité des transmissions (noter précisément quels documents ont été transmis, à qui, à quelle date — cette traçabilité est indispensable en cas de contestation ultérieure) ; conservation des copies (ne jamais remettre les originaux sans garder une copie). Détruire des documents est une obstruction à la justice passible de poursuites pénales graves.', 1, null::integer[], array['theme2','seq2']::text[], 79)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap3-q153','ssiap3-q154','ssiap3-q157','ssiap3-q159','ssiap3-q162','ssiap3-q170','ssiap3-q172','ssiap3-q177','ssiap3-q178','ssiap3-q181','ssiap3-q183','ssiap3-q184','ssiap3-q185','ssiap3-q186','ssiap3-q188','ssiap3-q191','ssiap3-q192','ssiap3-q193','ssiap3-q194','ssiap3-q198');
commit;

-- ===== ssiap3-partie3-sub01.sql =====
begin;
-- SSIAP 3 — Expertise technique et ingénierie (partie 3, sub 1/3, 20 cc_questions)
values ('ssiap3-partie3', 3, 'Expertise technique et ingénierie', '53 cc_questions', '⚙️', 'from-cyan-500 to-blue-600', 2, true)
on conflict (id) do update set title=excluded.title, subtitle=excluded.subtitle, icon=excluded.icon, color=excluded.color, display_order=excluded.display_order;
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap3-q12', 'ssiap3-partie3', 'quiz', 'Le SSIAP 3 participe à la conception d''un nouveau bâtiment ERP. Quand doit-il intervenir dans le processus de construction pour être le plus efficace ?', 'Intervenir le plus tôt possible dans le processus de construction est le principe fondamental de la sécurité incendie by design. Le SSIAP 3 doit s''impliquer dès la phase de programmation architecturale (avant même les premiers plans) pour : définir les contraintes réglementaires qui conditionneront les choix architecturaux (compartimentage, dégagements, accessibilité pompiers) ; éviter les modifications coûteuses post-conception ; intégrer les systèmes de sécurité (SSI, désenfumage, sprinklers) de manière optimale dès le départ. Plus l''intervention est tardive, plus les adaptations sont coûteuses et contraignantes. Un SSIAP 3 sollicité uniquement à la réception trouvera des problèmes impossibles ou très coûteux à corriger.', 1, null::integer[], array['theme1','seq1','Intégration de la sécurité en phase conception','Conception et ingénierie incendie']::text[], 0),
('ssiap3-q13', 'ssiap3-partie3', 'quiz', 'Qu''est-ce que l''approche ''SFPE'' (Society of Fire Protection Engineers) dans le contexte de l''ingénierie de sécurité incendie ?', 'La SFPE (Society of Fire Protection Engineers) est une organisation professionnelle internationale qui promeut l''ingénierie de sécurité incendie (Fire Protection Engineering - FPE), démarche qui s''appuie sur les sciences du feu (modélisation de l''incendie et de la propagation des fumées par CFD - Computational Fluid Dynamics), l''analyse du comportement humain (RSET - Required Safe Egress Time) et les probabilités de risque pour concevoir des solutions de sécurité performantes et adaptées à chaque projet. Cette approche est complémentaire et parfois alternative aux prescriptions réglementaires classiques, notamment pour les projets architecturaux innovants. Le SSIAP 3 expert peut utiliser ces outils pour des projets complexes ou pour justifier des dérogations argumentées.', 1, null::integer[], array['theme2','seq1','Ingénierie de sécurité incendie avancée','Conception et ingénierie incendie']::text[], 1),
('ssiap3-q14', 'ssiap3-partie3', 'multiple-select', 'Le SSIAP 3 doit évaluer la pertinence d''un système d''extinction automatique à eau brouillard (water mist) pour protéger une cuisine professionnelle. Quels sont ses avantages par rapport aux sprinklers classiques ? (plusieurs réponses possibles)', 'Les systèmes à eau brouillard (water mist) présentent plusieurs avantages spécifiques : consommation d''eau très faible (5 à 50 fois moins que les sprinklers classiques) grâce aux gouttelettes de très petite taille (< 200 microns) offrant une surface d''échange thermique optimale, ce qui réduit considérablement les dégâts des eaux sur les équipements et denrées ; efficacité sur les feux de classes A et B car les gouttelettes fines pénètrent les flammes et atteignent la surface du combustible liquide ; refroidissement des gaz et fumées par vaporisation intense (absorption de chaleur latente), limitant la propagation. En revanche, ils ne supportent pas mieux les basses températures que les sprinklers (problème similaire de gel) et leur coût d''installation est généralement supérieur aux sprinklers classiques.', null, array[0,1,3]::integer[], array['theme3','seq2','Systèmes d''extinction spéciaux','Systèmes d''extinction avancés']::text[], 2),
('ssiap3-q15', 'ssiap3-partie3', 'multiple-select', 'Dans un IGH de classe GHD (hôtel de grande hauteur), quelles exigences spécifiques de sécurité incendie s''appliquent par rapport à un hôtel ERP classique ? (plusieurs réponses possibles)', 'Les IGH de classe GHD (hôtels de grande hauteur, plancher au-dessus de 28 m) ont des exigences beaucoup plus strictes que les hôtels ERP : service de sécurité permanent 24h/24 7j/7 sans dérogation admise (les établissements à sommeil de grande hauteur présentent un risque maximal) ; compartimentage par niveau avec planchers REI 120 (contra minimum REI 60 pour un hôtel ERP standard) ; sprinkler généralisé obligatoire dans toutes les chambres et parties communes (exigence unique aux IGH) ; mise en pression des cages d''escaliers (pour maintenir des voies d''évacuation praticables à travers plusieurs étages de fumées). Les exercices d''évacuation mensuels ne sont pas imposés (bi-annuels comme pour les ERP).', null, array[0,1,2,4]::integer[], array['theme4','seq3','IGH - Exigences techniques avancées','IGH - Expertise spécifique']::text[], 3),
('ssiap3-q34', 'ssiap3-partie3', 'quiz', 'Qu''est-ce que la simulation numérique de l''incendie (CFD - Computational Fluid Dynamics) et comment le SSIAP 3 peut-il l''exploiter ?', 'La simulation CFD (Computational Fluid Dynamics) appliquée à l''incendie (logiciels FDS - Fire Dynamics Simulator, PHOENICS, Pyrosim) modélise numériquement la physique du feu : propagation des flammes, dispersion des fumées et des gaz toxiques, champs de température, visibilité dans les voies d''évacuation, en 3D et en temps réel. Le SSIAP 3 expert peut l''exploiter pour : valider une conception de désenfumage (vérifier que les exutoires positionnés selon le plan assurent bien la stratification souhaitée) ; démontrer l''équivalence d''une solution alternative à la prescription réglementaire dans le cadre d''une dérogation ; analyser un sinistre passé pour comprendre comment il s''est propagé. Ces outils sont utilisés dans l''ingénierie de sécurité incendie par performance (ISI) et nécessitent une formation spécialisée.', 1, null::integer[], array['theme2','seq1','Ingénierie de sécurité incendie avancée','Conception et ingénierie incendie']::text[], 4),
('ssiap3-q35', 'ssiap3-partie3', 'multiple-select', 'Le SSIAP 3 analyse un projet de data center avec des risques incendie très spécifiques. Quelles caractéristiques de protection doit-il préconiser ? (plusieurs réponses possibles)', 'Les data centers présentent des risques incendie très spécifiques nécessitant des solutions adaptées : extinction à gaz inerte (argonite, inergen, Novec 1230 ou FM-200 pour les suppressions chimiques) permettant l''extinction sans endommager les équipements électroniques et sans résidu ; détection très précoce par aspiration (VESDA - Very Early Smoke Detection Apparatus) capturant des particules de combustion bien avant que la fumée soit visible, permettant d''intervenir avant le départ de feu ; compartimentage renforcé (les salles de serveurs, les locaux électriques, les locaux de climatisation doivent être des compartiments distincts pour limiter la propagation) ; procédures de mise hors tension (essentielle avant toute intervention humaine dans une salle sous tension). Les sprinklers à eau standard sont incompatibles avec les équipements électroniques sensibles.', null, array[0,1,3,4]::integer[], array['theme3','seq2','Systèmes d''extinction spéciaux','Systèmes d''extinction avancés']::text[], 5),
('ssiap3-q36', 'ssiap3-partie3', 'multiple-select', 'Lors d''une réception technique d''un nouveau SSI après installation, quelles vérifications le SSIAP 3 doit-il effectuer ou faire effectuer ? (plusieurs réponses possibles)', 'La réception d''un nouveau SSI est une étape critique que le SSIAP 3 doit superviser ou valider rigoureusement : vérification de conformité du câblage par rapport aux plans d''exécution et aux normes NF S 61-932 (section des câbles, cheminement, distances) ; test exhaustif de chaque détecteur (simulation de fumée/chaleur) et de chaque déclencheur manuel pour s''assurer de leur bon fonctionnement ; vérification fonctionnelle de chaque DAS (les portes CF se ferment-elles bien ? Les exutoires s''ouvrent-ils dans le bon sens ?) ; test des alimentations électriques (coupure du secteur pour vérifier la bascule sur AES et le maintien de toutes les fonctions) ; signature du procès-verbal de réception qui engage l''installateur et atteste que le système est conforme. Cette réception est produite à la commission de sécurité lors de la demande d''ouverture.', null, array[0,1,2,3,4]::integer[], array['theme10','seq4','Réception technique des installations','Réception et mise en service']::text[], 6),
('ssiap3-q37', 'ssiap3-partie3', 'multiple-select', 'Le SSIAP 3 évalue l''installation d''un système de gestion de l''évacuation basé sur l''intelligence artificielle. Quels avantages et limites doit-il analyser ?', 'Les systèmes d''aide à l''évacuation par IA représentent une innovation prometteuse avec des avantages réels : optimisation des chemins d''évacuation en temps réel (guidage dynamique évitant les zones enfumées, équilibrage des flux aux nœuds de circulation) intégrant la localisation des occupants (via badges, smartphones) et l''état des dégagements (capteurs). Mais les limites sont importantes : dépendance au réseau électrique et informatique (que se passe-t-il si le système tombe en panne au moment du sinistre ?) ; vulnérabilité aux cyberattaques (un système IA mal sécurisé peut être manipulé pour désorienter l''évacuation) ; nécessité absolue de procédures manuelles de secours et de formation des agents pour fonctionner sans le système. La réglementation française ne reconnaît pas encore ces systèmes comme substituts aux exigences réglementaires classiques (en 2025).', null, array[0,2]::integer[], array['theme11','seq5','Innovation et nouvelles technologies','Technologies émergentes']::text[], 7),
('ssiap3-q65', 'ssiap3-partie3', 'quiz', 'Lors d''une expertise technique sur une installation de sprinklers existante, le SSIAP 3 constate que la densité d''arrosage ne correspond pas aux risques actuels du local (stockage de produits plus inflammables qu''initialement prévu). Quelle est sa démarche ?', 'Un changement d''activité modifiant la nature ou la quantité des matières stockées peut invalider le dimensionnement initial d''une installation sprinkler. La règle APSAD R1 définit des classes de risque (OH1 à OH4 pour les risques ordinaires, HH pour les hauts risques) avec des densités d''arrosage différentes. Si le risque augmente, l''installation doit être recalculée et mise à niveau. Le SSIAP 3 doit : mandater une étude de vérification par un bureau d''études spécialisé ; soumettre à un organisme agréé APSAD ; engager les travaux nécessaires. Une réception antérieure ne dispense pas d''une mise en conformité lors d''un changement d''usage.', 1, null::integer[], array['theme1','seq1']::text[], 8),
('ssiap3-q66', 'ssiap3-partie3', 'quiz', 'La qualification Q18 concerne les entreprises de maintenance :', 'La qualification Q18 de l''APSAD (Assemblée Plénière des Sociétés d''Assurances Dommages) concerne spécifiquement la maintenance des Systèmes de Sécurité Incendie (SSI) : centrales de détection, CMSI, équipements d''alarme, DAS. Les extincteurs relèvent de la qualification Q1/Q2, les colonnes sèches de Q15, l''éclairage de sécurité de Q17. Aucune des propositions listées ne correspond à Q18.', 1, null::integer[], array['theme1','seq1']::text[], 9),
('ssiap3-q67', 'ssiap3-partie3', 'multiple-select', 'Le SSIAP 3 doit évaluer la pertinence d''installer un système de détection par aspiration (type VESDA) dans une salle informatique critique. Quels arguments justifient ce choix ? (plusieurs réponses)', 'Les systèmes de détection par aspiration (Very Early Smoke Detection Apparatus - VESDA et équivalents) présentent des avantages majeurs pour les salles informatiques critiques : détection au stade incipient (particules de combustion imperceptibles bien avant la fumée visible) permettant une intervention avant tout dommage matériel ; efficacité en environnement à fort débit d''air (climatisation) où les détecteurs ponctuels sont peu efficaces car les fumées sont diluées et dispersées ; seuils de détection multiples et programmables permettant de distinguer la pollution normale de l''alarme réelle (réduction des fausses alarmes) ; localisation par identification du point d''aspiration actif. En revanche, leur coût d''installation est nettement supérieur aux détecteurs ponctuels (réseau de tubes capillaires à poser dans tout le faux-plancher et faux-plafond).', null, array[0,1,3,4]::integer[], array['theme1','seq1']::text[], 10),
('ssiap3-q68', 'ssiap3-partie3', 'quiz', 'Comment le SSIAP 3 détermine-t-il la catégorie d''un SSI appropriée pour un ERP de 2ème catégorie de type M (centre commercial) avec détection automatique généralisée ?', 'Pour un ERP de type M (magasins, centres commerciaux) de 2ème catégorie (1501 à 5000 personnes au 1er sous-sol/en étage ou 3001 à 5000 en RDC), la réglementation (article MS 53 et suivants) impose un SSI de catégorie A : c''est le niveau le plus élevé, comprenant un SDI (Système de Détection Incendie) avec détection automatique généralisée et un SMSI (Système de Mise en Sécurité Incendie) gérant automatiquement tous les DAS, le désenfumage et l''alarme. La catégorie A est également requise dès qu''une détection automatique généralisée est présente, quelle que soit la taille. Les catégories B à E correspondent à des niveaux de complexité décroissants pour des établissements moins importants.', 1, null::integer[], array['theme1','seq1']::text[], 11),
('ssiap3-q70', 'ssiap3-partie3', 'multiple-select', 'Le SSIAP 3 est sollicité pour donner son avis sur la mise en place d''un système d''extinction automatique à gaz dans une archive. Quels types de gaz inertes sont adaptés et pourquoi ? (plusieurs réponses)', 'Pour les archives, le choix de l''agent extincteur est crucial car l''eau, la poudre ou certains gaz chimiques peuvent détruire les documents : IG-55 (50% Ar / 50% N2) et IG-100 (N2 pur) : gaz naturels inertes qui éteignent par réduction du taux d''O2 en dessous de 15% sans résidu, sans corrosion, sans contamination des documents — solution de référence pour les archives et locaux avec équipements sensibles ; CO2 : très efficace techniquement mais mortel pour les personnes à concentration d''extinction (34-40%) — utilisable uniquement dans des locaux strictement inaccessibles aux personnes avec procédure de sécurité draconienne. Le HFC-227ea (FM-200) est un gaz chimique halogéné efficace mais son impact sur les documents anciens est discuté et son PRG (Potentiel de Réchauffement Global) élevé pose des cc_questions environnementales. La poudre est catastrophique pour les archives (contamination irréversible).', null, array[0,1,3]::integer[], array['theme1','seq1']::text[], 12),
('ssiap3-q75', 'ssiap3-partie3', 'quiz', 'Dans le cadre de la gestion des risques, comment le SSIAP 3 utilise-t-il la méthode HAZOP (Hazard and Operability Study) ?', 'La méthode HAZOP (Hazard and Operability Study) est une technique d''analyse structurée des risques originellement développée pour l''industrie chimique mais applicable à tout système complexe. Dans le contexte SSIAP 3, elle permet d''analyser les dérives possibles des installations de sécurité incendie : pour chaque composant (détecteur, DAS, centrale), on applique des mots-guides (PAS DE, PLUS DE, MOINS DE, INVERSE DE, AUTRE QUE) pour identifier les défaillances et leurs conséquences. Exemples : ''PAS DE détection dans une zone'' → conséquence = incendie non détecté → barrière compensatoire ? ''AUTRE QUE ouverture pour un DAS'' → DAS se ferme quand il devrait s''ouvrir → quelle conséquence sur le désenfumage ? HAZOP est différent d''AMDEC qui part des modes de défaillance sans les mots-guides.', 0, null::integer[], array['theme2','seq2']::text[], 13),
('ssiap3-q76', 'ssiap3-partie3', 'multiple-select', 'Le SSIAP 3 est chargé de la sécurité incendie d''un data center de 2000 m² en sous-sol. Quelles mesures spécifiques au sous-sol doit-il prévoir ? (plusieurs réponses)', 'Un data center en sous-sol cumule les contraintes d''un local à risques élevés et d''un local souterrain : désenfumage exclusivement mécanique (pas d''exutoires naturels possibles en sous-sol, extracteurs mécaniques avec amenées d''air forcées) ; résistance au feu des structures renforcée (l''accès des secours par le dessus est impossible, toute la charge doit être portée par les structures en cas d''effondrement partiel) ; procédure de coupure électrique des équipements informatiques avant intervention (risque d''électrocution dans un environnement avec de nombreuses alimentations 230/400V, onduleurs, batteries) ; colonnes sèches pour l''alimentation des lances en sous-sol sans avoir à dérouler des tuyaux dans les escaliers ; éclairage de sécurité de haute autonomie (le personnel doit pouvoir évacuer en l''absence de toute lumière naturelle).', null, array[0,1,2,3,4]::integer[], array['theme1','seq1']::text[], 14),
('ssiap3-q79', 'ssiap3-partie3', 'multiple-select', 'Comment le SSIAP 3 évalue-t-il la faisabilité de la mise en place d''un système de gestion des fluides (sprinklers, colonnes humides) dans un bâtiment haussmannien parisien ? (plusieurs réponses)', 'L''installation de sprinklers dans un bâtiment haussmannien est techniquement possible mais exige une étude approfondie : analyse structurelle (les planchers haussmanniens en bois et plâtre peuvent nécessiter un renforcement pour supporter le poids des canalisations remplies d''eau, soit environ 1 à 2 kg/ml) ; vérification hydraulique (la pression sur le réseau public parisien est souvent insuffisante — une surpression avec réservoir de stockage peut être nécessaire) ; contraintes patrimoniales (dans les secteurs sauvegardés ou sites classés, l''ABF peut refuser certaines installations — des solutions discrètes comme les sprinklers à boîtier caché sont souvent imposées) ; étude du cheminement (éviter la destruction des stucs, moulures, parquets anciens en optimisant le tracé). Ce type de projet requiert une coordination entre le SSIAP 3, un BET fluides et l''ABF.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 15),
('ssiap3-q83', 'ssiap3-partie3', 'multiple-select', 'Le SSIAP 3 doit définir les zones de défense incendie d''un ERP complexe de type W (administration) sur 8 niveaux. Sur quels critères base-t-il ce découpage ? (plusieurs réponses)', 'Le découpage en zones de détection d''un SSI catégorie A répond à des critères techniques précis : la superficie par zone est limitée (2 500 m² maximum par zone de détection selon la norme NF S 61-970, pour permettre une localisation précise du sinistre) ; la cohérence avec le compartimentage coupe-feu est essentielle (une zone de détection doit idéalement correspondre à un compartiment coupe-feu pour que la mise en sécurité soit cohérente — déclenchement du désenfumage du bon compartiment, fermeture des bonnes portes CF) ; l''adéquation avec les zones de désenfumage permet une gestion automatique cohérente. La facilité de ronde est un critère opérationnel secondaire. Le nombre de détecteurs par boucle dépend des équipements choisis et n''est pas limité à 32 dans les systèmes modernes adressables.', null, array[0,1,3]::integer[], array['theme1','seq1']::text[], 16),
('ssiap3-q84', 'ssiap3-partie3', 'quiz', 'Quelle est la différence entre un CMSI (Centralisateur de Mise en Sécurité Incendie) de type A et de type B ?', 'La norme NF S 61-934 définit deux types de CMSI : le CMSI de type A gère de manière entièrement automatique toutes les fonctions de mise en sécurité (déclenchement de l''alarme, activation du désenfumage, fermeture des portes CF, etc.) sans intervention humaine — c''est le niveau requis pour les SSI de catégorie A dans les ERP importants ; le CMSI de type B nécessite une confirmation manuelle par un opérateur pour déclencher certaines fonctions de mise en sécurité (notamment l''évacuation générale dans les établissements où une levée de doute est organisée). Le type A est plus contraignant techniquement mais offre une réponse plus rapide sans dépendre de la présence d''un opérateur.', 1, null::integer[], array['theme1','seq1']::text[], 17),
('ssiap3-q85', 'ssiap3-partie3', 'quiz', 'Le délai maximal de transmission d''une alarme au télésurveilleur dans un système de télésurveillance d''un SSI est de :', 'Les délais de transmission des alarmes en télésurveillance sont définis par la norme NF S 61-932 et les cahiers des charges APSAD. Pour les alarmes feu, la transmission doit être quasi immédiate (quelques secondes après détection). Les valeurs de 30 secondes, 2 minutes ou 5 minutes correspondent à des contextes différents (délai de levée de doute interne avant transmission externe, délai de confirmation). Aucune des valeurs proposées ne correspond exactement au délai réglementaire standard de transmission brute d''une alarme feu.', 3, null::integer[], array['theme1','seq1']::text[], 18),
('ssiap3-q86', 'ssiap3-partie3', 'multiple-select', 'Le SSIAP 3 supervise la réception d''un nouveau système de désenfumage mécanique. Quels essais de réception doit-il exiger ? (plusieurs réponses)', 'La réception d''un désenfumage mécanique comprend des essais fonctionnels obligatoires : mesure des débits d''extraction dans chaque bouche et chaque zone (les débits réels doivent être conformes aux débits calculés dans l''étude, avec une tolérance de ±10%) ; chronométrage du délai de mise en route des extracteurs depuis le déclenchement de la commande (la norme IT 246 fixe des délais maximaux selon les applications) ; test d''asservissement complet depuis le SSI (déclenchement d''un détecteur → commande CMSI → ouverture des volets de désenfumage → démarrage extracteur : vérification de la séquence complète et des délais). La résistance mécanique des gaines est vérifiée lors des contrôles de réalisation, pas à la réception fonctionnelle. Le niveau sonore est un critère de confort, pas de sécurité.', null, array[0,1,2]::integer[], array['theme1','seq1']::text[], 19)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap3-q12','ssiap3-q13','ssiap3-q14','ssiap3-q15','ssiap3-q34','ssiap3-q35','ssiap3-q36','ssiap3-q37','ssiap3-q65','ssiap3-q66','ssiap3-q67','ssiap3-q68','ssiap3-q70','ssiap3-q75','ssiap3-q76','ssiap3-q79','ssiap3-q83','ssiap3-q84','ssiap3-q85','ssiap3-q86');
commit;

-- ===== ssiap3-partie3-sub02.sql =====
begin;
-- SSIAP 3 — Expertise technique et ingénierie (partie 3, sub 2/3, 20 cc_questions)
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap3-q89', 'ssiap3-partie3', 'multiple-select', 'Comment le SSIAP 3 évalue-t-il l''adéquation de l''éclairage de sécurité d''un ERP lors d''une inspection ? (plusieurs réponses)', 'L''éclairage de sécurité doit répondre à des exigences précises de la norme NF C 71-800 : présence dans tous les dégagements, escaliers, locaux de plus de 100 m² et locaux à risques ; autonomie minimale d''1 heure en mode secours (test mensuel de 1 heure recommandé, test annuel de décharge complète) ; niveau d''éclairement minimal de 1 lux sur l''axe des chemins d''évacuation (pas besoin de lire, juste de voir le sol et de suivre la direction) et 5 lux sur les obstacles ; vérification du marquage CE, de la date de fabrication (durée de vie des accumulateurs limitée, généralement 4 ans) et de la date d''installation. L''éclairage de sécurité n''est pas dimensionné pour permettre la lecture (1 lux est très faible) mais pour guider vers les sorties.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 20),
('ssiap3-q95', 'ssiap3-partie3', 'multiple-select', 'Comment le SSIAP 3 intègre-t-il les risques cyber dans la sécurité des installations SSI connectées ? (plusieurs réponses)', 'La cybersécurité des systèmes SSI connectés est une préoccupation croissante : sécurisation des accès distants (télémaintenance, supervision multi-sites) par VPN et authentification forte (double facteur) pour éviter les intrusions depuis Internet ; segmentation réseau (le réseau SSI ne doit pas être directement accessible depuis le réseau bureautique général — une compromission du réseau IT ne doit pas pouvoir affecter le SSI) ; plan de continuité en cas de cyberattaque (si le SSI est indisponible suite à une attaque, quelles mesures compensatoires : rondes renforcées, surveillance humaine accrue, coupure de l''accès distant) ; mises à jour des firmwares (les équipements connectés ont des vulnérabilités corrigées par les fabricants). Prétendre que les SSI ne sont jamais connectés est faux — de plus en plus de systèmes disposent d''interfaces de supervision à distance.', null, array[0,1,2,4]::integer[], array['theme2','seq2']::text[], 21),
('ssiap3-q106', 'ssiap3-partie3', 'multiple-select', 'Le SSIAP 3 doit évaluer la pertinence d''une installation de sprinklers dans un entrepôt logistique de 10 000 m² à racks de grande hauteur. Quels critères techniques sont déterminants ? (plusieurs réponses)', 'Le dimensionnement d''une installation sprinkler pour un entrepôt logistique à haute densité dépend de critères techniques précis définis par les règles APSAD R1 et les normes EN 12845 : hauteur de stockage (au-delà de 5-6 m, les sprinklers de plafond ne peuvent plus atteindre efficacement la base du feu à travers les fumées et la chaleur — des sprinklers en rack (in-rack sprinklers) sont alors nécessaires à intervalles de hauteur) ; nature des marchandises (plastiques, mousses, liquides inflammables = charge calorifique très élevée imposant une densité d''arrosage majorée) ; configuration (rayonnages fermés ou palettes entières créent des zones inaccessibles au spray des sprinklers de plafond). La présence humaine n''est pas un critère de dimensionnement technique. L''obligation réglementaire dépend du type d''établissement (ICPE ou ERP) et non uniquement de la superficie.', null, array[0,1,2]::integer[], array['theme1','seq1']::text[], 22),
('ssiap3-q109', 'ssiap3-partie3', 'multiple-select', 'Le SSIAP 3 est sollicité pour expertiser la sécurité incendie d''un tunnel routier souterrain de 800 m. Quelles mesures spécifiques aux tunnels doit-il analyser ? (plusieurs réponses)', 'Les tunnels routiers présentent des risques incendie spécifiques couverts par la réglementation française (circulaire du 25 août 2000 et instruction technique) : ventilation longitudinale avec jets d''air (jet fans) permettant de maîtriser le sens d''écoulement des fumées pour diriger les fumées à l''opposé des occupants qui fuient et créer une zone d''air frais pour l''évacuation ; niches de sécurité (refuges piétons avec porte coupe-feu, alimentation téléphonique d''urgence) à intervalles réglementaires permettant aux usagers de se mettre à l''abri en attendant les secours ; détection linéaire de chaleur sur le plafond pour une détection rapide sur toute la longueur ; points d''eau pour les pompiers (le réseau public est généralement inaccessible en souterrain) ; signalisation dynamique (flèches lumineuses, panneaux à messages variables) guidant les usagers vers la sortie opposée au feu.', null, array[0,1,2,3,4]::integer[], array['theme1','seq1']::text[], 23),
('ssiap3-q112', 'ssiap3-partie3', 'multiple-select', 'Quelle est la différence entre un ''sinistre déclaré'' et un ''sinistre couvant'' et comment le SSIAP 3 adapte-t-il sa surveillance pour détecter les sinistres couvants ? (plusieurs réponses)', 'La distinction sinistre déclaré/couvant est fondamentale pour adapter la surveillance : un sinistre couvant est une pyrolyse ou combustion lente (souvent électrique, ou dans un stockage dense) sans flamme visible, produisant du CO et des aérosols de particules fines — il peut couver des heures avant de s''embraser brutalement (flashover) ; il se produit fréquemment la nuit dans des locaux électriques, archives, stockages ; les détecteurs optiques (diffusion de lumière) sont les plus efficaces pour les sinistres couvants (ils détectent les aérosols de particules visibles) — les ioniques sont plus efficaces pour les feux à flammes vives ; les rondes nocturnes avec vigilance olfactive (odeur de brûlé caractéristique de la pyrolyse électrique) et les systèmes de détection par aspiration (VESDA) complètent la surveillance instrumentale. Un sinistre couvant peut parfaitement évoluer en incendie déclaré — c''est même le risque principal.', null, array[0,1,3]::integer[], array['theme1','seq1']::text[], 24),
('ssiap3-q113', 'ssiap3-partie3', 'multiple-select', 'Le SSIAP 3 doit évaluer les risques liés à l''installation de panneaux photovoltaïques en toiture d''un ERP. Quels risques spécifiques doit-il identifier ? (plusieurs réponses)', 'Les installations photovoltaïques présentent des risques spécifiques pour la sécurité incendie : impossibilité de coupure totale (les panneaux génèrent en permanence une tension DC tant qu''ils sont éclairés — même avec le disjoncteur général ouvert, les câbles DC entre panneaux et onduleur restent sous tension, créant un risque d''électrocution pour les pompiers) ; risque électrique des câbles DC (connecteurs MC4 vieillissants, câbles mal protégés contre les UV, arcs électriques pouvant démarrer un incendie en toiture) ; modification de l''accessibilité de la toiture pour les pompiers (les panneaux encombrent les zones de circulation en toiture) ; risque d''arc électrique en cas de dégradation mécanique d''un panneau lors d''une intervention. Le SSIAP 3 doit informer les pompiers locaux de l''installation et prévoir un protocole d''intervention spécifique.', null, array[0,1,2,4]::integer[], array['theme2','seq2']::text[], 25),
('ssiap3-q118', 'ssiap3-partie3', 'quiz', 'Comment le SSIAP 3 évalue-t-il la pertinence du positionnement des RIA (Robinets d''Incendie Armés) dans un ERP après une modification des locaux ?', 'Toute modification des locaux peut invalider le positionnement initial des RIA. Le SSIAP 3 doit vérifier après chaque réaménagement significatif : la règle de couverture (la portée utile d''un jet de RIA est d''environ 5 à 8 m selon la pression — en ajoutant la longueur de tuyau de 20 ou 30 m selon le modèle, la zone couverte est calculée ; tout point doit être accessible depuis au moins un RIA) ; l''absence d''obstruction (un RIA caché derrière une nouvelle cloison ou un meuble fixe est inutilisable en urgence) ; la visibilité et l''accessibilité permanente (le RIA doit être visible, identifiable et immédiatement accessible sans déplacer d''obstacles). En cas de lacune de couverture suite aux travaux, l''installation de RIA supplémentaires ou le déplacement des existants est obligatoire.', 1, null::integer[], array['theme1','seq1']::text[], 26),
('ssiap3-q122', 'ssiap3-partie3', 'multiple-select', 'Lors de la réception d''un nouveau bâtiment, le SSIAP 3 doit valider la conformité du SSI. Quelle est la procédure de réception réglementaire ? (plusieurs réponses)', 'La réception d''un SSI est une procédure formelle encadrée par la norme NF S 61-932 : vérification documentaire (les plans d''exécution as-built doivent correspondre à ce qui est installé, les notices des équipements doivent être remises) ; tests exhaustifs (chaque détecteur, chaque DM, chaque DAS est testé individuellement — pour un SSI de taille moyenne cela peut représenter plusieurs jours d''essais) ; vérification des séquences et délais (déclenchement d''un détecteur → signalisation centrale → activation des DAS : chaque étape est chronométrée et vérifiée) ; PV de réception signé contradictoirement entre l''installateur, le maître d''ouvrage (ou son représentant) et l''organisme de contrôle agréé — ce document officialise la mise en service et transfère la responsabilité de maintenance. Le SSIAP 3 seul ne peut pas réceptionner un SSI sans organisme de contrôle agréé.', null, array[0,1,2,3]::integer[], array['theme1','seq1']::text[], 27),
('ssiap3-q123', 'ssiap3-partie3', 'quiz', 'L''instruction technique IT 246 concerne :', 'L''instruction technique IT 246 concerne le désenfumage des bâtiments d''habitation. L''IT 263 concerne le désenfumage dans les ERP et IGH. Le désenfumage des parcs de stationnement est traité par des textes spécifiques (règlement de sécurité type PS). La résistance au feu est traitée par les normes EN 13501 et les DTU. Les systèmes d''extinction à eau relèvent des règles APSAD R1. Aucune des propositions ne correspond correctement à l''IT 246.', 0, null::integer[], array['theme1','seq1']::text[], 28),
('ssiap3-q124', 'ssiap3-partie3', 'multiple-select', 'Le SSIAP 3 doit arbitrer entre deux technologies d''extinction automatique pour un local informatique critique : HFC-227ea (gaz halogéné) et IG-55 (gaz inerte). Quels critères différencient ces deux choix ? (plusieurs réponses)', 'HFC-227ea (FM-200) et IG-55 (Argonite) sont deux agents d''extinction gazeux avec des caractéristiques très différentes : mode d''action (HFC-227ea : inhibition chimique de la réaction en chaîne + refroidissement léger ; IG-55 : réduction du taux d''O2 de 21% à environ 12-13%, en dessous du point d''inflammation des matériaux) ; concentration d''extinction (HFC-227ea : ~7-8% v/v donc bouteilles plus petites et moins nombreuses, coût d''installation généralement inférieur ; IG-55 : ~40% v/v donc grands volumes de gaz nécessaires, bouteilles nombreuses et lourdes) ; impact environnemental (IG-55 = mélange d''argon et d''azote naturels, PRG = 0 ; HFC-227ea a un PRG de 3220 — son utilisation est progressivement restreinte par la réglementation F-Gaz) ; sécurité pour les personnes (à concentration d''extinction de 40%, l''IG-55 réduit l''O2 à ~12% — tolérable brièvement mais les personnes doivent évacuer avant déclenchement).', null, array[0,1,2,3]::integer[], array['theme1','seq1']::text[], 29),
('ssiap3-q127', 'ssiap3-partie3', 'multiple-select', 'Le SSIAP 3 doit gérer le renouvellement d''une installation d''extinction automatique à gaz dont l''agent (Halon 1301) est interdit par le protocole de Montréal. Quelle est sa démarche ? (plusieurs réponses)', 'Le Halon 1301 est interdit à la production depuis 1994 par le protocole de Montréal (destruction de la couche d''ozone) mais les installations existantes peuvent légalement continuer à fonctionner — le stock de Halon s''épuise cependant et le renouvellement ou la recharge sont impossibles. La démarche de remplacement : sélection de l''agent de substitution selon les contraintes du local (IG-541 = Inergen pour locaux occupés, HFC-227ea pour locaux sans contrainte de volume, FK-5-1-12 = Novec pour locaux sensibles avec personnes) ; vérification de la compatibilité avec le volume (l''IG-541 à 37% v/v nécessite de grandes bouteilles — le local doit pouvoir les accueillir) ; destruction du Halon existant par une entreprise agréée (le Halon est un déchet dangereux réglementé, sa destruction est encadrée). Le CO2 n''est pas un remplacement universel (dangereux pour les personnes à concentration d''extinction).', null, array[1,2,4]::integer[], array['theme1','seq1']::text[], 30),
('ssiap3-q130', 'ssiap3-partie3', 'multiple-select', 'Comment le SSIAP 3 gère-t-il l''intégration d''un local de charge pour véhicules électriques (voitures + vélos) dans un parking existant ? (plusieurs réponses)', 'L''intégration de bornes de recharge VE dans un parking existant pose des risques spécifiques : les batteries lithium-ion en thermal runaway produisent des gaz inflammables et toxiques (fluorure d''hydrogène HF notamment) et peuvent brûler à 800-1000°C avec re-ignition possible plusieurs heures après extinction apparente ; la détection classique peut être insuffisante (les feux de batteries commencent souvent par des gaz avant les flammes — des détecteurs de gaz H2/CO en complément peuvent être pertinents) ; la procédure pompiers est spécifique (noyer la batterie dans l''eau est efficace pour refroidir et éviter la re-ignition mais nécessite de grandes quantités d''eau — les pompiers utilisent des lances à débit élevé ou des containers de noyage) ; vérification de la capacité électrique (les bornes de recharge rapide 22-150 kW peuvent surcharger un tableau électrique vieillissant). L''interdiction totale des VE en parking est disproportionnée et impraticable.', null, array[0,1,2,4]::integer[], array['theme2','seq2']::text[], 31),
('ssiap3-q136', 'ssiap3-partie3', 'quiz', 'Comment le SSIAP 3 évalue-t-il la capacité d''un escalier d''évacuation à absorber l''effectif d''un niveau d''un ERP en termes de temps d''évacuation ?', 'Le calcul du débit d''évacuation est un outil fondamental de l''ISI : la largeur d''un dégagement en UP détermine son débit théorique (une porte de 2 UP = 1,20 m permet le passage d''environ 60 à 80 personnes/minute selon les modèles) ; le temps d''évacuation d''un niveau = effectif du niveau / débit de l''escalier (en tenant compte des temps de réaction, de démarrage et de la superposition des flux de différents niveaux dans le même escalier) ; ce temps est comparé à l''ASET (temps disponible avant conditions intenables) pour vérifier la condition RSET < ASET. Des formules simplifiées (méthodes hydrauliques de Predtechenskii, SFPE Handbook) permettent un calcul rapide ; des logiciels de simulation de foule (FDS+Evac, Pathfinder, Simulex) permettent une modélisation plus fine. Le calcul analytique est toujours le point de départ avant toute simulation.', 1, null::integer[], array['theme2','seq2']::text[], 32),
('ssiap3-q138', 'ssiap3-partie3', 'multiple-select', 'Comment le SSIAP 3 gère-t-il la sécurité incendie d''un centre de données (data center) de niveau Tier III en exploitation continue ? (plusieurs réponses)', 'Un data center Tier III (redondance N+1, disponibilité cible 99,982%) impose des contraintes spécifiques à la sécurité incendie : les procédures de maintenance à chaud (hot maintenance) permettent les interventions sur les systèmes de sécurité sans couper l''alimentation des serveurs (utilisation des redondances) ; la détection très précoce (VESDA, détection par aspiration) est essentielle pour maximiser le temps de réaction avant que l''extinction automatique ne se déclenche (permettant de vérifier s''il s''agit d''un vrai sinistre et d''évacuer le personnel) ; la coordination avec les équipes IT est critique pour la procédure EPO (Emergency Power Off) avant intervention pompiers — les serveurs sous tension créent un risque d''électrocution pour les intervenants et peuvent alimenter un feu électrique ; le délai d''activation de l''extinction (abort switch, délai de 30 à 60 secondes) permet l''évacuation. La coupure électrique est parfois nécessaire malgré les contraintes de continuité.', null, array[1,2,3,4]::integer[], array['theme1','seq1']::text[], 33),
('ssiap3-q142', 'ssiap3-partie3', 'quiz', 'Quelle est la responsabilité du SSIAP 3 vis-à-vis des systèmes de contrôle d''accès dont la défaillance peut impacter l''évacuation incendie ?', 'L''interface entre contrôle d''accès et sécurité incendie est une responsabilité directe du SSIAP 3 : toute porte équipée d''un contrôle d''accès et positionnée sur une voie d''évacuation réglementaire doit impérativement être configurée en mode fail-safe (déverrouillage automatique) en cas d''alarme incendie (asservissement SSI → contrôle d''accès) ET en cas de coupure électrique générale (pour éviter le verrouillage de toutes les portes lors d''une coupure liée à l''incendie) ; le SSIAP 3 doit participer aux tests périodiques de cet asservissement et exiger sa mise en conformité si nécessaire ; la configuration des portes relève d''une décision commune entre sécurité incendie (SSIAP 3), sûreté et informatique — le SSIAP 3 a un droit de veto sur toute configuration incompatible avec l''évacuation. Les systèmes ne sont pas indépendants : ils doivent être intégrés.', 1, null::integer[], array['theme1','seq1']::text[], 34),
('ssiap3-q145', 'ssiap3-partie3', 'multiple-select', 'Lors de la mise en place d''un système de Gestion Technique du Bâtiment (GTB) intégrant le SSI, quelles précautions le SSIAP 3 doit-il prendre ? (plusieurs réponses)', 'L''intégration d''un SSI dans une GTB présente des avantages (supervision centralisée, historique des événements) mais aussi des risques si elle est mal conçue : le SSI doit rester maître de ses propres fonctions — la GTB peut recevoir des informations du SSI (états, alarmes) mais ne doit pas pouvoir modifier le fonctionnement du SSI (inhiber une zone, modifier un seuil) sans validation explicite du SSIAP ; la norme NF S 61-932 définit les conditions d''interface entre SSI et systèmes extérieurs (dont les GTB) — la conformité est obligatoire ; les opérateurs GTB qui voient les alarmes SSI sur leur console doivent savoir quoi faire (alerter le SSIAP, ne pas réinitialiser eux-mêmes) ; une interface de commande directe du SSI (tableau de signalisation autonome) doit subsister en cas de défaillance de la GTB. Commander directement les DAS depuis la GTB contourne la logique de sécurité du CMSI et est inadmissible.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 35),
('ssiap3-q147', 'ssiap3-partie3', 'quiz', 'Comment le SSIAP 3 intègre-t-il les contraintes liées à la présence d''œuvres d''art ou de collections de valeur dans les procédures de désenfumage d''un musée ?', 'Les musées posent un dilemme spécifique entre sécurité des personnes et protection des collections : le désenfumage mécanique active des ventilateurs qui peuvent créer des courants d''air propageant les fumées vers des zones non encore atteintes par le sinistre, exposant des œuvres fragiles (toiles, papiers, textiles) aux fumées corrosives et aux dépôts de suie ; l''eau des sprinklers peut irrémédiablement détruire des œuvres inestimables. Le SSIAP 3 doit travailler avec les conservateurs pour définir des procédures équilibrées : désenfumage zonal limitant la propagation des fumées aux zones non sinistrées, systèmes d''extinction adaptés (gaz inertes plutôt qu''eau dans les salles d''exposition), PSO (Plan de Sauvegarde des Œuvres) coordonné avec les procédures SSIAP. La priorité reste la sécurité des personnes mais les mesures doivent minimiser les dommages collatéraux aux collections.', 1, null::integer[], array['theme1','seq1']::text[], 36),
('ssiap3-q151', 'ssiap3-partie3', 'multiple-select', 'Le SSIAP 3 doit intégrer les risques liés aux énergies renouvelables dans son évaluation des risques. Un projet d''installation de batteries de stockage d''énergie (BESS) est prévu dans un local technique. Quels risques spécifiques doit-il analyser ? (plusieurs réponses)', 'Les batteries de stockage d''énergie (BESS - Battery Energy Storage System) à technologie lithium-ion présentent des risques spécifiques et sévères : thermal runaway (emballement thermique) : réaction exothermique auto-entretenue pouvant se propager de cellule en cellule, génère des températures dépassant 800°C, impossible à arrêter une fois lancée, peut durer plusieurs heures voire jours ; production de gaz (lors du thermal runaway : H2 inflammable, CO toxique et inflammable, HF extrêmement toxique et corrosif, CH4) créant un risque d''explosion en local confiné sans ventilation adaptée ; l''extinction est très difficile (l''eau refroidit mais ne stoppe pas la réaction chimique interne — il faut immerger complètement et longtemps) ; la certification CE atteste la conformité de fabrication en conditions normales mais ne garantit pas l''absence de risque en cas de défaut, choc ou surtension. Des mesures spécifiques (détection gaz, ventilation forcée, extinction eau en grand volume, procédure pompiers) sont indispensables.', null, array[0,1,2,4]::integer[], array['theme2','seq2']::text[], 37),
('ssiap3-q152', 'ssiap3-partie3', 'quiz', 'Comment le SSIAP 3 évalue-t-il la conformité des voies d''accès pour les engins de secours autour de son établissement ?', 'La conformité des voies d''accès pour engins de secours est une obligation réglementaire de l''exploitant ERP définie par l''article R111-5 du Code de la Construction et de l''Habitation et le règlement de sécurité ERP : largeur minimale de la voie (généralement 3,50 m de chaussée stabilisée, 6 m pour les voies permettant le croisement) ; hauteur libre minimale (4 m pour permettre le passage des échelles autoportables) ; résistance au sol (16 tonnes par essieu pour supporter les engins de grande capacité) ; rayon de courbure permettant la manœuvre des grandes échelles ; aires de mise en station des échelles maintenues dégagées en permanence. Le SSIAP 3 doit vérifier régulièrement que ces voies ne sont pas obstruées (stationnement sauvage, travaux, livraisons) et faire appliquer les mesures conservatoires nécessaires.', 1, null::integer[], array['theme1','seq1']::text[], 38),
('ssiap3-q155', 'ssiap3-partie3', 'multiple-select', 'Le SSIAP 3 est sollicité pour donner un avis sur l''installation d''une terrasse couverte par une toiture végétalisée sur un ERP existant. Quels risques spécifiques doit-il évaluer ? (plusieurs réponses)', 'Une toiture végétalisée sur un ERP existant présente plusieurs risques à évaluer : risque d''incendie de la végétation en période de sécheresse (les substrats secs et la végétation desséchée peuvent s''enflammer et propager un feu en toiture — le classement Broof(t4) des toitures végétalisées doit être vérifié) ; surcharge structurelle (une toiture végétalisée intensive peut peser 150 à 500 kg/m² — impact sur la résistance au feu des planchers porteurs si la structure est sollicitée au-delà de ses limites) ; obstruction des exutoires de désenfumage existants par le substrat ou la végétation (les exutoires doivent rester dégagés et accessibles) ; accès des engins de secours si la terrasse végétalisée limite la circulation en toiture pour les pompiers. Les toitures végétalisées ne sont pas incombustibles — leur classement dépend du type de végétation et du substrat.', null, array[0,1,2,4]::integer[], array['theme2','seq2']::text[], 39)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap3-q89','ssiap3-q95','ssiap3-q106','ssiap3-q109','ssiap3-q112','ssiap3-q113','ssiap3-q118','ssiap3-q122','ssiap3-q123','ssiap3-q124','ssiap3-q127','ssiap3-q130','ssiap3-q136','ssiap3-q138','ssiap3-q142','ssiap3-q145','ssiap3-q147','ssiap3-q151','ssiap3-q152','ssiap3-q155');
commit;

-- ===== ssiap3-partie3-sub03.sql =====
begin;
-- SSIAP 3 — Expertise technique et ingénierie (partie 3, sub 3/3, 13 cc_questions)
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap3-q156', 'ssiap3-partie3', 'quiz', 'La norme NF EN 54 concerne :', 'La norme NF EN 54 est la série de normes européennes relatives aux systèmes de détection et d''alarme incendie (SDAI) : elle couvre les composants des systèmes de détection incendie (centrales, détecteurs de fumée, détecteurs de chaleur, déclencheurs manuels, dispositifs de signalisation sonore et visuelle). Les systèmes d''extinction à eau relèvent de la norme EN 12845. Le désenfumage relève des normes EN 12101. Les systèmes d''intrusion relèvent des normes EN 50131. La réponse ''systèmes de détection et d''alarme incendie'' est correcte mais n''est pas proposée dans les options.', 2, null::integer[], array['theme1','seq1']::text[], 40),
('ssiap3-q160', 'ssiap3-partie3', 'quiz', 'Comment le SSIAP 3 intègre-t-il les risques liés aux drones dans la sécurité incendie de son établissement (survol, livraison, malveillance) ?', 'Les drones présentent des risques émergents que le SSIAP 3 doit intégrer : risque incendie direct (chute d''un drone avec batterie Li-ion en thermal runaway sur une zone sensible, projection de débris enflammés sur des matériaux combustibles) ; risque malveillant (drone transportant un engin incendiaire ou un produit chimique — scénario retenu dans les plans Vigipirate pour les sites sensibles) ; la procédure doit prévoir : identification et signalement d''un drone suspect au PC sécurité, alerte aux forces de l''ordre si comportement anormal (survol prolongé, approche des prises d''air), pas d''intervention directe des agents SSIAP sur un drone (risque d''incident avec les rotors). La coordination avec les autorités (préfecture, gendarmerie) est nécessaire pour les établissements à risque élevé. Les filets anti-drones existent mais ne relèvent pas du SSIAP 3.', 1, null::integer[], array['theme2','seq2']::text[], 41),
('ssiap3-q163', 'ssiap3-partie3', 'quiz', 'Comment le SSIAP 3 gère-t-il la problématique des faux plafonds et faux planchers dans l''évaluation des risques incendie d''un bâtiment tertiaire ?', 'Les faux plafonds et faux planchers sont des espaces techniques présentant des risques spécifiques souvent sous-estimés : propagation silencieuse du feu (un incendie démarrant dans un faux plafond (câble électrique, ballast de luminaire) peut se propager sur de grandes distances sans être détecté, traversant les compartimentages si les cloisons ne sont pas montées jusqu''à la dalle) ; accumulation de câbles électriques représentant une charge calorifique élevée ; dépôts de poussières inflammables dans les vides techniques ; les réglementations imposent la détection dans les faux plafonds au-delà de certaines dimensions ou dans certains types d''ERP. Le SSIAP 3 doit vérifier : la continuité du compartimentage jusqu''à la dalle dans ces espaces, la présence de détection si réglementairement requise, l''absence de charges combustibles non autorisées stockées dans ces espaces.', 1, null::integer[], array['theme1','seq1']::text[], 42),
('ssiap3-q164', 'ssiap3-partie3', 'multiple-select', 'Le SSIAP 3 doit choisir entre maintenir en exploitation un SSI vieillissant (20 ans, pièces détachées rares) ou le renouveler intégralement. Quels critères orientent sa décision ? (plusieurs réponses)', 'La décision de maintien ou de renouvellement d''un SSI vieillissant repose sur une analyse multicritère : taux de défaillance (un SSI qui tombe en panne de plus en plus souvent crée des indisponibilités de protection et des coûts de maintenance curative croissants — la tendance est plus significative que la valeur instantanée) ; disponibilité des pièces détachées (un équipement dont le fabricant ne produit plus les pièces devient non maintenable — un délai de remplacement de 15 jours pour une centrale défaillante est inacceptable) ; conformité aux normes (les révisions de la norme NF S 61-970 ont modifié les exigences de fonctionnement — un SSI ancien peut avoir des lacunes fonctionnelles par rapport aux prescriptions actuelles) ; analyse coût-bénéfice (coût total de possession sur 5 ans en maintien vs coût de remplacement + bénéfices fonctionnels). L''esthétique n''est pas un critère de décision.', null, array[0,1,2,3]::integer[], array['theme2','seq2']::text[], 43),
('ssiap3-q167', 'ssiap3-partie3', 'quiz', 'Comment le SSIAP 3 intègre-t-il les risques liés aux travaux de déneigement en toiture dans sa gestion de la sécurité incendie hivernale ?', 'Les travaux de déneigement en toiture créent des risques spécifiques pour la sécurité incendie : les exutoires de désenfumage (EFC) peuvent être obstrués par la neige accumulée sur leurs trappes ou déplacés accidentellement par les pelles mécaniques — une vérification post-déneigement est indispensable ; les équipements électriques en toiture (centrales photoélectriques, câblages de désenfumage) exposés à l''eau de fonte et au gel peuvent être endommagés ; les interventions en hauteur sur toiture enneigée sont des travaux dangereux nécessitant un plan de prévention (risque de chute) avec coordination SSIAP pour maintenir les accès de sécurité. Le SSIAP 3 doit intégrer une vérification spécifique post-chutes de neige dans ses procédures saisonnières.', 1, null::integer[], array['theme2','seq2']::text[], 44),
('ssiap3-q169', 'ssiap3-partie3', 'multiple-select', 'Le SSIAP 3 doit constituer et maintenir à jour le dossier technique SSI de l''établissement. Quels documents essentiels ce dossier doit-il contenir ? (plusieurs réponses)', 'Le dossier technique SSI est un document de référence indispensable à la maintenance et à l''exploitation du système. Il doit contenir selon la norme NF S 61-932 : les plans d''implantation (plans par niveau avec position de chaque équipement, numérotation cohérente avec le tableau de signalisation, zones de détection délimitées) ; le livre de bord (journal chronologique de tous les événements significatifs : alarmes, défauts, modifications, interventions, essais — pièce essentielle en cas d''enquête) ; les notices techniques et manuels constructeurs (nécessaires pour la maintenance et les modifications) ; les rapports de vérifications périodiques avec le suivi de levée des non-conformités (traçabilité réglementaire obligatoire). Les factures d''achat sont des documents comptables sans utilité pour l''exploitation technique du SSI.', null, array[0,1,2,3]::integer[], array['theme1','seq1']::text[], 45),
('ssiap3-q171', 'ssiap3-partie3', 'multiple-select', 'Le SSIAP 3 doit évaluer les risques liés à l''utilisation de liquides inflammables dans un atelier de restauration de meubles anciens intégré à un ERP culturel. Quels éléments analyse-t-il ? (plusieurs réponses)', 'Un atelier de restauration avec solvants est un local à risques particuliers nécessitant une analyse spécifique : le point éclair des solvants détermine les conditions de stockage et d''utilisation (acétone : -18°C, white-spirit : 40-65°C, alcool éthylique : 12°C — ces produits s''enflamment facilement à température ambiante) ; les vapeurs de solvants étant plus lourdes que l''air, elles s''accumulent en partie basse et peuvent atteindre les zones d''ignition distantes (interrupteurs électriques au sol, moteurs d''outillage) — la ventilation basse est indispensable ; la détection optique peut être sensible aux vapeurs de solvants (fausses alarmes) ou au contraire peu efficace sur des vapeurs sans particules — des détecteurs gaz spécifiques peuvent être plus pertinents ; tout l''outillage électrique dans une zone ATEX potentielle doit être certifié ATEX. Les solvants même en faibles quantités présentent un risque réel.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 46),
('ssiap3-q174', 'ssiap3-partie3', 'multiple-select', 'Le SSIAP 3 est sollicité pour donner un avis sur la construction d''un nouveau local de stockage d''archives papier de 500 m² en sous-sol d''un bâtiment existant. Quelles mesures de sécurité incendie préconise-t-il ? (plusieurs réponses)', 'Un local d''archives papier de 500 m² en sous-sol représente un risque incendie très élevé (charge calorifique papier : 17 MJ/kg, densité de stockage importante) nécessitant des mesures renforcées : extinction automatique à gaz inerte (IG-55 ou IG-541) : les sprinklers dégraderaient irrémédiablement les archives, les gaz inertes éteignent sans résidu et sans dommage au papier — solution de référence pour les archives de valeur ; détection VESDA : permet une intervention très précoce (avant embrasement) pour déclencher l''extinction ou une intervention humaine avant que le feu ne soit établi ; compartimentage EI 120 minimum : le fort potentiel calorifique (feu pouvant durer plusieurs heures) justifie une résistance au feu supérieure au minimum réglementaire ; désenfumage mécanique obligatoire en sous-sol (pas d''exutoires naturels possibles). Les meubles métalliques offrent une protection partielle mais ne dispensent pas des autres mesures.', null, array[0,1,2,3]::integer[], array['theme1','seq1']::text[], 47),
('ssiap3-q176', 'ssiap3-partie3', 'multiple-select', 'Le SSIAP 3 doit définir les critères de sélection d''un système de communication d''urgence pour son établissement. Quels facteurs prend-il en compte ? (plusieurs réponses)', 'Le choix d''un système de communication d''urgence pour un service SSIAP doit répondre à des critères fonctionnels précis : couverture complète (les sous-sols, parkings et zones isolées sont souvent des zones de silence radio — des répéteurs ou une infrastructure filaire peuvent être nécessaires) ; redondance (en cas de défaillance du répéteur central ou de la batterie de base, les communications doivent pouvoir continuer — réseau maillé ou système alternatif) ; interopérabilité ANTARES (le réseau national des sapeurs-pompiers — la capacité à communiquer directement avec le COS lors d''une intervention est un avantage opérationnel significatif) ; autonomie des batteries (lors d''une coupure électrique prolongée, les terminaux doivent rester opérationnels pendant toute la durée de l''intervention). L''esthétique est un critère de confort secondaire sans impact sur la sécurité.', null, array[0,1,2,4]::integer[], array['theme2','seq2']::text[], 48),
('ssiap3-q180', 'ssiap3-partie3', 'multiple-select', 'Le SSIAP 3 doit évaluer l''impact d''une modification du système de chauffage (remplacement d''une chaudière gaz par une PAC air-air avec unités intérieures dans chaque local) sur la sécurité incendie. Quels aspects examine-t-il ? (plusieurs réponses)', 'Le remplacement d''un système de chauffage par une climatisation réversible a des impacts directs sur la sécurité incendie : les unités intérieures en fonctionnement créent des flux d''air dans les locaux qui peuvent diluer et disperser les fumées, empêchant les détecteurs ponctuels de déclencher (repositionnement des détecteurs ou utilisation de détecteurs à aspiration peut être nécessaire) ; les gaines de distribution d''air traversant les parois CF doivent être équipées de clapets coupe-feu (DAS) qui se ferment en cas de sinistre pour ne pas court-circuiter le compartimentage ; en cas de sinistre, les unités de climatisation doivent être asservies au SSI pour s''arrêter automatiquement (elles pourraient sinon propager les fumées d''un local à l''autre via les gaines) ; le désenfumage peut être perturbé par les flux de climatisation (simulation CFD recommandée pour les configurations complexes). Les climatiseurs n''ont aucune propriété coupe-feu.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 49),
('ssiap3-q182', 'ssiap3-partie3', 'multiple-select', 'Lors de la conception d''un système de désenfumage pour un atrium de 30 m de hauteur, quelles contraintes spécifiques le SSIAP 3 doit-il intégrer ? (plusieurs réponses)', 'Le désenfumage d''un atrium de grande hauteur pose des défis techniques spécifiques : la stratification thermique (les fumées chaudes et légères montent naturellement et forment une couche en hauteur sous la toiture — cet effet est bénéfique car il maintient une zone d''air frais en bas pour l''évacuation, mais la hauteur de la couche de fumées doit être maintenue au-dessus des occupants) ; la déstratification par la CVC (les systèmes de brassage d''air peuvent mélanger la couche de fumées stratifiées avec l''air frais en dessous, réduisant à néant le bénéfice de la stratification — asservissement de la CVC au désenfumage obligatoire) ; exutoires en partie haute (pour extraire les fumées de la couche stratifiée en toiture) avec calcul du débit selon la méthode en régime établi (IT 263 ou NFPA 92) ou par simulation CFD pour les géométries complexes ; les détecteurs ponctuels à 30 m de hauteur nécessitent une sensibilité compensée ou le recours à des détecteurs à aspiration ou des détecteurs linéaires.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 50),
('ssiap3-q196', 'ssiap3-partie3', 'quiz', 'Comment le SSIAP 3 intègre-t-il les résultats des simulations numériques (CFD) dans ses décisions opérationnelles de sécurité incendie ?', 'Les simulations numériques (CFD - Computational Fluid Dynamics pour la thermique des fumées, et modèles d''évacuation de foule) sont des outils de plus en plus accessibles et pertinents pour le SSIAP 3 : dimensionnement des systèmes (une simulation CFD valide ou remet en cause les débits d''extraction calculés analytiquement, en tenant compte de la géométrie réelle du local — elle peut révéler des zones mortes ou des déstratifications non prévues) ; validation des stratégies d''évacuation (les modèles de foule simulent le comportement de l''évacuation, identifient les goulots d''étranglement et estiment le RSET) ; justification auprès de la commission (une simulation documentée et réalisée par un bureau d''études reconnu est un argument technique solide pour une solution alternative). La simulation ne remplace pas les essais terrain mais les complète — les deux approches doivent être cohérentes.', 1, null::integer[], array['theme2','seq2']::text[], 51),
('ssiap3-q199', 'ssiap3-partie3', 'multiple-select', 'Le SSIAP 3 supervise l''installation d''un nouveau système de gestion centralisée des accès (SGAC) interconnecté avec le SSI. Quelles vérifications techniques préalables doit-il exiger ? (plusieurs réponses)', 'L''interconnexion SGAC/SSI doit être rigoureusement vérifiée pour garantir que la sécurité d''accès ne compromet jamais la sécurité incendie : conformité NF S 61-932 (la norme définit les conditions d''interface entre le SSI et les systèmes tiers — les signaux de commande et leur priorité doivent être conformes) ; test exhaustif du déverrouillage sur alarme (chaque porte d''évacuation équipée d''un contrôle d''accès doit s''ouvrir automatiquement sur alarme SSI — test de chaque porte individuellement) ; vérification de la non-interférence (le SGAC ne doit jamais pouvoir inhiber une commande du SSI ou retarder une mise en sécurité) ; test du mode dégradé (si le serveur SGAC tombe en panne ou si la coupure électrique survient, toutes les portes d''évacuation doivent se déverrouiller automatiquement — fail-safe). Le réseau sans redondance est insuffisant pour un système de sécurité critique.', null, array[0,1,2,4]::integer[], array['theme1','seq1']::text[], 52)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap3-q156','ssiap3-q160','ssiap3-q163','ssiap3-q164','ssiap3-q167','ssiap3-q169','ssiap3-q171','ssiap3-q174','ssiap3-q176','ssiap3-q180','ssiap3-q182','ssiap3-q196','ssiap3-q199');
commit;

-- ===== ssiap3-partie4-sub01.sql =====
begin;
-- SSIAP 3 — Coordination institutionnelle (partie 4, sub 1/1, 7 cc_questions)
values ('ssiap3-partie4', 3, 'Coordination institutionnelle', '7 cc_questions', '👨‍🚒', 'from-emerald-500 to-teal-600', 3, true)
on conflict (id) do update set title=excluded.title, subtitle=excluded.subtitle, icon=excluded.icon, color=excluded.color, display_order=excluded.display_order;
  id, module_id, type, question, explanation, correct_answer, correct_answers, tags, display_order
) values
('ssiap3-q16', 'ssiap3-partie4', 'quiz', 'Le SSIAP 3 entretient des relations institutionnelles avec le SDIS local. Dans quel cadre et dans quel but ?', 'La relation entre le SSIAP 3 et le SDIS (Service Départemental d''Incendie et de Secours) est fondamentale pour l''efficacité de la réponse aux sinistres : partage régulier des plans d''intervention (le SDIS possède les plans de l''établissement et les met à jour lors de modifications) ; définition de procédures de coordination claires (qui fait quoi à l''arrivée des pompiers, point de rendez-vous, transmission d''informations) ; participation aux exercices communs (incl. exercices SSIAP/SDIS qui testent l''interface des deux services) ; interopérabilité des communications (radio compatibles ANTARES dans les IGH et grands ERP) ; pour les IGH, des visites de reconnaissance des pompiers dans le bâtiment sont organisées périodiquement. Cette relation est proactive et régulière, pas uniquement réactive lors des sinistres.', 1, null::integer[], array['theme1','seq1','Partenariat SSIAP 3 - SDIS','Relations avec les services de secours']::text[], 0),
('ssiap3-q17', 'ssiap3-partie4', 'multiple-select', 'En cas de sinistre grave nécessitant la fermeture temporaire d''un ERP, le SSIAP 3 doit gérer la communication de crise. Quels acteurs doit-il informer et dans quel ordre de priorité ? (plusieurs réponses possibles)', 'La gestion des communications après un sinistre grave suit une hiérarchie : en priorité absolue, alerter les pompiers (18) si le sinistre est actif ; informer la direction immédiatement après la sécurisation des personnes (la direction décide des orientations stratégiques : fermeture, communication externe) ; l''autorité de police (maire ou préfet selon l''ERP) doit être informée en cas de fermeture même temporaire (l''exploitant est tenu de signaler toute situation mettant en cause la sécurité publique) ; la commission de sécurité doit être informée si la fermeture est prolongée (au-delà de quelques jours, une visite de la commission conditionne la réouverture). Les médias relèvent de la direction de la communication, pas du SSIAP 3 directement.', null, array[0,1,2,4]::integer[], array['theme2','seq2','Communication de crise','Gestion de crise institutionnelle']::text[], 1),
('ssiap3-q18', 'ssiap3-partie4', 'quiz', 'Le SSIAP 3 est confronté à un désaccord technique avec le bureau de contrôle lors d''une vérification. Quelle est la procédure adéquate ?', 'Un désaccord technique avec un bureau de contrôle doit être géré de manière professionnelle et documentée : analyser précisément les observations (sont-elles fondées réglementairement ? Y a-t-il ambiguïté dans le texte ?) ; argumenter techniquement en citant les textes réglementaires précis (articles du règlement de sécurité, normes applicables) pour les points contestés ; chercher un accord documenté (compte-rendu de réunion technique précisant les points d''accord et de désaccord) ; en cas de désaccord persistant sur l''interprétation réglementaire, solliciter l''avis de la commission de sécurité ou d''un expert indépendant. Cette démarche professionnelle est préférable à la confrontation ou à la capitulation systématique. Le SSIAP 3 doit avoir une solide maîtrise réglementaire pour tenir ce rôle.', 2, null::integer[], array['theme3','seq3','Gestion des relations avec bureaux de contrôle','Relations avec les organismes de contrôle']::text[], 2),
('ssiap3-q19', 'ssiap3-partie4', 'multiple-select', 'Quels sont les enjeux éthiques et déontologiques propres à la fonction de SSIAP 3 chef de service ? (plusieurs réponses possibles)', 'La fonction de SSIAP 3 comporte des enjeux éthiques forts : indépendance de jugement (ne pas céder aux pressions commerciales pour accepter des non-conformités ou réduire les effectifs) ; obligation de signalement (le SSIAP 3 a le devoir légal de signaler les situations dangereuses même si cela nuit commercialement ou révèle des manquements de la direction - sa responsabilité pénale est engagée s''il tait sciemment un danger) ; impartialité dans les appels d''offres (éviter les conflits d''intérêt avec les prestataires) ; formation continue (la réglementation évolue, les techniques aussi). La confidentialité sur les non-conformités identifiées n''est pas un principe éthique valable : les non-conformités doivent être documentées et escaladées, jamais cachées.', null, array[0,2,3,4]::integer[], array['theme4','seq4','Éthique du chef de service SSIAP 3','Éthique et déontologie professionnelle']::text[], 3),
('ssiap3-q23', 'ssiap3-partie4', 'quiz', 'Le document ''ORSEC'' (Organisation de la Réponse de Sécurité Civile) implique les ERP dans :', 'Le plan ORSEC est le cadre général de la planification et de la gestion des situations de catastrophe ou de crise (catastrophes naturelles, accidents industriels, événements climatiques extrêmes). Il prévoit la mobilisation des acteurs publics et privés (dont les ERP grands établissements) pour contribuer à la gestion de crise (accueil de sinistrés, points de rassemblement, soutien logistique). Le SSIAP 3 d''un grand ERP peut être impliqué dans les plans ORSEC de sa commune. Aucune des propositions (trafic routier, marchés publics, crues uniquement) ne correspond correctement à la portée large d''ORSEC.', 3, null::integer[], array['theme1','seq1','Partenariat SSIAP 3 - SDIS','Relations avec les services de secours']::text[], 4),
('ssiap3-q38', 'ssiap3-partie4', 'multiple-select', 'Le SSIAP 3 d''un ERP organise un exercice de crise majeure en collaboration avec les autorités locales (préfecture, SDIS, SAMU). Comment structure-t-il cet exercice ? (plusieurs réponses possibles)', 'Un exercice de crise majeure multi-acteurs bien structuré comprend : un scénario réaliste et documenté (avec une fiche de déroulement, des injectants planifiés - ''à 10h15 : simulation d''une victime inconsciente en zone C'') ; toutes les phases du sinistre (détection, alarme, levée de doute, évacuation, accueil SDIS/SAMU, tri des victimes, communication de crise) ; évaluation croisée de chaque acteur et de leurs interfaces (le délai de remontée d''information du SSIAP au COS est-il satisfaisant ?) ; compte-rendu partagé permettant à chaque partenaire d''identifier ses propres points faibles. Les exercices surprises totaux sont déconseillés pour les grands ERP (risque de débordement, paniques réelles) mais une surprise partielle (heure non connue dans une fenêtre annoncée) est pertinente. La transparence totale (tout le monde sait tout à l''avance) réduit la valeur testante.', null, array[0,1,2,4]::integer[], array['theme5','seq5','Exercices de grande ampleur','Exercices de crise multi-acteurs']::text[], 5),
('ssiap3-q39', 'ssiap3-partie4', 'multiple-select', 'Lors d''une enquête judiciaire après un sinistre grave dans son établissement, le SSIAP 3 est convoqué pour audition. Quelles précautions doit-il avoir prises en amont pour se protéger ? (plusieurs réponses possibles)', 'En cas d''enquête judiciaire post-sinistre, la protection du SSIAP 3 repose sur la traçabilité irréprochable de ses actes professionnels : registre de sécurité complet prouvant que toutes les vérifications ont été effectuées, toutes les anomalies signalées et toutes les mesures compensatoires mises en place ; traces écrites des alertes et recommandations à la direction (un courriel non-répondu recommandant un investissement de sécurité refusé par la direction dégage considérablement la responsabilité du SSIAP 3) ; documentation de chaque intervention, décision et vérification avec dates et signatures ; rapports de vérification signés prouvant que les contrôles ont bien eu lieu. La destruction de documents en prévision d''une enquête est une infraction pénale grave (obstruction à la justice, destruction de preuves) qui aggraverait considérablement la situation.', null, array[0,1,2,4]::integer[], array['theme4','seq4','Éthique du chef de service SSIAP 3','Éthique et déontologie professionnelle']::text[], 6)
on conflict (id) do update set
  type=excluded.type, question=excluded.question, explanation=excluded.explanation,
  correct_answer=excluded.correct_answer, correct_answers=excluded.correct_answers,
  tags=excluded.tags, display_order=excluded.display_order, updated_at=now();
delete from public.cc_question_options where question_id in ('ssiap3-q16','ssiap3-q17','ssiap3-q18','ssiap3-q19','ssiap3-q23','ssiap3-q38','ssiap3-q39');
commit;

-- ===== ssiap3-partie5-sub01.sql =====
begin;
-- SSIAP 3 — Analyse des risques et amélioration continue (partie 5, sub 1/1, 6 cc_questions)
values ('ssiap3-partie5', 3, 'Analyse des risques et amélioration continue', '6 cc_questions', '🎯', 'from-purple-500 to-pink-600', 4, true)
