insert into public.cc_questions (
insert into public.cc_question_options (question_id, option_index, option_text) values
('ssiap2-q178', 0, 'C''est une non-conformité esthétique sans impact sur la sécurité'),
('ssiap2-q178', 1, 'C''est une non-conformité au compartimentage coupe-feu : le calfeutrement des pénétrations (conduits, câbles) dans les parois CF est obligatoire pour maintenir l''intégrité de la barrière coupe-feu ; sans calfeutrement, le feu peut traverser la paroi par ce passage en quelques minutes'),
('ssiap2-q178', 2, 'C''est une non-conformité mineure à traiter lors du prochain ravalement'),
('ssiap2-q178', 3, 'Les gaines de ventilation sont exemptées de calfeutrement car l''air circule dedans'),
('ssiap2-q179', 0, 'Le CO2 liquéfié se dégrade chimiquement avec le temps'),
('ssiap2-q179', 1, 'La pression interne peut diminuer par micro-fuites au niveau du robinet ou de la valve, réduisant l''efficacité à l''utilisation'),
('ssiap2-q179', 2, 'La bouteille métallique peut se corroder intérieurement ou extérieurement, risquant une rupture en service'),
('ssiap2-q179', 3, 'Les normes réglementaires imposent une vérification tous les 5 ans et une recharge selon la perte de pression'),
('ssiap2-q179', 4, 'Pour vérifier la conformité du marquage sur l''extincteur'),
('ssiap2-q180', 0, 'Un robinet sur les colonnes sèches permettant de couper l''eau'),
('ssiap2-q180', 1, 'Un dispositif mécanique installé dans les conduits de ventilation au droit des parois coupe-feu, qui se ferme automatiquement en cas d''incendie (action thermique ou électrique) pour empêcher la propagation du feu par les gaines'),
('ssiap2-q180', 2, 'Une porte coupe-feu avec loquet automatique'),
('ssiap2-q180', 3, 'Un fusible électrique protégeant le SSI'),
('ssiap2-q181', 0, 'La pression disponible au robinet (débit et pression résiduels conformes à la norme)'),
('ssiap2-q181', 1, 'L''état du dévidoir (rotation sans blocage), du tuyau (absence de détérioration, de craquelures) et du jet'),
('ssiap2-q181', 2, 'La présence du mode d''emploi affiché à proximité'),
('ssiap2-q181', 3, 'Le bon fonctionnement du robinet d''arrêt (ouverture et fermeture)'),
('ssiap2-q181', 4, 'La conformité du bac de rétention sous le RIA'),
('ssiap2-q182', 0, 'Le SSI s''arrête lors d''une coupure secteur'),
('ssiap2-q182', 1, 'Le SSI est alimenté par ses propres alimentations électriques de sécurité (batteries ou alimentation sur source de sécurité) avec une autonomie minimale de 1 heure en alarme après avoir maintenu la veille pendant 12 heures'),
('ssiap2-q182', 2, 'Le SSI passe sur groupe électrogène immédiatement'),
