insert into public.cc_question_options (question_id, option_index, option_text) values
('ssiap3-q149', 0, 'Sa responsabilité se limite aux seules zones accessibles au public'),
('ssiap3-q149', 1, 'Sa responsabilité s''étend à l''ensemble de l''établissement y compris les locaux techniques, qui présentent souvent des risques plus élevés et doivent faire l''objet de vérifications spécifiques et de procédures d''intervention adaptées'),
('ssiap3-q149', 2, 'Les locaux techniques relèvent exclusivement du service de maintenance'),
('ssiap3-q149', 3, 'Sa responsabilité est partagée à 50/50 avec le responsable maintenance'),
('ssiap3-q149', 4, 'Aucune de ces réponses n''est correcte'),
('ssiap3-q158', 0, 'Dans tous les ERP sans exception'),
('ssiap3-q158', 1, 'Dans les ERP de grande hauteur et les ERP comportant des niveaux en hauteur où l''évacuation totale vers l''extérieur est difficile ou dangereuse pour les PMR ou les occupants à mobilité réduite temporaire'),
('ssiap3-q158', 2, 'Uniquement dans les maisons de retraite'),
('ssiap3-q158', 3, 'Dans les ERP dont le sous-sol dépasse 1 000 m²'),
('ssiap3-q158', 4, 'Aucune de ces réponses n''est correcte'),
('ssiap3-q161', 0, 'Identification des biens essentiels à protéger (vies humaines, biens patrimoniaux, continuité d''exploitation)'),
('ssiap3-q161', 1, 'Recensement des sources de risque (menaces : défaillances techniques, comportements humains, malveillance, causes naturelles)'),
('ssiap3-q161', 2, 'Évaluation de la vraisemblance et de la gravité de chaque scénario de risque'),
('ssiap3-q161', 3, 'Définition des mesures de traitement du risque résiduel'),
('ssiap3-q161', 4, 'Calcul du coût exact de chaque sinistre potentiel'),
('ssiap3-q165', 0, 'Contester le rapport de l''organisme pour protéger l''établissement'),
('ssiap3-q165', 1, 'Informer immédiatement la direction, engager les mesures correctives ou compensatoires selon l''urgence, consigner dans le registre de sécurité et planifier la levée de la non-conformité avec un délai réaliste'),
('ssiap3-q165', 2, 'Attendre la prochaine visite de commission pour traiter la non-conformité'),
('ssiap3-q165', 3, 'Demander à l''organisme de ne pas mentionner la non-conformité dans son rapport'),
('ssiap3-q165', 4, 'Aucune de ces réponses n''est correcte'),
('ssiap3-q166', 0, 'Adéquation du nombre et de la largeur des dégagements pour le nouvel effectif'),
('ssiap3-q166', 1, 'Conformité de la ventilation et du désenfumage pour un local recevant plus de personnes'),
('ssiap3-q166', 2, 'Vérification que la modification ne nécessite pas un dépôt de dossier modificatif à la commission'),
('ssiap3-q166', 3, 'Vérification de la charge calorifique (mobilier de réunion vs mobilier de bureau)'),
('ssiap3-q166', 4, 'Vérification que le changement d''affectation ne modifie pas la catégorie ERP ou le type'),
('ssiap3-q168', 0, 'En affirmant simplement que la solution est équivalente sans démonstration technique'),
('ssiap3-q168', 1, 'En produisant une étude ISI documentée avec modélisation des scénarios de sinistre, calcul RSET/ASET, démonstration que les objectifs de sécurité (évacuation, confinement, accès secours) sont atteints avec la solution proposée, validée par un bureau d''études spécialisé et un organisme agréé'),
('ssiap3-q168', 2, 'En copiant une étude réalisée pour un bâtiment similaire sans adaptation'),
('ssiap3-q168', 3, 'L''équivalence ne peut jamais être démontrée, seul le prescriptif réglementaire est acceptable'),
('ssiap3-q168', 4, 'Aucune de ces réponses n''est correcte'),
('ssiap3-q173', 0, '1 an'),
('ssiap3-q173', 1, '5 ans'),
('ssiap3-q173', 2, 'Aucune de ces réponses n''est correcte'),
('ssiap3-q173', 3, '10 ans'),
('ssiap3-q175', 0, 'La cuisine ouverte ne présente pas de risque spécifique'),
('ssiap3-q175', 1, 'Il évalue les risques de propagation du feu et des fumées de cuisson vers la salle (absence de séparation coupe-feu), vérifie l''adéquation du système d''extraction des graisses et de la hotte, et s''assure de la présence de moyens d''extinction adaptés aux feux de classe F à portée des cuisiniers'),
('ssiap3-q175', 2, 'Il impose systématiquement une paroi coupe-feu entre la cuisine et la salle'),
('ssiap3-q175', 3, 'La cuisine ouverte est interdite dans les ERP de catégorie 1'),
('ssiap3-q175', 4, 'Aucune de ces réponses n''est correcte'),
('ssiap3-q179', 0, 'Interface entre la réglementation habitation (CCH) et la réglementation ERP (règlement de sécurité)'),
('ssiap3-q179', 1, 'Compartimentage entre la partie commerciale et la partie habitation (plancher entre R+1 commercial et R+2 logement)'),
('ssiap3-q179', 2, 'Système d''alarme adapté aux deux types d''occupants (commerçants le jour, résidents la nuit)'),
('ssiap3-q179', 3, 'Les deux réglementations s''excluant mutuellement, seule la plus contraignante s''applique'),
('ssiap3-q179', 4, 'Coordination entre le service SSIAP de la partie commerciale et les résidents en cas de sinistre'),
('ssiap3-q187', 0, 'Uniquement l''état esthétique des équipements visibles'),
('ssiap3-q187', 1, 'État de conformité réglementaire des installations (SSI, extincteurs, désenfumage, éclairage de sécurité), état du registre de sécurité, historique des visites de commission et des non-conformités, et identification des travaux nécessaires avant ou après cession'),
('ssiap3-q187', 2, 'Uniquement la valeur marchande des équipements de sécurité'),
('ssiap3-q187', 3, 'L''audit de sécurité incendie n''est pas possible sans autorisation de la commission de sécurité'),
('ssiap3-q187', 4, 'Aucune de ces réponses n''est correcte'),
('ssiap3-q189', 0, 'Ignorer la mise en demeure et poursuivre l''exploitation'),
('ssiap3-q189', 1, 'Informer immédiatement la direction, analyser les motifs précis de la mise en demeure, engager en urgence les mesures correctives permettant de lever les points bloquants, documenter les actions et demander une contre-visite dans les délais impartis'),
('ssiap3-q189', 2, 'Contester juridiquement sans engager de travaux'),
('ssiap3-q189', 3, 'Fermer définitivement l''établissement sans possibilité de réouverture'),
('ssiap3-q189', 4, 'Aucune de ces réponses n''est correcte'),
('ssiap3-q190', 0, 'Classe A2'),
('ssiap3-q190', 1, 'Classe B'),
('ssiap3-q190', 2, 'Classe C'),
('ssiap3-q190', 3, 'Aucune de ces réponses n''est correcte'),
('ssiap3-q195', 0, 'Forte densité de public dans l''obscurité rendant l''évacuation difficile et la panique probable'),
('ssiap3-q195', 1, 'Effets spéciaux (fumée artificielle, lasers, stroboscopes) pouvant perturber la détection ou désorienté le public'),
('ssiap3-q195', 2, 'Consommation d''alcool réduisant la réactivité et le comportement rationnel en cas d''alarme'),
('ssiap3-q195', 3, 'Les discothèques ne sont pas soumises à la réglementation ERP'),
('ssiap3-q195', 4, 'Niveau sonore élevé pouvant couvrir l''alarme incendie standard'),
('ssiap3-q197', 0, 'Détection automatique généralisée obligatoire dans la totalité de l''établissement y compris les chambres'),
('ssiap3-q197', 1, 'Stratégie d''évacuation horizontale progressive adaptée à des résidents à mobilité réduite'),
('ssiap3-q197', 2, 'Effectif SSIAP renforcé la nuit en raison de la vulnérabilité des résidents endormis'),
('ssiap3-q197', 3, 'Possibilité d''évacuer les 120 résidents vers l''extérieur en moins de 3 minutes'),
('ssiap3-q197', 4, 'Formation spécifique du personnel soignant aux procédures d''évacuation incendie');
