insert into public.cc_question_options (question_id, option_index, option_text) values
('ssiap3-q7', 0, 'Contrats de maintenance des équipements de sécurité (SSI, extincteurs, sprinklers)'),
('ssiap3-q7', 1, 'Vérifications périodiques réglementaires par organismes agréés'),
('ssiap3-q7', 2, 'Formations et recyclages du personnel SSIAP'),
('ssiap3-q7', 3, 'Renouvellement et remplacement des équipements obsolètes ou hors service'),
('ssiap3-q7', 4, 'Frais de communication commerciale de l''établissement'),
('ssiap3-q8', 0, 'La prévention n''est pas du ressort du SSIAP 3, uniquement la réponse aux sinistres'),
('ssiap3-q8', 1, 'En mettant en place une politique globale : audits réguliers des risques, formation de tous les occupants, suivi des non-conformités, analyse des retours d''expérience, et communication proactive avec la direction sur les investissements nécessaires'),
('ssiap3-q8', 2, 'En augmentant uniquement le nombre d''extincteurs'),
('ssiap3-q8', 3, 'En confiant la prévention à un bureau d''études extérieur'),
('ssiap3-q8', 4, 'Aucune de ces réponses n''est correcte'),
('ssiap3-q9', 0, 'La superficie totale et le nombre de niveaux'),
('ssiap3-q9', 1, 'L''effectif du public autorisé'),
('ssiap3-q9', 2, 'La catégorie et le type d''ERP selon la réglementation (instruction technique SSIAP)'),
('ssiap3-q9', 3, 'Les horaires d''ouverture (effectif différent jour/nuit/fermeture)'),
('ssiap3-q9', 4, 'Le nombre de restaurants présents dans le centre'),
('ssiap3-q10', 0, 'La sécurité incendie n''a aucun lien avec le PCA'),
('ssiap3-q10', 1, 'Il contribue en définissant les scénarios de sinistre incendie pouvant impacter l''activité, les procédures de retour à la normale après sinistre, et les mesures permettant la continuité partielle en cas d''incident'),
('ssiap3-q10', 2, 'Il rédige uniquement la liste des équipements de remplacement'),
('ssiap3-q10', 3, 'Le PCA est entièrement rédigé par la direction sans contribution du SSIAP 3'),
('ssiap3-q10', 4, 'Aucune de ces réponses n''est correcte'),
('ssiap3-q11', 0, 'Il ne peut rien faire si la direction refuse, il doit accepter'),
('ssiap3-q11', 1, 'En présentant une analyse coût/risque : coût de l''investissement vs coûts potentiels d''un sinistre (pertes matérielles, interruption d''activité, responsabilité pénale, impact d''image), et en formalisant le refus de la direction par écrit'),
('ssiap3-q11', 2, 'En menaçant de démissionner'),
('ssiap3-q11', 3, 'En effectuant les travaux sans autorisation'),
('ssiap3-q11', 4, 'Aucune de ces réponses n''est correcte'),
('ssiap3-q30', 0, 'Qualifications et certifications de l''entreprise et de ses techniciens'),
('ssiap3-q30', 1, 'Délais d''intervention garantis contractuellement (astreinte 24h/24)'),
('ssiap3-q30', 2, 'Qualité et exhaustivité des rapports de vérification fournis'),
('ssiap3-q30', 3, 'Prix le plus bas sans autre considération'),
('ssiap3-q30', 4, 'Références dans des établissements similaires au vôtre'),
('ssiap3-q31', 0, 'La RSE n''a aucun lien avec la sécurité incendie'),
('ssiap3-q31', 1, 'Il peut contribuer à la RSE en optimisant l''empreinte environnementale (réduction des fausses alarmes inutiles mobilisant les pompiers, choix d''agents extincteurs écologiques), en favorisant le bien-être des agents et en assurant la transparence de sa gouvernance sécurité'),
('ssiap3-q31', 2, 'La RSE concerne uniquement le département RH'),
('ssiap3-q31', 3, 'Il applique la RSE en réduisant les effectifs SSIAP pour diminuer les coûts'),
('ssiap3-q31', 4, 'Aucune de ces réponses n''est correcte'),
('ssiap3-q32', 0, 'Ce rôle n''existe pas, chaque établissement est totalement indépendant'),
('ssiap3-q32', 1, 'Définir un référentiel commun de procédures, de standards de formation et d''indicateurs de performance, tout en respectant les spécificités réglementaires locales et de chaque établissement'),
('ssiap3-q32', 2, 'Imposer exactement le même POI à tous les établissements sans adaptation'),
('ssiap3-q32', 3, 'Centraliser toutes les décisions sans consulter les SSIAP 3 de chaque site'),
('ssiap3-q32', 4, 'Aucune de ces réponses n''est correcte'),
('ssiap3-q33', 0, 'Il cède à la pression économique pour préserver son emploi'),
('ssiap3-q33', 1, 'Il documente formellement les risques liés aux économies demandées, propose des alternatives permettant de réduire les coûts sans compromettre la sécurité, et formalise son avis contraire par écrit si la direction maintient une décision dangereuse'),
('ssiap3-q33', 2, 'Il démissionne immédiatement'),
('ssiap3-q33', 3, 'Il applique les réductions sans en informer la commission de sécurité'),
('ssiap3-q33', 4, 'Aucune de ces réponses n''est correcte'),
('ssiap3-q40', 0, 'La culture sécurité ne concerne que le personnel SSIAP'),
('ssiap3-q40', 1, 'En développant des actions de sensibilisation pour tous les occupants : formations, affichages pédagogiques, exercices, communication sur les incidents, et en intégrant la sécurité dans l''accueil des nouveaux arrivants'),
('ssiap3-q40', 2, 'En sanctionnant immédiatement tout comportement à risque sans explication'),
('ssiap3-q40', 3, 'En réduisant les exercices d''évacuation pour ne pas déranger les occupants'),
('ssiap3-q40', 4, 'Aucune de ces réponses n''est correcte'),
('ssiap3-q51', 0, 'Il se base uniquement sur les obligations de recyclage réglementaires (SSIAP 1 : tous les 3 ans)'),
('ssiap3-q51', 1, 'Il croise les obligations réglementaires de recyclage, l''analyse des points faibles identifiés lors des exercices et audits, les évolutions des installations de l''établissement et les retours d''expérience d''incidents'),
('ssiap3-q51', 2, 'La formation continue n''est pas obligatoire au-delà du recyclage triennal'),
('ssiap3-q51', 3, 'Il délègue entièrement cette responsabilité aux SSIAP 2'),
('ssiap3-q51', 4, 'Aucune de ces réponses n''est correcte'),
('ssiap3-q52', 0, 'Il peut confier la maintenance à n''importe quel prestataire proposant le tarif le plus bas'),
('ssiap3-q52', 1, 'Il doit s''assurer que les prestataires sont qualifiés (qualification Q18 pour le SSI, certifications adaptées), définir des niveaux de service contractuels et vérifier l''exécution des prestations'),
('ssiap3-q52', 2, 'La responsabilité de la maintenance appartient entièrement au prestataire une fois le contrat signé'),
('ssiap3-q52', 3, 'La maintenance peut être réalisée par les agents SSIAP sans qualification spécifique'),
('ssiap3-q52', 4, 'Le SSIAP 3 n''a aucun rôle dans la sélection des prestataires'),
('ssiap3-q53', 0, 'Présenter uniquement le coût de mise en conformité réglementaire'),
('ssiap3-q53', 1, 'Construire une analyse coût-risque démontrant le coût de la non-conformité (responsabilité pénale, fermeture administrative, coût d''un sinistre) versus le coût de la mise en conformité, avec un plan de financement pluriannuel si nécessaire'),
('ssiap3-q53', 2, 'Imposer la décision sans justification, la sécurité ne se discute pas'),
('ssiap3-q53', 3, 'Réduire le périmètre de la mise à niveau pour baisser le coût'),
('ssiap3-q53', 4, 'Attendre la prochaine visite de commission pour que celle-ci impose les travaux'),
('ssiap3-q54', 0, 'Mesurable objectivement et régulièrement'),
('ssiap3-q54', 1, 'Directement lié aux objectifs de sécurité de l''établissement'),
('ssiap3-q54', 2, 'Suffisamment simple pour être compris par la direction non spécialiste'),
('ssiap3-q54', 3, 'Exclusivement quantitatif (aucun indicateur qualitatif n''est pertinent)'),
('ssiap3-q54', 4, 'Permettant de comparer les performances dans le temps (tendance)'),
