('ssiap3-q63', 3, 'Recruter en urgence au moment du départ pour minimiser les coûts'),
('ssiap3-q63', 4, 'Demander aux agents partant de continuer à travailler en tant que bénévoles');
insert into public.cc_questions (
insert into public.cc_question_options (question_id, option_index, option_text) values
('ssiap3-q71', 0, 'Il n''a pas vocation à participer au CHSCT/CSE'),
('ssiap3-q71', 1, 'Il apporte son expertise technique, présente les statistiques de sécurité incendie, informe sur les non-conformités et les plans d''action, et répond aux cc_questions des représentants du personnel'),
